--
-- Name: _job_backoff_minutes(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_job_backoff_minutes"("p_attempts" integer) RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
declare
  v int;
begin
  v := greatest(coalesce(p_attempts, 0), 0);
  if v <= 1 then
    return 1;
  end if;
  return least(1440, (2 ^ (v - 1))::int);
end;
$$;


