--
-- Name: _match_workflow_rule("jsonb", numeric, "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_match_workflow_rule"("p_conditions" "jsonb", "p_amount" numeric, "p_company_id" "uuid", "p_branch_id" "uuid", "p_currency" "text") RETURNS boolean
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
declare
  v_min numeric;
  v_max numeric;
  v_ccy text;
begin
  v_min := nullif(p_conditions->>'minAmount','')::numeric;
  v_max := nullif(p_conditions->>'maxAmount','')::numeric;
  v_ccy := nullif(p_conditions->>'currency','');

  if v_min is not null and p_amount < v_min then
    return false;
  end if;
  if v_max is not null and p_amount > v_max then
    return false;
  end if;
  if v_ccy is not null and upper(v_ccy) <> upper(coalesce(p_currency,'')) then
    return false;
  end if;
  if p_conditions ? 'companyId' then
    if nullif(p_conditions->>'companyId','')::uuid is distinct from p_company_id then
      return false;
    end if;
  end if;
  if p_conditions ? 'branchId' then
    if nullif(p_conditions->>'branchId','')::uuid is distinct from p_branch_id then
      return false;
    end if;
  end if;
  return true;
exception
  when others then
    return false;
end;
$$;


ALTER FUNCTION "public"."_match_workflow_rule"("p_conditions" "jsonb", "p_amount" numeric, "p_company_id" "uuid", "p_branch_id" "uuid", "p_currency" "text") OWNER TO "postgres";

--
-- Name: _merge_stock_items("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_merge_stock_items"("p_items" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item jsonb;
  v_map jsonb := '{}'::jsonb;
  v_item_id text;
  v_qty numeric;
  v_result jsonb := '[]'::jsonb;
  v_key text;
begin
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    return '[]'::jsonb;
  end if;

  for v_item in select value from jsonb_array_elements(p_items)
  loop
    v_item_id := nullif(btrim(coalesce(v_item->>'itemId', v_item->>'id')), '');
    v_qty := coalesce(nullif((v_item->>'quantity')::numeric, null), 0);
    if v_item_id is null or v_qty <= 0 then
      continue;
    end if;
    v_map := jsonb_set(
      v_map,
      array[v_item_id],
      to_jsonb(coalesce(nullif((v_map->>v_item_id)::numeric, null), 0) + v_qty),
      true
    );
  end loop;

  for v_key in select key from jsonb_each(v_map)
  loop
    v_result := v_result || jsonb_build_object('itemId', v_key, 'quantity', (v_map->>v_key)::numeric);
  end loop;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."_merge_stock_items"("p_items" "jsonb") OWNER TO "postgres";

