-- Name: _open_item_effective_fx_rate(numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_open_item_effective_fx_rate"("p_foreign" numeric, "p_base" numeric) RETURNS numeric
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select
    case
      when p_foreign is null then null
      when abs(coalesce(p_foreign,0)) <= 1e-12 then null
      else (p_base / p_foreign)
    end
$$;


