--
-- Name: _party_ledger_delta("uuid", "text", numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_party_ledger_delta"("p_account_id" "uuid", "p_direction" "text", "p_amount" numeric) RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_norm text;
  v_amt numeric;
begin
  if p_account_id is null then
    return 0;
  end if;
  v_amt := coalesce(p_amount, 0);
  if v_amt = 0 then
    return 0;
  end if;
  select coa.normal_balance into v_norm from public.chart_of_accounts coa where coa.id = p_account_id;
  v_norm := coalesce(v_norm, 'debit');
  if v_norm = 'debit' then
    return case when p_direction = 'debit' then v_amt else -v_amt end;
  end if;
  return case when p_direction = 'credit' then v_amt else -v_amt end;
end;
$$;


ALTER FUNCTION "public"."_party_ledger_delta"("p_account_id" "uuid", "p_direction" "text", "p_amount" numeric) OWNER TO "postgres";

--
-- Name: _party_open_item_apply_delta("uuid", numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_party_open_item_apply_delta"("p_open_item_id" "uuid", "p_delta_base" numeric, "p_delta_foreign" numeric) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item public.party_open_items%rowtype;
  v_new_base numeric;
  v_new_foreign numeric;
begin
  select * into v_item
  from public.party_open_items poi
  where poi.id = p_open_item_id
  for update;

  if not found then
    raise exception 'open item not found';
  end if;

  v_new_base := coalesce(v_item.open_base_amount, 0) + coalesce(p_delta_base, 0);

  if v_item.open_foreign_amount is null then
    v_new_foreign := null;
  else
    v_new_foreign := coalesce(v_item.open_foreign_amount, 0) + coalesce(p_delta_foreign, 0);
  end if;

  if v_new_base < -1e-6 then
    raise exception 'open_base_amount would become negative';
  end if;

  if v_new_foreign is not null and v_new_foreign < -1e-6 then
    raise exception 'open_foreign_amount would become negative';
  end if;

  update public.party_open_items
  set open_base_amount = greatest(v_new_base, 0),
      open_foreign_amount = case when v_new_foreign is null then null else greatest(v_new_foreign, 0) end,
      status = case
        when greatest(v_new_base, 0) <= 1e-6 and (v_new_foreign is null or greatest(v_new_foreign, 0) <= 1e-6) then 'settled'
        when greatest(v_new_base, 0) <= 1e-6 and v_new_foreign is not null and greatest(v_new_foreign, 0) > 1e-6 then 'partially_settled'
        when greatest(v_new_base, 0) > 1e-6 then 'partially_settled'
        else 'open'
      end
  where id = p_open_item_id;
end;
$$;


ALTER FUNCTION "public"."_party_open_item_apply_delta"("p_open_item_id" "uuid", "p_delta_base" numeric, "p_delta_foreign" numeric) OWNER TO "postgres";

--
-- Name: _party_open_item_type("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_party_open_item_type"("p_source_table" "text", "p_source_event" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
declare
  v_st text := lower(coalesce(p_source_table,''));
  v_ev text := lower(coalesce(p_source_event,''));
begin
  if v_st = 'party_documents' then
    if v_ev = 'ar_invoice' then return 'invoice'; end if;
    if v_ev = 'ap_bill' then return 'bill'; end if;
    if v_ev = 'ar_receipt' then return 'receipt'; end if;
    if v_ev = 'ap_payment' then return 'payment'; end if;
    if v_ev = 'advance' then return 'advance'; end if;
    if v_ev = 'custodian' then return 'advance'; end if;
    if v_ev = 'ar_credit_note' then return 'credit_note'; end if;
    if v_ev = 'ap_credit_note' then return 'credit_note'; end if;
    if v_ev = 'ar_debit_note' then return 'debit_note'; end if;
    if v_ev = 'ap_debit_note' then return 'debit_note'; end if;
    return 'document';
  end if;

  if v_st = 'orders' then
    return 'invoice';
  end if;

  if v_st = 'purchase_orders' then
    return 'bill';
  end if;

  if v_st = 'payments' then
    if v_ev like 'in:%' then return 'receipt'; end if;
    if v_ev like 'out:%' then return 'payment'; end if;
    return 'payment';
  end if;

  if v_st = 'supplier_credit_notes' then
    return 'credit_note';
  end if;

  if v_st = 'manual' then
    return 'manual';
  end if;

  return 'other';
end;
$$;


ALTER FUNCTION "public"."_party_open_item_type"("p_source_table" "text", "p_source_event" "text") OWNER TO "postgres";

--
-- Name: _payroll_last_day("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_payroll_last_day"("p_period_ym" "text") RETURNS "date"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
declare
  v_year int;
  v_month int;
  v_first date;
begin
  v_year := nullif(split_part(p_period_ym, '-', 1), '')::int;
  v_month := nullif(split_part(p_period_ym, '-', 2), '')::int;
  if v_year is null or v_month is null or v_month < 1 or v_month > 12 then
    raise exception 'invalid period_ym';
  end if;
  v_first := make_date(v_year, v_month, 1);
  return (v_first + interval '1 month - 1 day')::date;
end;
$$;


ALTER FUNCTION "public"."_payroll_last_day"("p_period_ym" "text") OWNER TO "postgres";

--
-- Name: _payroll_line_apply(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_payroll_line_apply"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_g numeric;
  v_a numeric;
  v_d numeric;
begin
  v_g := coalesce(new.gross, 0);
  v_a := coalesce(new.allowances, 0);
  v_d := coalesce(new.deductions, 0);
  if v_g < 0 or v_a < 0 or v_d < 0 then
    raise exception 'invalid payroll line values';
  end if;
  new.net := greatest(0, v_g + v_a - v_d);
  return new;
end;
$$;


ALTER FUNCTION "public"."_payroll_line_apply"() OWNER TO "postgres";

--
-- Name: _payroll_lock_non_draft_lines(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_payroll_lock_non_draft_lines"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_status text;
  v_run_id uuid;
begin
  v_run_id := coalesce(new.run_id, old.run_id);
  select r.status into v_status from public.payroll_runs r where r.id = v_run_id;
  if coalesce(v_status,'draft') <> 'draft' then
    raise exception 'payroll run is locked';
  end if;
  return coalesce(new, old);
end;
$$;


ALTER FUNCTION "public"."_payroll_lock_non_draft_lines"() OWNER TO "postgres";

--
-- Name: _pick_fx_for_landed_cost("text", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_pick_fx_for_landed_cost"("p_currency" "text", "p_date" "date") RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
  v_base_hi boolean := false;
  v_cur text;
  v_cur_hi boolean := false;
  v_acc numeric;
  v_op numeric;
  v_fx numeric;
begin
  v_base := public.get_base_currency();
  v_cur := upper(nullif(btrim(coalesce(p_currency, '')), ''));
  if v_cur is null or v_cur = '' then
    v_cur := v_base;
  end if;
  if v_cur = v_base then
    return 1;
  end if;

  begin
    select coalesce(c.is_high_inflation, false)
    into v_base_hi
    from public.currencies c
    where upper(c.code) = upper(v_base)
    limit 1;
  exception when others then
    v_base_hi := false;
  end;

  begin
    select coalesce(c.is_high_inflation, false)
    into v_cur_hi
    from public.currencies c
    where upper(c.code) = upper(v_cur)
    limit 1;
  exception when others then
    v_cur_hi := false;
  end;

  v_acc := public.get_fx_rate(v_cur, p_date, 'accounting');
  v_op := public.get_fx_rate(v_cur, p_date, 'operational');

  if v_acc is not null and v_acc > 0 then
    v_fx := v_acc;
  elsif v_op is not null and v_op > 0 then
    v_fx := v_op;
  else
    return null;
  end if;

  if v_acc is not null and v_acc > 0 and v_op is not null and v_op > 0 then
    if (not v_base_hi) and v_cur_hi then
      v_fx := least(v_acc, v_op);
    elsif v_base_hi and (not v_cur_hi) then
      v_fx := greatest(v_acc, v_op);
    else
      if v_acc > (v_op * 100) then
        v_fx := v_op;
      elsif v_op > (v_acc * 100) then
        v_fx := v_acc;
      end if;
    end if;
  end if;

  return v_fx;
end;
$$;


ALTER FUNCTION "public"."_pick_fx_for_landed_cost"("p_currency" "text", "p_date" "date") OWNER TO "postgres";

--
-- Name: _receive_purchase_order_partial_impl("uuid", "jsonb", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_receive_purchase_order_partial_impl"("p_order_id" "uuid", "p_items" "jsonb", "p_occurred_at" timestamp with time zone DEFAULT "now"()) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $_$
declare
  v_po record;
  v_item jsonb;
  v_item_id text;
  v_qty numeric;
  v_unit_cost numeric;
  v_existing_qty numeric;
  v_apply_qty numeric;
  v_old_qty numeric;
  v_old_avg numeric;
  v_new_qty numeric;
  v_effective_unit_cost numeric;
  v_new_avg numeric;
  v_receipt_id uuid;
  v_receipt_total numeric := 0;
  v_all_received boolean := true;
  v_ordered numeric;
  v_received numeric;
  v_expiry text;
  v_harvest text;
  v_expiry_iso text;
  v_harvest_iso text;
  v_category text;
  v_is_food boolean;
  v_expiry_required boolean;
  v_batch_id uuid;
  v_movement_id uuid;
  v_wh uuid;
  v_receipt_req_id uuid;
  v_receipt_req_status text;
  v_receipt_requires_approval boolean;
  v_receipt_approval_status text;
  v_po_req_id uuid;
  v_payload jsonb;
  v_payload_hash text;
  v_required_receipt boolean := false;
  v_required_po boolean := false;
  v_po_approved boolean := false;
  v_qc_status text;
  v_transport_cost numeric;
  v_supply_tax_cost numeric;
  v_used_transport_cost numeric;
  v_used_supply_tax_cost numeric;
  v_import_shipment_id uuid;
  v_idempotency_key text;
  v_existing_receipt_id uuid;
  v_reuse_receipt boolean := false;
  v_post_error text := null;
  v_post_failed boolean := false;
  v_post_status text := 'pending';
  v_mark_posted boolean := false;
  v_cost_sum numeric;
  v_remaining_to_allocate numeric;
  v_take_qty numeric;
  v_line_remaining numeric;
  v_pi record;
  v_uom_id uuid;
  v_uom_code text;
  v_qty_base numeric;
begin
  perform public._require_staff('receive_purchase_order_partial');
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;

  v_idempotency_key := nullif(
    btrim(
      coalesce(
        (p_items->0->>'idempotencyKey'),
        (p_items->0->>'idempotency_key')
      )
    ),
    ''
  );

  perform pg_advisory_xact_lock(hashtext('receive_po:' || p_order_id::text));

  select * into v_po
  from public.purchase_orders
  where id = p_order_id
  for update;
  if not found then
    raise exception 'purchase order not found';
  end if;
  if v_po.status = 'cancelled' then
    raise exception 'cannot receive cancelled purchase order';
  end if;

  begin
    update public.purchase_orders
    set fx_locked = true
    where id = p_order_id
      and coalesce(fx_locked, false) = false;
  exception when undefined_column then
    null;
  end;

  select public._resolve_default_warehouse_id() into v_wh;
  v_wh := coalesce(v_po.warehouse_id, v_wh);
  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  if to_regclass('public.warehouses') is not null then
    if not exists (select 1 from public.warehouses w where w.id = v_wh and coalesce(w.is_active, true) = true) then
      select public._resolve_default_warehouse_id() into v_wh;
      if v_wh is null then
        raise exception 'warehouse_id is required';
      end if;
    end if;
  end if;

  begin
    v_import_shipment_id := nullif(coalesce(p_items->0->>'importShipmentId', p_items->0->>'import_shipment_id'), '')::uuid;
  exception when others then
    v_import_shipment_id := null;
  end;

  v_payload := jsonb_build_object(
    'purchaseOrderId', p_order_id::text,
    'warehouseId', v_wh::text,
    'importShipmentId', case when v_import_shipment_id is null then null else v_import_shipment_id::text end
  );
  v_payload_hash := md5(coalesce(v_payload::text, ''));

  v_required_receipt := false;
  v_receipt_req_id := null;
  v_receipt_req_status := 'approved';
  v_receipt_requires_approval := false;
  v_receipt_approval_status := 'approved';

  begin
    insert into public.purchase_receipts(
      purchase_order_id,
      received_at,
      created_by,
      approval_status,
      approval_request_id,
      requires_approval,
      warehouse_id,
      branch_id,
      company_id,
      import_shipment_id,
      idempotency_key,
      posting_status
    )
    values (
      p_order_id,
      coalesce(p_occurred_at, now()),
      auth.uid(),
      case when v_receipt_req_id is null then 'pending' else 'approved' end,
      v_receipt_req_id,
      v_required_receipt,
      v_wh,
      v_po.branch_id,
      v_po.company_id,
      v_import_shipment_id,
      v_idempotency_key,
      'pending'
    )
    returning id into v_receipt_id;
  exception when unique_violation then
    if v_idempotency_key is not null then
      select pr.id
      into v_existing_receipt_id
      from public.purchase_receipts pr
      where pr.purchase_order_id = p_order_id
        and pr.idempotency_key = v_idempotency_key
      order by pr.created_at desc
      limit 1;
      if v_existing_receipt_id is not null then
        v_receipt_id := v_existing_receipt_id;
        v_reuse_receipt := true;
      else
        raise;
      end if;
    else
      raise;
    end if;
  end;

  for v_item in select value from jsonb_array_elements(p_items)
  loop
    v_item_id := coalesce(v_item->>'itemId', v_item->>'id');
    v_qty := coalesce(nullif(v_item->>'quantity', '')::numeric, 0);
    v_transport_cost := nullif(coalesce(v_item->>'transportCost', v_item->>'transport_cost'), '')::numeric;
    v_supply_tax_cost := nullif(coalesce(v_item->>'supplyTaxCost', v_item->>'supply_tax_cost'), '')::numeric;
    v_expiry := nullif(v_item->>'expiryDate', '');
    v_harvest := nullif(coalesce(v_item->>'harvestDate', v_item->>'productionDate'), '');
    v_expiry_iso := null;
    v_harvest_iso := null;
    v_category := null;

    begin
      v_import_shipment_id := nullif(coalesce(v_item->>'importShipmentId', v_item->>'import_shipment_id'), '')::uuid;
    exception when others then
      v_import_shipment_id := null;
    end;

    if v_item_id is null or v_item_id = '' then
      raise exception 'Invalid itemId';
    end if;
    if v_qty <= 0 then
      continue;
    end if;

    v_uom_id := null;
    begin
      v_uom_id := nullif(coalesce(v_item->>'uomId', v_item->>'uom_id'), '')::uuid;
    exception when others then
      v_uom_id := null;
    end;

    v_uom_code := nullif(btrim(coalesce(v_item->>'uomCode', v_item->>'uom_code', v_item->>'uom', v_item->>'unit', v_item->>'unitType')), '');
    if v_uom_id is null and v_uom_code is not null then
      v_uom_id := public.ensure_uom_code(v_uom_code, null);
    end if;

    if v_uom_id is null then
      select base_uom_id into v_uom_id from public.item_uom where item_id = v_item_id limit 1;
    end if;
    if v_uom_id is null then
      select max(pi.uom_id) into v_uom_id
      from public.purchase_items pi
      where pi.purchase_order_id = p_order_id
        and pi.item_id = v_item_id;
    end if;

    v_qty_base := public.item_qty_to_base(v_item_id, v_qty, v_uom_id);

    select coalesce(sum(coalesce(pri.quantity, 0)), 0)
    into v_existing_qty
    from public.purchase_receipt_items pri
    where pri.receipt_id = v_receipt_id
      and pri.item_id = v_item_id;

    v_apply_qty := greatest(v_qty_base - coalesce(v_existing_qty, 0), 0);
    if coalesce(v_apply_qty, 0) <= 0 then
      continue;
    end if;

    if v_reuse_receipt then
      update public.purchase_receipts
      set posting_status = 'pending',
          posting_error = null,
          posted_at = null,
          branch_id = coalesce(branch_id, v_po.branch_id),
          company_id = coalesce(company_id, v_po.company_id),
          import_shipment_id = coalesce(import_shipment_id, v_import_shipment_id)
      where id = v_receipt_id;
    end if;

    perform 1
    from public.purchase_items pi
    where pi.purchase_order_id = p_order_id
      and pi.item_id = v_item_id
    for update;
    if not found then
      raise exception 'item % not found in purchase order', v_item_id;
    end if;

    select
      coalesce(sum(
        case
          when pi.qty_base is not null then pi.qty_base
          when pi.uom_id is not null then public.item_qty_to_base(pi.item_id, pi.quantity, pi.uom_id)
          else coalesce(pi.quantity, 0)
        end
      ), 0),
      coalesce(sum(coalesce(pi.received_quantity, 0)), 0)
    into v_ordered, v_received
    from public.purchase_items pi
    where pi.purchase_order_id = p_order_id
      and pi.item_id = v_item_id;

    if (v_received + v_apply_qty) > (v_ordered + 1e-9) then
      raise exception 'received exceeds ordered for item %', v_item_id;
    end if;

    v_cost_sum := 0;
    v_remaining_to_allocate := v_apply_qty;
    for v_pi in
      select
        pi.id,
        coalesce(
          pi.qty_base,
          case
            when pi.uom_id is not null then public.item_qty_to_base(pi.item_id, pi.quantity, pi.uom_id)
            else pi.quantity
          end,
          0
        ) as quantity,
        coalesce(pi.received_quantity, 0) as received_quantity,
        coalesce(pi.unit_cost_base, pi.unit_cost, 0) as unit_cost
      from public.purchase_items pi
      where pi.purchase_order_id = p_order_id
        and pi.item_id = v_item_id
      order by pi.created_at asc, pi.id asc
      for update
    loop
      v_line_remaining := greatest(coalesce(v_pi.quantity, 0) - coalesce(v_pi.received_quantity, 0), 0);
      if v_line_remaining <= 0 then
        continue;
      end if;
      v_take_qty := least(v_line_remaining, v_remaining_to_allocate);
      if v_take_qty <= 0 then
        exit;
      end if;

      update public.purchase_items
      set received_quantity = coalesce(received_quantity, 0) + v_take_qty
      where id = v_pi.id;

      v_cost_sum := v_cost_sum + (v_take_qty * coalesce(v_pi.unit_cost, 0));
      v_remaining_to_allocate := v_remaining_to_allocate - v_take_qty;
      exit when v_remaining_to_allocate <= 1e-9;
    end loop;

    if v_remaining_to_allocate > 1e-9 then
      raise exception 'received exceeds ordered for item %', v_item_id;
    end if;

    v_unit_cost := case when v_apply_qty > 0 then (v_cost_sum / v_apply_qty) else 0 end;

    insert into public.stock_management(item_id, warehouse_id, available_quantity, qc_hold_quantity, reserved_quantity, unit, low_stock_threshold, last_updated, data)
    select v_item_id, v_wh, 0, 0, 0, coalesce(mi.unit_type, 'piece'), 5, now(), '{}'::jsonb
    from public.menu_items mi
    where mi.id = v_item_id
    on conflict (item_id, warehouse_id) do nothing;

    select coalesce(sm.available_quantity, 0) + coalesce(sm.qc_hold_quantity, 0), coalesce(sm.avg_cost, 0)
    into v_old_qty, v_old_avg
    from public.stock_management sm
    where sm.item_id::text = v_item_id
      and sm.warehouse_id = v_wh
    for update;

    select
      coalesce(v_transport_cost, coalesce(mi.transport_cost, 0)),
      coalesce(v_supply_tax_cost, coalesce(mi.supply_tax_cost, 0)),
      (v_unit_cost + coalesce(v_transport_cost, coalesce(mi.transport_cost, 0)) + coalesce(v_supply_tax_cost, coalesce(mi.supply_tax_cost, 0))),
      mi.category,
      coalesce(mi.is_food, false),
      coalesce(mi.expiry_required, false)
    into v_used_transport_cost, v_used_supply_tax_cost, v_effective_unit_cost, v_category, v_is_food, v_expiry_required
    from public.menu_items mi
    where mi.id = v_item_id;

    if v_old_qty < 0 then v_old_qty := 0; end if;
    if v_effective_unit_cost < 0 then v_effective_unit_cost := 0; end if;

    v_new_qty := v_old_qty + v_apply_qty;
    v_new_avg := case when v_new_qty > 0 then ((v_old_qty * v_old_avg) + (v_apply_qty * v_effective_unit_cost)) / v_new_qty else v_old_avg end;

    v_is_food := coalesce(v_is_food, (coalesce(v_category,'') = 'food'), false);
    v_expiry_required := coalesce(v_expiry_required, v_is_food, false);

    if v_expiry is not null and v_expiry <> '' then
      if v_expiry ~ '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' then
        v_expiry_iso := v_expiry;
      else
        raise exception 'invalid expiryDate for item %', v_item_id;
      end if;
    end if;
    if v_harvest is not null and v_harvest ~ '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' then
      v_harvest_iso := v_harvest;
    end if;

    if v_expiry_required and (v_expiry_iso is null or v_expiry_iso = '') then
      raise exception 'expiryDate is required for food item %', v_item_id;
    end if;

    v_qc_status := case when v_expiry_required then 'pending' else 'released' end;

    insert into public.batches(
      id,
      item_id,
      receipt_item_id,
      receipt_id,
      warehouse_id,
      batch_code,
      production_date,
      expiry_date,
      quantity_received,
      quantity_consumed,
      quantity_transferred,
      unit_cost,
      qc_status,
      status,
      data
    )
    values (
      gen_random_uuid(),
      v_item_id,
      null,
      v_receipt_id,
      v_wh,
      null,
      case when v_harvest_iso is null then null else v_harvest_iso::date end,
      case when v_expiry_iso is null then null else v_expiry_iso::date end,
      v_apply_qty,
      0,
      0,
      v_effective_unit_cost,
      v_qc_status,
      'active',
      jsonb_build_object(
        'purchaseOrderId', p_order_id,
        'purchaseReceiptId', v_receipt_id,
        'expiryDate', v_expiry_iso,
        'harvestDate', v_harvest_iso,
        'warehouseId', v_wh,
        'transportCost', v_used_transport_cost,
        'supplyTaxCost', v_used_supply_tax_cost,
        'importShipmentId', case when v_import_shipment_id is null then null else v_import_shipment_id::text end,
        'trxQty', v_qty,
        'trxUomId', case when v_uom_id is null then null else v_uom_id::text end
      )
    )
    returning id into v_batch_id;

    if v_qc_status = 'pending' then
      update public.stock_management
      set qc_hold_quantity = coalesce(qc_hold_quantity, 0) + v_apply_qty,
          avg_cost = v_new_avg,
          last_batch_id = v_batch_id,
          last_updated = now(),
          updated_at = now()
      where item_id::text = v_item_id
        and warehouse_id = v_wh;
    else
      update public.stock_management
      set available_quantity = coalesce(available_quantity, 0) + v_apply_qty,
          avg_cost = v_new_avg,
          last_batch_id = v_batch_id,
          last_updated = now(),
          updated_at = now()
      where item_id::text = v_item_id
        and warehouse_id = v_wh;
    end if;

    insert into public.purchase_receipt_items(receipt_id, item_id, quantity, unit_cost, total_cost, transport_cost, supply_tax_cost)
    values (v_receipt_id, v_item_id, v_apply_qty, v_effective_unit_cost, (v_apply_qty * v_effective_unit_cost), coalesce(v_used_transport_cost, 0), coalesce(v_used_supply_tax_cost, 0));

    v_receipt_total := v_receipt_total + (v_apply_qty * v_effective_unit_cost);

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_item_id, 'purchase_in', v_apply_qty, v_effective_unit_cost, (v_apply_qty * v_effective_unit_cost),
      'purchase_receipts', v_receipt_id::text, coalesce(p_occurred_at, now()), auth.uid(),
      jsonb_build_object(
        'purchaseOrderId', p_order_id,
        'purchaseReceiptId', v_receipt_id,
        'batchId', v_batch_id,
        'expiryDate', v_expiry_iso,
        'harvestDate', v_harvest_iso,
        'warehouseId', v_wh,
        'importShipmentId', case when v_import_shipment_id is null then null else v_import_shipment_id::text end
      ),
      v_batch_id,
      v_wh
    )
    returning id into v_movement_id;

    begin
      perform public.post_inventory_movement(v_movement_id);
      v_mark_posted := true;
    exception when others then
      v_post_failed := true;
      v_post_error := coalesce(v_post_error, sqlerrm);
    end;
  end loop;

  if v_post_failed then
    if v_post_error ~* 'not allowed|not authorized|permission|_require_staff|accounting\\.post' then
      v_post_status := 'pending';
    else
      v_post_status := 'failed';
    end if;
    update public.purchase_receipts
    set posting_status = v_post_status,
        posting_error = left(coalesce(v_post_error, ''), 2000),
        posted_at = null
    where id = v_receipt_id;
  elsif v_mark_posted then
    update public.purchase_receipts
    set posting_status = 'posted',
        posting_error = null,
        posted_at = now()
    where id = v_receipt_id;
  end if;

  for v_item_id, v_ordered, v_received in
    select
      pi.item_id,
      coalesce(
        pi.qty_base,
        case
          when pi.uom_id is not null then public.item_qty_to_base(pi.item_id, pi.quantity, pi.uom_id)
          else pi.quantity
        end,
        0
      ),
      coalesce(pi.received_quantity, 0)
    from public.purchase_items pi
    where pi.purchase_order_id = p_order_id
  loop
    if (v_received + 1e-9) < v_ordered then
      v_all_received := false;
      exit;
    end if;
  end loop;

  v_required_po := false;
  v_po_req_id := null;
  v_po_approved := true;

  if v_all_received then
    update public.purchase_orders
    set status = 'completed',
        updated_at = now(),
        approval_status = case when v_po_approved then 'approved' else approval_status end,
        approval_request_id = coalesce(approval_request_id, v_po_req_id)
    where id = p_order_id;
  else
    update public.purchase_orders
    set status = 'partial',
        updated_at = now()
    where id = p_order_id;
  end if;

  return v_receipt_id;
end;
$_$;


ALTER FUNCTION "public"."_receive_purchase_order_partial_impl"("p_order_id" "uuid", "p_items" "jsonb", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: _record_job_metric("text", boolean, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_record_job_metric"("p_job_type" "text", "p_succeeded" boolean, "p_runtime_ms" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_date date := current_date;
  v_type text := lower(coalesce(p_job_type,''));
  v_prev_avg numeric;
  v_prev_cnt int;
  v_new_avg numeric;
begin
  if v_type = '' then
    return;
  end if;

  select coalesce(succeeded_count,0) + coalesce(failed_count,0), avg_runtime_ms
  into v_prev_cnt, v_prev_avg
  from public.accounting_job_metrics m
  where m.metric_date = v_date and m.job_type = v_type;

  if v_prev_cnt is null then
    v_prev_cnt := 0;
    v_prev_avg := null;
  end if;

  if p_runtime_ms is not null and p_runtime_ms >= 0 then
    if v_prev_cnt = 0 or v_prev_avg is null then
      v_new_avg := p_runtime_ms;
    else
      v_new_avg := ((v_prev_avg * v_prev_cnt) + p_runtime_ms) / (v_prev_cnt + 1);
    end if;
  else
    v_new_avg := v_prev_avg;
  end if;

  insert into public.accounting_job_metrics(metric_date, job_type, succeeded_count, failed_count, avg_runtime_ms, updated_at)
  values (v_date, v_type, case when p_succeeded then 1 else 0 end, case when p_succeeded then 0 else 1 end, v_new_avg, now())
  on conflict (metric_date, job_type)
  do update set
    succeeded_count = public.accounting_job_metrics.succeeded_count + case when p_succeeded then 1 else 0 end,
    failed_count = public.accounting_job_metrics.failed_count + case when p_succeeded then 0 else 1 end,
    avg_runtime_ms = v_new_avg,
    updated_at = now();
exception when others then
  null;
end;
$$;


ALTER FUNCTION "public"."_record_job_metric"("p_job_type" "text", "p_succeeded" boolean, "p_runtime_ms" integer) OWNER TO "postgres";

--
-- Name: _require_staff("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_require_staff"("p_action" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if auth.uid() is null then
    raise exception 'not authenticated';
  end if;
  if not public.is_staff() then
    raise exception 'not allowed: %', coalesce(p_action, 'operation');
  end if;
end;
$$;


ALTER FUNCTION "public"."_require_staff"("p_action" "text") OWNER TO "postgres";

--
-- Name: _require_stock_manager("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_require_stock_manager"("p_action" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if auth.uid() is null then
    raise exception 'not authenticated';
  end if;
  if not public.has_admin_permission('stock.manage') then
    raise exception 'not allowed: %', coalesce(p_action, 'stock');
  end if;
end;
$$;


ALTER FUNCTION "public"."_require_stock_manager"("p_action" "text") OWNER TO "postgres";

--
-- Name: _resolve_batch_sale_failure_reason("text", "uuid", numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_resolve_batch_sale_failure_reason"("p_item_id" "text", "p_warehouse_id" "uuid", "p_quantity" numeric) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_qty numeric := greatest(coalesce(p_quantity, 0), 0);
  v_total_released numeric := 0;
  v_has_nonexpired boolean := false;
  v_has_nonexpired_unreleased boolean := false;
begin
  if p_item_id is null or btrim(p_item_id) = '' or p_warehouse_id is null then
    return 'NO_VALID_BATCH';
  end if;
  if v_qty <= 0 then
    v_qty := 1;
  end if;

  select exists(
    select 1
    from public.batches b
    where b.item_id::text = p_item_id::text
      and b.warehouse_id = p_warehouse_id
      and coalesce(b.status, 'active') = 'active'
      and (b.expiry_date is null or b.expiry_date >= current_date)
      and greatest(coalesce(b.quantity_received,0) - coalesce(b.quantity_consumed,0) - coalesce(b.quantity_transferred,0), 0) > 0
  ) into v_has_nonexpired;

  if not v_has_nonexpired then
    return 'NO_VALID_BATCH';
  end if;

  select exists(
    select 1
    from public.batches b
    where b.item_id::text = p_item_id::text
      and b.warehouse_id = p_warehouse_id
      and coalesce(b.status, 'active') = 'active'
      and (b.expiry_date is null or b.expiry_date >= current_date)
      and greatest(coalesce(b.quantity_received,0) - coalesce(b.quantity_consumed,0) - coalesce(b.quantity_transferred,0), 0) > 0
      and coalesce(b.qc_status,'released') <> 'released'
  ) into v_has_nonexpired_unreleased;

  if v_has_nonexpired_unreleased then
    return 'BATCH_NOT_RELEASED';
  end if;

  select coalesce(sum(greatest(coalesce(b.quantity_received,0) - coalesce(b.quantity_consumed,0) - coalesce(b.quantity_transferred,0), 0)), 0)
  into v_total_released
  from public.batches b
  where b.item_id::text = p_item_id::text
    and b.warehouse_id = p_warehouse_id
    and coalesce(b.status, 'active') = 'active'
    and (b.expiry_date is null or b.expiry_date >= current_date)
    and coalesce(b.qc_status,'released') = 'released';

  if v_total_released + 1e-9 < v_qty then
    return 'INSUFFICIENT_BATCH_QUANTITY';
  end if;

  return null;
end;
$$;


ALTER FUNCTION "public"."_resolve_batch_sale_failure_reason"("p_item_id" "text", "p_warehouse_id" "uuid", "p_quantity" numeric) OWNER TO "postgres";

--
-- Name: _resolve_default_admin_warehouse_id(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_resolve_default_admin_warehouse_id"() RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select w.id
  from public.warehouses w
  where w.is_active = true
  order by case when upper(coalesce(w.code,'')) = 'MAIN' then 0 else 1 end,
           w.created_at asc,
           w.code asc
  limit 1;
$$;


ALTER FUNCTION "public"."_resolve_default_admin_warehouse_id"() OWNER TO "postgres";

--
-- Name: _resolve_default_min_margin_pct("text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_resolve_default_min_margin_pct"("p_item_id" "text", "p_warehouse_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item jsonb;
  v_wh_pricing jsonb;
  v_settings jsonb;
  v_val numeric;
begin
  if p_item_id is null or btrim(p_item_id) = '' then
    return 0;
  end if;

  select data into v_item from public.menu_items mi where mi.id::text = p_item_id;
  if v_item is not null then
    begin
      v_val := nullif((v_item->'pricing'->>'minMarginPct')::numeric, null);
    exception when others then
      v_val := null;
    end;
    if v_val is not null then
      return greatest(0, v_val);
    end if;
  end if;

  if p_warehouse_id is not null then
    select pricing into v_wh_pricing from public.warehouses w where w.id = p_warehouse_id;
    if v_wh_pricing is not null then
      begin
        v_val := nullif((v_wh_pricing->>'defaultMinMarginPct')::numeric, null);
      exception when others then
        v_val := null;
      end;
      if v_val is not null then
        return greatest(0, v_val);
      end if;
    end if;
  end if;

  select data into v_settings from public.app_settings where id = 'singleton';
  if v_settings is not null then
    begin
      v_val := nullif((v_settings->'pricing'->>'defaultMinMarginPct')::numeric, null);
    exception when others then
      v_val := null;
    end;
    if v_val is not null then
      return greatest(0, v_val);
    end if;
  end if;

  return 0;
end;
$$;


ALTER FUNCTION "public"."_resolve_default_min_margin_pct"("p_item_id" "text", "p_warehouse_id" "uuid") OWNER TO "postgres";

--
-- Name: _resolve_default_warehouse_id(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_resolve_default_warehouse_id"() RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_warehouse_id uuid;
begin
  select w.id
  into v_warehouse_id
  from public.warehouses w
  where w.is_active = true
  order by (upper(coalesce(w.code, '')) = 'MAIN') desc, w.code asc
  limit 1;

  if v_warehouse_id is null then
    raise exception 'No active warehouse found';
  end if;
  return v_warehouse_id;
end;
$$;


ALTER FUNCTION "public"."_resolve_default_warehouse_id"() OWNER TO "postgres";

--
-- Name: _resolve_main_warehouse_id(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_resolve_main_warehouse_id"() RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select public._resolve_default_warehouse_id();
$$;


