--
-- Name: _resolve_open_shift_for_cash("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_resolve_open_shift_for_cash"("p_operator" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_shift_id uuid;
begin
  select s.id
  into v_shift_id
  from public.cash_shifts s
  where s.cashier_id = p_operator
    and coalesce(s.status, 'open') = 'open'
  order by s.opened_at desc
  limit 1;

  return v_shift_id;
end;
$$;


ALTER FUNCTION "public"."_resolve_open_shift_for_cash"("p_operator" "uuid") OWNER TO "postgres";

--
-- Name: _resolve_party_for_entry("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_resolve_party_for_entry"("p_source_table" "text", "p_source_id" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_party_id uuid;
  v_order record;
  v_po record;
  v_pay record;
  v_exp record;
  v_party_text text;
  v_emp uuid;
begin
  v_party_id := null;

  if p_source_table = 'orders' then
    begin
      select o.customer_auth_user_id, o.currency, o.fx_rate, o.total, o.base_total
      into v_order
      from public.orders o
      where o.id = (p_source_id)::uuid;
      if v_order.customer_auth_user_id is not null then
        v_party_id := public.ensure_financial_party_for_customer(v_order.customer_auth_user_id);
      end if;
    exception when others then
      v_party_id := null;
    end;
    return v_party_id;
  end if;

  if p_source_table = 'purchase_orders' then
    begin
      select po.supplier_id, po.currency, po.fx_rate, po.total_amount, po.base_total
      into v_po
      from public.purchase_orders po
      where po.id = (p_source_id)::uuid;
      if v_po.supplier_id is not null then
        v_party_id := public.ensure_financial_party_for_supplier(v_po.supplier_id);
      end if;
    exception when others then
      v_party_id := null;
    end;
    return v_party_id;
  end if;

  if p_source_table = 'inventory_movements' then
    begin
      select po.supplier_id
      into v_po
      from public.inventory_movements im
      left join public.batches b on b.id = im.batch_id
      left join public.purchase_receipts pr on pr.id = b.receipt_id
      left join public.purchase_orders po on po.id = pr.purchase_order_id
      where im.id = (p_source_id)::uuid;
    exception when others then
      v_po := null;
    end;
    if v_po.supplier_id is not null then
      return public.ensure_financial_party_for_supplier(v_po.supplier_id);
    end if;
    return null;
  end if;

  if p_source_table = 'payments' then
    begin
      select *
      into v_pay
      from public.payments p
      where p.id = (p_source_id)::uuid;
    exception when others then
      return null;
    end;
    if v_pay.id is null then
      return null;
    end if;

    if v_pay.reference_table = 'orders' then
      return public._resolve_party_for_entry('orders', v_pay.reference_id);
    end if;
    if v_pay.reference_table = 'purchase_orders' then
      return public._resolve_party_for_entry('purchase_orders', v_pay.reference_id);
    end if;
    if v_pay.reference_table = 'financial_parties' then
      begin
        v_party_id := nullif(trim(coalesce(v_pay.reference_id, '')), '')::uuid;
        return v_party_id;
      exception when others then
        return null;
      end;
    end if;
    if v_pay.reference_table = 'expenses' then
      begin
        select e.data
        into v_exp
        from public.expenses e
        where e.id = (v_pay.reference_id)::uuid;
      exception when others then
        v_exp := null;
      end;
      if v_exp is not null then
        v_party_text := nullif(trim(coalesce(v_exp.data->>'partyId','')), '');
        if v_party_text is not null then
          begin
            return v_party_text::uuid;
          exception when others then
            null;
          end;
        end if;
        v_party_text := nullif(trim(coalesce(v_exp.data->>'employeeId','')), '');
        if v_party_text is not null then
          begin
            v_emp := v_party_text::uuid;
            return public.ensure_financial_party_for_employee(v_emp);
          exception when others then
            null;
          end;
        end if;
      end if;
      return null;
    end if;
  end if;

  if p_source_table = 'expenses' then
    begin
      select e.data into v_exp from public.expenses e where e.id = (p_source_id)::uuid;
    exception when others then
      v_exp := null;
    end;
    if v_exp is not null then
      v_party_text := nullif(trim(coalesce(v_exp.data->>'partyId','')), '');
      if v_party_text is not null then
        begin
          return v_party_text::uuid;
        exception when others then
          null;
        end;
      end if;
      v_party_text := nullif(trim(coalesce(v_exp.data->>'employeeId','')), '');
      if v_party_text is not null then
        begin
          v_emp := v_party_text::uuid;
          return public.ensure_financial_party_for_employee(v_emp);
        exception when others then
          null;
        end;
      end if;
    end if;
    return null;
  end if;

  return null;
end;
$$;


ALTER FUNCTION "public"."_resolve_party_for_entry"("p_source_table" "text", "p_source_id" "text") OWNER TO "postgres";

--
-- Name: _run_accounting_job("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_run_accounting_job"("p_job_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_job public.accounting_jobs%rowtype;
  v_type text;
  v_period_end date;
  v_party_id uuid;
  v_started timestamptz;
  v_finished timestamptz;
  v_runtime_ms int;
  v_delay int;
  v_next timestamptz;
  v_attempt_no int;
  v_err text;
  v_sqlstate text;
begin
  select * into v_job
  from public.accounting_jobs j
  where j.id = p_job_id
  for update;
  if not found then
    return;
  end if;
  if v_job.status not in ('queued','failed') then
    return;
  end if;

  if v_job.attempts >= v_job.max_attempts then
    insert into public.accounting_job_dead_letters(job_id, job_type, payload, attempts, max_attempts, first_scheduled_at, dead_at, last_error)
    values (v_job.id, lower(v_job.job_type), v_job.payload, v_job.attempts, v_job.max_attempts, v_job.scheduled_at, clock_timestamp(), coalesce(v_job.last_error,'max attempts reached'))
    on conflict (job_id) do nothing;

    update public.accounting_jobs
    set status = 'dead',
        finished_at = clock_timestamp(),
        last_error = coalesce(last_error, 'max attempts reached')
    where id = v_job.id;
    return;
  end if;

  v_started := clock_timestamp();
  v_attempt_no := coalesce(v_job.attempts,0) + 1;

  update public.accounting_jobs
  set status = 'running',
      attempts = v_attempt_no,
      started_at = v_started,
      last_error = null
  where id = v_job.id;

  v_type := lower(v_job.job_type);
  v_err := null;
  v_sqlstate := null;

  begin
    if v_type = 'fx_revaluation' or v_type like 'smoke_fx_revaluation_%' then
      v_period_end := nullif(v_job.payload->>'periodEnd','')::date;
      if v_period_end is null then
        raise exception 'periodEnd required';
      end if;
      perform public.run_fx_revaluation(v_period_end);
    elsif v_type = 'auto_settlement' or v_type like 'smoke_auto_settlement_%' then
      v_party_id := nullif(v_job.payload->>'partyId','')::uuid;
      if v_party_id is null then
        raise exception 'partyId required';
      end if;
      perform public.auto_settle_party_items(v_party_id);
    elsif v_type = 'ledger_snapshot' or v_type like 'smoke_ledger_snapshot_%' then
      v_period_end := nullif(v_job.payload->>'asOf','')::date;
      if v_period_end is null then
        raise exception 'asOf required';
      end if;
      perform public.create_ledger_snapshot(v_period_end, null, null, 'job');
    elsif v_type = 'open_items_snapshot' or v_type like 'smoke_open_items_snapshot_%' then
      v_period_end := nullif(v_job.payload->>'asOf','')::date;
      if v_period_end is null then
        raise exception 'asOf required';
      end if;
      perform public.create_party_open_items_snapshot(v_period_end, null, null, 'job');
    else
      perform 1;
    end if;
  exception
    when others then
      v_err := left(coalesce(sqlerrm,'error'), 2000);
      v_sqlstate := coalesce(sqlstate,'');
  end;

  v_finished := clock_timestamp();
  v_runtime_ms := (extract(epoch from (v_finished - v_started)) * 1000)::int;

  if v_err is null then
    update public.accounting_jobs
    set status = 'succeeded',
        finished_at = v_finished
    where id = v_job.id;

    perform public._record_job_metric(v_type, true, v_runtime_ms);

    insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
    values (
      'accounting_jobs.succeeded',
      'accounting',
      v_job.id::text,
      auth.uid(),
      now(),
      jsonb_build_object('jobId', v_job.id::text, 'jobType', v_type, 'runtimeMs', v_runtime_ms),
      'LOW',
      'JOB_SUCCEEDED'
    );
    return;
  end if;

  v_delay := public._job_backoff_minutes(v_attempt_no);
  v_next := v_finished + make_interval(mins => v_delay);

  update public.accounting_jobs
  set status = case when v_attempt_no >= max_attempts then 'dead' else 'failed' end,
      finished_at = v_finished,
      scheduled_at = case when v_attempt_no >= max_attempts then scheduled_at else v_next end,
      last_error = v_err
  where id = v_job.id;

  insert into public.accounting_job_failures(job_id, job_type, attempt_no, occurred_at, error_message, error_detail, payload)
  values (
    v_job.id,
    lower(coalesce(v_job.job_type,'')),
    v_attempt_no,
    v_finished,
    v_err,
    jsonb_build_object('sqlstate', v_sqlstate, 'backoffMinutes', v_delay),
    coalesce(v_job.payload,'{}'::jsonb)
  );

  perform public._record_job_metric(lower(coalesce(v_job.job_type,'')), false, null);

  if v_attempt_no >= coalesce(v_job.max_attempts,5) then
    insert into public.accounting_job_dead_letters(job_id, job_type, payload, attempts, max_attempts, first_scheduled_at, dead_at, last_error)
    values (v_job.id, lower(coalesce(v_job.job_type,'')), coalesce(v_job.payload,'{}'::jsonb), v_attempt_no, coalesce(v_job.max_attempts,5), coalesce(v_job.scheduled_at, v_finished), v_finished, v_err)
    on conflict (job_id) do nothing;
  end if;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'accounting_jobs.failed',
    'accounting',
    v_job.id::text,
    auth.uid(),
    now(),
    jsonb_build_object('jobId', v_job.id::text, 'error', left(coalesce(v_err,'error'), 1000), 'backoffMinutes', v_delay),
    'MEDIUM',
    'JOB_FAILED'
  );
end;
$$;


ALTER FUNCTION "public"."_run_accounting_job"("p_job_id" "uuid") OWNER TO "postgres";

--
-- Name: _sync_order_terms_columns(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_sync_order_terms_columns"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
    declare
      v_terms text;
      v_net_days integer;
      v_due date;
      v_due_text text;
      v_basis timestamptz;
    begin
      v_terms := nullif(trim(coalesce(new.data->>'invoiceTerms','')), '');
      if v_terms is null then
        if coalesce((new.data->>'isCreditSale')::boolean, false) or coalesce(new.data->>'paymentMethod','') = 'ar' then
          v_terms := 'credit';
        else
          v_terms := 'cash';
        end if;
      end if;
      if v_terms <> 'credit' then
        v_terms := 'cash';
      end if;

      v_net_days := 0;
      begin
        v_net_days := greatest(0, coalesce(nullif((new.data->>'netDays')::int, 0), (new.data->>'creditDays')::int, new.net_days, 0));
      exception when others then
        v_net_days := greatest(0, coalesce(new.net_days, 0));
      end;

      v_due_text := nullif(trim(coalesce(new.data->>'dueDate','')), '');
      v_due := null;
      if v_due_text is not null then
        begin
          v_due := v_due_text::date;
        exception when others then
          v_due := null;
        end;
      end if;

      if v_due is null then
        begin
          v_basis := nullif(trim(coalesce(new.data->>'invoiceIssuedAt','')), '')::timestamptz;
        exception when others then
          v_basis := null;
        end;
        if v_basis is null then
          begin
            v_basis := nullif(trim(coalesce(new.data->>'deliveredAt','')), '')::timestamptz;
          exception when others then
            v_basis := null;
          end;
        end if;
        if v_basis is null then
          v_basis := coalesce(new.created_at, now());
        end if;

        if v_terms = 'cash' then
          v_due := (v_basis::date);
        else
          v_due := (v_basis::date + greatest(v_net_days, 0));
        end if;
      end if;

      new.invoice_terms := v_terms;
      new.net_days := greatest(0, coalesce(v_net_days, 0));
      new.due_date := v_due;
      return new;
    end
    $$;


ALTER FUNCTION "public"."_sync_order_terms_columns"() OWNER TO "postgres";

--
-- Name: _trg_inventory_transfers_unified_number(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_trg_inventory_transfers_unified_number"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_branch_id uuid;
begin
  if new.transfer_number is null
     or length(btrim(new.transfer_number)) = 0
     or new.transfer_number ~* '^IT-'
  then
    v_branch_id := public.branch_from_warehouse(new.from_warehouse_id);
    v_branch_id := coalesce(v_branch_id, public.get_default_branch_id());
    new.transfer_number := public.next_document_number('transfer', v_branch_id, coalesce(new.transfer_date, current_date));
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."_trg_inventory_transfers_unified_number"() OWNER TO "postgres";

