--
-- Name: _trg_purchase_orders_po_number(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_trg_purchase_orders_po_number"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if new.po_number is null or length(btrim(new.po_number)) = 0 then
    new.po_number := public._assign_po_number_v2(new.branch_id, new.purchase_date);
  end if;
  if new.reference_number is not null and length(btrim(new.reference_number)) = 0 then
    new.reference_number := null;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."_trg_purchase_orders_po_number"() OWNER TO "postgres";

--
-- Name: _trg_purchase_receipts_grn_number(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_trg_purchase_receipts_grn_number"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
    begin
      if new.grn_number is null or length(btrim(new.grn_number)) = 0 then
        if new.branch_id is null then
          new.grn_number := upper(concat('GRN-', substr(new.id::text, 1, 8)));
        else
          new.grn_number := public._assign_grn_number_v2(new.branch_id, new.received_at);
        end if;
      end if;
      return new;
    end;
    $$;


