--
-- Name: audit_changed_columns("jsonb", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."audit_changed_columns"("p_old" "jsonb", "p_new" "jsonb") RETURNS "text"[]
    LANGUAGE "plpgsql"
    AS $$
declare
  k text;
  keys text[];
  result text[] := '{}'::text[];
begin
  if p_old is null then
    p_old := '{}'::jsonb;
  end if;
  if p_new is null then
    p_new := '{}'::jsonb;
  end if;

  select array_agg(distinct key)
  into keys
  from (
    select jsonb_object_keys(p_old) as key
    union all
    select jsonb_object_keys(p_new) as key
  ) s;

  if keys is null then
    return result;
  end if;

  foreach k in array keys loop
    if (p_old -> k) is distinct from (p_new -> k) then
      result := array_append(result, k);
    end if;
  end loop;

  return result;
end;
$$;


ALTER FUNCTION "public"."audit_changed_columns"("p_old" "jsonb", "p_new" "jsonb") OWNER TO "postgres";

--
-- Name: audit_get_record_id("text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."audit_get_record_id"("p_table" "text", "p_row" "jsonb") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF p_row IS NULL THEN
    RETURN NULL;
  END IF;

  CASE p_table
    WHEN 'admin_users' THEN RETURN p_row->>'auth_user_id';
    WHEN 'customers' THEN RETURN p_row->>'auth_user_id';
    WHEN 'orders' THEN RETURN p_row->>'id';
    WHEN 'menu_items' THEN RETURN p_row->>'id';
    WHEN 'stock_management' THEN RETURN p_row->>'item_id';
    WHEN 'purchase_orders' THEN RETURN p_row->>'id';
    WHEN 'purchase_items' THEN RETURN p_row->>'id';
    WHEN 'addons' THEN RETURN p_row->>'id';
    WHEN 'delivery_zones' THEN RETURN p_row->>'id';
    WHEN 'coupons' THEN RETURN p_row->>'id';
    WHEN 'ads' THEN RETURN p_row->>'id';
    WHEN 'challenges' THEN RETURN p_row->>'id';
    WHEN 'app_settings' THEN RETURN p_row->>'id';
    WHEN 'item_categories' THEN RETURN p_row->>'id';
    WHEN 'unit_types' THEN RETURN p_row->>'id';
    WHEN 'freshness_levels' THEN RETURN p_row->>'id';
    WHEN 'banks' THEN RETURN p_row->>'id';
    WHEN 'transfer_recipients' THEN RETURN p_row->>'id';
    WHEN 'reviews' THEN RETURN p_row->>'id';
    ELSE
      IF (p_row ? 'id') THEN RETURN p_row->>'id'; END IF;
      RETURN NULL;
  END CASE;
END;
$$;


ALTER FUNCTION "public"."audit_get_record_id"("p_table" "text", "p_row" "jsonb") OWNER TO "postgres";

--
-- Name: audit_row_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."audit_row_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_table text := tg_table_name;
  v_op text := lower(tg_op);
  v_row jsonb;
  v_old jsonb;
  v_new jsonb;
  v_record_id text;
  v_changed text[];
  v_changed_filtered text[] := '{}'::text[];
  v_key text;
  v_metadata jsonb;
  v_risk_level text;
  v_reason_code text;
BEGIN
  IF auth.uid() IS NULL THEN
    IF tg_op = 'DELETE' THEN RETURN old; END IF;
    RETURN new;
  END IF;

  IF v_table IN ('customers', 'reviews') AND NOT public.is_admin() THEN
    IF tg_op = 'DELETE' THEN RETURN old; END IF;
    RETURN new;
  END IF;

  -- Try to capture reason from session setting (set by app before critical ops)
  -- App should run: set_config('app.audit_reason', 'USER_CANCELLATION', true);
  BEGIN
    v_reason_code := current_setting('app.audit_reason', true);
  EXCEPTION WHEN OTHERS THEN
    v_reason_code := NULL;
  END;

  v_metadata := jsonb_build_object(
    'table', v_table,
    'op', v_op
  );

  IF tg_op = 'INSERT' THEN
    v_new := to_jsonb(new);
    v_row := v_new;
    v_record_id := public.audit_get_record_id(v_table, v_row);
    v_metadata := v_metadata || jsonb_build_object('recordId', v_record_id, 'new_values', v_new);
    v_risk_level := public.calculate_risk_level(v_table, v_op, NULL, v_new);
  
  ELSIF tg_op = 'UPDATE' THEN
    v_old := to_jsonb(old);
    v_new := to_jsonb(new);
    v_row := v_new;
    v_record_id := public.audit_get_record_id(v_table, v_row);
    
    v_changed := public.audit_changed_columns(v_old, v_new);
    
    IF v_changed IS NOT NULL THEN
      FOREACH v_key IN ARRAY v_changed LOOP
        IF v_key NOT IN ('updated_at', 'created_at', 'last_updated') THEN
          v_changed_filtered := array_append(v_changed_filtered, v_key);
        END IF;
      END LOOP;
    END IF;

    IF array_length(v_changed_filtered, 1) IS NULL THEN
      RETURN new;
    END IF;

    v_metadata := v_metadata || jsonb_build_object(
        'recordId', v_record_id, 
        'changedColumns', v_changed_filtered,
        'old_values', v_old,
        'new_values', v_new
    );
    v_risk_level := public.calculate_risk_level(v_table, v_op, v_old, v_new);

  ELSE -- DELETE
    v_old := to_jsonb(old);
    v_row := v_old;
    v_record_id := public.audit_get_record_id(v_table, v_row);
    v_metadata := v_metadata || jsonb_build_object('recordId', v_record_id, 'old_values', v_old);
    v_risk_level := public.calculate_risk_level(v_table, v_op, v_old, NULL);
  END IF;

  -- Enforce Reason Code for HIGH risk operations if missing (Soft Check for now to avoid breakage, but logs warning)
  IF v_risk_level = 'HIGH' AND v_reason_code IS NULL THEN
     v_reason_code := 'MISSING_REASON';
     -- In strict mode, we would: RAISE EXCEPTION 'Reason code is required for high risk operations';
  END IF;

  INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  VALUES (
    v_table || '.' || v_op,
    public.audit_table_module(v_table),
    jsonb_build_object(
      'recordId', v_record_id,
      'changedColumns', v_changed_filtered,
      'risk', v_risk_level
    )::text,
    auth.uid(),
    now(),
    v_metadata,
    v_risk_level,
    v_reason_code
  );

  IF tg_op = 'DELETE' THEN
    RETURN old;
  END IF;
  RETURN new;
END;
$$;


ALTER FUNCTION "public"."audit_row_change"() OWNER TO "postgres";

--
-- Name: audit_table_module("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."audit_table_module"("p_table" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  CASE p_table
    WHEN 'admin_users' THEN RETURN 'auth';
    WHEN 'customers' THEN RETURN 'customers';
    WHEN 'menu_items' THEN RETURN 'inventory';
    WHEN 'addons' THEN RETURN 'inventory';
    WHEN 'stock_management' THEN RETURN 'inventory';
    WHEN 'purchase_orders' THEN RETURN 'purchasing';
    WHEN 'purchase_items' THEN RETURN 'purchasing';
    WHEN 'delivery_zones' THEN RETURN 'orders';
    WHEN 'orders' THEN RETURN 'orders';
    WHEN 'coupons' THEN RETURN 'orders';
    WHEN 'ads' THEN RETURN 'marketing';
    WHEN 'challenges' THEN RETURN 'marketing';
    WHEN 'app_settings' THEN RETURN 'settings';
    WHEN 'item_categories' THEN RETURN 'inventory';
    WHEN 'unit_types' THEN RETURN 'inventory';
    WHEN 'freshness_levels' THEN RETURN 'inventory';
    WHEN 'banks' THEN RETURN 'settings';
    WHEN 'transfer_recipients' THEN RETURN 'settings';
    WHEN 'reviews' THEN RETURN 'reviews';
    ELSE
      RETURN 'system';
  END CASE;
END;
$$;


ALTER FUNCTION "public"."audit_table_module"("p_table" "text") OWNER TO "postgres";

--
-- Name: auto_allocate_payments_for_order("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."auto_allocate_payments_for_order"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_open record;
  v_delivered_at timestamptz;
  v_pay record;
  v_amt numeric;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.manage')) then
    raise exception 'not authorized';
  end if;
  if p_order_id is null then
    raise exception 'order_id required';
  end if;
  select public.order_delivered_at(p_order_id) into v_delivered_at;
  if v_delivered_at is null then
    return;
  end if;
  select *
  into v_open
  from public.ar_open_items
  where order_id = p_order_id
    and status = 'open'
  order by created_at desc
  limit 1;
  if not found then
    return;
  end if;
  for v_pay in
    select id, coalesce(base_amount, amount, 0) as base_amount
    from public.payments
    where reference_table = 'orders'
      and reference_id = p_order_id::text
      and direction = 'in'
      and coalesce(base_amount, amount, 0) > 0
      and occurred_at >= v_delivered_at
    order by occurred_at asc
  loop
    begin
      perform public.flag_payment_allocation_status(v_pay.id);
    exception when others then
      null;
    end;
    select least(greatest(coalesce(v_open.open_balance, 0), 0), v_pay.base_amount)
    into v_amt;
    if coalesce(v_amt, 0) > 0 then
      perform public.allocate_payment_to_open_item(v_open.id, v_pay.id, v_amt);
      select * into v_open from public.ar_open_items where id = v_open.id;
      if coalesce(v_open.open_balance, 0) <= 0 then
        exit;
      end if;
    end if;
  end loop;
end;
$$;


ALTER FUNCTION "public"."auto_allocate_payments_for_order"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: auto_settle_party_items("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."auto_settle_party_items"("p_party_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_allocs jsonb := '[]'::jsonb;
  v_debit record;
  v_credit record;
  v_remaining_base numeric;
  v_remaining_foreign numeric;
  v_alloc_base numeric;
  v_alloc_foreign numeric;
  v_id uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  if p_party_id is null then
    raise exception 'party_id required';
  end if;

  if public.is_in_closed_period(now()) then
    raise exception 'accounting period is closed';
  end if;

  for v_debit in
    select *
    from public.party_open_items
    where party_id = p_party_id
      and status in ('open','partially_settled')
      and direction = 'debit'
    order by due_date asc nulls last, occurred_at asc, created_at asc
  loop
    v_remaining_base := coalesce(v_debit.open_base_amount, 0);
    v_remaining_foreign := coalesce(v_debit.open_foreign_amount, 0);

    if v_remaining_base <= 1e-6 and (v_debit.open_foreign_amount is null or v_remaining_foreign <= 1e-6) then
      continue;
    end if;

    for v_credit in
      select *
      from public.party_open_items
      where party_id = p_party_id
        and status in ('open','partially_settled')
        and direction = 'credit'
        and upper(currency_code) = upper(v_debit.currency_code)
      order by due_date asc nulls last, occurred_at asc, created_at asc
    loop
      if v_remaining_base <= 1e-6 and (v_debit.open_foreign_amount is null or v_remaining_foreign <= 1e-6) then
        exit;
      end if;

      if v_credit.open_foreign_amount is not null or v_debit.open_foreign_amount is not null then
        if v_credit.open_foreign_amount is null or v_debit.open_foreign_amount is null then
          continue;
        end if;
        v_alloc_foreign := least(coalesce(v_remaining_foreign,0), coalesce(v_credit.open_foreign_amount,0));
        if v_alloc_foreign <= 1e-6 then
          continue;
        end if;
        v_allocs := v_allocs || jsonb_build_array(jsonb_build_object('fromOpenItemId', v_debit.id::text, 'toOpenItemId', v_credit.id::text, 'allocatedForeignAmount', v_alloc_foreign));
        v_remaining_foreign := v_remaining_foreign - v_alloc_foreign;
        v_remaining_base := v_remaining_base - (v_alloc_foreign * coalesce(public._open_item_effective_fx_rate(v_debit.foreign_amount, v_debit.base_amount), 1));
      else
        v_alloc_base := least(coalesce(v_remaining_base,0), coalesce(v_credit.open_base_amount,0));
        if v_alloc_base <= 1e-6 then
          continue;
        end if;
        v_allocs := v_allocs || jsonb_build_array(jsonb_build_object('fromOpenItemId', v_debit.id::text, 'toOpenItemId', v_credit.id::text, 'allocatedBaseAmount', v_alloc_base));
        v_remaining_base := v_remaining_base - v_alloc_base;
      end if;
    end loop;
  end loop;

  if jsonb_array_length(v_allocs) = 0 then
    return null;
  end if;

  v_id := public.create_settlement(p_party_id, now(), v_allocs, 'auto_settle_party_items');

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'settlements.auto_run',
    'accounting',
    coalesce(v_id, '00000000-0000-0000-0000-000000000000'::uuid)::text,
    auth.uid(),
    now(),
    jsonb_build_object('partyId', p_party_id::text, 'settlementId', coalesce(v_id, '00000000-0000-0000-0000-000000000000'::uuid)::text),
    'LOW',
    'SETTLEMENT_AUTO'
  );

  return v_id;
end;
$$;


ALTER FUNCTION "public"."auto_settle_party_items"("p_party_id" "uuid") OWNER TO "postgres";

--
-- Name: backfill_batches_from_movements(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."backfill_batches_from_movements"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_inserted int := 0;
  v_updated int := 0;
  v_default_wh uuid;
  v_im record;
  v_receipt_id uuid;
  v_receipt_item_id uuid;
  v_expiry date;
  v_production date;
  v_wh uuid;
  v_consumed numeric;
begin
  -- تحديد مخزن افتراضي عند الحاجة
  if to_regclass('public.warehouses') is not null then
    select w.id
    into v_default_wh
    from public.warehouses w
    where w.is_active = true
    order by (upper(coalesce(w.code,''))='MAIN') desc, w.code asc
    limit 1;
  else
    v_default_wh := null;
  end if;

  for v_im in
    select *
    from public.inventory_movements im
    where im.movement_type = 'purchase_in'
      and im.batch_id is not null
  loop
    v_receipt_id := null;
    v_receipt_item_id := null;
    v_wh := coalesce(
      v_im.warehouse_id,
      case
        when (v_im.data ? 'warehouseId') and (v_im.data->>'warehouseId') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$'
          then (v_im.data->>'warehouseId')::uuid
        else v_default_wh
      end
    );

    -- receipt_id من reference أو من data
    if coalesce(v_im.reference_table,'') = 'purchase_receipts' then
      begin
        if coalesce(v_im.reference_id,'') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$' then
          v_receipt_id := v_im.reference_id::uuid;
        end if;
      exception when others then
        v_receipt_id := null;
      end;
    end if;
    if v_receipt_id is null and (v_im.data ? 'purchaseReceiptId') then
      begin
        v_receipt_id := (v_im.data->>'purchaseReceiptId')::uuid;
      exception when others then
        v_receipt_id := null;
      end;
    end if;

    if v_receipt_id is not null then
      select pri.id
      into v_receipt_item_id
      from public.purchase_receipt_items pri
      where pri.receipt_id = v_receipt_id
        and pri.item_id = v_im.item_id
      limit 1;
    end if;

    -- تواريخ الصلاحية/الإنتاج
    v_expiry := null;
    v_production := null;
    if (v_im.data ? 'expiryDate') and (v_im.data->>'expiryDate') ~ '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' then
      v_expiry := (v_im.data->>'expiryDate')::date;
    end if;
    if (v_im.data ? 'harvestDate') and (v_im.data->>'harvestDate') ~ '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' then
      v_production := (v_im.data->>'harvestDate')::date;
    end if;

    -- كمية مستهلكة من الحركات الخارجة
    select coalesce(sum(im2.quantity), 0)
    into v_consumed
    from public.inventory_movements im2
    where im2.batch_id = v_im.batch_id
      and im2.movement_type in ('sale_out','wastage_out','adjust_out','return_out','transfer_out');

    if exists (select 1 from public.batches b where b.id = v_im.batch_id) then
      update public.batches
      set item_id = v_im.item_id,
          receipt_item_id = v_receipt_item_id,
          receipt_id = v_receipt_id,
          warehouse_id = v_wh,
          unit_cost = v_im.unit_cost,
          quantity_received = v_im.quantity,
          quantity_consumed = least(greatest(v_consumed, 0), v_im.quantity),
          expiry_date = coalesce(v_expiry, expiry_date),
          production_date = coalesce(v_production, production_date),
          data = coalesce(data, '{}'::jsonb) || jsonb_build_object('source','backfill')
      where id = v_im.batch_id;
      v_updated := v_updated + 1;
    else
      insert into public.batches(
        id, item_id, receipt_item_id, receipt_id, warehouse_id,
        batch_code, production_date, expiry_date,
        quantity_received, quantity_consumed, unit_cost, data
      )
      values (
        v_im.batch_id, v_im.item_id, v_receipt_item_id, v_receipt_id, v_wh,
        null, v_production, v_expiry,
        v_im.quantity, least(greatest(v_consumed,0), v_im.quantity), v_im.unit_cost,
        jsonb_build_object('source','backfill')
      );
      v_inserted := v_inserted + 1;
    end if;
  end loop;

  return json_build_object('inserted', v_inserted, 'updated', v_updated);
end;
$_$;


ALTER FUNCTION "public"."backfill_batches_from_movements"() OWNER TO "postgres";

--
-- Name: backfill_party_ledger_entries_for_party("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."backfill_party_ledger_entries_for_party"("p_party_id" "uuid", "p_batch" integer DEFAULT 5000) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_count integer := 0;
  v_limit integer := greatest(1, coalesce(p_batch, 5000));
  r record;
begin
  if p_party_id is null then
    raise exception 'party_id is required';
  end if;

  if current_user <> 'postgres' then
    if auth.role() = 'service_role' then
      null;
    elsif public.has_admin_permission('accounting.view') then
      null;
    else
      raise exception 'not allowed';
    end if;
  end if;

  for r in
    select distinct jl.journal_entry_id as journal_entry_id
    from public.journal_lines jl
    join public.journal_entries je on je.id = jl.journal_entry_id
    where je.status = 'posted'
      and exists (
        select 1
        from public.party_subledger_accounts psa
        where psa.account_id = jl.account_id
          and psa.is_active = true
      )
      and not exists (
        select 1
        from public.party_ledger_entries ple
        where ple.journal_line_id = jl.id
      )
      and public._resolve_party_for_entry(coalesce(je.source_table, ''), coalesce(je.source_id, '')) = p_party_id
    order by jl.journal_entry_id asc
    limit v_limit
  loop
    perform public.insert_party_ledger_for_entry(r.journal_entry_id);
    v_count := v_count + 1;
  end loop;

  return v_count;
end;
$$;


ALTER FUNCTION "public"."backfill_party_ledger_entries_for_party"("p_party_id" "uuid", "p_batch" integer) OWNER TO "postgres";

--
-- Name: backfill_party_ledger_for_existing_entries(integer, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."backfill_party_ledger_for_existing_entries"("p_batch" integer DEFAULT 5000, "p_only_party_id" "uuid" DEFAULT NULL::"uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_count int := 0;
  r record;
begin
  if current_user <> 'postgres' then
    if auth.role() = 'service_role' then
      null;
    elsif public.has_admin_permission('accounting.manage') then
      null;
    else
      raise exception 'not allowed';
    end if;
  end if;

  update public.journal_lines jl
  set party_id = x.party_id
  from (
    select
      jl2.id as journal_line_id,
      public._resolve_party_for_entry(coalesce(je.source_table, ''), coalesce(je.source_id, '')) as party_id
    from public.journal_lines jl2
    join public.journal_entries je on je.id = jl2.journal_entry_id
    where jl2.party_id is null
      and exists (
        select 1
        from public.party_subledger_accounts psa
        where psa.account_id = jl2.account_id
          and psa.is_active = true
        limit 1
      )
      and (p_only_party_id is null or public._resolve_party_for_entry(coalesce(je.source_table, ''), coalesce(je.source_id, '')) = p_only_party_id)
  ) x
  where jl.id = x.journal_line_id
    and x.party_id is not null;

  for r in
    select distinct jl.journal_entry_id as entry_id
    from public.journal_lines jl
    join public.journal_entries je on je.id = jl.journal_entry_id
    where jl.party_id is not null
      and exists (
        select 1
        from public.party_subledger_accounts psa
        where psa.account_id = jl.account_id
          and psa.is_active = true
        limit 1
      )
      and not exists (
        select 1
        from public.party_ledger_entries ple
        where ple.journal_line_id = jl.id
        limit 1
      )
      and (p_only_party_id is null or jl.party_id = p_only_party_id)
    order by jl.journal_entry_id asc
    limit greatest(1, coalesce(p_batch, 5000))
  loop
    perform public.insert_party_ledger_for_entry(r.entry_id);
    v_count := v_count + 1;
  end loop;

  return v_count;
end;
$$;


ALTER FUNCTION "public"."backfill_party_ledger_for_existing_entries"("p_batch" integer, "p_only_party_id" "uuid") OWNER TO "postgres";

--
-- Name: backfill_party_open_items_for_party("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."backfill_party_open_items_for_party"("p_party_id" "uuid", "p_batch" integer DEFAULT 5000) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_ledger int := 0;
  v_open int := 0;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  if p_party_id is null then
    raise exception 'party_id is required';
  end if;

  begin
    v_ledger := coalesce(public.backfill_party_ledger_for_existing_entries(coalesce(p_batch, 5000), p_party_id), 0);
  exception when others then
    v_ledger := 0;
  end;

  with candidates as (
    select
      ple.party_id,
      ple.journal_entry_id,
      ple.journal_line_id,
      ple.account_id,
      ple.direction,
      ple.occurred_at,
      je.source_table,
      je.source_id,
      je.source_event,
      psa.role as item_role,
      public._party_open_item_type(je.source_table, je.source_event) as item_type,
      upper(coalesce(ple.currency_code, public.get_base_currency())) as currency_code,
      ple.foreign_amount,
      ple.base_amount,
      case
        when coalesce(je.source_table,'') = 'party_documents' then nullif(je.source_id,'')::uuid
        else null
      end as party_document_id
    from public.party_ledger_entries ple
    join public.journal_entries je on je.id = ple.journal_entry_id
    join public.party_subledger_accounts psa on psa.account_id = ple.account_id and psa.is_active = true
    left join public.party_open_items poi on poi.journal_line_id = ple.journal_line_id
    where ple.party_id = p_party_id
      and poi.id is null
      and coalesce(je.source_table,'') <> 'settlements'
      and coalesce(je.source_event,'') <> 'realized_fx'
    order by ple.occurred_at asc, ple.journal_entry_id asc, ple.journal_line_id asc
    limit greatest(1, coalesce(p_batch, 5000))
  )
  insert into public.party_open_items(
    party_id,
    journal_entry_id,
    journal_line_id,
    account_id,
    direction,
    occurred_at,
    due_date,
    item_role,
    item_type,
    source_table,
    source_id,
    source_event,
    party_document_id,
    currency_code,
    foreign_amount,
    base_amount,
    open_foreign_amount,
    open_base_amount,
    status
  )
  select
    c.party_id,
    c.journal_entry_id,
    c.journal_line_id,
    c.account_id,
    c.direction,
    c.occurred_at,
    c.occurred_at::date,
    c.item_role,
    c.item_type,
    c.source_table,
    c.source_id,
    c.source_event,
    c.party_document_id,
    c.currency_code,
    c.foreign_amount,
    c.base_amount,
    c.foreign_amount,
    c.base_amount,
    'open'
  from candidates c
  on conflict (journal_line_id) do nothing;

  get diagnostics v_open = row_count;

  return jsonb_build_object(
    'ledgerBackfilled', coalesce(v_ledger, 0),
    'openItemsCreated', coalesce(v_open, 0)
  );
end;
$$;


ALTER FUNCTION "public"."backfill_party_open_items_for_party"("p_party_id" "uuid", "p_batch" integer) OWNER TO "postgres";

--
-- Name: backfill_purchase_items_qty_base(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."backfill_purchase_items_qty_base"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_n int := 0;
begin
  if to_regclass('public.purchase_items') is null then
    return 0;
  end if;
  if to_regclass('public.item_uom') is null then
    return 0;
  end if;
  update public.purchase_items pi
  set uom_id = coalesce(pi.uom_id, iu.base_uom_id),
      qty_base = coalesce(
        nullif(pi.qty_base, 0),
        public.item_qty_to_base_safe(pi.item_id::text, pi.quantity, coalesce(pi.uom_id, iu.base_uom_id))
      )
  from public.item_uom iu
  where iu.item_id::text = pi.item_id::text
    and coalesce(pi.quantity, 0) > 0
    and coalesce(pi.qty_base, 0) = 0;
  get diagnostics v_n = row_count;
  notify pgrst, 'reload schema';
  return coalesce(v_n, 0);
end;
$$;


ALTER FUNCTION "public"."backfill_purchase_items_qty_base"() OWNER TO "postgres";

--
-- Name: backfill_receipt_items_qty_base(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."backfill_receipt_items_qty_base"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_n int := 0;
begin
  if to_regclass('public.purchase_receipt_items') is null then
    return 0;
  end if;
  update public.purchase_receipt_items pri
  set qty_base = coalesce(
    nullif(pri.qty_base, 0),
    public.item_qty_to_base_safe(pri.item_id, pri.quantity, pri.uom_id)
  )
  where coalesce(pri.qty_base, 0) = 0
    and coalesce(pri.quantity, 0) > 0;
  get diagnostics v_n = row_count;
  notify pgrst, 'reload schema';
  return coalesce(v_n, 0);
end;
$$;


