--
-- Name: budget_variance_analysis("uuid", "date", "date", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."budget_variance_analysis"("p_budget_id" "uuid", "p_start" "date", "p_end" "date", "p_rollup" "text" DEFAULT 'ifrs_line'::"text", "p_cost_center_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("group_key" "text", "group_name" "text", "account_type" "text", "actual_base" numeric, "budget_base" numeric, "variance" numeric, "variance_pct" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with actual as (
    select
      case
        when lower(coalesce(p_rollup,'')) = 'ifrs_line' then coalesce(nullif(l.ifrs_line,''), l.account_code)
        when lower(coalesce(p_rollup,'')) = 'ifrs_category' then coalesce(l.ifrs_category, l.account_type, l.account_code)
        else l.account_code
      end as group_key,
      max(
        case
          when lower(coalesce(p_rollup,'')) = 'ifrs_line' then coalesce(nullif(l.ifrs_line,''), l.account_code)
          when lower(coalesce(p_rollup,'')) = 'ifrs_category' then coalesce(l.ifrs_category, l.account_type, l.account_code)
          else l.account_name
        end
      ) as group_name,
      max(l.account_type) as account_type,
      sum(
        case
          when l.account_type = 'income' then l.signed_base_amount
          when l.account_type = 'expense' then -l.signed_base_amount
          else 0
        end
      ) as actual_base
    from public.enterprise_gl_lines l
    where public.can_view_enterprise_financial_reports()
      and l.entry_date between p_start and p_end
      and (p_cost_center_id is null or l.cost_center_id = p_cost_center_id)
      and l.account_type in ('income','expense')
    group by 1
  ),
  bud as (
    select
      case
        when lower(coalesce(p_rollup,'')) = 'ifrs_line' then coalesce(nullif(coa.ifrs_line,''), coa.code)
        when lower(coalesce(p_rollup,'')) = 'ifrs_category' then coalesce(coa.ifrs_category, coa.account_type, coa.code)
        else coa.code
      end as group_key,
      max(
        case
          when lower(coalesce(p_rollup,'')) = 'ifrs_line' then coalesce(nullif(coa.ifrs_line,''), coa.code)
          when lower(coalesce(p_rollup,'')) = 'ifrs_category' then coalesce(coa.ifrs_category, coa.account_type, coa.code)
          else coa.name
        end
      ) as group_name,
      max(coa.account_type) as account_type,
      sum(bl.amount_base) as budget_base
    from public.budget_lines bl
    join public.chart_of_accounts coa on coa.id = bl.account_id
    where public.has_admin_permission('accounting.view')
      and bl.budget_id = p_budget_id
      and bl.period_start between date_trunc('month', p_start)::date and date_trunc('month', p_end)::date
      and (p_cost_center_id is null or bl.cost_center_id = p_cost_center_id)
      and coa.account_type in ('income','expense')
    group by 1
  )
  select
    coalesce(a.group_key, b.group_key) as group_key,
    coalesce(a.group_name, b.group_name) as group_name,
    coalesce(a.account_type, b.account_type) as account_type,
    coalesce(a.actual_base,0) as actual_base,
    coalesce(b.budget_base,0) as budget_base,
    coalesce(a.actual_base,0) - coalesce(b.budget_base,0) as variance,
    case
      when abs(coalesce(b.budget_base,0)) < 1e-9 then null
      else (coalesce(a.actual_base,0) - coalesce(b.budget_base,0)) / nullif(b.budget_base,0)
    end as variance_pct
  from actual a
  full join bud b on b.group_key = a.group_key
  where abs(coalesce(a.actual_base,0)) > 1e-9 or abs(coalesce(b.budget_base,0)) > 1e-9
  order by abs(coalesce(a.actual_base,0) - coalesce(b.budget_base,0)) desc;
$$;


ALTER FUNCTION "public"."budget_variance_analysis"("p_budget_id" "uuid", "p_start" "date", "p_end" "date", "p_rollup" "text", "p_cost_center_id" "uuid") OWNER TO "postgres";

--
-- Name: budget_vs_actual_pnl("uuid", "date", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."budget_vs_actual_pnl"("p_budget_id" "uuid", "p_start" "date", "p_end" "date", "p_cost_center_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("account_code" "text", "account_name" "text", "account_type" "text", "actual_base" numeric, "budget_base" numeric, "variance" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with actual as (
    select
      l.account_code,
      max(l.account_name) as account_name,
      max(l.account_type) as account_type,
      sum(
        case
          when l.account_type = 'income' then l.signed_base_amount
          when l.account_type = 'expense' then -l.signed_base_amount
          else 0
        end
      ) as actual_base
    from public.enterprise_gl_lines l
    where public.can_view_enterprise_financial_reports()
      and l.entry_date between p_start and p_end
      and (p_cost_center_id is null or l.cost_center_id = p_cost_center_id)
      and l.account_type in ('income','expense')
    group by l.account_code
  ),
  bud as (
    select
      coa.code as account_code,
      sum(bl.amount_base) as budget_base
    from public.budget_lines bl
    join public.budget_headers bh on bh.id = bl.budget_id
    join public.chart_of_accounts coa on coa.id = bl.account_id
    where public.has_admin_permission('accounting.view')
      and bl.budget_id = p_budget_id
      and bl.period_start between date_trunc('month', p_start)::date and date_trunc('month', p_end)::date
      and (p_cost_center_id is null or bl.cost_center_id = p_cost_center_id)
    group by coa.code
  )
  select
    coalesce(a.account_code, b.account_code) as account_code,
    coalesce(a.account_name, (select name from public.chart_of_accounts where code = b.account_code limit 1)) as account_name,
    coalesce(a.account_type, (select account_type from public.chart_of_accounts where code = b.account_code limit 1)) as account_type,
    coalesce(a.actual_base,0) as actual_base,
    coalesce(b.budget_base,0) as budget_base,
    coalesce(a.actual_base,0) - coalesce(b.budget_base,0) as variance
  from actual a
  full join bud b on b.account_code = a.account_code
  where abs(coalesce(a.actual_base,0)) > 1e-9 or abs(coalesce(b.budget_base,0)) > 1e-9
  order by abs(coalesce(a.actual_base,0) - coalesce(b.budget_base,0)) desc;
$$;


ALTER FUNCTION "public"."budget_vs_actual_pnl"("p_budget_id" "uuid", "p_start" "date", "p_end" "date", "p_cost_center_id" "uuid") OWNER TO "postgres";

--
-- Name: calculate_cash_shift_expected("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_cash_shift_expected"("p_shift_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_shift record;
  v_cash_in numeric;
  v_cash_out numeric;
  v_base text;
begin
  if p_shift_id is null then
    raise exception 'p_shift_id is required';
  end if;

  v_base := public.get_base_currency();

  select *
  into v_shift
  from public.cash_shifts s
  where s.id = p_shift_id;

  if not found then
    raise exception 'cash shift not found';
  end if;

  select
    coalesce(sum(
      case
        when p.direction = 'in' then coalesce(
          p.base_amount,
          case when upper(coalesce(p.currency,'')) = upper(v_base) then p.amount else null end,
          0
        )
        else 0
      end
    ), 0),
    coalesce(sum(
      case
        when p.direction = 'out' then coalesce(
          p.base_amount,
          case when upper(coalesce(p.currency,'')) = upper(v_base) then p.amount else null end,
          0
        )
        else 0
      end
    ), 0)
  into v_cash_in, v_cash_out
  from public.payments p
  where p.method = 'cash'
    and (
      p.shift_id = p_shift_id
      or (
        p.shift_id is null
        and p.created_by = v_shift.cashier_id
        and p.occurred_at >= coalesce(v_shift.opened_at, now())
        and p.occurred_at <= coalesce(v_shift.closed_at, now())
      )
    );

  return coalesce(v_shift.start_amount, 0) + coalesce(v_cash_in, 0) - coalesce(v_cash_out, 0);
end;
$$;


ALTER FUNCTION "public"."calculate_cash_shift_expected"("p_shift_id" "uuid") OWNER TO "postgres";

--
-- Name: calculate_risk_level("text", "text", "jsonb", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_risk_level"("p_table" "text", "p_op" "text", "p_old" "jsonb", "p_new" "jsonb") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- DELETE operations are generally High Risk
  IF p_op = 'delete' THEN
    IF p_table IN ('orders', 'stock_management', 'purchase_orders', 'admin_users', 'journal_entries') THEN
        RETURN 'HIGH';
    END IF;
    RETURN 'MEDIUM';
  END IF;

  -- UPDATE operations
  IF p_op = 'update' THEN
    -- Orders: Status Change to Cancelled or Delivered is High/Medium
    IF p_table = 'orders' THEN
        IF (p_new->>'status') = 'cancelled' AND (p_old->>'status') <> 'cancelled' THEN
            RETURN 'HIGH';
        END IF;
        IF (p_new->>'status') = 'delivered' AND (p_old->>'status') <> 'delivered' THEN
            RETURN 'MEDIUM'; -- Delivery is normal but important
        END IF;
        -- Financial tampering check
        IF (p_new->>'total') <> (p_old->>'total') OR (p_new->>'subtotal') <> (p_old->>'subtotal') THEN
            RETURN 'HIGH';
        END IF;
    END IF;

    -- Stock: Quantity changes
    IF p_table = 'stock_management' THEN
        IF (p_new->>'available_quantity') <> (p_old->>'available_quantity') THEN
            RETURN 'MEDIUM'; -- Frequent but important
        END IF;
    END IF;

    -- Auth: Role/Permission changes
    IF p_table = 'admin_users' THEN
         RETURN 'HIGH';
    END IF;
  END IF;

  -- INSERT operations
  IF p_op = 'insert' THEN
     IF p_table IN ('admin_users') THEN
        RETURN 'HIGH';
     END IF;
  END IF;

  RETURN 'LOW';
END;
$$;


ALTER FUNCTION "public"."calculate_risk_level"("p_table" "text", "p_op" "text", "p_old" "jsonb", "p_new" "jsonb") OWNER TO "postgres";

--
-- Name: calculate_shipment_landed_cost("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_shipment_landed_cost"("p_shipment_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
  v_ship record;
  v_date date;
  v_total_expenses_base numeric := 0;
  v_total_fob_base numeric := 0;
  v_fx numeric;
  v_item record;
  v_base_qty numeric;
  v_unit_cost_trx numeric;
  v_item_fob_base_total numeric;
  v_alloc_item_base numeric;
  v_per_unit_alloc numeric;
begin
  if p_shipment_id is null then
    raise exception 'p_shipment_id is required';
  end if;

  v_base := public.get_base_currency();

  select s.*
  into v_ship
  from public.import_shipments s
  where s.id = p_shipment_id;
  if not found then
    return;
  end if;

  v_date := coalesce(v_ship.actual_arrival_date, v_ship.expected_arrival_date, v_ship.departure_date, current_date);

  select coalesce(sum(coalesce(ie.amount,0) * coalesce(ie.exchange_rate,1)), 0)
  into v_total_expenses_base
  from public.import_expenses ie
  where ie.shipment_id = p_shipment_id;

  v_total_fob_base := 0;
  for v_item in
    with linked_receipts as (
      select pr.id, pr.purchase_order_id
      from public.purchase_receipts pr
      where pr.import_shipment_id = p_shipment_id
    ),
    receipt_qty as (
      select pri.item_id::text as item_id, sum(coalesce(pri.quantity,0))::numeric as base_qty
      from linked_receipts lr
      join public.purchase_receipt_items pri on pri.receipt_id = lr.id
      group by pri.item_id
    ),
    linked_orders as (
      select distinct lr.purchase_order_id
      from linked_receipts lr
      where lr.purchase_order_id is not null
    ),
    po_cost as (
      select
        pi.item_id::text as item_id,
        case
          when sum(coalesce(pi.qty_base, pi.quantity, 0)) > 0 then
            sum(
              coalesce(pi.qty_base, pi.quantity, 0)
              * public.item_unit_cost_to_base(pi.item_id::text, coalesce(pi.unit_cost, 0), pi.uom_id)
            )
            / sum(coalesce(pi.qty_base, pi.quantity, 0))
          else 0
        end::numeric as unit_cost_base
      from public.purchase_items pi
      join linked_orders lo on lo.purchase_order_id = pi.purchase_order_id
      group by pi.item_id
    )
    select
      isi.id,
      isi.item_id::text as item_id,
      upper(coalesce(nullif(btrim(isi.currency),''), v_base)) as currency,
      coalesce(rq.base_qty, isi.quantity, 0) as base_qty,
      coalesce(pc.unit_cost_base, isi.unit_price_fob, 0) as unit_cost_trx
    from public.import_shipments_items isi
    left join receipt_qty rq on rq.item_id = isi.item_id::text
    left join po_cost pc on pc.item_id = isi.item_id::text
    where isi.shipment_id = p_shipment_id
  loop
    v_base_qty := coalesce(v_item.base_qty, 0);
    if v_base_qty <= 0 then
      continue;
    end if;
    v_unit_cost_trx := coalesce(v_item.unit_cost_trx, 0);
    v_fx := public._pick_fx_for_landed_cost(v_item.currency, v_date);
    if v_fx is null or v_fx <= 0 then
      continue;
    end if;
    v_total_fob_base := v_total_fob_base + (v_base_qty * v_unit_cost_trx * v_fx);
  end loop;

  if coalesce(v_total_fob_base, 0) <= 0 then
    return;
  end if;

  for v_item in
    with linked_receipts as (
      select pr.id, pr.purchase_order_id
      from public.purchase_receipts pr
      where pr.import_shipment_id = p_shipment_id
    ),
    receipt_qty as (
      select pri.item_id::text as item_id, sum(coalesce(pri.quantity,0))::numeric as base_qty
      from linked_receipts lr
      join public.purchase_receipt_items pri on pri.receipt_id = lr.id
      group by pri.item_id
    ),
    linked_orders as (
      select distinct lr.purchase_order_id
      from linked_receipts lr
      where lr.purchase_order_id is not null
    ),
    po_cost as (
      select
        pi.item_id::text as item_id,
        case
          when sum(coalesce(pi.qty_base, pi.quantity, 0)) > 0 then
            sum(
              coalesce(pi.qty_base, pi.quantity, 0)
              * public.item_unit_cost_to_base(pi.item_id::text, coalesce(pi.unit_cost, 0), pi.uom_id)
            )
            / sum(coalesce(pi.qty_base, pi.quantity, 0))
          else 0
        end::numeric as unit_cost_base
      from public.purchase_items pi
      join linked_orders lo on lo.purchase_order_id = pi.purchase_order_id
      group by pi.item_id
    )
    select
      isi.id,
      isi.item_id::text as item_id,
      upper(coalesce(nullif(btrim(isi.currency),''), v_base)) as currency,
      coalesce(rq.base_qty, isi.quantity, 0) as base_qty,
      coalesce(pc.unit_cost_base, isi.unit_price_fob, 0) as unit_cost_trx
    from public.import_shipments_items isi
    left join receipt_qty rq on rq.item_id = isi.item_id::text
    left join po_cost pc on pc.item_id = isi.item_id::text
    where isi.shipment_id = p_shipment_id
  loop
    v_base_qty := coalesce(v_item.base_qty, 0);
    if v_base_qty <= 0 then
      continue;
    end if;
    v_unit_cost_trx := coalesce(v_item.unit_cost_trx, 0);
    v_fx := public._pick_fx_for_landed_cost(v_item.currency, v_date);
    if v_fx is null or v_fx <= 0 then
      continue;
    end if;

    v_item_fob_base_total := v_base_qty * v_unit_cost_trx * v_fx;
    v_alloc_item_base := (v_item_fob_base_total / v_total_fob_base) * coalesce(v_total_expenses_base, 0);
    v_per_unit_alloc := v_alloc_item_base / v_base_qty;

    update public.import_shipments_items
    set landing_cost_per_unit = (v_unit_cost_trx * v_fx) + v_per_unit_alloc,
        updated_at = now()
    where id = v_item.id;
  end loop;
end;
$$;


ALTER FUNCTION "public"."calculate_shipment_landed_cost"("p_shipment_id" "uuid") OWNER TO "postgres";

--
-- Name: calculate_three_way_match("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_three_way_match"("p_invoice_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_line record;
  v_qty_po numeric;
  v_qty_grn numeric;
  v_price_po numeric;
  v_qty_tol numeric;
  v_price_tol numeric;
  v_status text;
begin
  delete from public.three_way_match_results where invoice_id = p_invoice_id;

  for v_line in
    select *
    from public.supplier_invoice_lines
    where invoice_id = p_invoice_id
  loop
    select coalesce(sum(pi.quantity), 0), coalesce(avg(pi.unit_cost), 0)
    into v_qty_po, v_price_po
    from public.purchase_items pi
    where pi.purchase_order_id = v_line.po_id
      and pi.item_id = v_line.item_id;

    select coalesce(sum(pri.quantity), 0)
    into v_qty_grn
    from public.purchase_receipt_items pri
    join public.purchase_receipts pr on pr.id = pri.receipt_id
    where pr.purchase_order_id = v_line.po_id
      and pri.item_id = v_line.item_id;

    select coalesce(it.qty_tolerance, 0), coalesce(it.price_tolerance, 0)
    into v_qty_tol, v_price_tol
    from public.invoice_tolerances it
    join public.supplier_invoices si on si.id = p_invoice_id
    where (it.supplier_id is null or it.supplier_id = si.supplier_id)
      and (it.item_id is null or it.item_id = v_line.item_id)
      and it.is_active = true
    order by (it.supplier_id is not null) desc, (it.item_id is not null) desc
    limit 1;

    if abs(coalesce(v_line.unit_price, 0) - coalesce(v_price_po, 0)) > v_price_tol then
      v_status := 'price_variance';
    elsif coalesce(v_line.quantity, 0) > coalesce(v_qty_grn, 0) + v_qty_tol then
      v_status := 'qty_variance';
    else
      v_status := 'matched';
    end if;

    insert into public.three_way_match_results(
      invoice_id, po_id, receipt_id, item_id,
      qty_po, qty_grn, qty_inv, price_po, price_inv, status
    )
    values (
      p_invoice_id, v_line.po_id, v_line.receipt_id, v_line.item_id,
      coalesce(v_qty_po, 0), coalesce(v_qty_grn, 0), coalesce(v_line.quantity, 0),
      coalesce(v_price_po, 0), coalesce(v_line.unit_price, 0), v_status
    );
  end loop;

  if exists (
    select 1 from public.three_way_match_results
    where invoice_id = p_invoice_id and status <> 'matched'
  ) then
    update public.supplier_invoices set status = 'exception' where id = p_invoice_id;
  else
    update public.supplier_invoices set status = 'matched' where id = p_invoice_id;
  end if;
end;
$$;


ALTER FUNCTION "public"."calculate_three_way_match"("p_invoice_id" "uuid") OWNER TO "postgres";

