-- Name: cancel_accounting_document("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."cancel_accounting_document"("p_document_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not public.has_admin_permission('accounting.approve') then
    raise exception 'not allowed';
  end if;
  update public.accounting_documents
  set status = 'cancelled',
      memo = concat(coalesce(memo,''), ' | cancelled: ', coalesce(nullif(trim(p_reason),''),''))
  where id = p_document_id
    and status in ('draft','approved');
end;
$$;


