--
-- Name: confirm_order_delivery_with_credit("uuid", "jsonb", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."confirm_order_delivery_with_credit"("p_order_id" "uuid", "p_items" "jsonb", "p_updated_data" "jsonb", "p_warehouse_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if auth.role() <> 'service_role' then
    if not public.is_staff() then
      raise exception 'not allowed';
