--
-- Name: consolidated_trial_balance("uuid", "date", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."consolidated_trial_balance"("p_group_id" "uuid", "p_as_of" "date", "p_rollup" "text" DEFAULT 'account'::"text", "p_currency_view" "text" DEFAULT 'base'::"text") RETURNS TABLE("group_key" "text", "group_name" "text", "account_type" "text", "ifrs_statement" "text", "ifrs_category" "text", "currency_code" "text", "balance_base" numeric, "revalued_balance_base" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text := upper(public.get_base_currency());
  v_reporting text;
  v_view text := lower(nullif(btrim(coalesce(p_currency_view,'')), ''));
  v_roll text := lower(nullif(btrim(coalesce(p_rollup,'')), ''));
  v_start_ytd date;
begin
  if not public.can_view_enterprise_financial_reports() then
    raise exception 'not allowed';
  end if;
  if p_group_id is null then
    raise exception 'group_id required';
  end if;
  if p_as_of is null then
    raise exception 'as_of required';
  end if;

  select upper(coalesce(nullif(btrim(cg.reporting_currency),''), v_base))
  into v_reporting
  from public.consolidation_groups cg
  where cg.id = p_group_id;

  if v_reporting is null then
    v_reporting := v_base;
  end if;

  v_start_ytd := date_trunc('year', p_as_of)::date;

  return query
  with members as (
    select m.company_id, m.ownership_pct, m.consolidation_method
    from public.consolidation_group_members m
    where m.group_id = p_group_id
  ),
  excluded as (
    select r.account_code
    from public.intercompany_elimination_rules r
    where r.group_id = p_group_id
      and r.rule_type = 'exclude'
  ),
  elim_accounts as (
    select elimination_type, account_code
    from public.consolidation_elimination_accounts a
    where a.group_id = p_group_id
  ),
  upr as (
    select r.inventory_account_code, r.cogs_account_code, r.percent_remaining
    from public.consolidation_unrealized_profit_rules r
    where r.group_id = p_group_id and r.is_active = true
  ),
  lines as (
    select
      l.*,
      m.ownership_pct,
      m.consolidation_method,
      case when m.consolidation_method = 'full' then 1 else coalesce(m.ownership_pct, 1) end as eff_pct,
      exists(
        select 1
        from public.consolidation_intercompany_parties icp
        where icp.group_id = p_group_id
          and icp.company_id = l.company_id
          and icp.party_id = l.party_id
      ) as is_intercompany
    from public.enterprise_gl_lines l
    join members m on m.company_id = l.company_id
    where l.entry_date <= p_as_of
      and not exists (select 1 from excluded e where e.account_code = l.account_code)
  ),
  base_grouped as (
    select
      case
        when v_roll = 'ifrs_line' then coalesce(nullif(l.ifrs_line,''), l.account_code)
        when v_roll = 'ifrs_category' then coalesce(l.ifrs_category, l.account_type, l.account_code)
        else l.account_code
      end as group_key,
      case
        when v_roll = 'ifrs_line' then max(coalesce(nullif(l.ifrs_line,''), l.account_code))
        when v_roll = 'ifrs_category' then max(coalesce(l.ifrs_category, l.account_type, l.account_code))
        else max(l.account_name)
      end as group_name,
      max(l.account_type) as account_type,
      max(l.ifrs_statement) as ifrs_statement,
      max(l.ifrs_category) as ifrs_category,
      upper(
        case
          when v_view in ('revalued','foreign') then coalesce(nullif(l.currency_code,''), v_base)
          when v_view in ('reporting','translated') then v_reporting
          else v_base
        end
      ) as currency_code,
      sum(l.signed_base_amount * l.eff_pct) as balance_base,
      sum(l.signed_foreign_amount * l.eff_pct) as balance_foreign,
      sum(
        case
          when v_view not in ('reporting','translated') then 0
          when l.account_type in ('asset','liability') then public.fx_convert((l.signed_base_amount * l.eff_pct), v_base, v_reporting, p_as_of, 'accounting')
          when l.account_type in ('income','expense') then (l.signed_base_amount * l.eff_pct) / public.get_fx_rate_avg(v_reporting, v_start_ytd, p_as_of, 'accounting')
          else public.fx_convert((l.signed_base_amount * l.eff_pct), v_base, v_reporting, l.entry_date, 'accounting')
        end
      ) as translated_amount
    from lines l
    group by 1, 6
  ),
  elim_adjustments as (
    select
      l.account_code as account_code,
      sum(l.signed_base_amount * l.eff_pct) as amt_base,
      sum(l.signed_foreign_amount * l.eff_pct) as amt_foreign,
      sum(
        case
          when l.account_type in ('asset','liability') then public.fx_convert((l.signed_base_amount * l.eff_pct), v_base, v_reporting, p_as_of, 'accounting')
          when l.account_type in ('income','expense') then (l.signed_base_amount * l.eff_pct) / public.get_fx_rate_avg(v_reporting, v_start_ytd, p_as_of, 'accounting')
          else public.fx_convert((l.signed_base_amount * l.eff_pct), v_base, v_reporting, l.entry_date, 'accounting')
        end
      ) as amt_reporting
    from lines l
    join elim_accounts ea on ea.account_code = l.account_code
    where l.is_intercompany = true
      and ea.elimination_type in ('ar_ap','revenue_expense','fx')
    group by l.account_code
  ),
  elim_rows as (
    select
      ea.account_code,
      coa.name as account_name,
      coa.account_type,
      coa.ifrs_statement,
      coa.ifrs_category,
      coa.ifrs_line,
      (-coalesce(ea.amt_base,0)) as balance_base,
      (-coalesce(ea.amt_foreign,0)) as balance_foreign,
      (-coalesce(ea.amt_reporting,0)) as translated_amount
    from elim_adjustments ea
    join public.chart_of_accounts coa on coa.code = ea.account_code
  ),
  unrealized_calc as (
    select
      (select inventory_account_code from upr) as inventory_code,
      (select cogs_account_code from upr) as cogs_code,
      (select percent_remaining from upr) as pct,
      coalesce(sum(
        case
          when l.is_intercompany is not true then 0
          when l.account_type = 'income' then (l.signed_base_amount * l.eff_pct)
          when l.account_type = 'expense' then -(l.signed_base_amount * l.eff_pct)
          else 0
        end
      ),0) as interco_gross_profit_base
    from lines l
    where exists (select 1 from upr)
  ),
  unrealized_rows as (
    select
      inv.code as account_code,
      inv.name as account_name,
      inv.account_type,
      inv.ifrs_statement,
      inv.ifrs_category,
      inv.ifrs_line,
      (-(coalesce(uc.interco_gross_profit_base,0) * coalesce(uc.pct,0))) as balance_base,
      null::numeric as balance_foreign,
      (-(public.fx_convert((coalesce(uc.interco_gross_profit_base,0) * coalesce(uc.pct,0)), v_base, v_reporting, p_as_of, 'accounting'))) as translated_amount
    from unrealized_calc uc
    join public.chart_of_accounts inv on inv.code = uc.inventory_code
    where coalesce(uc.pct,0) > 0
    union all
    select
      cogs.code as account_code,
      cogs.name as account_name,
      cogs.account_type,
      cogs.ifrs_statement,
      cogs.ifrs_category,
      cogs.ifrs_line,
      (coalesce(uc.interco_gross_profit_base,0) * coalesce(uc.pct,0)) as balance_base,
      null::numeric as balance_foreign,
      (public.fx_convert((coalesce(uc.interco_gross_profit_base,0) * coalesce(uc.pct,0)), v_base, v_reporting, p_as_of, 'accounting')) as translated_amount
    from unrealized_calc uc
    join public.chart_of_accounts cogs on cogs.code = uc.cogs_code
    where coalesce(uc.pct,0) > 0
  ),
  company_net_assets as (
    select
      l.company_id,
      coalesce(sum(case when l.account_type = 'asset' then l.signed_base_amount else 0 end),0) as assets_base,
      coalesce(sum(case when l.account_type = 'liability' then l.signed_base_amount else 0 end),0) as liabilities_base
    from lines l
    group by l.company_id
  ),
  nci_calc as (
    select
      coalesce(sum(
        (1 - coalesce(m.ownership_pct,1)) * (coalesce(c.assets_base,0) - coalesce(c.liabilities_base,0))
      ),0) as nci_base
    from members m
    join company_net_assets c on c.company_id = m.company_id
    where m.consolidation_method = 'full'
      and coalesce(m.ownership_pct,1) < 1
  ),
  nci_row as (
    select
      coa.code as account_code,
      coa.name as account_name,
      coa.account_type,
      coa.ifrs_statement,
      coa.ifrs_category,
      coa.ifrs_line,
      coalesce(n.nci_base,0) as balance_base,
      null::numeric as balance_foreign,
      public.fx_convert(coalesce(n.nci_base,0), v_base, v_reporting, p_as_of, 'accounting') as translated_amount
    from nci_calc n
    join public.chart_of_accounts coa on coa.code = '3060'
    where abs(coalesce(n.nci_base,0)) > 1e-6
  ),
  all_rows as (
    select
      bg.group_key,
      bg.group_name,
      bg.account_type,
      bg.ifrs_statement,
      bg.ifrs_category,
      bg.currency_code,
      coalesce(bg.balance_base,0) as balance_base,
      case
        when v_view = 'revalued' then
          case
            when upper(bg.currency_code) = upper(v_base) or bg.balance_foreign is null then coalesce(bg.balance_base,0)
            else coalesce(bg.balance_foreign,0) * public.get_fx_rate(bg.currency_code, p_as_of, 'accounting')
          end
        when v_view in ('reporting','translated') then coalesce(bg.translated_amount,0)
        else coalesce(bg.balance_base,0)
      end as view_balance_base
    from base_grouped bg
    union all
    select
      er.account_code as group_key,
      max(er.account_name) as group_name,
      max(er.account_type) as account_type,
      max(er.ifrs_statement) as ifrs_statement,
      max(er.ifrs_category) as ifrs_category,
      upper(case when v_view in ('reporting','translated') then v_reporting else v_base end) as currency_code,
      sum(er.balance_base) as balance_base,
      sum(
        case when v_view in ('reporting','translated') then er.translated_amount else er.balance_base end
      ) as view_balance_base
    from (
      select * from elim_rows
      union all
      select * from unrealized_rows
      union all
      select * from nci_row
    ) er
    group by er.account_code
  ),
  cta_amount as (
    select
      case
        when v_view not in ('reporting','translated') then 0
        else coalesce(sum(case when ar.account_type = 'asset' then ar.view_balance_base else 0 end),0)
           - coalesce(sum(case when ar.account_type = 'liability' then ar.view_balance_base else 0 end),0)
           - coalesce(sum(case when ar.account_type = 'equity' then ar.view_balance_base else 0 end),0)
      end as cta
    from all_rows ar
  ),
  cta_row as (
    select
      coa.code as group_key,
      coa.name as group_name,
      coa.account_type,
      coa.ifrs_statement,
      coa.ifrs_category,
      v_reporting as currency_code,
      public.fx_convert(ca.cta, v_reporting, v_base, p_as_of, 'accounting') as balance_base,
      ca.cta as view_balance_base
    from cta_amount ca
    join public.chart_of_accounts coa on coa.code = '3055'
    where abs(coalesce(ca.cta,0)) > 1e-6
  ),
  final_rows as (
    select * from all_rows
    union all
    select * from cta_row
  )
  select
    fr.group_key,
    max(fr.group_name) as group_name,
    max(fr.account_type) as account_type,
    max(fr.ifrs_statement) as ifrs_statement,
    max(fr.ifrs_category) as ifrs_category,
    fr.currency_code,
    coalesce(sum(fr.balance_base),0) as balance_base,
    coalesce(sum(fr.view_balance_base),0) as revalued_balance_base
  from final_rows fr
  group by fr.group_key, fr.currency_code
  having abs(coalesce(sum(fr.view_balance_base),0)) > 1e-9
  order by fr.group_key;
end;
$$;


ALTER FUNCTION "public"."consolidated_trial_balance"("p_group_id" "uuid", "p_as_of" "date", "p_rollup" "text", "p_currency_view" "text") OWNER TO "postgres";

--
-- Name: convert_qty(numeric, "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."convert_qty"("p_qty" numeric, "p_from" "uuid", "p_to" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_num bigint;
  v_den bigint;
begin
  if p_from = p_to then
    return p_qty;
  end if;
  select numerator, denominator into v_num, v_den
  from public.uom_conversions
  where from_uom_id = p_from and to_uom_id = p_to
  limit 1;
  if v_num is null or v_den is null then
    raise exception 'missing uom conversion';
  end if;
  return p_qty * (v_num::numeric / v_den::numeric);
end;
$$;


ALTER FUNCTION "public"."convert_qty"("p_qty" numeric, "p_from" "uuid", "p_to" "uuid") OWNER TO "postgres";

--
-- Name: create_accounting_document("text", "text", "text", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_accounting_document"("p_document_type" "text", "p_source_table" "text", "p_source_id" "text", "p_branch_id" "uuid", "p_company_id" "uuid", "p_memo" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
begin
  select id into v_id
  from public.accounting_documents
  where source_table = p_source_table and source_id = p_source_id;
  if v_id is not null then
    return v_id;
  end if;
  insert into public.accounting_documents(
    document_type, source_table, source_id, branch_id, company_id, status, memo, created_by
  )
  values (
    p_document_type, p_source_table, p_source_id, p_branch_id, p_company_id, 'posted', p_memo, auth.uid()
  )
  returning id into v_id;
  return v_id;
end;
$$;


ALTER FUNCTION "public"."create_accounting_document"("p_document_type" "text", "p_source_table" "text", "p_source_id" "text", "p_branch_id" "uuid", "p_company_id" "uuid", "p_memo" "text") OWNER TO "postgres";

--
-- Name: create_approval_request("text", "text", "text", numeric, "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_approval_request"("p_target_table" "text", "p_target_id" "text", "p_request_type" "text", "p_amount" numeric, "p_payload" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_request_id uuid;
  v_policy_id uuid;
  v_payload_hash text;
begin
  if not public.approval_required(p_request_type, p_amount) then
    raise exception 'approval policy not found for request_type %', p_request_type;
  end if;

  v_payload_hash := encode(digest(convert_to(coalesce(p_payload::text, ''), 'utf8'), 'sha256'::text), 'hex');

  insert into public.approval_requests(
    target_table, target_id, request_type, status, requested_by, payload_hash
  )
  values (
    p_target_table, p_target_id, p_request_type, 'pending', auth.uid(), v_payload_hash
  )
  on conflict (target_table, target_id, request_type)
  do update set
    payload_hash = excluded.payload_hash
  where approval_requests.status = 'pending'
  returning id into v_request_id;

  select p.id into v_policy_id
  from public.approval_policies p
  where p.request_type = p_request_type
    and p.is_active = true
    and p.min_amount <= coalesce(p_amount, 0)
    and (p.max_amount is null or p.max_amount >= coalesce(p_amount, 0))
  order by p.min_amount desc
  limit 1;

  insert into public.approval_steps(request_id, step_no, approver_role, status)
  select v_request_id, s.step_no, s.approver_role, 'pending'
  from public.approval_policy_steps s
  where s.policy_id = v_policy_id
  order by s.step_no asc
  on conflict (request_id, step_no) do nothing;

  return v_request_id;
end;
$$;


ALTER FUNCTION "public"."create_approval_request"("p_target_table" "text", "p_target_id" "text", "p_request_type" "text", "p_amount" numeric, "p_payload" "jsonb") OWNER TO "postgres";

--
-- Name: create_budget("text", integer, "text", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_budget"("p_name" "text", "p_fiscal_year" integer, "p_currency_code" "text", "p_company_id" "uuid" DEFAULT NULL::"uuid", "p_branch_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  insert into public.budget_headers(name, fiscal_year, currency_code, status, company_id, branch_id, created_by)
  values (nullif(trim(coalesce(p_name,'')),''), p_fiscal_year, upper(coalesce(p_currency_code, public.get_base_currency())), 'draft', p_company_id, p_branch_id, auth.uid())
  returning id into v_id;
  return v_id;
end;
$$;


ALTER FUNCTION "public"."create_budget"("p_name" "text", "p_fiscal_year" integer, "p_currency_code" "text", "p_company_id" "uuid", "p_branch_id" "uuid") OWNER TO "postgres";

--
-- Name: create_budget_scenario("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_budget_scenario"("p_base_budget_id" "uuid", "p_name" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base public.budget_headers%rowtype;
  v_scenario uuid;
  v_budget uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_base_budget_id is null then
    raise exception 'base_budget_id required';
  end if;

  select * into v_base from public.budget_headers where id = p_base_budget_id;
  if v_base.id is null then
    raise exception 'base budget not found';
  end if;

  insert into public.budget_scenarios(base_budget_id, name, created_by)
  values (p_base_budget_id, nullif(trim(coalesce(p_name,'')),''), auth.uid())
  returning id into v_scenario;

  insert into public.budget_headers(name, fiscal_year, currency_code, status, company_id, branch_id, created_by, scenario_id)
  values (concat(v_base.name, ' - ', (select name from public.budget_scenarios where id = v_scenario)), v_base.fiscal_year, v_base.currency_code, 'draft', v_base.company_id, v_base.branch_id, auth.uid(), v_scenario)
  returning id into v_budget;

  insert into public.budget_lines(budget_id, period_start, account_id, cost_center_id, party_id, amount_base, currency_code, notes, created_by)
  select
    v_budget,
    bl.period_start,
    bl.account_id,
    bl.cost_center_id,
    bl.party_id,
    bl.amount_base,
    bl.currency_code,
    bl.notes,
    auth.uid()
  from public.budget_lines bl
  where bl.budget_id = p_base_budget_id;

  return v_budget;
end;
$$;


ALTER FUNCTION "public"."create_budget_scenario"("p_base_budget_id" "uuid", "p_name" "text") OWNER TO "postgres";

--
-- Name: create_chart_account("text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_chart_account"("p_code" "text", "p_name" "text", "p_account_type" "text", "p_normal_balance" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_code text;
  v_name text;
  v_id uuid;
begin
  if not public.is_owner() then
    raise exception 'not allowed';
  end if;

  v_code := btrim(coalesce(p_code, ''));
  v_name := btrim(coalesce(p_name, ''));
  if v_code = '' then
    raise exception 'code is required';
  end if;
  if v_code !~ '^[0-9]{3,10}$' then
    raise exception 'invalid code';
  end if;
  if v_name = '' then
    raise exception 'name is required';
  end if;
  if coalesce(p_account_type,'') not in ('asset','liability','equity','income','expense') then
    raise exception 'invalid account_type';
  end if;
  if coalesce(p_normal_balance,'') not in ('debit','credit') then
    raise exception 'invalid normal_balance';
  end if;

  insert into public.chart_of_accounts(code, name, account_type, normal_balance, is_active)
  values (v_code, v_name, p_account_type, p_normal_balance, true)
  returning id into v_id;

  return v_id;
end;
$_$;


ALTER FUNCTION "public"."create_chart_account"("p_code" "text", "p_name" "text", "p_account_type" "text", "p_normal_balance" "text") OWNER TO "postgres";

