--
-- Name: create_consolidation_snapshot("uuid", "date", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_consolidation_snapshot"("p_group_id" "uuid", "p_as_of" "date", "p_rollup" "text" DEFAULT 'account'::"text", "p_currency_view" "text" DEFAULT 'base'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
  v_reporting text;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_group_id is null then
    raise exception 'group_id required';
  end if;
  if p_as_of is null then
    raise exception 'as_of required';
  end if;

  select upper(coalesce(nullif(btrim(cg.reporting_currency),''), public.get_base_currency()))
  into v_reporting
  from public.consolidation_groups cg
  where cg.id = p_group_id;
  if v_reporting is null then
    v_reporting := upper(public.get_base_currency());
  end if;

  insert into public.consolidation_snapshot_headers(group_id, as_of, rollup, currency_view, reporting_currency, created_by)
  values (p_group_id, p_as_of, lower(coalesce(p_rollup,'account')), lower(coalesce(p_currency_view,'base')), v_reporting, auth.uid())
  on conflict (group_id, as_of, rollup, currency_view) do update
  set reporting_currency = excluded.reporting_currency,
      created_at = now(),
      created_by = excluded.created_by
  returning id into v_id;

  delete from public.consolidation_snapshot_lines where snapshot_id = v_id;

  insert into public.consolidation_snapshot_lines(
    snapshot_id, group_key, group_name, account_type, ifrs_statement, ifrs_category, currency_code, balance_base, view_balance
  )
  select
    v_id,
    tb.group_key,
    tb.group_name,
    tb.account_type,
    tb.ifrs_statement,
    tb.ifrs_category,
    tb.currency_code,
    tb.balance_base,
    tb.revalued_balance_base
  from public.consolidated_trial_balance(p_group_id, p_as_of, p_rollup, p_currency_view) tb;

  return v_id;
end;
$$;


ALTER FUNCTION "public"."create_consolidation_snapshot"("p_group_id" "uuid", "p_as_of" "date", "p_rollup" "text", "p_currency_view" "text") OWNER TO "postgres";

--
-- Name: create_financial_report_snapshot("text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_financial_report_snapshot"("p_report_type" "text", "p_params" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_type text := lower(nullif(btrim(coalesce(p_report_type,'')), ''));
  v_params jsonb := coalesce(p_params,'{}'::jsonb);
  v_hash text := md5(v_params::text);
  v_id uuid;
  v_start date;
  v_end date;
  v_as_of date;
  v_company uuid;
  v_branch uuid;
  v_currency_view text;
  v_rollup text;
  v_data jsonb := '{}'::jsonb;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if v_type is null then
    raise exception 'report_type required';
  end if;

  begin v_start := nullif(v_params->>'start','')::date; exception when others then v_start := null; end;
  begin v_end := nullif(v_params->>'end','')::date; exception when others then v_end := null; end;
  begin v_as_of := nullif(v_params->>'asOf','')::date; exception when others then v_as_of := null; end;
  begin v_company := nullif(v_params->>'companyId','')::uuid; exception when others then v_company := null; end;
  begin v_branch := nullif(v_params->>'branchId','')::uuid; exception when others then v_branch := null; end;
  v_currency_view := nullif(v_params->>'currencyView','');
  v_rollup := nullif(v_params->>'rollup','');

  if v_type = 'trial_balance' then
    select coalesce(jsonb_agg(to_jsonb(t) order by t.group_key), '[]'::jsonb)
    into v_data
    from public.enterprise_trial_balance(v_start, v_end, v_company, v_branch, null, null, null, coalesce(v_currency_view,'base'), coalesce(v_rollup,'account')) t;
  elsif v_type = 'balance_sheet' then
    if v_as_of is null then
      v_as_of := v_end;
    end if;
    select coalesce(jsonb_agg(to_jsonb(t) order by t.group_key), '[]'::jsonb)
    into v_data
    from public.enterprise_balance_sheet(v_as_of, v_company, v_branch, null, null, null, coalesce(v_currency_view,'base'), coalesce(v_rollup,'account')) t;
  elsif v_type = 'pl' then
    select coalesce(jsonb_agg(to_jsonb(t) order by abs(t.amount_base) desc), '[]'::jsonb)
    into v_data
    from public.enterprise_profit_and_loss(v_start, v_end, v_company, v_branch, null, null, null, coalesce(v_rollup,'ifrs_line')) t;
  elsif v_type = 'cash_flow_direct' then
    select to_jsonb(t) into v_data
    from public.enterprise_cash_flow_direct(v_start, v_end, v_company, v_branch, null) t;
  elsif v_type = 'cash_flow_indirect' then
    select to_jsonb(t) into v_data
    from public.enterprise_cash_flow_indirect(v_start, v_end, v_company, v_branch, null) t;
  else
    v_data := '{}'::jsonb;
  end if;

  insert into public.financial_report_snapshots(report_type, params, params_hash, period_start, period_end, as_of, company_id, branch_id, currency_view, rollup, generated_by, data)
  values (v_type, v_params, v_hash, v_start, v_end, v_as_of, v_company, v_branch, v_currency_view, v_rollup, auth.uid(), coalesce(v_data,'{}'::jsonb))
  on conflict (report_type, params_hash, period_start, period_end, as_of)
  do update set
    generated_at = now(),
    generated_by = excluded.generated_by,
    data = excluded.data
  returning id into v_id;

  return v_id;
end;
$$;


ALTER FUNCTION "public"."create_financial_report_snapshot"("p_report_type" "text", "p_params" "jsonb") OWNER TO "postgres";

--
-- Name: create_forecast_budget_from_actuals("text", "date", integer, integer, "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_forecast_budget_from_actuals"("p_name" "text", "p_start_month" "date", "p_months" integer DEFAULT 3, "p_lookback_months" integer DEFAULT 3, "p_company_id" "uuid" DEFAULT NULL::"uuid", "p_branch_id" "uuid" DEFAULT NULL::"uuid", "p_method" "text" DEFAULT 'avg'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_budget uuid;
  v_year int;
  v_base text := public.get_base_currency();
  v_start date := date_trunc('month', p_start_month)::date;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if v_start is null then
    raise exception 'start_month required';
  end if;

  v_year := extract(year from v_start)::int;
  v_budget := public.create_budget(nullif(trim(coalesce(p_name,'')),''), v_year, v_base, p_company_id, p_branch_id);

  with lookback as (
    select
      l.account_code,
      max(l.account_name) as account_name,
      max(l.account_type) as account_type,
      date_trunc('month', l.entry_date)::date as period_start,
      sum(
        case
          when l.account_type = 'income' then l.signed_base_amount
          when l.account_type = 'expense' then -l.signed_base_amount
          else 0
        end
      ) as amt
    from public.enterprise_gl_lines l
    where public.can_view_enterprise_financial_reports()
      and l.entry_date >= (v_start - make_interval(months => greatest(coalesce(p_lookback_months,3),1)))
      and l.entry_date < v_start
      and (p_company_id is null or l.company_id = p_company_id)
      and (p_branch_id is null or l.branch_id = p_branch_id)
      and l.account_type in ('income','expense')
    group by l.account_code, date_trunc('month', l.entry_date)::date
  ),
  agg as (
    select
      account_code,
      avg(amt) as avg_amt
    from lookback
    group by account_code
  ),
  months as (
    select (v_start + make_interval(months => gs))::date as period_start
    from generate_series(0, greatest(coalesce(p_months,3),1) - 1) gs
  )
  insert into public.budget_lines(budget_id, period_start, account_id, cost_center_id, party_id, amount_base, currency_code, notes, created_by)
  select
    v_budget,
    m.period_start,
    public.get_account_id_by_code(a.account_code),
    null,
    null,
    round(coalesce(a.avg_amt,0), 2),
    v_base,
    'forecast',
    auth.uid()
  from agg a
  cross join months m
  where public.get_account_id_by_code(a.account_code) is not null
  on conflict (budget_id, period_start, account_id, cost_center_id, party_id) do update
  set amount_base = excluded.amount_base,
      notes = excluded.notes;

  return v_budget;
end;
$$;


ALTER FUNCTION "public"."create_forecast_budget_from_actuals"("p_name" "text", "p_start_month" "date", "p_months" integer, "p_lookback_months" integer, "p_company_id" "uuid", "p_branch_id" "uuid", "p_method" "text") OWNER TO "postgres";

--
-- Name: create_inventory_transfer("uuid", "uuid", "jsonb", "date", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_inventory_transfer"("p_from_warehouse_id" "uuid", "p_to_warehouse_id" "uuid", "p_items" "jsonb", "p_transfer_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT NULL::"text", "p_idempotency_key" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_existing_id uuid;
  v_transfer_id uuid;
  v_transfer_number text;
  v_item jsonb;
  v_item_id text;
  v_batch_id text;
  v_qty numeric;
  v_batch record;
begin
  v_actor := auth.uid();
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;

  if p_from_warehouse_id is null or p_to_warehouse_id is null then
    raise exception 'warehouse ids are required';
  end if;
  if p_from_warehouse_id = p_to_warehouse_id then
    raise exception 'from and to warehouses must differ';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;

  if p_idempotency_key is not null and btrim(p_idempotency_key) <> '' then
    select it.id
    into v_existing_id
    from public.inventory_transfers it
    where it.create_idempotency_key = p_idempotency_key;
    if found then
      return v_existing_id;
    end if;
  end if;

  v_transfer_id := gen_random_uuid();
  v_transfer_number := 'IT-' || to_char(now(), 'YYYYMMDD-HH24MISS') || '-' || right(v_transfer_id::text, 6);

  insert into public.inventory_transfers(
    id,
    transfer_number,
    from_warehouse_id,
    to_warehouse_id,
    transfer_date,
    state,
    notes,
    payload,
    created_by,
    created_at,
    updated_at,
    create_idempotency_key
  )
  values (
    v_transfer_id,
    v_transfer_number,
    p_from_warehouse_id,
    p_to_warehouse_id,
    coalesce(p_transfer_date, current_date),
    'CREATED',
    p_notes,
    '{}'::jsonb,
    v_actor,
    now(),
    now(),
    nullif(btrim(p_idempotency_key), '')
  );

  for v_item in select value from jsonb_array_elements(p_items)
  loop
    v_item_id := coalesce(v_item->>'itemId', v_item->>'id');
    v_batch_id := nullif(v_item->>'batchId', '');
    v_qty := coalesce(nullif(v_item->>'quantity', '')::numeric, 0);
    if v_item_id is null or v_item_id = '' then
      raise exception 'Invalid itemId';
    end if;
    if v_batch_id is null then
      raise exception 'batchId is required';
    end if;
    if v_qty <= 0 then
      raise exception 'quantity must be > 0';
    end if;

    select b.id, b.item_id, b.warehouse_id, b.unit_cost, b.expiry_date
    into v_batch
    from public.batches b
    where b.id = v_batch_id::uuid
      and b.item_id::text = v_item_id
      and b.warehouse_id = p_from_warehouse_id
    for update;

    if not found then
      raise exception 'Batch % not found in source warehouse', v_batch_id;
    end if;

    insert into public.inventory_transfer_items(
      transfer_id,
      item_id,
      source_batch_id,
      quantity,
      unit_cost,
      total_cost,
      created_at,
      updated_at
    )
    values (
      v_transfer_id,
      v_item_id,
      v_batch.id,
      v_qty,
      coalesce(v_batch.unit_cost, 0),
      v_qty * coalesce(v_batch.unit_cost, 0),
      now(),
      now()
    );
  end loop;

  return v_transfer_id;
end;
$$;


ALTER FUNCTION "public"."create_inventory_transfer"("p_from_warehouse_id" "uuid", "p_to_warehouse_id" "uuid", "p_items" "jsonb", "p_transfer_date" "date", "p_notes" "text", "p_idempotency_key" "text") OWNER TO "postgres";

--
-- Name: create_ledger_snapshot("date", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_ledger_snapshot"("p_as_of" "date", "p_company_id" "uuid" DEFAULT NULL::"uuid", "p_branch_id" "uuid" DEFAULT NULL::"uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
  v_base text := public.get_base_currency();
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_as_of is null then
    raise exception 'as_of required';
  end if;

  insert into public.ledger_snapshot_headers(as_of, snapshot_type, company_id, branch_id, notes, created_by)
  values (p_as_of, 'ledger_balances', p_company_id, p_branch_id, nullif(trim(coalesce(p_notes,'')),''), auth.uid())
  on conflict (as_of, snapshot_type, company_id, branch_id) do update
  set notes = excluded.notes
  returning id into v_id;

  delete from public.ledger_snapshot_lines where snapshot_id = v_id;

  insert into public.ledger_snapshot_lines(snapshot_id, account_id, currency_code, cost_center_id, dept_id, project_id, base_balance, foreign_balance, revalued_balance)
  with lines as (
    select
      jl.account_id,
      upper(coalesce(jl.currency_code, v_base)) as currency_code,
      jl.cost_center_id,
      jl.dept_id,
      jl.project_id,
      sum(case when coa.normal_balance = 'credit' then (jl.credit - jl.debit) else (jl.debit - jl.credit) end) as base_balance,
      sum(
        case
          when jl.currency_code is null or upper(jl.currency_code) = upper(v_base) or jl.foreign_amount is null then null
          when coa.normal_balance = 'credit' then (case when jl.credit > 0 then coalesce(jl.foreign_amount,0) else -coalesce(jl.foreign_amount,0) end) * -1
          else (case when jl.debit > 0 then coalesce(jl.foreign_amount,0) else -coalesce(jl.foreign_amount,0) end)
        end
      ) as foreign_balance
    from public.journal_lines jl
    join public.journal_entries je on je.id = jl.journal_entry_id
    join public.chart_of_accounts coa on coa.id = jl.account_id
    where je.entry_date::date <= p_as_of
      and (p_company_id is null or je.company_id = p_company_id)
      and (p_branch_id is null or je.branch_id = p_branch_id)
    group by jl.account_id, upper(coalesce(jl.currency_code, v_base)), jl.cost_center_id, jl.dept_id, jl.project_id
  )
  select
    v_id,
    l.account_id,
    l.currency_code,
    l.cost_center_id,
    l.dept_id,
    l.project_id,
    coalesce(l.base_balance,0),
    l.foreign_balance,
    case
      when l.currency_code is null or upper(l.currency_code) = upper(v_base) or l.foreign_balance is null then coalesce(l.base_balance,0)
      else coalesce(l.foreign_balance,0) * public.get_fx_rate(l.currency_code, p_as_of, 'accounting')
    end as revalued_balance
  from lines l;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'ledger.snapshot',
    'accounting',
    v_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('snapshotId', v_id::text, 'asOf', p_as_of::text),
    'LOW',
    'LEDGER_SNAPSHOT'
  );

  return v_id;
end;
$$;


ALTER FUNCTION "public"."create_ledger_snapshot"("p_as_of" "date", "p_company_id" "uuid", "p_branch_id" "uuid", "p_notes" "text") OWNER TO "postgres";

--
-- Name: create_manual_journal_entry(timestamp with time zone, "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_manual_journal_entry"("p_entry_date" timestamp with time zone, "p_memo" "text", "p_lines" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_entry_id uuid;
  v_line jsonb;
  v_account_code text;
  v_account_id uuid;
  v_debit numeric;
  v_credit numeric;
  v_memo text;
  v_cost_center_id uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  if p_lines is null or jsonb_typeof(p_lines) <> 'array' then
    raise exception 'p_lines must be a json array';
  end if;

  v_memo := nullif(trim(coalesce(p_memo, '')), '');

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    coalesce(p_entry_date, now()),
    v_memo,
    'manual',
    null,
    null,
    auth.uid()
  )
  returning id into v_entry_id;

  for v_line in select value from jsonb_array_elements(p_lines)
  loop
    v_account_code := nullif(trim(coalesce(v_line->>'accountCode', '')), '');
    v_debit := coalesce(nullif(v_line->>'debit', '')::numeric, 0);
    v_credit := coalesce(nullif(v_line->>'credit', '')::numeric, 0);
    v_cost_center_id := nullif(trim(coalesce(v_line->>'costCenterId', '')), '')::uuid;

    if v_account_code is null then
      raise exception 'accountCode is required';
    end if;

    if v_debit < 0 or v_credit < 0 then
      raise exception 'invalid debit/credit';
    end if;

    if (v_debit > 0 and v_credit > 0) or (v_debit = 0 and v_credit = 0) then
      raise exception 'invalid line amounts';
    end if;

    v_account_id := public.get_account_id_by_code(v_account_code);
    if v_account_id is null then
      raise exception 'account not found %', v_account_code;
    end if;

    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, cost_center_id)
    values (
      v_entry_id,
      v_account_id,
      v_debit,
      v_credit,
      nullif(trim(coalesce(v_line->>'memo', '')), ''),
      v_cost_center_id
    );
  end loop;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'journal_entries.manual_draft',
    'accounting',
    v_entry_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('entryId', v_entry_id::text),
    'LOW',
    'ACCOUNTING_DRAFT'
  );

  return v_entry_id;
end;
$$;


ALTER FUNCTION "public"."create_manual_journal_entry"("p_entry_date" timestamp with time zone, "p_memo" "text", "p_lines" "jsonb") OWNER TO "postgres";

--
-- Name: create_manual_journal_entry(timestamp with time zone, "text", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_manual_journal_entry"("p_entry_date" timestamp with time zone, "p_memo" "text", "p_lines" "jsonb", "p_journal_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_entry_id uuid;
  v_line jsonb;
  v_account_code text;
  v_account_id uuid;
  v_debit numeric;
  v_credit numeric;
  v_memo text;
  v_cost_center_id uuid;
  v_journal_id uuid;
  v_party_id uuid;
  v_currency_code text;
  v_fx_rate numeric;
  v_foreign_amount numeric;
  v_entry_date timestamptz;
  v_base text := public.get_base_currency();
  v_base_amount numeric;
begin
  if not public.is_owner_or_manager() then
    raise exception 'not allowed';
  end if;

  if p_lines is null or jsonb_typeof(p_lines) <> 'array' then
    raise exception 'p_lines must be a json array';
  end if;

  v_entry_date := coalesce(p_entry_date, now());
  v_memo := nullif(trim(coalesce(p_memo, '')), '');
  v_journal_id := coalesce(p_journal_id, public.get_default_journal_id(), '00000000-0000-4000-8000-000000000001'::uuid);

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, journal_id)
  values (
    v_entry_date,
    v_memo,
    'manual',
    null,
    null,
    auth.uid(),
    v_journal_id
  )
  returning id into v_entry_id;

  for v_line in select value from jsonb_array_elements(p_lines)
  loop
    v_account_code := nullif(trim(coalesce(v_line->>'accountCode', '')), '');
    v_debit := coalesce(nullif(v_line->>'debit', '')::numeric, 0);
    v_credit := coalesce(nullif(v_line->>'credit', '')::numeric, 0);
    v_cost_center_id := nullif(v_line->>'costCenterId', '')::uuid;
    v_party_id := nullif(v_line->>'partyId', '')::uuid;
    v_currency_code := upper(nullif(trim(coalesce(v_line->>'currencyCode','')), ''));
    v_fx_rate := null;
    v_foreign_amount := null;
    begin
      v_fx_rate := nullif(v_line->>'fxRate', '')::numeric;
    exception when others then
      v_fx_rate := null;
    end;
    begin
      v_foreign_amount := nullif(v_line->>'foreignAmount', '')::numeric;
    exception when others then
      v_foreign_amount := null;
    end;

    if v_account_code is null then
      raise exception 'accountCode is required';
    end if;

    select id into v_account_id
    from public.chart_of_accounts
    where code = v_account_code
      and is_active = true
    limit 1;
    if v_account_id is null then
      raise exception 'account not found: %', v_account_code;
    end if;

    if (v_debit > 0 and v_credit > 0) or (v_debit = 0 and v_credit = 0) then
      raise exception 'either debit or credit must be > 0';
    end if;

    if v_currency_code is not null and upper(v_currency_code) = upper(v_base) then
      v_currency_code := null;
      v_fx_rate := null;
      v_foreign_amount := null;
    end if;

    if v_currency_code is not null and upper(v_currency_code) <> upper(v_base) then
      if v_fx_rate is null or v_fx_rate <= 0 then
        v_fx_rate := public.get_fx_rate(v_currency_code, v_entry_date::date, 'accounting');
      end if;
      if v_fx_rate is null or v_fx_rate <= 0 then
        raise exception 'accounting fx rate missing for currency % at %', v_currency_code, v_entry_date::date;
      end if;
      if v_foreign_amount is null or v_foreign_amount <= 0 then
        v_foreign_amount := greatest(coalesce(v_debit, 0), coalesce(v_credit, 0));
      end if;
      if v_foreign_amount is null or v_foreign_amount <= 0 then
        raise exception 'foreignAmount required for currency %', v_currency_code;
      end if;
      v_base_amount := public._money_round(v_foreign_amount * v_fx_rate);
      if v_debit > 0 then
        v_debit := v_base_amount;
        v_credit := 0;
      else
        v_credit := v_base_amount;
        v_debit := 0;
      end if;
    else
      v_currency_code := null;
      v_fx_rate := null;
      v_foreign_amount := null;
    end if;

    v_memo := nullif(trim(coalesce(v_line->>'memo', '')), '');

    insert into public.journal_lines(
      journal_entry_id,
      account_id,
      debit,
      credit,
      line_memo,
      cost_center_id,
      party_id,
      currency_code,
      fx_rate,
      foreign_amount
    )
    values (
      v_entry_id,
      v_account_id,
      v_debit,
      v_credit,
      v_memo,
      v_cost_center_id,
      v_party_id,
      v_currency_code,
      v_fx_rate,
      v_foreign_amount
    );
  end loop;

  perform public.check_journal_entry_balance(v_entry_id);
  return v_entry_id;
end;
$$;


ALTER FUNCTION "public"."create_manual_journal_entry"("p_entry_date" timestamp with time zone, "p_memo" "text", "p_lines" "jsonb", "p_journal_id" "uuid") OWNER TO "postgres";

--
-- Name: create_order_secure("jsonb", "uuid", "text", "text", "text", "jsonb", "text", "text", boolean, timestamp with time zone, "text", numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_order_secure"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text" DEFAULT NULL::"text", "p_points_redeemed_value" numeric DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
    v_user_id uuid;
    v_order_id uuid;
    v_item_input jsonb;
    v_menu_item record;
    v_menu_item_data jsonb;
    v_cart_item jsonb;
    v_final_items jsonb := '[]'::jsonb;
    v_subtotal numeric := 0;
    v_total numeric := 0;
    v_delivery_fee numeric := 0;
    v_discount_amount numeric := 0;
    v_tax_amount numeric := 0;
    v_tax_rate numeric := 0;
    v_points_earned numeric := 0;
    v_settings jsonb;
    v_zone_data jsonb;
    v_line_total numeric;
    v_addons_price numeric;
    v_unit_price numeric;
    v_base_price numeric;
    v_addon_key text;
    v_addon_qty numeric;
    v_addon_def jsonb;
    v_grade_id text;
    v_grade_def jsonb;
    v_weight numeric;
    v_quantity numeric;
    v_unit_type text;
    v_delivery_pin text;
    v_available_addons jsonb;
    v_selected_addons_map jsonb;
    v_final_selected_addons jsonb;
    v_points_settings jsonb;
    v_currency_val_per_point numeric;
    v_points_per_currency numeric;
    v_coupon_record record;
    v_stock_items jsonb := '[]'::jsonb;
    v_item_name_ar text;
    v_item_name_en text;
begin
    v_user_id := auth.uid();
    if v_user_id is null then
        raise exception 'User not authenticated';
    end if;

    if exists (
      select 1
      from public.admin_users au
      where au.auth_user_id = v_user_id
        and au.is_active = true
      limit 1
    ) then
      raise exception 'لا يمكن لحسابات الموظفين إنشاء طلبات كعميل. استخدم شاشة الإدارة/نقطة البيع.';
    end if;

    select data into v_settings from public.app_settings where id = 'singleton';
    if v_settings is null then
        v_settings := '{}'::jsonb;
    end if;

    for v_item_input in select * from jsonb_array_elements(p_items)
    loop
        select * into v_menu_item from public.menu_items where id = (v_item_input->>'itemId');
        if not found then
            raise exception 'Item not found: %', v_item_input->>'itemId';
        end if;
        
        v_menu_item_data := v_menu_item.data;
        v_item_name_ar := v_menu_item_data->'name'->>'ar';
        v_item_name_en := v_menu_item_data->'name'->>'en';

        v_quantity := coalesce((v_item_input->>'quantity')::numeric, 0);
        v_weight := coalesce((v_item_input->>'weight')::numeric, 0);
        v_unit_type := coalesce(v_menu_item.unit_type, 'piece');
        
        if v_unit_type in ('kg', 'gram') then
             if v_unit_type = 'gram' and (v_menu_item.price_per_unit is not null or (v_menu_item_data->>'pricePerUnit') is not null) then
                 v_base_price := coalesce(v_menu_item.price_per_unit, (v_menu_item_data->>'pricePerUnit')::numeric) / 1000;
                 v_base_price := v_base_price * v_weight;
             else
                 v_base_price := v_menu_item.price * v_weight;
             end if;
             if v_quantity <= 0 then v_quantity := 1; end if;
        else
             v_base_price := v_menu_item.price;
             if v_quantity <= 0 then raise exception 'Quantity must be positive for item %', v_menu_item.id; end if;
        end if;

        v_grade_id := v_item_input->>'gradeId';
        v_grade_def := null;
        if v_grade_id is not null and (v_menu_item_data->'availableGrades') is not null then
             select value into v_grade_def 
             from jsonb_array_elements(v_menu_item_data->'availableGrades') 
             where value->>'id' = v_grade_id;
             
             if v_grade_def is not null then
                 v_base_price := v_base_price * coalesce((v_grade_def->>'priceMultiplier')::numeric, 1.0);
             end if;
        end if;

        v_addons_price := 0;
        v_available_addons := coalesce(v_menu_item_data->'addons', '[]'::jsonb);
        v_selected_addons_map := coalesce(v_item_input->'selectedAddons', '{}'::jsonb);
        v_final_selected_addons := '{}'::jsonb;
        
        for v_addon_key in select jsonb_object_keys(v_selected_addons_map)
        loop
            v_addon_qty := (v_selected_addons_map->>v_addon_key)::numeric;
            if v_addon_qty > 0 then
                select value into v_addon_def
                from jsonb_array_elements(v_available_addons)
                where value->>'id' = v_addon_key;
                
                if v_addon_def is not null then
                    v_addons_price := v_addons_price + ((v_addon_def->>'price')::numeric * v_addon_qty);
                    
                    v_final_selected_addons := jsonb_set(
                        v_final_selected_addons,
                        array[v_addon_key],
                        jsonb_build_object('addon', v_addon_def, 'quantity', v_addon_qty)
                    );
                end if;
            end if;
        end loop;

        v_unit_price := v_base_price + v_addons_price;
        v_line_total := (v_base_price + v_addons_price) * v_quantity; 
        
        v_subtotal := v_subtotal + v_line_total;

        v_cart_item := v_menu_item_data || jsonb_build_object(
            'quantity', v_quantity,
            'weight', v_weight,
            'selectedAddons', v_final_selected_addons,
            'selectedGrade', v_grade_def,
            'cartItemId', gen_random_uuid()::text,
            'price', v_menu_item.price
        );
        
        v_final_items := v_final_items || v_cart_item;
        
        v_stock_items := v_stock_items || jsonb_build_object(
            'itemId', v_menu_item.id,
            'quantity', v_quantity
        );
    end loop;

    if p_delivery_zone_id is not null then
        select data into v_zone_data from public.delivery_zones where id = p_delivery_zone_id;
        if v_zone_data is not null and (v_zone_data->>'isActive')::boolean then
             v_delivery_fee := coalesce((v_zone_data->>'deliveryFee')::numeric, 0);
        else
             v_delivery_fee := coalesce((v_settings->'deliverySettings'->>'baseFee')::numeric, 0);
        end if;
    else
        v_delivery_fee := coalesce((v_settings->'deliverySettings'->>'baseFee')::numeric, 0);
    end if;

    if (v_settings->'deliverySettings'->>'freeDeliveryThreshold') is not null and 
       v_subtotal >= (v_settings->'deliverySettings'->>'freeDeliveryThreshold')::numeric then
        v_delivery_fee := 0;
    end if;

    if p_coupon_code is not null and length(p_coupon_code) > 0 then
        select * into v_coupon_record from public.coupons where lower(code) = lower(p_coupon_code) and is_active = true;
        if found then
             if (v_coupon_record.data->>'expiresAt') is not null and (v_coupon_record.data->>'expiresAt')::timestamptz < now() then
                 raise exception 'Coupon expired';
             end if;
             if (v_coupon_record.data->>'minOrderAmount') is not null and v_subtotal < (v_coupon_record.data->>'minOrderAmount')::numeric then
                 raise exception 'Order amount too low for coupon';
             end if;
             if (v_coupon_record.data->>'usageLimit') is not null and 
                coalesce((v_coupon_record.data->>'usageCount')::int, 0) >= (v_coupon_record.data->>'usageLimit')::int then
                 raise exception 'Coupon usage limit reached';
             end if;
             
             if (v_coupon_record.data->>'type') = 'percentage' then
                 v_discount_amount := v_subtotal * ((v_coupon_record.data->>'value')::numeric / 100);
                 if (v_coupon_record.data->>'maxDiscount') is not null then
                     v_discount_amount := least(v_discount_amount, (v_coupon_record.data->>'maxDiscount')::numeric);
                 end if;
             else
                 v_discount_amount := (v_coupon_record.data->>'value')::numeric;
             end if;
             
             v_discount_amount := least(v_discount_amount, v_subtotal);
             
             update public.coupons 
             set data = jsonb_set(data, '{usageCount}', (coalesce((data->>'usageCount')::int, 0) + 1)::text::jsonb)
             where id = v_coupon_record.id;
        else
             v_discount_amount := 0;
        end if;
    end if;

    if p_points_redeemed_value > 0 then
        v_points_settings := v_settings->'loyaltySettings';
        if (v_points_settings->>'enabled')::boolean then
             v_currency_val_per_point := coalesce((v_points_settings->>'currencyValuePerPoint')::numeric, 0);
             if v_currency_val_per_point > 0 then
                 declare
                     v_user_points int;
                     v_points_needed numeric;
                 begin
                     select loyalty_points into v_user_points from public.customers where auth_user_id = v_user_id;
                     v_points_needed := p_points_redeemed_value / v_currency_val_per_point;
                     
                     if coalesce(v_user_points, 0) < v_points_needed then
                         raise exception 'Insufficient loyalty points';
                     end if;
                     
                     update public.customers 
                     set loyalty_points = loyalty_points - v_points_needed::int
                     where auth_user_id = v_user_id;
                     
                     v_discount_amount := v_discount_amount + p_points_redeemed_value;
                 end;
             end if;
        end if;
    end if;

    if (v_settings->'taxSettings'->>'enabled')::boolean then
        v_tax_rate := coalesce((v_settings->'taxSettings'->>'rate')::numeric, 0);
        v_tax_amount := greatest(0, v_subtotal - v_discount_amount) * (v_tax_rate / 100);
    end if;

    v_total := greatest(0, v_subtotal - v_discount_amount) + v_delivery_fee + v_tax_amount;

    v_points_settings := v_settings->'loyaltySettings';
    if (v_points_settings->>'enabled')::boolean then
        v_points_per_currency := coalesce((v_points_settings->>'pointsPerCurrencyUnit')::numeric, 0);
        v_points_earned := floor(v_subtotal * v_points_per_currency);
    end if;

    v_delivery_pin := floor(random() * 9000 + 1000)::text;

    insert into public.orders (
        customer_auth_user_id,
        status,
        invoice_number,
        data
    )
    values (
        v_user_id,
        case when p_is_scheduled then 'scheduled' else 'pending' end,
        null,
        jsonb_build_object(
            'id', gen_random_uuid(),
            'userId', v_user_id,
            'orderSource', 'online',
            'items', v_final_items,
            'subtotal', v_subtotal,
            'deliveryFee', v_delivery_fee,
            'discountAmount', v_discount_amount,
            'total', v_total,
            'taxAmount', v_tax_amount,
            'taxRate', v_tax_rate,
            'pointsEarned', v_points_earned,
            'pointsRedeemedValue', p_points_redeemed_value,
            'deliveryZoneId', p_delivery_zone_id,
            'paymentMethod', p_payment_method,
            'notes', p_notes,
            'address', p_address,
            'location', p_location,
            'customerName', p_customer_name,
            'phoneNumber', p_phone_number,
            'isScheduled', p_is_scheduled,
            'scheduledAt', p_scheduled_at,
            'deliveryPin', v_delivery_pin,
            'appliedCouponCode', p_coupon_code
        )
    )
    returning id into v_order_id;

    update public.orders 
    set data = jsonb_set(data, '{id}', to_jsonb(v_order_id::text))
    where id = v_order_id
    returning data into v_item_input;

    perform public.reserve_stock_for_order(v_stock_items, v_order_id);

    insert into public.order_events (order_id, action, actor_type, actor_id, to_status, payload)
    values (
        v_order_id,
        'order.created',
        'customer',
        v_user_id,
        case when p_is_scheduled then 'scheduled' else 'pending' end,
        jsonb_build_object(
            'total', v_total,
            'method', p_payment_method
        )
    );

    return v_item_input;
end;
$$;


ALTER FUNCTION "public"."create_order_secure"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text", "p_points_redeemed_value" numeric) OWNER TO "postgres";

--
-- Name: create_order_secure("jsonb", "uuid", "text", "text", "text", "jsonb", "text", "text", boolean, timestamp with time zone, "text", numeric, "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_order_secure"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text" DEFAULT NULL::"text", "p_points_redeemed_value" numeric DEFAULT 0, "p_explicit_customer_id" "uuid" DEFAULT NULL::"uuid", "p_order_source" "text" DEFAULT 'online'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
    v_user_id uuid;
    v_order_id uuid;
    v_item_input jsonb;
    v_menu_item record;
    v_menu_item_data jsonb;
    v_cart_item jsonb;
    v_final_items jsonb := '[]'::jsonb;
    v_subtotal numeric := 0;
    v_total numeric := 0;
    v_delivery_fee numeric := 0;
    v_discount_amount numeric := 0;
    v_tax_amount numeric := 0;
    v_tax_rate numeric := 0;
    v_points_earned numeric := 0;
    v_settings jsonb;
    v_zone_data jsonb;
    v_line_total numeric;
    v_addons_price numeric;
    v_unit_price numeric;
    v_base_price numeric;
    v_addon_key text;
    v_addon_qty numeric;
    v_addon_def jsonb;
    v_grade_id text;
    v_grade_def jsonb;
    v_weight numeric;
    v_quantity numeric;
    v_unit_type text;
    v_delivery_pin text;
    v_available_addons jsonb;
    v_selected_addons_map jsonb;
    v_final_selected_addons jsonb;
    v_points_settings jsonb;
    v_currency_val_per_point numeric;
    v_points_per_currency numeric;
    v_coupon_record record;
    v_stock_items jsonb := '[]'::jsonb;
    v_item_name_ar text;
    v_item_name_en text;
    v_priced_unit numeric;
    v_pricing_qty numeric;
    v_warehouse_id uuid;
    v_stock_qty numeric;
    v_has_promotions boolean := false;
    v_promotion_id uuid;
    v_bundle_qty numeric;
    v_promo_snapshot jsonb;
    v_promotion_lines jsonb := '[]'::jsonb;
    v_promo_line_id uuid;
    v_promo_item jsonb;
    v_is_staff boolean := false;
begin
    v_user_id := auth.uid();
    if v_user_id is null then
        raise exception 'User not authenticated';
    end if;

    -- Check if user is staff
    if exists (
      select 1
      from public.admin_users au
      where au.auth_user_id = v_user_id
        and au.is_active = true
      limit 1
    ) then
      v_is_staff := true;
    end if;

    -- Staff Blocking Logic
    if v_is_staff then
       if p_order_source = 'online' and p_explicit_customer_id is null then
          -- Staff trying to make a personal online order? Block.
          raise exception 'لا يمكن لحسابات الموظفين إنشاء طلبات كعميل. استخدم شاشة الإدارة/نقطة البيع.';
       end if;
       
       -- Allow substituting the customer ID
       if p_explicit_customer_id is not null then
          v_user_id := p_explicit_customer_id;
       elsif p_order_source = 'in_store' then
          -- Walk-in customer entered by staff
          v_user_id := null;
       end if;
    else
       -- Normal customer
       -- Ensure order_source is consistent (force online if not specified? or allow app to say in_store?)
       -- Usually customers are 'online'.
       if p_order_source <> 'online' then
          -- Maybe in future we allow Kiosk mode? For now trust caller or force 'online'
          -- p_order_source := 'online'; -- Let's respect it for now but default is online
          null;
       end if;
    end if;

    v_warehouse_id := public._resolve_default_warehouse_id();

    select data into v_settings from public.app_settings where id = 'singleton';
    if v_settings is null then
        v_settings := '{}'::jsonb;
    end if;

    if p_items is null or jsonb_typeof(p_items) <> 'array' then
      raise exception 'p_items must be a json array';
    end if;

    for v_item_input in select * from jsonb_array_elements(p_items)
    loop
        v_promotion_id := public._uuid_or_null(v_item_input->>'promotionId');
        if v_promotion_id is not null or coalesce(nullif(v_item_input->>'lineType',''), '') = 'promotion' then
          v_has_promotions := true;
          v_bundle_qty := coalesce(nullif((v_item_input->>'bundleQty')::numeric, null), nullif((v_item_input->>'quantity')::numeric, null), 1);
          if v_bundle_qty <= 0 then v_bundle_qty := 1; end if;

          if p_coupon_code is not null and length(p_coupon_code) > 0 then
            raise exception 'promotion_coupon_conflict';
          end if;
          if coalesce(p_points_redeemed_value, 0) > 0 then
            raise exception 'promotion_points_conflict';
          end if;

          v_promo_snapshot := public._compute_promotion_snapshot(v_promotion_id, v_user_id, v_warehouse_id, v_bundle_qty, null, true);
          v_promo_line_id := gen_random_uuid();

          v_cart_item := jsonb_build_object(
            'lineType', 'promotion',
            'promotionId', v_promotion_id::text,
            'promotionLineId', v_promo_line_id::text,
            'name', v_promo_snapshot->>'name',
            'bundleQty', coalesce(nullif((v_promo_snapshot->>'bundleQty')::numeric, null), v_bundle_qty),
            'originalTotal', coalesce(nullif((v_promo_snapshot->>'computedOriginalTotal')::numeric, null), 0),
            'finalTotal', coalesce(nullif((v_promo_snapshot->>'finalTotal')::numeric, null), 0),
            'promotionExpense', coalesce(nullif((v_promo_snapshot->>'promotionExpense')::numeric, null), 0),
            'cartItemId', coalesce(nullif(v_item_input->>'cartItemId',''), gen_random_uuid()::text)
          );

          v_final_items := v_final_items || v_cart_item;
          v_subtotal := v_subtotal + coalesce(nullif((v_promo_snapshot->>'finalTotal')::numeric, null), 0);

          v_promotion_lines := v_promotion_lines || (v_promo_snapshot || jsonb_build_object(
            'promotionLineId', v_promo_line_id::text
          ));

          for v_promo_item in select value from jsonb_array_elements(coalesce(v_promo_snapshot->'items','[]'::jsonb))
          loop
            v_stock_items := v_stock_items || jsonb_build_object(
              'itemId', v_promo_item->>'itemId',
              'quantity', coalesce(nullif((v_promo_item->>'quantity')::numeric, null), 0)
            );
          end loop;

          continue;
        end if;

        select * into v_menu_item from public.menu_items where id = (v_item_input->>'itemId');
        if not found then
            raise exception 'Item not found: %', v_item_input->>'itemId';
        end if;
        
        v_menu_item_data := v_menu_item.data;
        v_item_name_ar := v_menu_item_data->'name'->>'ar';
        v_item_name_en := v_menu_item_data->'name'->>'en';

        v_quantity := coalesce((v_item_input->>'quantity')::numeric, 0);
        v_weight := coalesce((v_item_input->>'weight')::numeric, 0);
        v_unit_type := coalesce(v_menu_item.unit_type, 'piece');

        if v_unit_type in ('kg', 'gram') then
            if v_weight <= 0 then
              raise exception 'Weight must be positive for item %', v_menu_item.id;
            end if;
            if v_quantity <= 0 then v_quantity := 1; end if;
            v_pricing_qty := v_weight;
            v_priced_unit := public.get_item_price_with_discount(v_menu_item.id::text, v_user_id, v_pricing_qty);
            v_base_price := v_priced_unit * v_weight;
            v_stock_qty := v_weight;
        else
            if v_quantity <= 0 then raise exception 'Quantity must be positive for item %', v_menu_item.id; end if;
            v_pricing_qty := v_quantity;
            v_priced_unit := public.get_item_price_with_discount(v_menu_item.id::text, v_user_id, v_pricing_qty);
            v_base_price := v_priced_unit;
            v_stock_qty := v_quantity;
        end if;

        v_grade_id := v_item_input->>'gradeId';
        v_grade_def := null;
        if v_grade_id is not null and (v_menu_item_data->'availableGrades') is not null then
            select value into v_grade_def
            from jsonb_array_elements(v_menu_item_data->'availableGrades')
            where value->>'id' = v_grade_id;
            
            if v_grade_def is not null then
                v_priced_unit := v_priced_unit * coalesce((v_grade_def->>'priceMultiplier')::numeric, 1.0);
                v_base_price := v_base_price * coalesce((v_grade_def->>'priceMultiplier')::numeric, 1.0);
            end if;
        end if;

        v_addons_price := 0;
        v_available_addons := coalesce(v_menu_item_data->'addons', '[]'::jsonb);
        v_selected_addons_map := coalesce(v_item_input->'selectedAddons', '{}'::jsonb);
        v_final_selected_addons := '{}'::jsonb;
        
        for v_addon_key in select jsonb_object_keys(v_selected_addons_map)
        loop
            v_addon_qty := (v_selected_addons_map->>v_addon_key)::numeric;
            if v_addon_qty > 0 then
                select value into v_addon_def
                from jsonb_array_elements(v_available_addons)
                where value->>'id' = v_addon_key;
                
                if v_addon_def is not null then
                    v_addons_price := v_addons_price + ((v_addon_def->>'price')::numeric * v_addon_qty);
                    v_final_selected_addons := jsonb_set(
                        v_final_selected_addons,
                        array[v_addon_key],
                        jsonb_build_object('addon', v_addon_def, 'quantity', v_addon_qty)
                    );
                end if;
            end if;
        end loop;

        if v_unit_type in ('kg', 'gram') then
            v_unit_price := v_base_price + v_addons_price;
            v_line_total := (v_base_price + v_addons_price) * v_quantity;
        else
            v_unit_price := v_priced_unit + v_addons_price;
            v_line_total := (v_priced_unit + v_addons_price) * v_quantity;
        end if;
        
        v_subtotal := v_subtotal + v_line_total;

        v_cart_item := v_menu_item_data || jsonb_build_object(
            'quantity', v_quantity,
            'weight', v_weight,
            'selectedAddons', v_final_selected_addons,
            'selectedGrade', v_grade_def,
            'cartItemId', gen_random_uuid()::text,
            'price', v_priced_unit
        );
        if v_unit_type = 'gram' then
          v_cart_item := v_cart_item || jsonb_build_object('pricePerUnit', (v_priced_unit * 1000));
        end if;
        
        v_final_items := v_final_items || v_cart_item;
        
        v_stock_items := v_stock_items || jsonb_build_object(
            'itemId', v_menu_item.id,
            'quantity', v_stock_qty
        );
    end loop;

    if p_delivery_zone_id is not null then
        select data into v_zone_data from public.delivery_zones where id = p_delivery_zone_id;
        if v_zone_data is not null and (v_zone_data->>'isActive')::boolean then
            v_delivery_fee := coalesce((v_zone_data->>'deliveryFee')::numeric, 0);
        else
            v_delivery_fee := coalesce((v_settings->'deliverySettings'->>'baseFee')::numeric, 0);
        end if;
    else
        v_delivery_fee := coalesce((v_settings->'deliverySettings'->>'baseFee')::numeric, 0);
    end if;

    if (v_settings->'deliverySettings'->>'freeDeliveryThreshold') is not null and
       v_subtotal >= (v_settings->'deliverySettings'->>'freeDeliveryThreshold')::numeric then
        v_delivery_fee := 0;
    end if;

    if not v_has_promotions and p_coupon_code is not null and length(p_coupon_code) > 0 then
        select * into v_coupon_record from public.coupons where lower(code) = lower(p_coupon_code) and is_active = true;
        if found then
            if (v_coupon_record.data->>'expiresAt') is not null and (v_coupon_record.data->>'expiresAt')::timestamptz < now() then
                raise exception 'Coupon expired';
            end if;
            if (v_coupon_record.data->>'minOrderAmount') is not null and v_subtotal < (v_coupon_record.data->>'minOrderAmount')::numeric then
                raise exception 'Order amount too low for coupon';
            end if;
            if (v_coupon_record.data->>'usageLimit') is not null and
               coalesce((v_coupon_record.data->>'usageCount')::int, 0) >= (v_coupon_record.data->>'usageLimit')::int then
                raise exception 'Coupon usage limit reached';
            end if;
            
            if (v_coupon_record.data->>'type') = 'percentage' then
                v_discount_amount := v_subtotal * ((v_coupon_record.data->>'value')::numeric / 100);
                if (v_coupon_record.data->>'maxDiscount') is not null then
                    v_discount_amount := least(v_discount_amount, (v_coupon_record.data->>'maxDiscount')::numeric);
                end if;
            else
                v_discount_amount := (v_coupon_record.data->>'value')::numeric;
            end if;
            
            v_discount_amount := least(v_discount_amount, v_subtotal);
            
            update public.coupons
            set data = jsonb_set(data, '{usageCount}', (coalesce((data->>'usageCount')::int, 0) + 1)::text::jsonb)
            where id = v_coupon_record.id;
        else
            v_discount_amount := 0;
        end if;
    end if;

    if not v_has_promotions and p_points_redeemed_value > 0 then
        v_points_settings := v_settings->'loyaltySettings';
        if (v_points_settings->>'enabled')::boolean then
            v_currency_val_per_point := coalesce((v_points_settings->>'currencyValuePerPoint')::numeric, 0);
            if v_currency_val_per_point > 0 then
                declare
                    v_user_points int;
                    v_points_needed numeric;
                begin
                    -- If Walk-in (v_user_id is null), they cannot redeem points!
                    if v_user_id is null then
                        raise exception 'Cannot redeem points for walk-in customer';
                    end if;
                    select loyalty_points into v_user_points from public.customers where auth_user_id = v_user_id;
                    v_points_needed := p_points_redeemed_value / v_currency_val_per_point;
                    
                    if coalesce(v_user_points, 0) < v_points_needed then
                        raise exception 'Insufficient loyalty points';
                    end if;
                    
                    update public.customers
                    set loyalty_points = loyalty_points - v_points_needed::int
                    where auth_user_id = v_user_id;
                    
                    v_discount_amount := v_discount_amount + p_points_redeemed_value;
                end;
            end if;
        end if;
    end if;

    if (v_settings->'taxSettings'->>'enabled')::boolean then
        v_tax_rate := coalesce((v_settings->'taxSettings'->>'rate')::numeric, 0);
        v_tax_amount := greatest(0, v_subtotal - v_discount_amount) * (v_tax_rate / 100);
    end if;

    v_total := greatest(0, v_subtotal - v_discount_amount) + v_delivery_fee + v_tax_amount;

    v_points_settings := v_settings->'loyaltySettings';
    if (v_points_settings->>'enabled')::boolean then
        v_points_per_currency := coalesce((v_points_settings->>'pointsPerCurrencyUnit')::numeric, 0);
        v_points_earned := floor(v_subtotal * v_points_per_currency);
    end if;

    v_delivery_pin := floor(random() * 9000 + 1000)::text;

    v_stock_items := public._merge_stock_items(v_stock_items);

    insert into public.orders (
        customer_auth_user_id,
        status,
        invoice_number,
        data
    )
    values (
        v_user_id,
        case when p_is_scheduled then 'scheduled' else 'pending' end,
        null,
        jsonb_build_object(
            'id', gen_random_uuid(),
            'userId', v_user_id,
            'orderSource', p_order_source,
            'items', v_final_items,
            'promotionLines', case when v_has_promotions then v_promotion_lines else '[]'::jsonb end,
            'subtotal', public._money_round(v_subtotal),
            'deliveryFee', public._money_round(v_delivery_fee),
            'discountAmount', public._money_round(v_discount_amount),
            'total', public._money_round(v_total),
            'taxAmount', public._money_round(v_tax_amount),
            'taxRate', v_tax_rate,
            'pointsEarned', v_points_earned,
            'pointsRedeemedValue', p_points_redeemed_value,
            'deliveryZoneId', p_delivery_zone_id,
            'paymentMethod', p_payment_method,
            'notes', p_notes,
            'address', p_address,
            'location', p_location,
            'customerName', p_customer_name,
            'phoneNumber', p_phone_number,
            'isScheduled', p_is_scheduled,
            'scheduledAt', p_scheduled_at,
            'deliveryPin', v_delivery_pin,
            'appliedCouponCode', p_coupon_code,
            'warehouseId', v_warehouse_id
        )
    )
    returning id into v_order_id;

    update public.orders
    set data = jsonb_set(data, '{id}', to_jsonb(v_order_id::text))
    where id = v_order_id
    returning data into v_item_input;

    perform public.reserve_stock_for_order(v_stock_items, v_order_id, v_warehouse_id);

    if v_has_promotions then
      for v_promo_snapshot in select value from jsonb_array_elements(v_promotion_lines)
      loop
        insert into public.promotion_usage(
          promotion_id,
          promotion_line_id,
          order_id,
          bundle_qty,
          channel,
          warehouse_id,
          snapshot,
          created_by
        )
        values (
          (v_promo_snapshot->>'promotionId')::uuid,
          (v_promo_snapshot->>'promotionLineId')::uuid,
          v_order_id,
          coalesce(nullif((v_promo_snapshot->>'bundleQty')::numeric, null), 1),
          p_order_source,
          v_warehouse_id,
          v_promo_snapshot,
          auth.uid()
        );
      end loop;
    end if;

    insert into public.order_events (order_id, action, actor_type, actor_id, to_status, payload)
    values (
        v_order_id,
        'order.created',
        'customer',
        coalesce(v_user_id, auth.uid()), -- If walked in, actor is staff (auth.uid). If customer, actor is user.
        case when p_is_scheduled then 'scheduled' else 'pending' end,
        jsonb_build_object('total', public._money_round(v_total), 'method', p_payment_method)
    );

    return v_item_input;
end;
$$;


ALTER FUNCTION "public"."create_order_secure"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text", "p_points_redeemed_value" numeric, "p_explicit_customer_id" "uuid", "p_order_source" "text") OWNER TO "postgres";

--
-- Name: create_order_secure("jsonb", "uuid", "text", "text", "text", "jsonb", "text", "text", boolean, timestamp with time zone, "text", numeric, "uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_order_secure"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text" DEFAULT NULL::"text", "p_points_redeemed_value" numeric DEFAULT 0, "p_explicit_customer_id" "uuid" DEFAULT NULL::"uuid", "p_order_source" "text" DEFAULT 'online'::"text", "p_currency" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
    v_user_id uuid;
    v_order_id uuid;
    v_item_input jsonb;
    v_menu_item record;
    v_menu_item_data jsonb;
    v_cart_item jsonb;
    v_final_items jsonb := '[]'::jsonb;
    v_subtotal numeric := 0;
    v_total numeric := 0;
    v_delivery_fee numeric := 0;
    v_discount_amount numeric := 0;
    v_tax_amount numeric := 0;
    v_tax_rate numeric := 0;
    v_points_earned numeric := 0;
    v_settings jsonb;
    v_zone_data jsonb;
    v_line_total numeric;
    v_addons_price numeric;
    v_unit_price numeric;
    v_base_price numeric;
    v_addon_key text;
    v_addon_qty numeric;
    v_addon_def jsonb;
    v_grade_id text;
    v_grade_def jsonb;
    v_weight numeric;
    v_quantity numeric;
    v_unit_type text;
    v_delivery_pin text;
    v_available_addons jsonb;
    v_selected_addons_map jsonb;
    v_final_selected_addons jsonb;
    v_points_settings jsonb;
    v_currency_val_per_point numeric;
    v_points_per_currency numeric;
    v_coupon_record record;
    v_stock_items jsonb := '[]'::jsonb;
    v_item_name_ar text;
    v_item_name_en text;
    v_priced_unit numeric;
    v_pricing_qty numeric;
    v_warehouse_id uuid;
    v_stock_qty numeric;
    v_has_promotions boolean := false;
    v_promotion_id uuid;
    v_bundle_qty numeric;
    v_promo_snapshot jsonb;
    v_promotion_lines jsonb := '[]'::jsonb;
    v_promo_line_id uuid;
    v_promo_item jsonb;
    v_is_staff boolean := false;
    v_base_currency text;
    v_currency text;
    v_fx_rate numeric := 1;
    v_subtotal_tx numeric := 0;
    v_total_tx numeric := 0;
    v_delivery_fee_tx numeric := 0;
    v_discount_amount_tx numeric := 0;
    v_tax_amount_tx numeric := 0;
    v_points_redeemed_value_tx numeric := 0;
    v_addon_def_tx jsonb;
begin
    v_user_id := auth.uid();
    if v_user_id is null then
        raise exception 'User not authenticated';
    end if;

    if exists (
      select 1
      from public.admin_users au
      where au.auth_user_id = v_user_id
        and au.is_active = true
      limit 1
    ) then
      v_is_staff := true;
    end if;

    if v_is_staff then
       if p_order_source = 'online' and p_explicit_customer_id is null then
          raise exception 'لا يمكن لحسابات الموظفين إنشاء طلبات كعميل. استخدم شاشة الإدارة/نقطة البيع.';
       end if;

       if p_explicit_customer_id is not null then
          v_user_id := p_explicit_customer_id;
       elsif p_order_source = 'in_store' then
          v_user_id := null;
       end if;
    end if;

    v_warehouse_id := public._resolve_default_warehouse_id();

    select data into v_settings from public.app_settings where id = 'singleton';
    if v_settings is null then
        v_settings := '{}'::jsonb;
    end if;

    v_base_currency := public.get_base_currency();
    v_currency := upper(nullif(btrim(coalesce(p_currency, '')), ''));
    if v_currency is null then
      v_currency := v_base_currency;
    end if;
    if v_currency = v_base_currency then
      v_fx_rate := 1;
    else
      v_fx_rate := public.get_fx_rate(v_currency, current_date, 'operational');
      if v_fx_rate is null or not (v_fx_rate > 0) then
        raise exception 'لا يوجد سعر صرف تشغيلي صالح لهذه العملة. أضف السعر من شاشة أسعار الصرف.';
      end if;
    end if;

    if p_items is null or jsonb_typeof(p_items) <> 'array' then
      raise exception 'p_items must be a json array';
    end if;

    for v_item_input in select * from jsonb_array_elements(p_items)
    loop
        v_promotion_id := public._uuid_or_null(v_item_input->>'promotionId');
        if v_promotion_id is not null or coalesce(nullif(v_item_input->>'lineType',''), '') = 'promotion' then
          v_has_promotions := true;
          v_bundle_qty := coalesce(nullif((v_item_input->>'bundleQty')::numeric, null), nullif((v_item_input->>'quantity')::numeric, null), 1);
          if v_bundle_qty <= 0 then v_bundle_qty := 1; end if;

          if p_coupon_code is not null and length(p_coupon_code) > 0 then
            raise exception 'promotion_coupon_conflict';
          end if;
          if coalesce(p_points_redeemed_value, 0) > 0 then
            raise exception 'promotion_points_conflict';
          end if;

          v_promo_snapshot := public._compute_promotion_snapshot(v_promotion_id, v_user_id, v_warehouse_id, v_bundle_qty, null, true);
          v_promo_line_id := gen_random_uuid();

          v_cart_item := jsonb_build_object(
            'lineType', 'promotion',
            'promotionId', v_promotion_id::text,
            'promotionLineId', v_promo_line_id::text,
            'name', v_promo_snapshot->>'name',
            'bundleQty', coalesce(nullif((v_promo_snapshot->>'bundleQty')::numeric, null), v_bundle_qty),
            'originalTotal', public._money_round(coalesce(nullif((v_promo_snapshot->>'computedOriginalTotal')::numeric, null), 0) / v_fx_rate),
            'finalTotal', public._money_round(coalesce(nullif((v_promo_snapshot->>'finalTotal')::numeric, null), 0) / v_fx_rate),
            'promotionExpense', public._money_round(coalesce(nullif((v_promo_snapshot->>'promotionExpense')::numeric, null), 0) / v_fx_rate),
            'cartItemId', coalesce(nullif(v_item_input->>'cartItemId',''), gen_random_uuid()::text)
          );

          v_final_items := v_final_items || v_cart_item;
          v_subtotal := v_subtotal + coalesce(nullif((v_promo_snapshot->>'finalTotal')::numeric, null), 0);
          v_promotion_lines := v_promotion_lines || jsonb_build_object(
            'promotionId', v_promotion_id::text,
            'promotionLineId', v_promo_line_id::text,
            'bundleQty', v_bundle_qty,
            'snapshot', v_promo_snapshot
          );
          continue;
        end if;

        select * into v_menu_item from public.menu_items where id = (v_item_input->>'itemId');
        if not found then
            raise exception 'Item not found: %', v_item_input->>'itemId';
        end if;

        v_menu_item_data := v_menu_item.data;
        v_item_name_ar := v_menu_item_data->'name'->>'ar';
        v_item_name_en := v_menu_item_data->'name'->>'en';

        v_quantity := coalesce((v_item_input->>'quantity')::numeric, 0);
        v_weight := coalesce((v_item_input->>'weight')::numeric, 0);
        v_unit_type := coalesce(v_menu_item.unit_type, 'piece');

        if v_unit_type in ('kg', 'gram') then
            if v_quantity <= 0 then v_quantity := 1; end if;
            v_pricing_qty := case when v_weight > 0 then v_weight else v_quantity end;
            v_priced_unit := public.get_item_price_with_discount(v_menu_item.id::text, v_user_id, v_pricing_qty);
            v_base_price := v_priced_unit * v_weight;
            v_stock_qty := v_weight;
        else
            if v_quantity <= 0 then raise exception 'Quantity must be positive for item %', v_menu_item.id; end if;
            v_pricing_qty := v_quantity;
            v_priced_unit := public.get_item_price_with_discount(v_menu_item.id::text, v_user_id, v_pricing_qty);
            v_base_price := v_priced_unit;
            v_stock_qty := v_quantity;
        end if;

        v_grade_id := v_item_input->>'gradeId';
        v_grade_def := null;
        if v_grade_id is not null and (v_menu_item_data->'availableGrades') is not null then
            select value into v_grade_def
            from jsonb_array_elements(v_menu_item_data->'availableGrades')
            where value->>'id' = v_grade_id;

            if v_grade_def is not null then
                v_priced_unit := v_priced_unit * coalesce((v_grade_def->>'priceMultiplier')::numeric, 1.0);
                v_base_price := v_base_price * coalesce((v_grade_def->>'priceMultiplier')::numeric, 1.0);
            end if;
        end if;

        v_addons_price := 0;
        v_available_addons := coalesce(v_menu_item_data->'addons', '[]'::jsonb);
        v_selected_addons_map := coalesce(v_item_input->'selectedAddons', '{}'::jsonb);
        v_final_selected_addons := '{}'::jsonb;

        for v_addon_key in select jsonb_object_keys(v_selected_addons_map)
        loop
            v_addon_qty := (v_selected_addons_map->>v_addon_key)::numeric;
            if v_addon_qty > 0 then
                select value into v_addon_def
                from jsonb_array_elements(v_available_addons)
                where value->>'id' = v_addon_key;

                if v_addon_def is not null then
                    v_addons_price := v_addons_price + ((v_addon_def->>'price')::numeric * v_addon_qty);
                    v_addon_def_tx := jsonb_set(v_addon_def, '{price}', to_jsonb(public._money_round(((v_addon_def->>'price')::numeric) / v_fx_rate)), true);
                    v_final_selected_addons := jsonb_set(
                        v_final_selected_addons,
                        array[v_addon_key],
                        jsonb_build_object('addon', v_addon_def_tx, 'quantity', v_addon_qty)
                    );
                end if;
            end if;
        end loop;

        if v_unit_type in ('kg', 'gram') then
            v_unit_price := v_base_price + v_addons_price;
            v_line_total := (v_base_price + v_addons_price) * v_quantity;
        else
            v_unit_price := v_priced_unit + v_addons_price;
            v_line_total := (v_priced_unit + v_addons_price) * v_quantity;
        end if;

        v_subtotal := v_subtotal + v_line_total;

        v_cart_item := v_menu_item_data || jsonb_build_object(
            'quantity', v_quantity,
            'weight', v_weight,
            'selectedAddons', v_final_selected_addons,
            'selectedGrade', v_grade_def,
            'cartItemId', gen_random_uuid()::text,
            'price', public._money_round(v_priced_unit / v_fx_rate)
        );
        if v_unit_type = 'gram' then
          v_cart_item := v_cart_item || jsonb_build_object('pricePerUnit', public._money_round((v_priced_unit / v_fx_rate) * 1000));
        end if;

        v_final_items := v_final_items || v_cart_item;

        v_stock_items := v_stock_items || jsonb_build_object(
            'itemId', v_menu_item.id,
            'quantity', v_stock_qty
        );
    end loop;

    if p_delivery_zone_id is not null then
        select data into v_zone_data from public.delivery_zones where id = p_delivery_zone_id;
        if v_zone_data is not null and (v_zone_data->>'isActive')::boolean then
            v_delivery_fee := coalesce((v_zone_data->>'deliveryFee')::numeric, 0);
        else
            v_delivery_fee := coalesce((v_settings->'deliverySettings'->>'baseFee')::numeric, 0);
        end if;
    else
        v_delivery_fee := coalesce((v_settings->'deliverySettings'->>'baseFee')::numeric, 0);
    end if;

    if (v_settings->'deliverySettings'->>'freeDeliveryThreshold') is not null and
       v_subtotal >= (v_settings->'deliverySettings'->>'freeDeliveryThreshold')::numeric then
        v_delivery_fee := 0;
    end if;

    if not v_has_promotions and p_coupon_code is not null and length(p_coupon_code) > 0 then
        select * into v_coupon_record from public.coupons where lower(code) = lower(p_coupon_code) and is_active = true;
        if found then
            if (v_coupon_record.data->>'expiresAt') is not null and (v_coupon_record.data->>'expiresAt')::timestamptz < now() then
                raise exception 'Coupon expired';
            end if;
            if (v_coupon_record.data->>'minOrderAmount') is not null and v_subtotal < (v_coupon_record.data->>'minOrderAmount')::numeric then
                raise exception 'Order amount too low for coupon';
            end if;
            if (v_coupon_record.data->>'usageLimit') is not null and
               coalesce((v_coupon_record.data->>'usageCount')::int, 0) >= (v_coupon_record.data->>'usageLimit')::int then
                raise exception 'Coupon usage limit reached';
            end if;

            if (v_coupon_record.data->>'type') = 'percentage' then
                v_discount_amount := v_subtotal * ((v_coupon_record.data->>'value')::numeric / 100);
                if (v_coupon_record.data->>'maxDiscount') is not null then
                    v_discount_amount := least(v_discount_amount, (v_coupon_record.data->>'maxDiscount')::numeric);
                end if;
            else
                v_discount_amount := (v_coupon_record.data->>'value')::numeric;
            end if;

            v_discount_amount := least(v_discount_amount, v_subtotal);

            update public.coupons
            set data = jsonb_set(data, '{usageCount}', (coalesce((data->>'usageCount')::int, 0) + 1)::text::jsonb)
            where id = v_coupon_record.id;
        else
            v_discount_amount := 0;
        end if;
    end if;

    if not v_has_promotions and p_points_redeemed_value > 0 then
        v_points_settings := v_settings->'loyaltySettings';
        if (v_points_settings->>'enabled')::boolean then
            v_currency_val_per_point := coalesce((v_points_settings->>'currencyValuePerPoint')::numeric, 0);
            if v_currency_val_per_point > 0 then
                declare
                    v_user_points int;
                    v_points_needed numeric;
                begin
                    if v_user_id is null then
                        raise exception 'Cannot redeem points for walk-in customer';
                    end if;
                    select loyalty_points into v_user_points from public.customers where auth_user_id = v_user_id;
                    v_points_needed := p_points_redeemed_value / v_currency_val_per_point;

                    if coalesce(v_user_points, 0) < v_points_needed then
                        raise exception 'Insufficient loyalty points';
                    end if;

                    update public.customers
                    set loyalty_points = loyalty_points - v_points_needed::int
                    where auth_user_id = v_user_id;

                    v_discount_amount := v_discount_amount + p_points_redeemed_value;
                end;
            end if;
        end if;
    end if;

    if (v_settings->'taxSettings'->>'enabled')::boolean then
        v_tax_rate := coalesce((v_settings->'taxSettings'->>'rate')::numeric, 0);
        v_tax_amount := greatest(0, v_subtotal - v_discount_amount) * (v_tax_rate / 100);
    end if;

    v_total := greatest(0, v_subtotal - v_discount_amount) + v_delivery_fee + v_tax_amount;

    v_points_settings := v_settings->'loyaltySettings';
    if (v_points_settings->>'enabled')::boolean then
        v_points_per_currency := coalesce((v_points_settings->>'pointsPerCurrencyUnit')::numeric, 0);
        v_points_earned := floor(v_subtotal * v_points_per_currency);
    end if;

    v_delivery_pin := floor(random() * 9000 + 1000)::text;

    v_stock_items := public._merge_stock_items(v_stock_items);

    v_subtotal_tx := public._money_round(v_subtotal / v_fx_rate);
    v_delivery_fee_tx := public._money_round(v_delivery_fee / v_fx_rate);
    v_discount_amount_tx := public._money_round(v_discount_amount / v_fx_rate);
    v_tax_amount_tx := public._money_round(v_tax_amount / v_fx_rate);
    v_total_tx := public._money_round(v_total / v_fx_rate);
    v_points_redeemed_value_tx := public._money_round(coalesce(p_points_redeemed_value, 0) / v_fx_rate);

    insert into public.orders (
        customer_auth_user_id,
        status,
        invoice_number,
        data
    )
    values (
        v_user_id,
        case when p_is_scheduled then 'scheduled' else 'pending' end,
        null,
        jsonb_build_object(
            'id', gen_random_uuid(),
            'userId', v_user_id,
            'orderSource', p_order_source,
            'currency', v_currency,
            'fxRate', v_fx_rate,
            'baseCurrency', v_base_currency,
            'items', v_final_items,
            'promotionLines', case when v_has_promotions then v_promotion_lines else '[]'::jsonb end,
            'subtotal', v_subtotal_tx,
            'deliveryFee', v_delivery_fee_tx,
            'discountAmount', v_discount_amount_tx,
            'total', v_total_tx,
            'taxAmount', v_tax_amount_tx,
            'taxRate', v_tax_rate,
            'pointsEarned', v_points_earned,
            'pointsRedeemedValue', v_points_redeemed_value_tx,
            'deliveryZoneId', p_delivery_zone_id,
            'paymentMethod', p_payment_method,
            'notes', p_notes,
            'address', p_address,
            'location', p_location,
            'customerName', p_customer_name,
            'phoneNumber', p_phone_number,
            'isScheduled', p_is_scheduled,
            'scheduledAt', p_scheduled_at,
            'deliveryPin', v_delivery_pin,
            'appliedCouponCode', p_coupon_code,
            'warehouseId', v_warehouse_id
        )
    )
    returning id into v_order_id;

    update public.orders
    set data = jsonb_set(data, '{id}', to_jsonb(v_order_id::text))
    where id = v_order_id
    returning data into v_item_input;

    perform public.reserve_stock_for_order(v_stock_items, v_order_id, v_warehouse_id);

    if v_has_promotions then
      for v_promo_snapshot in select value from jsonb_array_elements(v_promotion_lines)
      loop
        insert into public.promotion_usage(
          promotion_id,
          promotion_line_id,
          order_id,
          bundle_qty,
          channel,
          warehouse_id,
          snapshot,
          created_by
        )
        values (
          (v_promo_snapshot->>'promotionId')::uuid,
          (v_promo_snapshot->>'promotionLineId')::uuid,
          v_order_id,
          coalesce(nullif((v_promo_snapshot->>'bundleQty')::numeric, null), 1),
          p_order_source,
          v_warehouse_id,
          v_promo_snapshot,
          auth.uid()
        );
      end loop;
    end if;

    insert into public.order_events (order_id, action, actor_type, actor_id, to_status, payload)
    values (
        v_order_id,
        'order.created',
        'customer',
        coalesce(v_user_id, auth.uid()),
        case when p_is_scheduled then 'scheduled' else 'pending' end,
        jsonb_build_object('total', v_total_tx, 'method', p_payment_method, 'currency', v_currency, 'fxRate', v_fx_rate)
    );

    return v_item_input;
end;
$$;


ALTER FUNCTION "public"."create_order_secure"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text", "p_points_redeemed_value" numeric, "p_explicit_customer_id" "uuid", "p_order_source" "text", "p_currency" "text") OWNER TO "postgres";

--
-- Name: create_order_secure_with_payment_proof("jsonb", "uuid", "text", "text", "text", "jsonb", "text", "text", boolean, timestamp with time zone, "text", numeric, "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_order_secure_with_payment_proof"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text" DEFAULT NULL::"text", "p_points_redeemed_value" numeric DEFAULT 0, "p_payment_proof_type" "text" DEFAULT NULL::"text", "p_payment_proof" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_payment_method text;
  v_proof_type text;
  v_proof text;
  v_order jsonb;
  v_order_id uuid;
  v_coupon_id uuid;
  v_customer_name text;
  v_phone text;
  v_address text;
begin
  v_payment_method := lower(btrim(coalesce(p_payment_method, '')));
  if v_payment_method not in ('cash', 'kuraimi', 'network') then
    raise exception 'طريقة الدفع غير صالحة';
  end if;

  v_customer_name := btrim(coalesce(p_customer_name, ''));
  if length(v_customer_name) < 3 or length(v_customer_name) > 50 or v_customer_name !~ '^[\u0600-\u06FFa-zA-Z\s]+$' then
    raise exception 'اسم العميل غير صحيح';
  end if;

  v_phone := btrim(coalesce(p_phone_number, ''));
  if v_phone !~ '^(77|73|71|70)[0-9]{7}$' then
    raise exception 'رقم الهاتف غير صحيح';
  end if;

  v_address := btrim(coalesce(p_address, ''));
  if length(v_address) < 10 or length(v_address) > 200 then
    raise exception 'العنوان غير صحيح';
  end if;

  v_proof_type := nullif(btrim(coalesce(p_payment_proof_type, '')), '');
  v_proof := nullif(btrim(coalesce(p_payment_proof, '')), '');

  if v_payment_method = 'cash' then
    if v_proof_type is not null or v_proof is not null then
      raise exception 'لا يسمح بإثبات دفع للدفع النقدي';
    end if;
  else
    if v_payment_method in ('kuraimi', 'network') then
      if v_proof_type is null or v_proof is null then
        raise exception 'إثبات الدفع مطلوب لطرق الدفع غير النقدية';
      end if;
      if v_proof_type not in ('image', 'ref_number') then
        raise exception 'نوع إثبات الدفع غير صالح';
      end if;
    end if;
  end if;

  if p_coupon_code is not null and length(btrim(p_coupon_code)) > 0 then
    select c.id
    into v_coupon_id
    from public.coupons c
    where lower(c.code) = lower(btrim(p_coupon_code))
      and c.is_active = true
    for update;
  end if;

  v_order := public.create_order_secure(
    p_items,
    p_delivery_zone_id,
    v_payment_method,
    p_notes,
    v_address,
    p_location,
    v_customer_name,
    v_phone,
    p_is_scheduled,
    p_scheduled_at,
    p_coupon_code,
    p_points_redeemed_value
  );

  v_order_id := (v_order->>'id')::uuid;

  if v_payment_method in ('kuraimi', 'network') then
    update public.orders
    set data = jsonb_set(
      jsonb_set(data, '{paymentProofType}', to_jsonb(v_proof_type), true),
      '{paymentProof}',
      to_jsonb(p_payment_proof),
      true
    )
    where id = v_order_id;

    v_order := jsonb_set(
      jsonb_set(v_order, '{paymentProofType}', to_jsonb(v_proof_type), true),
      '{paymentProof}',
      to_jsonb(p_payment_proof),
      true
    );
  end if;

  return v_order;
end;
$_$;


ALTER FUNCTION "public"."create_order_secure_with_payment_proof"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text", "p_points_redeemed_value" numeric, "p_payment_proof_type" "text", "p_payment_proof" "text") OWNER TO "postgres";

--
-- Name: create_order_secure_with_payment_proof("jsonb", "uuid", "text", "text", "text", "jsonb", "text", "text", boolean, timestamp with time zone, "text", numeric, "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_order_secure_with_payment_proof"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text" DEFAULT NULL::"text", "p_points_redeemed_value" numeric DEFAULT 0, "p_payment_proof_type" "text" DEFAULT NULL::"text", "p_payment_proof" "text" DEFAULT NULL::"text", "p_order_source" "text" DEFAULT 'online'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_payment_method text;
  v_proof_type text;
  v_proof text;
  v_order jsonb;
  v_order_id uuid;
  v_coupon_id uuid;
  v_customer_name text;
  v_phone text;
  v_address text;
begin
  v_payment_method := lower(btrim(coalesce(p_payment_method, '')));
  if v_payment_method not in ('cash', 'kuraimi', 'network', 'mixed', 'unknown') then
     -- 'mixed' and 'unknown' are allowed for in_store
     if p_order_source = 'online' then
        raise exception 'طريقة الدفع غير صالحة';
     end if;
  end if;

  v_customer_name := btrim(coalesce(p_customer_name, ''));
  if length(v_customer_name) < 2 then
    if p_order_source = 'in_store' then
       v_customer_name := 'زبون حضوري';
    else
       raise exception 'اسم العميل قصير جداً';
    end if;
  end if;

  v_phone := btrim(coalesce(p_phone_number, ''));
  
  -- Validation Logic for Phone
  if length(v_phone) > 0 then
      -- If provided, must look like a phone number (relaxed)
      -- Allow 7x or 05x or just digits 9+ length
      if v_phone !~ '^[0-9+]{9,15}$' and v_phone !~ '^(77|73|71|70)[0-9]{7}$' then
          -- Keep strict Yemen check if it looks short, otherwise allow international?
          -- For now, let's just enforce the previous strict check ONLY if it matches the length of local mobile
          -- Or just allow it if it's in_store?
          if p_order_source = 'online' and v_phone !~ '^(77|73|71|70)[0-9]{7}$' then
             raise exception 'رقم الهاتف غير صحيح';
          end if;
      end if;
  else
      -- Empty phone
      if p_order_source = 'online' then
         raise exception 'رقم الهاتف مطلوب للطلبات الإلكترونية';
      end if;
  end if;

  v_address := btrim(coalesce(p_address, ''));
  if length(v_address) < 2 then
     if p_order_source = 'in_store' then
        v_address := 'داخل المحل';
     else
        raise exception 'العنوان قصير جداً';
     end if;
  end if;

  v_proof_type := nullif(btrim(coalesce(p_payment_proof_type, '')), '');
  v_proof := nullif(btrim(coalesce(p_payment_proof, '')), '');

  if v_payment_method = 'cash' then
    if v_proof_type is not null or v_proof is not null then
      -- In store cash might have reference? No.
      null; 
    end if;
  else
    if v_payment_method in ('kuraimi', 'network') and p_order_source = 'online' then
      if v_proof_type is null or v_proof is null then
        raise exception 'إثبات الدفع مطلوب لطرق الدفع غير النقدية';
      end if;
    end if;
  end if;

  if p_coupon_code is not null and length(btrim(p_coupon_code)) > 0 then
    select c.id
    into v_coupon_id
    from public.coupons c
    where lower(c.code) = lower(btrim(p_coupon_code))
      and c.is_active = true
    for update;
  end if;

  -- Create the order using core function (defaults to online)
  v_order := public.create_order_secure(
    p_items,
    p_delivery_zone_id,
    v_payment_method,
    p_notes,
    v_address,
    p_location,
    v_customer_name,
    v_phone,
    p_is_scheduled,
    p_scheduled_at,
    p_coupon_code,
    p_points_redeemed_value
  );

  v_order_id := (v_order->>'id')::uuid;

  -- Post-Creation Updates
  
  -- 1. Update Order Source if not online
  if p_order_source <> 'online' then
      update public.orders
      set data = jsonb_set(data, '{orderSource}', to_jsonb(p_order_source), true),
          order_source = p_order_source -- if column exists, usually mapped from data
      where id = v_order_id;
      
      v_order := jsonb_set(v_order, '{orderSource}', to_jsonb(p_order_source), true);
  end if;

  -- 2. Update Payment Proof info if needed
  if v_proof_type is not null then
    update public.orders
    set data = jsonb_set(
      jsonb_set(data, '{paymentProofType}', to_jsonb(v_proof_type), true),
      '{paymentProof}',
      to_jsonb(v_proof),
      true
    )
    where id = v_order_id;

    v_order := jsonb_set(
      jsonb_set(v_order, '{paymentProofType}', to_jsonb(v_proof_type), true),
      '{paymentProof}',
      to_jsonb(v_proof),
      true
    );
  end if;

  return v_order;
end;
$_$;


