      end if;
  end if;

  v_address := btrim(coalesce(p_address, ''));
  if length(v_address) < 2 then
     if p_order_source = 'in_store' then
        v_address := 'داخل المحل';
     else
        raise exception 'العنوان قصير جداً';
     end if;
  end if;

  v_proof_type := nullif(btrim(coalesce(p_payment_proof_type, '')), '');
  v_proof := nullif(btrim(coalesce(p_payment_proof, '')), '');

  if v_payment_method = 'cash' then
    if v_proof_type is not null or v_proof is not null then
      null;
    end if;
  else
    if v_payment_method in ('kuraimi', 'network') and p_order_source = 'online' then
       if v_proof_type is null or v_proof is null then
         raise exception 'إثبات الدفع مطلوب لطرق الدفع غير النقدية';
       end if;
    end if;
  end if;

  if p_coupon_code is not null and length(btrim(p_coupon_code)) > 0 then
    select c.id
    into v_coupon_id
    from public.coupons c
    where lower(c.code) = lower(btrim(p_coupon_code))
      and c.is_active = true
    for update;
  end if;

  v_order := public.create_order_secure(
    p_items,
    p_delivery_zone_id,
    v_payment_method,
    p_notes,
    v_address,
    p_location,
    v_customer_name,
    v_phone,
    p_is_scheduled,
    p_scheduled_at,
    p_coupon_code,
    p_points_redeemed_value,
    p_explicit_customer_id,
    p_order_source,
    p_currency
  );

  v_order_id := (v_order->>'id')::uuid;

  if v_proof_type is not null then
    update public.orders
    set data = jsonb_set(
      jsonb_set(data, '{paymentProofType}', to_jsonb(v_proof_type), true),
      '{paymentProof}',
      to_jsonb(v_proof),
      true
    )
    where id = v_order_id;

    v_order := jsonb_set(
      jsonb_set(v_order, '{paymentProofType}', to_jsonb(v_proof_type), true),
      '{paymentProof}',
      to_jsonb(v_proof),
      true
    );
  end if;

  return v_order;
end;
$_$;


ALTER FUNCTION "public"."create_order_secure_with_payment_proof"("p_items" "jsonb", "p_delivery_zone_id" "uuid", "p_payment_method" "text", "p_notes" "text", "p_address" "text", "p_location" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_is_scheduled" boolean, "p_scheduled_at" timestamp with time zone, "p_coupon_code" "text", "p_points_redeemed_value" numeric, "p_payment_proof_type" "text", "p_payment_proof" "text", "p_order_source" "text", "p_explicit_customer_id" "uuid", "p_currency" "text") OWNER TO "postgres";

--
-- Name: create_party_document("text", timestamp with time zone, "uuid", "text", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_party_document"("p_doc_type" "text", "p_occurred_at" timestamp with time zone, "p_party_id" "uuid", "p_memo" "text", "p_lines" "jsonb", "p_journal_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc_id uuid;
  v_doc_number text;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  if p_party_id is null then
    raise exception 'party_id is required';
  end if;

  if p_doc_type is null or lower(trim(p_doc_type)) not in (
    'ar_invoice','ap_bill','ar_receipt','ap_payment','advance','custodian',
    'ar_credit_note','ap_credit_note','ar_debit_note','ap_debit_note'
  ) then
    raise exception 'invalid doc_type';
  end if;

  if p_lines is null or jsonb_typeof(p_lines) <> 'array' then
    raise exception 'p_lines must be a json array';
  end if;

  v_doc_number := public.generate_party_document_number(p_doc_type);

  insert into public.party_documents(doc_type, doc_number, occurred_at, memo, party_id, status, created_by, lines)
  values (
    lower(trim(p_doc_type)),
    v_doc_number,
    coalesce(p_occurred_at, now()),
    nullif(trim(coalesce(p_memo,'')),''),
    p_party_id,
    'draft',
    auth.uid(),
    p_lines
  )
  returning id into v_doc_id;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'party_documents.create',
    'documents',
    v_doc_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('documentId', v_doc_id::text, 'docNumber', v_doc_number, 'docType', lower(trim(p_doc_type))),
    'LOW',
    'DOCUMENT_CREATE'
  );

  return v_doc_id;
end;
$$;


ALTER FUNCTION "public"."create_party_document"("p_doc_type" "text", "p_occurred_at" timestamp with time zone, "p_party_id" "uuid", "p_memo" "text", "p_lines" "jsonb", "p_journal_id" "uuid") OWNER TO "postgres";

--
-- Name: create_party_open_items_snapshot("date", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_party_open_items_snapshot"("p_as_of" "date", "p_company_id" "uuid" DEFAULT NULL::"uuid", "p_branch_id" "uuid" DEFAULT NULL::"uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_as_of is null then
    raise exception 'as_of required';
  end if;

  insert into public.ledger_snapshot_headers(as_of, snapshot_type, company_id, branch_id, notes, created_by)
  values (p_as_of, 'open_items', p_company_id, p_branch_id, nullif(trim(coalesce(p_notes,'')),''), auth.uid())
  on conflict (as_of, snapshot_type, company_id, branch_id) do update
  set notes = excluded.notes
  returning id into v_id;

  delete from public.open_item_snapshots where snapshot_id = v_id;
  delete from public.party_balance_snapshots where snapshot_id = v_id;

  insert into public.open_item_snapshots(
    snapshot_id, open_item_id, party_id, currency_code, open_base_amount, open_foreign_amount, status,
    occurred_at, due_date, item_role, item_type
  )
  select
    v_id,
    poi.id,
    poi.party_id,
    poi.currency_code,
    poi.open_base_amount,
    poi.open_foreign_amount,
    poi.status,
    poi.occurred_at,
    poi.due_date,
    poi.item_role,
    poi.item_type
  from public.party_open_items poi
  join public.journal_entries je on je.id = poi.journal_entry_id
  where poi.occurred_at::date <= p_as_of
    and poi.status in ('open','partially_settled')
    and (p_company_id is null or je.company_id = p_company_id)
    and (p_branch_id is null or je.branch_id = p_branch_id);

  insert into public.party_balance_snapshots(snapshot_id, party_id, item_role, currency_code, open_base_amount, open_foreign_amount)
  select
    v_id,
    s.party_id,
    s.item_role,
    s.currency_code,
    sum(s.open_base_amount),
    sum(s.open_foreign_amount)
  from public.open_item_snapshots s
  where s.snapshot_id = v_id
  group by s.party_id, s.item_role, s.currency_code;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'open_items.snapshot',
    'accounting',
    v_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('snapshotId', v_id::text, 'asOf', p_as_of::text),
    'LOW',
    'OPEN_ITEMS_SNAPSHOT'
  );

  return v_id;
end;
$$;


ALTER FUNCTION "public"."create_party_open_items_snapshot"("p_as_of" "date", "p_company_id" "uuid", "p_branch_id" "uuid", "p_notes" "text") OWNER TO "postgres";

--
-- Name: create_payroll_run("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_payroll_run"("p_period_ym" "text", "p_memo" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_run_id uuid;
  v_expense_id uuid;
  v_date date;
  v_total numeric := 0;
  v_row record;
  v_base text;
  v_cur text;
  v_fx numeric;
  v_gross_foreign numeric;
  v_gross_base numeric;
begin
  if not (public.can_manage_expenses() or public.has_admin_permission('accounting.manage') or public.is_admin()) then
    raise exception 'not allowed';
  end if;

  v_date := public._payroll_last_day(p_period_ym);

  if exists (select 1 from public.payroll_runs pr where pr.period_ym = p_period_ym) then
    raise exception 'payroll run already exists';
  end if;

  v_base := public.get_base_currency();

  insert into public.payroll_runs(period_ym, status, memo, created_by)
  values (p_period_ym, 'draft', nullif(trim(coalesce(p_memo,'')), ''), auth.uid())
  returning id into v_run_id;

  for v_row in
    select id, full_name, monthly_salary, currency
    from public.payroll_employees
    where is_active = true
    order by full_name asc
  loop
    v_cur := upper(nullif(btrim(coalesce(v_row.currency, v_base)), ''));
    if v_cur is null then
      v_cur := v_base;
    end if;
    v_gross_foreign := coalesce(v_row.monthly_salary, 0);
    if v_gross_foreign < 0 then
      raise exception 'invalid salary';
    end if;

    if v_cur = v_base then
      v_fx := 1;
    else
      v_fx := public.get_fx_rate(v_cur, v_date, 'accounting');
      if v_fx is null then
        v_fx := public.get_fx_rate(v_cur, v_date, 'operational');
      end if;
      if v_fx is null or v_fx <= 0 then
        raise exception 'fx rate missing for currency % at %', v_cur, v_date;
      end if;
    end if;

    v_gross_base := round(v_gross_foreign * v_fx, 2);

    insert into public.payroll_run_lines(run_id, employee_id, gross, deductions, net, line_memo, foreign_amount, fx_rate, currency_code)
    values (v_run_id, v_row.id, v_gross_base, 0, v_gross_base, null, v_gross_foreign, v_fx, v_cur);

    v_total := v_total + v_gross_base;
  end loop;

  if v_total <= 0 then
    raise exception 'no active employees or total is zero';
  end if;

  insert into public.expenses(title, amount, category, date, notes, created_by)
  values (
    concat('رواتب ', p_period_ym),
    v_total,
    'salary',
    v_date,
    concat('Payroll run ', p_period_ym),
    auth.uid()
  )
  returning id into v_expense_id;

  update public.payroll_runs
  set expense_id = v_expense_id,
      total_gross = v_total,
      total_net = v_total,
      total_deductions = 0
  where id = v_run_id;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    'payroll_run_created',
    'payroll',
    concat('Payroll run created ', p_period_ym),
    auth.uid(),
    now(),
    jsonb_build_object('runId', v_run_id::text, 'period', p_period_ym, 'expenseId', v_expense_id::text, 'total_base', v_total, 'base_currency', v_base)
  );

  return v_run_id;
end;
$$;


ALTER FUNCTION "public"."create_payroll_run"("p_period_ym" "text", "p_memo" "text") OWNER TO "postgres";

--
-- Name: create_production_order("jsonb", "jsonb", "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_production_order"("p_inputs" "jsonb", "p_outputs" "jsonb", "p_notes" "text" DEFAULT NULL::"text", "p_occurred_at" timestamp with time zone DEFAULT "now"()) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order_id uuid;
  v_in jsonb;
  v_out jsonb;
  v_item_id text;
  v_qty numeric;
  v_old_qty numeric;
  v_old_avg numeric;
  v_unit_cost numeric;
  v_total_cost numeric;
  v_inputs_total_cost numeric := 0;
  v_outputs_total_qty numeric := 0;
  v_out_unit_cost numeric := 0;
  v_movement_id uuid;
begin
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;
  if p_inputs is null or jsonb_typeof(p_inputs) <> 'array' then
    raise exception 'p_inputs must be a json array';
  end if;
  if p_outputs is null or jsonb_typeof(p_outputs) <> 'array' then
    raise exception 'p_outputs must be a json array';
  end if;

  insert into public.production_orders(occurred_at, created_by, notes)
  values (coalesce(p_occurred_at, now()), auth.uid(), p_notes)
  returning id into v_order_id;

  for v_in in select value from jsonb_array_elements(p_inputs)
  loop
    v_item_id := v_in->>'itemId';
    v_qty := coalesce(nullif(v_in->>'quantity', '')::numeric, 0);
    if v_item_id is null or v_item_id = '' then
      raise exception 'Invalid input itemId';
    end if;
    if v_qty <= 0 then
      continue;
    end if;

    select coalesce(sm.available_quantity, 0), coalesce(sm.avg_cost, 0)
    into v_old_qty, v_old_avg
    from public.stock_management sm
    where sm.item_id = v_item_id
    for update;
    if not found then
      raise exception 'Stock record not found for input %', v_item_id;
    end if;
    if (v_old_qty + 1e-9) < v_qty then
      raise exception 'Insufficient stock for input % (available %, requested %)', v_item_id, v_old_qty, v_qty;
    end if;

    v_unit_cost := v_old_avg;
    v_total_cost := v_unit_cost * v_qty;
    v_inputs_total_cost := v_inputs_total_cost + v_total_cost;

    update public.stock_management
    set available_quantity = greatest(0, available_quantity - v_qty),
        last_updated = now(),
        updated_at = now()
    where item_id = v_item_id;

    insert into public.production_order_inputs(order_id, item_id, quantity, unit_cost, total_cost)
    values (v_order_id, v_item_id, v_qty, v_unit_cost, v_total_cost);

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data
    )
    values (
      v_item_id, 'adjust_out', v_qty, v_unit_cost, v_total_cost,
      'production_orders', v_order_id::text, coalesce(p_occurred_at, now()), auth.uid(),
      jsonb_build_object('reason', 'production_consume', 'productionOrderId', v_order_id)
    )
    returning id into v_movement_id;
  end loop;

  for v_out in select value from jsonb_array_elements(p_outputs)
  loop
    v_outputs_total_qty := v_outputs_total_qty + coalesce(nullif(v_out->>'quantity', '')::numeric, 0);
  end loop;
  if v_outputs_total_qty <= 0 then
    raise exception 'Total output quantity must be > 0';
  end if;
  v_out_unit_cost := v_inputs_total_cost / v_outputs_total_qty;

  for v_out in select value from jsonb_array_elements(p_outputs)
  loop
    v_item_id := v_out->>'itemId';
    v_qty := coalesce(nullif(v_out->>'quantity', '')::numeric, 0);
    if v_item_id is null or v_item_id = '' then
      raise exception 'Invalid output itemId';
    end if;
    if v_qty <= 0 then
      continue;
    end if;

    select coalesce(sm.available_quantity, 0), coalesce(sm.avg_cost, 0)
    into v_old_qty, v_old_avg
    from public.stock_management sm
    where sm.item_id = v_item_id
    for update;

    v_unit_cost := v_out_unit_cost;
    v_total_cost := v_unit_cost * v_qty;

    update public.stock_management
    set available_quantity = available_quantity + v_qty,
        avg_cost = case when (coalesce(v_old_qty, 0) + v_qty) <= 1e-9
                        then v_unit_cost
                        else ((coalesce(v_old_qty, 0) * coalesce(v_old_avg, 0)) + (v_qty * v_unit_cost)) / (coalesce(v_old_qty, 0) + v_qty)
                   end,
        last_updated = now(),
        updated_at = now()
    where item_id = v_item_id;

    insert into public.production_order_outputs(order_id, item_id, quantity, unit_cost, total_cost)
    values (v_order_id, v_item_id, v_qty, v_unit_cost, v_total_cost);

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data
    )
    values (
      v_item_id, 'adjust_in', v_qty, v_unit_cost, v_total_cost,
      'production_orders', v_order_id::text, coalesce(p_occurred_at, now()), auth.uid(),
      jsonb_build_object('reason', 'production_output', 'productionOrderId', v_order_id)
    )
    returning id into v_movement_id;
  end loop;

  perform public.post_production_order(v_order_id);
  return v_order_id;
end;
$$;


ALTER FUNCTION "public"."create_production_order"("p_inputs" "jsonb", "p_outputs" "jsonb", "p_notes" "text", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: create_purchase_return("uuid", "jsonb", "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_purchase_return"("p_order_id" "uuid", "p_items" "jsonb", "p_reason" "text" DEFAULT NULL::"text", "p_occurred_at" timestamp with time zone DEFAULT "now"()) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_po record;
  v_item jsonb;
  v_item_id_text text;
  v_item_id_uuid uuid;
  v_qty numeric;
  v_po_unit_cost numeric;
  v_stock_available numeric;
  v_stock_reserved numeric;
  v_stock_avg_cost numeric;
  v_return_item_total numeric;
  v_return_total numeric := 0;
  v_new_total numeric;
  v_return_id uuid;
  v_movement_id uuid;
  v_stock_item_id_is_uuid boolean;
  v_return_items_item_id_is_uuid boolean;
  v_inventory_movements_item_id_is_uuid boolean;
  v_inventory_movements_reference_id_is_uuid boolean;
  v_has_sm_warehouse boolean := false;
  v_has_im_batch boolean := false;
  v_has_im_warehouse boolean := false;
  v_has_bb boolean := false;
  v_has_bb_warehouse boolean := false;
  v_wh uuid;
  v_received_qty numeric;
  v_prev_returned numeric;
  v_needed numeric;
  v_take numeric;
  v_batch record;
begin
  if not public.can_manage_stock() then
    raise exception 'not allowed';
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;
  if not exists (
    select 1
    from jsonb_array_elements(p_items) e
    where coalesce(nullif(e.value->>'quantity', '')::numeric, 0) > 0
  ) then
    raise exception 'no return items';
  end if;
  v_has_sm_warehouse := exists (
    select 1
    from information_schema.columns
    where table_schema = 'public'
      and table_name = 'stock_management'
      and column_name = 'warehouse_id'
  );
  v_has_bb := to_regclass('public.batch_balances') is not null;
  if v_has_bb then
    v_has_bb_warehouse := exists (
      select 1
      from information_schema.columns
      where table_schema = 'public'
        and table_name = 'batch_balances'
        and column_name = 'warehouse_id'
    );
  end if;
  v_has_im_batch := exists (
    select 1
    from information_schema.columns
    where table_schema = 'public'
      and table_name = 'inventory_movements'
      and column_name = 'batch_id'
  );
  v_has_im_warehouse := exists (
    select 1
    from information_schema.columns
    where table_schema = 'public'
      and table_name = 'inventory_movements'
      and column_name = 'warehouse_id'
  );
  select (t.typname = 'uuid')
  into v_stock_item_id_is_uuid
  from pg_attribute a
  join pg_class c on a.attrelid = c.oid
  join pg_namespace n on c.relnamespace = n.oid
  join pg_type t on a.atttypid = t.oid
  where n.nspname = 'public'
    and c.relname = 'stock_management'
    and a.attname = 'item_id'
    and a.attnum > 0
    and not a.attisdropped;
  select (t.typname = 'uuid')
  into v_return_items_item_id_is_uuid
  from pg_attribute a
  join pg_class c on a.attrelid = c.oid
  join pg_namespace n on c.relnamespace = n.oid
  join pg_type t on a.atttypid = t.oid
  where n.nspname = 'public'
    and c.relname = 'purchase_return_items'
    and a.attname = 'item_id'
    and a.attnum > 0
    and not a.attisdropped;
  select (t.typname = 'uuid')
  into v_inventory_movements_item_id_is_uuid
  from pg_attribute a
  join pg_class c on a.attrelid = c.oid
  join pg_namespace n on c.relnamespace = n.oid
  join pg_type t on a.atttypid = t.oid
  where n.nspname = 'public'
    and c.relname = 'inventory_movements'
    and a.attname = 'item_id'
    and a.attnum > 0
    and not a.attisdropped;
  select (t.typname = 'uuid')
  into v_inventory_movements_reference_id_is_uuid
  from pg_attribute a
  join pg_class c on a.attrelid = c.oid
  join pg_namespace n on c.relnamespace = n.oid
  join pg_type t on a.atttypid = t.oid
  where n.nspname = 'public'
    and c.relname = 'inventory_movements'
    and a.attname = 'reference_id'
    and a.attnum > 0
    and not a.attisdropped;
  select *
  into v_po
  from public.purchase_orders
  where id = p_order_id
  for update;
  if not found then
    raise exception 'purchase order not found';
  end if;
  if v_po.status = 'cancelled' then
    raise exception 'cannot return for cancelled purchase order';
  end if;
  if v_has_sm_warehouse then
    v_wh := coalesce(v_po.warehouse_id, public._resolve_default_warehouse_id());
    if v_wh is null then
      raise exception 'warehouse_id is required';
    end if;
  else
    v_wh := null;
  end if;
  insert into public.purchase_returns(purchase_order_id, returned_at, created_by, reason)
  values (p_order_id, coalesce(p_occurred_at, now()), auth.uid(), nullif(trim(coalesce(p_reason, '')), ''))
  returning id into v_return_id;
  for v_item in select value from jsonb_array_elements(p_items)
  loop
    v_item_id_text := coalesce(v_item->>'itemId', v_item->>'id');
    v_qty := coalesce(nullif(v_item->>'quantity', '')::numeric, 0);
    if v_item_id_text is null or v_item_id_text = '' then
      raise exception 'Invalid itemId';
    end if;
    if v_qty <= 0 then
      continue;
    end if;
    if coalesce(v_stock_item_id_is_uuid, false)
      or coalesce(v_return_items_item_id_is_uuid, false)
      or coalesce(v_inventory_movements_item_id_is_uuid, false)
    then
      begin
        v_item_id_uuid := v_item_id_text::uuid;
      exception when others then
        raise exception 'Invalid itemId %', v_item_id_text;
      end;
    end if;
    select coalesce(pi.received_quantity, 0), coalesce(pi.unit_cost, 0)
    into v_received_qty, v_po_unit_cost
    from public.purchase_items pi
    where pi.purchase_order_id = p_order_id
      and pi.item_id::text = v_item_id_text
    for update;
    if not found then
      raise exception 'item % not found in purchase order', v_item_id_text;
    end if;
    select coalesce(sum(pri.quantity), 0)
    into v_prev_returned
    from public.purchase_returns pr
    join public.purchase_return_items pri on pri.return_id = pr.id
    where pr.purchase_order_id = p_order_id
      and pri.item_id::text = v_item_id_text;
    if (coalesce(v_prev_returned, 0) + v_qty) > (coalesce(v_received_qty, 0) + 1e-9) then
      raise exception 'return exceeds received for item %', v_item_id_text;
    end if;
    if v_has_sm_warehouse then
      if coalesce(v_stock_item_id_is_uuid, false) then
        execute $q$
          insert into public.stock_management(item_id, warehouse_id, available_quantity, reserved_quantity, unit, low_stock_threshold, last_updated, data)
          select $1, $2, 0, 0, coalesce(mi.unit_type, 'piece'), 5, now(), '{}'::jsonb
          from public.menu_items mi
          where mi.id::text = $3
          on conflict (item_id, warehouse_id) do nothing
        $q$
        using v_item_id_uuid, v_wh, v_item_id_text;
      else
        execute $q$
          insert into public.stock_management(item_id, warehouse_id, available_quantity, reserved_quantity, unit, low_stock_threshold, last_updated, data)
          select $1, $2, 0, 0, coalesce(mi.unit_type, 'piece'), 5, now(), '{}'::jsonb
          from public.menu_items mi
          where mi.id::text = $3
          on conflict (item_id, warehouse_id) do nothing
        $q$
        using v_item_id_text, v_wh, v_item_id_text;
      end if;
      select
        coalesce(sm.available_quantity, 0),
        coalesce(sm.reserved_quantity, 0),
        coalesce(sm.avg_cost, 0)
      into v_stock_available, v_stock_reserved, v_stock_avg_cost
      from public.stock_management sm
      where sm.item_id::text = v_item_id_text
        and sm.warehouse_id = v_wh
      for update;
    else
      if coalesce(v_stock_item_id_is_uuid, false) then
        execute $q$
          insert into public.stock_management(item_id, available_quantity, reserved_quantity, unit, low_stock_threshold, last_updated, data)
          select $1, 0, 0, coalesce(mi.unit_type, 'piece'), 5, now(), '{}'::jsonb
          from public.menu_items mi
          where mi.id::text = $2
          on conflict (item_id) do nothing
        $q$
        using v_item_id_uuid, v_item_id_text;
      else
        execute $q$
          insert into public.stock_management(item_id, available_quantity, reserved_quantity, unit, low_stock_threshold, last_updated, data)
          select $1, 0, 0, coalesce(mi.unit_type, 'piece'), 5, now(), '{}'::jsonb
          from public.menu_items mi
          where mi.id::text = $2
          on conflict (item_id) do nothing
        $q$
        using v_item_id_text, v_item_id_text;
      end if;
      select
        coalesce(sm.available_quantity, 0),
        coalesce(sm.reserved_quantity, 0),
        coalesce(sm.avg_cost, 0)
      into v_stock_available, v_stock_reserved, v_stock_avg_cost
      from public.stock_management sm
      where sm.item_id::text = v_item_id_text
      for update;
    end if;
    if not found then
      raise exception 'Stock record not found for item %', v_item_id_text;
    end if;
    if (coalesce(v_stock_available, 0) - coalesce(v_stock_reserved, 0) + 1e-9) < v_qty then
      raise exception 'insufficient stock for return for item %', v_item_id_text;
    end if;
    if v_has_sm_warehouse then
      update public.stock_management
      set available_quantity = available_quantity - v_qty,
          last_updated = now(),
          updated_at = now()
      where item_id::text = v_item_id_text
        and warehouse_id = v_wh;
    else
      update public.stock_management
      set available_quantity = available_quantity - v_qty,
          last_updated = now(),
          updated_at = now()
      where item_id::text = v_item_id_text;
    end if;
    v_return_item_total := v_qty * coalesce(v_po_unit_cost, 0);
    v_return_total := v_return_total + v_return_item_total;
    if coalesce(v_return_items_item_id_is_uuid, false) then
      execute $q$
        insert into public.purchase_return_items(return_id, item_id, quantity, unit_cost, total_cost)
        values ($1, $2, $3, $4, $5)
      $q$
      using v_return_id, v_item_id_uuid, v_qty, v_po_unit_cost, v_return_item_total;
    else
      execute $q$
        insert into public.purchase_return_items(return_id, item_id, quantity, unit_cost, total_cost)
        values ($1, $2, $3, $4, $5)
      $q$
      using v_return_id, v_item_id_text, v_qty, v_po_unit_cost, v_return_item_total;
    end if;
    if coalesce(v_stock_avg_cost, 0) <= 0 then
      v_stock_avg_cost := coalesce(v_po_unit_cost, 0);
    end if;
    v_needed := v_qty;
    if v_has_bb and v_has_bb_warehouse and v_has_im_batch and v_has_im_warehouse then
      for v_batch in
        select bb.batch_id, coalesce(bb.quantity, 0) as qty, bb.expiry_date
        from public.batch_balances bb
        where bb.item_id::text = v_item_id_text
          and bb.warehouse_id = v_wh
          and coalesce(bb.quantity, 0) > 0
        order by (bb.expiry_date is null) asc, bb.expiry_date asc, bb.batch_id asc
        for update
      loop
        exit when v_needed <= 0;
        v_take := least(v_needed, coalesce(v_batch.qty, 0));
        if v_take <= 0 then
          continue;
        end if;
        update public.batch_balances
        set quantity = quantity - v_take,
            updated_at = now()
        where item_id::text = v_item_id_text
          and batch_id = v_batch.batch_id
          and warehouse_id = v_wh;
        if coalesce(v_inventory_movements_item_id_is_uuid, false) then
          if coalesce(v_inventory_movements_reference_id_is_uuid, false) then
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text, 'batchId', $8::text),
                $8, $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_uuid, v_take, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh, v_batch.batch_id;
          else
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4::text, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text, 'batchId', $8::text),
                $8, $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_uuid, v_take, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh, v_batch.batch_id;
          end if;
        else
          if coalesce(v_inventory_movements_reference_id_is_uuid, false) then
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text, 'batchId', $8::text),
                $8, $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_text, v_take, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh, v_batch.batch_id;
          else
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4::text, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text, 'batchId', $8::text),
                $8, $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_text, v_take, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh, v_batch.batch_id;
          end if;
        end if;
        perform public.post_inventory_movement(v_movement_id);
        v_needed := v_needed - v_take;
      end loop;
      if v_needed > 0.000000001 then
        raise exception 'insufficient batch stock for return for item %', v_item_id_text;
      end if;
    else
      if v_has_im_warehouse then
        if coalesce(v_inventory_movements_item_id_is_uuid, false) then
          if coalesce(v_inventory_movements_reference_id_is_uuid, false) then
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text),
                $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_uuid, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh;
          else
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4::text, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text),
                $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_uuid, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh;
          end if;
        else
          if coalesce(v_inventory_movements_reference_id_is_uuid, false) then
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text),
                $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_text, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh;
          else
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data, warehouse_id
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4::text, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text, 'warehouseId', $7::text),
                $7
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_text, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id, v_wh;
          end if;
        end if;
      else
        if coalesce(v_inventory_movements_item_id_is_uuid, false) then
          if coalesce(v_inventory_movements_reference_id_is_uuid, false) then
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text)
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_uuid, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id;
          else
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4::text, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text)
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_uuid, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id;
          end if;
        else
          if coalesce(v_inventory_movements_reference_id_is_uuid, false) then
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text)
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_text, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id;
          else
            execute $q$
              insert into public.inventory_movements(
                item_id, movement_type, quantity, unit_cost, total_cost,
                reference_table, reference_id, occurred_at, created_by, data
              )
              values (
                $1, 'return_out', $2, $3, ($2 * $3),
                'purchase_returns', $4::text, coalesce($5, now()), auth.uid(),
                jsonb_build_object('purchaseOrderId', $6, 'purchaseReturnId', $4::text)
              )
              returning id
            $q$
            into v_movement_id
            using v_item_id_text, v_qty, v_stock_avg_cost, v_return_id, p_occurred_at, p_order_id;
          end if;
        end if;
      end if;
      perform public.post_inventory_movement(v_movement_id);
    end if;
  end loop;
  if coalesce(v_po.total_amount, 0) > 0 and v_return_total > 0 then
    v_new_total := greatest(0, coalesce(v_po.total_amount, 0) - v_return_total);
    update public.purchase_orders
    set total_amount = v_new_total,
        paid_amount = least(coalesce(purchase_orders.paid_amount, 0), v_new_total),
        updated_at = now()
    where id = p_order_id;
  end if;
  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    'return',
    'purchases',
    concat('Created purchase return ', v_return_id::text, ' for PO ', p_order_id::text),
    auth.uid(),
    coalesce(p_occurred_at, now()),
    jsonb_build_object('purchaseOrderId', p_order_id::text, 'purchaseReturnId', v_return_id::text, 'reason', nullif(trim(coalesce(p_reason, '')), ''))
  );
  return v_return_id;
end;
$_$;


ALTER FUNCTION "public"."create_purchase_return"("p_order_id" "uuid", "p_items" "jsonb", "p_reason" "text", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: create_reversal_entry("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_reversal_entry"("p_entry_id" "uuid", "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_entry record;
  v_new_id uuid;
begin
  select * into v_entry from public.journal_entries where id = p_entry_id;
  if not found then
    raise exception 'journal entry not found';
  end if;

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, document_id, branch_id, company_id)
  values (
    now(),
    concat('Reversal: ', coalesce(v_entry.memo, ''), ' ', coalesce(p_reason, '')),
    'journal_entries',
    v_entry.id::text,
    'reversal',
    auth.uid(),
    v_entry.document_id,
    v_entry.branch_id,
    v_entry.company_id
  )
  returning id into v_new_id;

  insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
  select v_new_id, jl.account_id, jl.credit, jl.debit, 'Reversal'
  from public.journal_lines jl
  where jl.journal_entry_id = p_entry_id;

  return v_new_id;
end;
$$;


ALTER FUNCTION "public"."create_reversal_entry"("p_entry_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: create_settlement("uuid", timestamp with time zone, "jsonb", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_settlement"("p_party_id" "uuid", "p_settlement_date" timestamp with time zone, "p_allocations" "jsonb", "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_settlement_id uuid;
  v_currency text;
  v_alloc jsonb;
  v_first jsonb;
  v_from public.party_open_items%rowtype;
  v_to public.party_open_items%rowtype;
  v_alloc_foreign numeric;
  v_base_from numeric;
  v_base_to numeric;
  v_rate_from numeric;
  v_rate_to numeric;
  v_realized_fx numeric;
  v_role text;
  v_fx_total numeric := 0;
  v_fx_account uuid := null;
  v_fx_entry uuid := null;
  v_notes text;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  if p_party_id is null then
    raise exception 'party_id required';
  end if;

  if p_allocations is null or jsonb_typeof(p_allocations) <> 'array' then
    raise exception 'allocations must be json array';
  end if;

  if jsonb_array_length(p_allocations) = 0 then
    raise exception 'allocations is empty';
  end if;

  if public.is_in_closed_period(coalesce(p_settlement_date, now())) then
    raise exception 'accounting period is closed';
  end if;

  v_notes := nullif(trim(coalesce(p_notes,'')), '');

  v_first := p_allocations->0;
  select * into v_from
  from public.party_open_items poi
  where poi.id = nullif(v_first->>'fromOpenItemId','')::uuid;
  if not found then
    raise exception 'from open item not found';
  end if;
  v_currency := upper(coalesce(v_from.currency_code, public.get_base_currency()));

  insert into public.settlement_headers(party_id, settlement_date, currency_code, created_by, notes)
  values (p_party_id, coalesce(p_settlement_date, now()), v_currency, auth.uid(), v_notes)
  returning id into v_settlement_id;

  for v_alloc in select value from jsonb_array_elements(p_allocations)
  loop
    select * into v_from
    from public.party_open_items poi
    where poi.id = nullif(v_alloc->>'fromOpenItemId','')::uuid
    for update;

    if not found then
      raise exception 'from open item not found';
    end if;

    select * into v_to
    from public.party_open_items poi
    where poi.id = nullif(v_alloc->>'toOpenItemId','')::uuid
    for update;

    if not found then
      raise exception 'to open item not found';
    end if;

    if v_from.party_id <> p_party_id or v_to.party_id <> p_party_id then
      raise exception 'party mismatch';
    end if;

    if v_from.status = 'settled' or v_to.status = 'settled' then
      raise exception 'open item already settled';
    end if;

    if v_from.direction <> 'debit' or v_to.direction <> 'credit' then
      raise exception 'allocations must be debit(from) to credit(to)';
    end if;

    if upper(coalesce(v_from.currency_code,'')) <> upper(coalesce(v_to.currency_code,'')) then
      raise exception 'currency mismatch';
    end if;

    v_currency := upper(coalesce(v_from.currency_code, public.get_base_currency()));
    if upper(coalesce(v_currency,'')) <> upper(coalesce((select currency_code from public.settlement_headers where id = v_settlement_id), v_currency)) then
      raise exception 'settlement currency mismatch';
    end if;

    if v_from.open_foreign_amount is not null or v_to.open_foreign_amount is not null then
      v_alloc_foreign := nullif(trim(coalesce(v_alloc->>'allocatedForeignAmount','')), '')::numeric;
      if v_alloc_foreign is null or v_alloc_foreign <= 0 then
        raise exception 'allocatedForeignAmount required for foreign settlement';
      end if;
      if v_from.open_foreign_amount is null or v_to.open_foreign_amount is null then
        raise exception 'both items must have foreign amount';
      end if;
      if v_alloc_foreign - least(coalesce(v_from.open_foreign_amount,0), coalesce(v_to.open_foreign_amount,0)) > 1e-6 then
        raise exception 'allocated foreign exceeds open';
      end if;

      v_rate_from := coalesce(public._open_item_effective_fx_rate(v_from.foreign_amount, v_from.base_amount), 1);
      v_rate_to := coalesce(public._open_item_effective_fx_rate(v_to.foreign_amount, v_to.base_amount), 1);

      v_base_from := v_alloc_foreign * v_rate_from;
      v_base_to := v_alloc_foreign * v_rate_to;
    else
      v_alloc_foreign := null;
      v_base_from := nullif(trim(coalesce(v_alloc->>'allocatedBaseAmount','')), '')::numeric;
      if v_base_from is null or v_base_from <= 0 then
        raise exception 'allocatedBaseAmount required';
      end if;
      if v_base_from - least(coalesce(v_from.open_base_amount,0), coalesce(v_to.open_base_amount,0)) > 1e-6 then
        raise exception 'allocated base exceeds open';
      end if;
      v_base_to := v_base_from;
      v_rate_from := null;
      v_rate_to := null;
    end if;

    v_realized_fx := coalesce(v_base_to,0) - coalesce(v_base_from,0);

    insert into public.settlement_lines(
      settlement_id,
      from_open_item_id,
      to_open_item_id,
      allocated_foreign_amount,
      allocated_base_amount,
      allocated_counter_base_amount,
      fx_rate,
      counter_fx_rate,
      realized_fx_amount
    )
    values (
      v_settlement_id,
      v_from.id,
      v_to.id,
      v_alloc_foreign,
      v_base_from,
      v_base_to,
      v_rate_from,
      v_rate_to,
      v_realized_fx
    );

    perform public._party_open_item_apply_delta(v_from.id, -v_base_from, case when v_alloc_foreign is null then null else -v_alloc_foreign end);
    perform public._party_open_item_apply_delta(v_to.id, -v_base_to, case when v_alloc_foreign is null then null else -v_alloc_foreign end);

    select coalesce(v_from.item_role, v_to.item_role) into v_role;

    if v_alloc_foreign is not null
      and v_from.account_id = v_to.account_id
      and v_role in ('ar','ap')
      and upper(v_currency) <> upper(public.get_base_currency())
      and abs(coalesce(v_realized_fx,0)) > 1e-6
    then
      v_fx_total := v_fx_total + v_realized_fx;
      v_fx_account := v_from.account_id;
    end if;
  end loop;

  if abs(coalesce(v_fx_total,0)) > 1e-6 and v_fx_account is not null then
    v_fx_entry := public._create_settlement_fx_journal_entry(p_party_id, v_settlement_id, coalesce(p_settlement_date, now()), v_fx_account, v_fx_total);
  end if;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'settlements.create',
    'accounting',
    v_settlement_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('settlementId', v_settlement_id::text, 'partyId', p_party_id::text, 'fxEntryId', coalesce(v_fx_entry, '00000000-0000-0000-0000-000000000000'::uuid)::text),
    'MEDIUM',
    'SETTLEMENT_CREATE'
  );

  return v_settlement_id;
end;
$$;


ALTER FUNCTION "public"."create_settlement"("p_party_id" "uuid", "p_settlement_date" timestamp with time zone, "p_allocations" "jsonb", "p_notes" "text") OWNER TO "postgres";

