--
-- Name: debug_shipment_landed_cost("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."debug_shipment_landed_cost"("p_shipment_id" "uuid") RETURNS TABLE("item_id" "text", "currency" "text", "quantity" numeric, "unit_price_fob" numeric, "fx_accounting" numeric, "fx_operational" numeric, "fx_used" numeric, "unit_fob_base" numeric, "fob_base_total" numeric, "expenses_base_total" numeric, "alloc_item_base" numeric, "per_unit_alloc" numeric, "landed_cost_per_unit" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
  v_ship record;
  v_date date;
  v_total_fob_base numeric := 0;
  v_total_expenses_base numeric := 0;
  v_item record;
  v_fx_acc numeric;
  v_fx_op numeric;
  v_fx numeric;
  v_item_fob_base_total numeric;
  v_alloc_item_base numeric;
  v_unit_fob_base numeric;
  v_per_unit_alloc numeric;
begin
  v_base := public.get_base_currency();
  select s.* into v_ship from public.import_shipments s where s.id = p_shipment_id;
  if not found then
    return;
  end if;
  v_date := coalesce(v_ship.actual_arrival_date, v_ship.expected_arrival_date, v_ship.departure_date, current_date);

  select coalesce(sum(coalesce(ie.amount,0) * coalesce(ie.exchange_rate,1)), 0)
  into v_total_expenses_base
  from public.import_expenses ie
  where ie.shipment_id = p_shipment_id;

  v_total_fob_base := 0;
  for v_item in
    select isi.item_id, isi.quantity, isi.unit_price_fob, upper(coalesce(nullif(btrim(isi.currency),''), v_base)) as currency
    from public.import_shipments_items isi
    where isi.shipment_id = p_shipment_id
  loop
    v_fx := public._pick_fx_for_landed_cost(v_item.currency, v_date);
    if v_fx is not null and v_fx > 0 then
      v_total_fob_base := v_total_fob_base + (coalesce(v_item.quantity,0) * coalesce(v_item.unit_price_fob,0) * v_fx);
    end if;
  end loop;

  for v_item in
    select isi.item_id, isi.quantity, isi.unit_price_fob, upper(coalesce(nullif(btrim(isi.currency),''), v_base)) as currency, isi.landing_cost_per_unit
    from public.import_shipments_items isi
    where isi.shipment_id = p_shipment_id
  loop
    v_fx_acc := public.get_fx_rate(v_item.currency, v_date, 'accounting');
    v_fx_op := public.get_fx_rate(v_item.currency, v_date, 'operational');
    v_fx := public._pick_fx_for_landed_cost(v_item.currency, v_date);
    v_unit_fob_base := case when v_fx is not null and v_fx > 0 then coalesce(v_item.unit_price_fob,0) * v_fx else null end;
    v_item_fob_base_total := case when v_fx is not null and v_fx > 0 then coalesce(v_item.quantity,0) * coalesce(v_item.unit_price_fob,0) * v_fx else null end;
    if v_total_fob_base > 0 and v_item_fob_base_total is not null then
      v_alloc_item_base := (v_item_fob_base_total / v_total_fob_base) * coalesce(v_total_expenses_base,0);
      v_per_unit_alloc := case when coalesce(v_item.quantity,0) > 0 then v_alloc_item_base / v_item.quantity else null end;
    else
      v_alloc_item_base := null;
      v_per_unit_alloc := null;
    end if;

    item_id := v_item.item_id::text;
    currency := v_item.currency;
    quantity := v_item.quantity;
    unit_price_fob := v_item.unit_price_fob;
    fx_accounting := v_fx_acc;
    fx_operational := v_fx_op;
    fx_used := v_fx;
    unit_fob_base := v_unit_fob_base;
    fob_base_total := v_item_fob_base_total;
    expenses_base_total := v_total_expenses_base;
    alloc_item_base := v_alloc_item_base;
    per_unit_alloc := v_per_unit_alloc;
    landed_cost_per_unit := v_item.landing_cost_per_unit;
    return next;
  end loop;
end;
$$;


ALTER FUNCTION "public"."debug_shipment_landed_cost"("p_shipment_id" "uuid") OWNER TO "postgres";

--
-- Name: decide_workflow("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."decide_workflow"("p_instance_id" "uuid", "p_decision" "text", "p_note" "text" DEFAULT NULL::"text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_inst public.workflow_instances%rowtype;
  v_rule public.workflow_rules%rowtype;
  v_steps jsonb;
  v_step jsonb;
  v_permission text;
  v_min int;
  v_mode text;
  v_approved_count int;
  v_assign public.workflow_current_assignments%rowtype;
  v_next_step jsonb;
begin
  if not (public.has_admin_permission('accounting.manage') or public.has_admin_permission('accounting.approve')) then
    raise exception 'not allowed';
  end if;

  if p_instance_id is null then
    raise exception 'instance_id required';
  end if;

  select * into v_inst
  from public.workflow_instances wi
  where wi.id = p_instance_id
  for update;

  if not found then
    raise exception 'workflow instance not found';
  end if;

  if v_inst.status <> 'pending' then
    return v_inst.status;
  end if;

  select * into v_rule
  from public.workflow_rules wr
  where wr.id = v_inst.rule_id;

  v_steps := coalesce(v_rule.steps, '[]'::jsonb);
  v_step := null;
  select value into v_step
  from jsonb_array_elements(v_steps)
  where (value->>'stepNo')::int = v_inst.current_step
  limit 1;

  if v_step is null then
    update public.workflow_instances
    set status = 'approved',
        decided_at = now(),
        decided_by = auth.uid()
    where id = v_inst.id;
    perform public._workflow_log_event(v_inst.id, 'workflow.auto_approved', jsonb_build_object('reason','no_step'));
    return 'approved';
  end if;

  select * into v_assign
  from public.workflow_current_assignments a
  where a.instance_id = v_inst.id
    and a.step_no = v_inst.current_step
  order by a.created_at desc, a.id desc
  limit 1;

  v_permission := nullif(coalesce(v_assign.assigned_permission, v_step->>'approverPermission',''), '');
  if v_permission is not null then
    if v_assign.assigned_to is not null and v_assign.assigned_to <> auth.uid() then
      if public._workflow_is_delegated(v_assign.assigned_to, auth.uid(), now()) is not true then
        raise exception 'not allowed';
      end if;
    else
      if not public.has_admin_permission(v_permission) then
        raise exception 'missing permission %', v_permission;
      end if;
    end if;
  end if;

  if lower(coalesce(p_decision,'')) not in ('approved','rejected') then
    raise exception 'invalid decision';
  end if;

  insert into public.workflow_approvals(instance_id, step_no, decision, decided_by, note)
  values (v_inst.id, v_inst.current_step, lower(p_decision), auth.uid(), nullif(trim(coalesce(p_note,'')), ''))
  on conflict (instance_id, step_no, decided_by) do nothing;

  perform public._workflow_log_event(v_inst.id, concat('workflow.decision.', lower(p_decision)), jsonb_build_object('stepNo', v_inst.current_step, 'note', nullif(trim(coalesce(p_note,'')),'') ));

  if lower(p_decision) = 'rejected' then
    update public.workflow_instances
    set status = 'rejected',
        decided_at = now(),
        decided_by = auth.uid()
    where id = v_inst.id;
    insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
    values ('workflow.reject','workflow',v_inst.id::text,auth.uid(),now(),jsonb_build_object('instanceId',v_inst.id::text),'MEDIUM','WORKFLOW_REJECT');
    return 'rejected';
  end if;

  v_mode := lower(coalesce(v_step->>'mode','serial'));
  v_min := coalesce(nullif(v_step->>'minApprovals','')::int, 1);

  select count(*) into v_approved_count
  from public.workflow_approvals wa
  where wa.instance_id = v_inst.id
    and wa.step_no = v_inst.current_step
    and wa.decision = 'approved';

  if v_mode = 'parallel' then
    if v_approved_count < greatest(v_min, 1) then
      insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
      values ('workflow.approve_step_partial','workflow',v_inst.id::text,auth.uid(),now(),jsonb_build_object('instanceId',v_inst.id::text,'step',v_inst.current_step,'approvedCount',v_approved_count),'LOW','WORKFLOW_STEP_PARTIAL');
      return 'pending';
    end if;
  end if;

  update public.workflow_instances
  set current_step = current_step + 1
  where id = v_inst.id;

  select * into v_inst from public.workflow_instances where id = p_instance_id;

  select value into v_next_step
  from jsonb_array_elements(v_steps)
  where (value->>'stepNo')::int = v_inst.current_step
  limit 1;

  if v_next_step is null then
    update public.workflow_instances
    set status = 'approved',
        decided_at = now(),
        decided_by = auth.uid()
    where id = v_inst.id;
    insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
    values ('workflow.approve','workflow',v_inst.id::text,auth.uid(),now(),jsonb_build_object('instanceId',v_inst.id::text),'LOW','WORKFLOW_APPROVE');
    perform public._workflow_log_event(v_inst.id, 'workflow.approved', jsonb_build_object());
    return 'approved';
  end if;

  perform public._workflow_insert_assignment(v_inst.id, v_inst.definition_id, v_inst.current_step, v_next_step, 0, 'advance', null, null);
  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values ('workflow.advance','workflow',v_inst.id::text,auth.uid(),now(),jsonb_build_object('instanceId',v_inst.id::text,'step',v_inst.current_step),'LOW','WORKFLOW_ADVANCE');

  return 'pending';
end;
$$;


ALTER FUNCTION "public"."decide_workflow"("p_instance_id" "uuid", "p_decision" "text", "p_note" "text") OWNER TO "postgres";

--
-- Name: decrypt_text("bytea"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."decrypt_text"("p_encrypted" "bytea") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'extensions', 'public'
    AS $$
DECLARE
  v_key text;
BEGIN
  SELECT key_value INTO v_key FROM private.keys WHERE key_name = 'app.encryption_key';
  IF v_key IS NULL OR v_key = '' THEN
    RAISE EXCEPTION 'Encryption key not configured';
  END IF;

  IF p_encrypted IS NULL THEN 
    RETURN NULL;
  END IF;

  -- Try decrypting
  BEGIN
    RETURN extensions.pgp_sym_decrypt(p_encrypted, v_key);
  EXCEPTION WHEN OTHERS THEN
    RETURN NULL; -- Return null if decryption fails (wrong key)
  END;
END;
$$;


ALTER FUNCTION "public"."decrypt_text"("p_encrypted" "bytea") OWNER TO "postgres";

