    $$;


ALTER FUNCTION "public"."deduct_stock_on_delivery_v2"("p_items" "jsonb", "p_order_id" "uuid", "p_warehouse_id" "uuid") OWNER TO "postgres";

--
-- Name: deduct_stock_on_delivery_v2("uuid", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."deduct_stock_on_delivery_v2"("p_order_id" "uuid", "p_items" "jsonb", "p_warehouse_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_is_in_store boolean := false;
  v_item jsonb;
  v_item_id text;
  v_requested numeric;
  v_needed numeric;
  v_item_batch_text text;
  v_is_food boolean;
  v_avg_cost numeric;
  v_batch record;
  v_alloc numeric;
  v_unit_cost numeric;
  v_total_cost numeric;
  v_movement_id uuid;
  v_qr numeric;
  v_qc numeric;
begin
  perform public._require_staff('deduct_stock_on_delivery_v2');
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if p_warehouse_id is null then
    raise exception 'warehouse_id is required';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;

  if exists (
    select 1
    from public.inventory_movements im
    where im.reference_table = 'orders'
      and im.reference_id = p_order_id::text
      and im.warehouse_id = p_warehouse_id
      and im.movement_type = 'sale_out'
  ) then
    return;
  end if;

  select (coalesce(nullif(o.data->>'orderSource',''), '') = 'in_store')
  into v_is_in_store
  from public.orders o
  where o.id = p_order_id
  for update;
  if not found then
    raise exception 'order not found';
  end if;

  delete from public.order_item_cogs where order_id = p_order_id;

  for v_item in select value from jsonb_array_elements(coalesce(p_items, '[]'::jsonb))
  loop
    v_item_id := coalesce(nullif(v_item->>'itemId',''), nullif(v_item->>'id',''));
    v_requested := coalesce(nullif(v_item->>'quantity','')::numeric, nullif(v_item->>'qty','')::numeric, 0);
    v_item_batch_text := nullif(v_item->>'batchId', '');
    if v_item_id is null or v_item_id = '' or v_requested <= 0 then
      continue;
    end if;

    select (coalesce(mi.category,'') = 'food')
    into v_is_food
    from public.menu_items mi
    where mi.id::text = v_item_id::text;

    select coalesce(sm.avg_cost, 0)
    into v_avg_cost
    from public.stock_management sm
    where sm.item_id::text = v_item_id::text
      and sm.warehouse_id = p_warehouse_id;

    v_needed := v_requested;

    if not coalesce(v_is_in_store, false) then
      for v_batch in
        select
          r.id as reservation_id,
          r.quantity as reserved_qty,
          b.id as batch_id,
          b.expiry_date,
          b.unit_cost,
          greatest(
            coalesce(b.quantity_received,0)
            - coalesce(b.quantity_consumed,0)
            - coalesce(b.quantity_transferred,0),
            0
          ) as remaining_qty
        from public.order_item_reservations r
        join public.batches b on b.id = r.batch_id
        where r.order_id = p_order_id
          and r.item_id::text = v_item_id::text
          and r.warehouse_id = p_warehouse_id
          and (v_item_batch_text is null or r.batch_id <> v_item_batch_text::uuid)
          and coalesce(b.status,'active') = 'active'
          and coalesce(b.qc_status,'') = 'released'
          and not exists (
            select 1 from public.batch_recalls br
            where br.batch_id = b.id and br.status = 'active'
          )
          and (
            not coalesce(v_is_food, false)
            or (b.expiry_date is not null and b.expiry_date >= current_date)
          )
        order by b.expiry_date asc nulls last, r.created_at asc, r.batch_id asc
        for update
      loop
        exit when v_needed <= 0;
        v_alloc := least(v_needed, coalesce(v_batch.reserved_qty, 0));
        if v_alloc <= 0 then
          continue;
        end if;

        update public.batches
        set quantity_consumed = quantity_consumed + v_alloc
        where id = v_batch.batch_id
        returning quantity_received, quantity_consumed into v_qr, v_qc;
        if coalesce(v_qc,0) > coalesce(v_qr,0) then
          raise exception 'Over-consumption detected for batch %', v_batch.batch_id;
        end if;

        v_unit_cost := coalesce(v_batch.unit_cost, v_avg_cost, 0);
        v_total_cost := v_alloc * v_unit_cost;
        insert into public.order_item_cogs(order_id, item_id, quantity, unit_cost, total_cost, created_at)
        values (p_order_id, v_item_id::text, v_alloc, v_unit_cost, v_total_cost, now());

        insert into public.inventory_movements(
          item_id, movement_type, quantity, unit_cost, total_cost,
          reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
        )
        values (
          v_item_id::text, 'sale_out', v_alloc, v_unit_cost, v_total_cost,
          'orders', p_order_id::text, now(), auth.uid(),
          jsonb_build_object('orderId', p_order_id, 'warehouseId', p_warehouse_id, 'batchId', v_batch.batch_id),
          v_batch.batch_id,
          p_warehouse_id
        )
        returning id into v_movement_id;

        perform public.post_inventory_movement(v_movement_id);

        update public.order_item_reservations
        set quantity = quantity - v_alloc,
            updated_at = now()
        where id = v_batch.reservation_id;

        delete from public.order_item_reservations
        where id = v_batch.reservation_id
          and quantity <= 0;

        v_needed := v_needed - v_alloc;
      end loop;

      if v_needed > 0 then
        raise exception 'INSUFFICIENT_RESERVED_BATCH_STOCK_FOR_ITEM_%', v_item_id;
      end if;
    else
      if v_item_batch_text is not null then
        select
          b.id as batch_id,
          b.expiry_date,
          b.unit_cost,
          greatest(
            coalesce(b.quantity_received,0)
            - coalesce(b.quantity_consumed,0)
            - coalesce(b.quantity_transferred,0),
            0
          ) as remaining_qty
        into v_batch
        from public.batches b
        where b.id = v_item_batch_text::uuid
          and b.item_id::text = v_item_id::text
          and b.warehouse_id = p_warehouse_id
          and coalesce(b.status,'active') = 'active'
          and coalesce(b.qc_status,'') = 'released'
          and not exists (
            select 1 from public.batch_recalls br
            where br.batch_id = b.id and br.status = 'active'
          )
        for update;
        if not found then
          raise exception 'Batch % not found for item % in warehouse %', v_item_batch_text, v_item_id, p_warehouse_id;
        end if;
        if coalesce(v_is_food, false) and (v_batch.expiry_date is null or v_batch.expiry_date < current_date) then
          raise exception 'NO_VALID_BATCH_AVAILABLE';
        end if;
        v_alloc := least(v_needed, coalesce(v_batch.remaining_qty, 0));
        if v_alloc > 0 then
          update public.batches
          set quantity_consumed = quantity_consumed + v_alloc
          where id = v_batch.batch_id
          returning quantity_received, quantity_consumed into v_qr, v_qc;
          if coalesce(v_qc,0) > coalesce(v_qr,0) then
            raise exception 'Over-consumption detected for batch %', v_batch.batch_id;
          end if;

          v_unit_cost := coalesce(v_batch.unit_cost, v_avg_cost, 0);
          v_total_cost := v_alloc * v_unit_cost;
          insert into public.order_item_cogs(order_id, item_id, quantity, unit_cost, total_cost, created_at)
          values (p_order_id, v_item_id::text, v_alloc, v_unit_cost, v_total_cost, now());

          insert into public.inventory_movements(
            item_id, movement_type, quantity, unit_cost, total_cost,
            reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
          )
          values (
            v_item_id::text, 'sale_out', v_alloc, v_unit_cost, v_total_cost,
            'orders', p_order_id::text, now(), auth.uid(),
            jsonb_build_object('orderId', p_order_id, 'warehouseId', p_warehouse_id, 'batchId', v_batch.batch_id),
            v_batch.batch_id,
            p_warehouse_id
          )
          returning id into v_movement_id;

          perform public.post_inventory_movement(v_movement_id);

          v_needed := v_needed - v_alloc;
        end if;
      end if;

      for v_batch in
        select
          b.id as batch_id,
          b.expiry_date,
          b.unit_cost,
          greatest(
            coalesce(b.quantity_received,0)
            - coalesce(b.quantity_consumed,0)
            - coalesce(b.quantity_transferred,0),
            0
          ) as remaining_qty
        from public.batches b
        where b.item_id::text = v_item_id::text
          and b.warehouse_id = p_warehouse_id
          and coalesce(b.status,'active') = 'active'
          and coalesce(b.qc_status,'') = 'released'
          and not exists (
            select 1 from public.batch_recalls br
            where br.batch_id = b.id and br.status = 'active'
          )
          and greatest(
            coalesce(b.quantity_received,0)
            - coalesce(b.quantity_consumed,0)
            - coalesce(b.quantity_transferred,0),
            0
          ) > 0
          and (v_item_batch_text is null or b.id <> v_item_batch_text::uuid)
          and (
            not coalesce(v_is_food, false)
            or (b.expiry_date is not null and b.expiry_date >= current_date)
          )
        order by b.expiry_date asc nulls last, b.created_at asc, b.id asc
        for update
      loop
        exit when v_needed <= 0;
        v_alloc := least(v_needed, coalesce(v_batch.remaining_qty, 0));
        if v_alloc <= 0 then
          continue;
        end if;

        update public.batches
        set quantity_consumed = quantity_consumed + v_alloc
        where id = v_batch.batch_id
        returning quantity_received, quantity_consumed into v_qr, v_qc;
        if coalesce(v_qc,0) > coalesce(v_qr,0) then
          raise exception 'Over-consumption detected for batch %', v_batch.batch_id;
        end if;

        v_unit_cost := coalesce(v_batch.unit_cost, v_avg_cost, 0);
        v_total_cost := v_alloc * v_unit_cost;
        insert into public.order_item_cogs(order_id, item_id, quantity, unit_cost, total_cost, created_at)
        values (p_order_id, v_item_id::text, v_alloc, v_unit_cost, v_total_cost, now());

        insert into public.inventory_movements(
          item_id, movement_type, quantity, unit_cost, total_cost,
          reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
        )
        values (
          v_item_id::text, 'sale_out', v_alloc, v_unit_cost, v_total_cost,
          'orders', p_order_id::text, now(), auth.uid(),
          jsonb_build_object('orderId', p_order_id, 'warehouseId', p_warehouse_id, 'batchId', v_batch.batch_id),
          v_batch.batch_id,
          p_warehouse_id
        )
        returning id into v_movement_id;

        perform public.post_inventory_movement(v_movement_id);

        v_needed := v_needed - v_alloc;
      end loop;

      if v_needed > 0 then
        raise exception 'INSUFFICIENT_BATCH_STOCK_FOR_ITEM_%', v_item_id;
      end if;
    end if;

    update public.stock_management sm
    set reserved_quantity = coalesce((
          select sum(r.quantity)
          from public.order_item_reservations r
          where r.item_id = v_item_id::text
            and r.warehouse_id = p_warehouse_id
        ), 0),
        available_quantity = coalesce((
          select sum(
            greatest(coalesce(b.quantity_received,0) - coalesce(b.quantity_consumed,0) - coalesce(b.quantity_transferred,0), 0)
          )
          from public.batches b
          where b.item_id::text = v_item_id::text
            and b.warehouse_id = p_warehouse_id
            and coalesce(b.status,'active') = 'active'
            and coalesce(b.qc_status,'') = 'released'
            and not exists (
              select 1 from public.batch_recalls br
              where br.batch_id = b.id and br.status = 'active'
            )
            and (
              not coalesce(v_is_food, false)
              or (b.expiry_date is not null and b.expiry_date >= current_date)
            )
        ), 0),
        last_updated = now(),
        updated_at = now()
    where sm.item_id::text = v_item_id::text
      and sm.warehouse_id = p_warehouse_id;
  end loop;
end;
$$;


ALTER FUNCTION "public"."deduct_stock_on_delivery_v2"("p_order_id" "uuid", "p_items" "jsonb", "p_warehouse_id" "uuid") OWNER TO "postgres";

--
-- Name: delete_user_account("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."delete_user_account"("target_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  -- 1. Verify the caller is an admin
  if not public.is_admin() then
    raise exception 'Access denied: Only admins can delete users.';
  end if;

  -- 2. Delete from auth.users
  -- This will cascade to public.customers (ON DELETE CASCADE)
  -- This will set public.orders.customer_auth_user_id to NULL (ON DELETE SET NULL)
  delete from auth.users where id = target_user_id;

  -- Note: If the user doesn't exist in auth.users (e.g. only in public.customers due to sync error),
  -- we should also ensure public.customers is cleaned up.
  -- But cascade handles the common case.
  delete from public.customers where auth_user_id = target_user_id;
end;
$$;


ALTER FUNCTION "public"."delete_user_account"("target_user_id" "uuid") OWNER TO "postgres";

--
-- Name: detect_landed_cost_close_uom_inflation(timestamp with time zone, timestamp with time zone, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."detect_landed_cost_close_uom_inflation"("p_start" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_end" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_limit" integer DEFAULT 200) RETURNS TABLE("entry_id" "uuid", "entry_date" timestamp with time zone, "shipment_id" "text", "source_event" "text", "inventory_amount" numeric, "cogs_amount" numeric, "expenses_total" numeric, "expected_total" numeric, "inflation_factor" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_accounts jsonb;
  v_inventory uuid;
  v_cogs uuid;
begin
  perform public._require_staff('detect_landed_cost_close_uom_inflation');
  p_limit := greatest(1, least(coalesce(p_limit, 200), 2000));

  select s.data->'settings'->'accounting_accounts'
  into v_accounts
  from public.app_settings s
  where s.id = 'app';

  if v_accounts is null then
    select s.data->'accounting_accounts'
    into v_accounts
    from public.app_settings s
    where s.id = 'singleton';
  end if;

  v_inventory := null;
  if v_accounts is not null and nullif(v_accounts->>'inventory', '') is not null then
    begin
      v_inventory := (v_accounts->>'inventory')::uuid;
    exception when others then
      v_inventory := public.get_account_id_by_code(v_accounts->>'inventory');
    end;
  end if;
  v_inventory := coalesce(v_inventory, public.get_account_id_by_code('1410'));

  v_cogs := null;
  if v_accounts is not null and nullif(v_accounts->>'cogs', '') is not null then
    begin
      v_cogs := (v_accounts->>'cogs')::uuid;
    exception when others then
      v_cogs := public.get_account_id_by_code(v_accounts->>'cogs');
    end;
  end if;
  v_cogs := coalesce(v_cogs, public.get_account_id_by_code('5010'));

  return query
  with base as (
    select
      je.id as entry_id,
      je.entry_date,
      je.source_id as shipment_source_id,
      je.source_event,
      public.uuid_from_text(concat('uomfix:landed_cost:', je.id::text)) as fix_source_uuid
    from public.journal_entries je
    where je.source_table = 'import_shipments'
      and je.source_event in ('landed_cost_close', 'landed_cost_cogs_adjust')
      and (p_start is null or je.entry_date >= p_start)
      and (p_end is null or je.entry_date <= p_end)
    order by je.entry_date desc, je.id desc
    limit p_limit
  ),
  sums as (
    select
      b.entry_id,
      b.entry_date,
      b.shipment_source_id,
      b.source_event,
      sum(case when jl.account_id = v_inventory then coalesce(jl.debit, 0) - coalesce(jl.credit, 0) else 0 end)::numeric as inventory_amount,
      sum(case when jl.account_id = v_cogs then coalesce(jl.debit, 0) - coalesce(jl.credit, 0) else 0 end)::numeric as cogs_amount
    from base b
    join public.journal_lines jl on jl.journal_entry_id = b.entry_id
    group by b.entry_id, b.entry_date, b.shipment_source_id, b.source_event
  ),
  exp as (
    select
      s.entry_id,
      coalesce(sum(coalesce(ie.base_amount, coalesce(ie.amount, 0) * coalesce(ie.exchange_rate, 1))), 0)::numeric as expenses_total
    from sums s
    left join public.import_expenses ie on ie.shipment_id::text = s.shipment_source_id
    group by s.entry_id
  ),
  joined as (
    select
      s.entry_id,
      s.entry_date,
      coalesce(nullif(is1.reference_number, ''), s.shipment_source_id) as shipment_id,
      s.source_event,
      s.inventory_amount,
      s.cogs_amount,
      e.expenses_total,
      e.expenses_total as expected_total
    from sums s
    join exp e on e.entry_id = s.entry_id
    left join public.import_shipments is1 on is1.id::text = s.shipment_source_id
  )
  select
    j.entry_id,
    j.entry_date,
    j.shipment_id,
    j.source_event,
    j.inventory_amount,
    j.cogs_amount,
    j.expenses_total,
    j.expected_total,
    case when j.expected_total > 0 then ((j.inventory_amount + j.cogs_amount) / j.expected_total)::numeric else null end as inflation_factor
  from joined j
  where j.expected_total > 0
    and abs((j.inventory_amount + j.cogs_amount) - j.expected_total) > 0.01
    and ((j.inventory_amount + j.cogs_amount) / j.expected_total) > 1.05
    and ((j.inventory_amount + j.cogs_amount) / j.expected_total) < 500
  order by j.entry_date desc, j.entry_id desc;
end;
$$;


ALTER FUNCTION "public"."detect_landed_cost_close_uom_inflation"("p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_limit" integer) OWNER TO "postgres";

--
-- Name: detect_purchase_in_uom_inflation(timestamp with time zone, timestamp with time zone, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."detect_purchase_in_uom_inflation"("p_start" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_end" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_limit" integer DEFAULT 200) RETURNS TABLE("movement_id" "uuid", "occurred_at" timestamp with time zone, "item_id" "text", "reference_table" "text", "reference_id" "text", "quantity" numeric, "unit_cost" numeric, "total_cost" numeric, "expected_unit_cost" numeric, "expected_total_cost" numeric, "inflation_factor" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
begin
  perform public._require_staff('detect_purchase_in_uom_inflation');
  p_limit := greatest(1, least(coalesce(p_limit, 200), 2000));

  return query
  with mv as (
    select
      im.*,
      case when im.reference_id ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then im.reference_id::uuid else null end as ref_uuid,
      case when im.reference_table = 'purchase_receipts' and im.reference_id ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then im.reference_id::uuid else null end as ref_receipt_uuid,
      case when im.reference_table = 'purchase_orders' and im.reference_id ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then im.reference_id::uuid else null end as ref_po_uuid,
      case when (im.data->>'purchaseOrderId') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then (im.data->>'purchaseOrderId')::uuid else null end as data_po_uuid,
      case when (im.data->>'purchaseReceiptId') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then (im.data->>'purchaseReceiptId')::uuid else null end as data_receipt_uuid,
      public.uuid_from_text(concat('uomfix:purchase_in:', im.id::text)) as fix_source_uuid
    from public.inventory_movements im
    where im.movement_type = 'purchase_in'
      and (p_start is null or im.occurred_at >= p_start)
      and (p_end is null or im.occurred_at <= p_end)
    order by im.occurred_at desc, im.id desc
    limit p_limit
  ),
  joined as (
    select
      mv.id as movement_id,
      mv.occurred_at,
      mv.item_id,
      mv.reference_table,
      mv.reference_id,
      mv.quantity,
      mv.unit_cost,
      mv.total_cost,
      mv.qty_base as mv_qty_base,
      mv.uom_id as mv_uom_id,
      mv.warehouse_id,
      mv.data,
      mv.fix_source_uuid,
      pr.purchase_order_id as receipt_po_id,
      pi.qty_base as pi_qty_base,
      pi.quantity as pi_qty,
      pi.unit_cost_base as pi_unit_cost_base,
      pi.unit_cost as pi_unit_cost,
      pi.uom_id as pi_uom_id,
      mi.transport_cost as mi_transport_cost,
      mi.supply_tax_cost as mi_supply_tax_cost,
      pri.qty_base as pri_qty_base,
      pri.quantity as pri_qty,
      pri.unit_cost as pri_unit_cost,
      pri.uom_id as pri_uom_id,
      pri.transport_cost as pri_transport_cost,
      pri.supply_tax_cost as pri_supply_tax_cost
    from mv
    left join public.purchase_receipts pr
      on pr.id = coalesce(mv.ref_receipt_uuid, mv.data_receipt_uuid)
    left join public.purchase_items pi
      on pi.purchase_order_id = coalesce(mv.ref_po_uuid, mv.data_po_uuid, pr.purchase_order_id)
      and pi.item_id = mv.item_id
    left join public.menu_items mi on mi.id = mv.item_id
    left join public.purchase_receipt_items pri
      on pri.receipt_id = coalesce(mv.ref_receipt_uuid, mv.data_receipt_uuid, pr.id)
      and pri.item_id = mv.item_id
  ),
  uoms as (
    select
      j.*,
      iu.base_uom_id,
      iuu_pi.qty_in_base as pi_qty_in_base,
      iuu_pri.qty_in_base as pri_qty_in_base
    from joined j
    left join public.item_uom iu on iu.item_id = j.item_id
    left join public.item_uom_units iuu_pi
      on iuu_pi.item_id = j.item_id
      and iuu_pi.uom_id = j.pi_uom_id
      and iuu_pi.is_active = true
    left join public.item_uom_units iuu_pri
      on iuu_pri.item_id = j.item_id
      and iuu_pri.uom_id = j.pri_uom_id
      and iuu_pri.is_active = true
  ),
  calc as (
    select
      u.*,
      greatest(
        coalesce(u.mv_qty_base, u.pri_qty_base, u.pi_qty_base, u.quantity, u.pri_qty, u.pi_qty, 0),
        0
      )::numeric as expected_qty_base,
      (
        coalesce(
          case
            when u.pri_unit_cost is not null then
              case
                when u.pri_qty_base is not null and u.pri_qty is not null and u.pri_qty_base > 0 and u.pri_qty > 0 then (u.pri_unit_cost * u.pri_qty / u.pri_qty_base)
                when u.base_uom_id is null or u.pri_uom_id is null or u.pri_uom_id = u.base_uom_id then u.pri_unit_cost
                when u.pri_qty_in_base is not null and u.pri_qty_in_base > 0 then u.pri_unit_cost / u.pri_qty_in_base
                else null
              end
            else null
          end,
          case
            when u.pi_unit_cost is not null then
              case
                when u.pi_qty_base is not null and u.pi_qty is not null and u.pi_qty_base > 0 and u.pi_qty > 0 then (u.pi_unit_cost * u.pi_qty / u.pi_qty_base)
                when u.base_uom_id is null or u.pi_uom_id is null or u.pi_uom_id = u.base_uom_id then u.pi_unit_cost
                when u.pi_qty_in_base is not null and u.pi_qty_in_base > 0 then u.pi_unit_cost / u.pi_qty_in_base
                else null
              end
            else null
          end,
          nullif(u.pi_unit_cost_base, 0),
          coalesce(u.unit_cost, 0),
          0
        )
        + coalesce(u.mi_transport_cost, 0)
        + coalesce(u.mi_supply_tax_cost, 0)
        + coalesce(u.pri_transport_cost, 0)
        + coalesce(u.pri_supply_tax_cost, 0)
      )::numeric as expected_unit_cost
    from uoms u
  )
  select
    c.movement_id,
    c.occurred_at,
    c.item_id,
    c.reference_table,
    c.reference_id,
    c.quantity,
    c.unit_cost,
    c.total_cost,
    c.expected_unit_cost,
    (c.expected_qty_base * c.expected_unit_cost)::numeric as expected_total_cost,
    case
      when (c.expected_qty_base * c.expected_unit_cost) > 0 then (c.total_cost / (c.expected_qty_base * c.expected_unit_cost))::numeric
      else null
    end as inflation_factor
  from calc c
  where (c.expected_qty_base * c.expected_unit_cost) > 0
    and abs(coalesce(c.total_cost, 0) - (c.expected_qty_base * c.expected_unit_cost)) > 0.01
    and (coalesce(c.total_cost, 0) / (c.expected_qty_base * c.expected_unit_cost)) > 1.05
    and (coalesce(c.total_cost, 0) / (c.expected_qty_base * c.expected_unit_cost)) < 500
    and not exists (
      select 1
      from public.journal_entries je
      where je.source_table = 'ledger_repairs'
        and je.source_id = c.fix_source_uuid::text
        and je.source_event = 'fix_purchase_in_uom'
    )
  order by c.occurred_at desc, c.movement_id desc;
end;
$_$;


ALTER FUNCTION "public"."detect_purchase_in_uom_inflation"("p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_limit" integer) OWNER TO "postgres";

--
-- Name: dispatch_inventory_transfer("uuid", "text", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."dispatch_inventory_transfer"("p_transfer_id" "uuid", "p_idempotency_key" "text" DEFAULT NULL::"text", "p_cancel" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_transfer record;
  v_item record;
  v_sm record;
  v_reserved_batches jsonb;
  v_reserved_list jsonb;
  v_reserved_sum numeric;
  v_remaining numeric;
  v_expiry_date date;
  v_movement_id uuid;
begin
  v_actor := auth.uid();
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;
  if p_transfer_id is null then
    raise exception 'p_transfer_id is required';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_transfer_id::text));

  select *
  into v_transfer
  from public.inventory_transfers it
  where it.id = p_transfer_id
  for update;

  if not found then
    raise exception 'transfer not found';
  end if;

  if p_idempotency_key is not null and btrim(p_idempotency_key) <> '' then
    if v_transfer.dispatch_idempotency_key is not null and v_transfer.dispatch_idempotency_key = p_idempotency_key then
      return jsonb_build_object('status', v_transfer.state, 'transferId', p_transfer_id::text);
    end if;
  end if;

  if v_transfer.state = 'CANCELLED' then
    return jsonb_build_object('status', 'CANCELLED', 'transferId', p_transfer_id::text);
  end if;

  if p_cancel then
    if v_transfer.state <> 'CREATED' then
      raise exception 'cannot cancel transfer in state %', v_transfer.state;
    end if;
    update public.inventory_transfers
    set state = 'CANCELLED',
        updated_at = now(),
        dispatch_idempotency_key = nullif(btrim(p_idempotency_key), '')
    where id = p_transfer_id;
    return jsonb_build_object('status', 'CANCELLED', 'transferId', p_transfer_id::text);
  end if;

  if v_transfer.state <> 'CREATED' then
    return jsonb_build_object('status', v_transfer.state, 'transferId', p_transfer_id::text);
  end if;

  for v_item in
    select *
    from public.inventory_transfer_items iti
    where iti.transfer_id = p_transfer_id
    order by iti.created_at asc, iti.id asc
    for update
  loop
    if exists (
      select 1
      from public.inventory_movements im
      where im.reference_table = 'inventory_transfers'
        and im.reference_id = p_transfer_id::text
        and im.movement_type = 'transfer_out'
        and im.item_id = v_item.item_id
        and im.batch_id = v_item.source_batch_id
        and im.warehouse_id is not distinct from v_transfer.from_warehouse_id
    ) then
      update public.inventory_transfer_items
      set dispatched_qty = quantity,
          updated_at = now()
      where id = v_item.id;
      continue;
    end if;

    select *
    into v_sm
    from public.stock_management sm
    where sm.item_id::text = v_item.item_id
      and sm.warehouse_id = v_transfer.from_warehouse_id
    for update;

    if not found then
      raise exception 'Stock record not found for item % in source warehouse', v_item.item_id;
    end if;

    if (coalesce(v_sm.available_quantity,0) - coalesce(v_sm.reserved_quantity,0)) + 1e-9 < v_item.quantity then
      raise exception 'Insufficient non-reserved stock for item % in source warehouse', v_item.item_id;
    end if;

    select
      greatest(
        coalesce(b.quantity_received,0)
        - coalesce(b.quantity_consumed,0)
        - coalesce(b.quantity_transferred,0),
        0
      ),
      b.expiry_date
    into v_remaining, v_expiry_date
    from public.batches b
    where b.id = v_item.source_batch_id
      and b.warehouse_id = v_transfer.from_warehouse_id
    for update;

    if not found then
      raise exception 'Batch not found for transfer item';
    end if;

    if v_expiry_date is not null and v_expiry_date < current_date then
      raise exception 'BATCH_EXPIRED';
    end if;

    v_reserved_batches := coalesce(v_sm.data->'reservedBatches', '{}'::jsonb);
    v_reserved_list := v_reserved_batches->(v_item.source_batch_id::text);
    if v_reserved_list is not null then
      v_reserved_list :=
        case
          when jsonb_typeof(v_reserved_list) = 'array' then v_reserved_list
          when jsonb_typeof(v_reserved_list) = 'object' then jsonb_build_array(v_reserved_list)
          else '[]'::jsonb
        end;
      select coalesce(sum(coalesce(nullif(x->>'qty','')::numeric, 0)), 0)
      into v_reserved_sum
      from jsonb_array_elements(v_reserved_list) as x;
      if coalesce(v_reserved_sum,0) > 0 then
        raise exception 'Cannot transfer reserved batch stock';
      end if;
    end if;

    if coalesce(v_remaining,0) + 1e-9 < v_item.quantity then
      raise exception 'Insufficient batch remaining for transfer';
    end if;

    update public.batches
    set quantity_transferred = quantity_transferred + v_item.quantity
    where id = v_item.source_batch_id;

    update public.stock_management
    set available_quantity = greatest(0, available_quantity - v_item.quantity),
        last_updated = now(),
        updated_at = now()
    where item_id::text = v_item.item_id
      and warehouse_id = v_transfer.from_warehouse_id;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_item.item_id,
      'transfer_out',
      v_item.quantity,
      v_item.unit_cost,
      0,
      'inventory_transfers',
      p_transfer_id::text,
      now(),
      v_actor,
      jsonb_build_object(
        'transferId', p_transfer_id,
        'direction', 'out',
        'fromWarehouseId', v_transfer.from_warehouse_id,
        'toWarehouseId', v_transfer.to_warehouse_id,
        'sourceBatchId', v_item.source_batch_id
      ),
      v_item.source_batch_id,
      v_transfer.from_warehouse_id
    )
    returning id into v_movement_id;

    perform public.post_inventory_movement(v_movement_id);

    update public.inventory_transfer_items
    set dispatched_qty = quantity,
        updated_at = now()
    where id = v_item.id;
  end loop;

  update public.inventory_transfers
  set state = 'IN_TRANSIT',
      dispatched_by = v_actor,
      dispatched_at = now(),
      updated_at = now(),
      dispatch_idempotency_key = nullif(btrim(p_idempotency_key), '')
  where id = p_transfer_id;

  return jsonb_build_object('status', 'IN_TRANSIT', 'transferId', p_transfer_id::text);
end;
$$;


ALTER FUNCTION "public"."dispatch_inventory_transfer"("p_transfer_id" "uuid", "p_idempotency_key" "text", "p_cancel" boolean) OWNER TO "postgres";

--
-- Name: encrypt_text("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."encrypt_text"("p_text" "text") RETURNS "bytea"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'extensions', 'public'
    AS $$
DECLARE
  v_key text;
BEGIN
  SELECT key_value INTO v_key FROM private.keys WHERE key_name = 'app.encryption_key';
  IF v_key IS NULL OR v_key = '' THEN
    RAISE EXCEPTION 'Encryption key not configured';
  END IF;
  IF p_text IS NULL OR p_text = '' THEN 
    RETURN NULL;
  END IF;
  RETURN extensions.pgp_sym_encrypt(p_text, v_key);
END;
$$;


ALTER FUNCTION "public"."encrypt_text"("p_text" "text") OWNER TO "postgres";

--
-- Name: enforce_purchase_items_editability(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enforce_purchase_items_editability"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_order_id uuid;
  v_status text;
  v_has_receipts boolean;
begin
  v_order_id := coalesce(new.purchase_order_id, old.purchase_order_id);

  select po.status
  into v_status
  from public.purchase_orders po
  where po.id = v_order_id;

  if not found then
    raise exception 'purchase order not found';
  end if;

  select exists(select 1 from public.purchase_receipts pr where pr.purchase_order_id = v_order_id)
  into v_has_receipts;

  if tg_op = 'INSERT' then
    if v_status <> 'draft' or coalesce(v_has_receipts, false) then
      raise exception 'cannot add purchase items after receiving';
    end if;
    return new;
  end if;

  if tg_op = 'DELETE' then
    if v_status <> 'draft' or coalesce(v_has_receipts, false) or coalesce(old.received_quantity, 0) > 0 then
      raise exception 'cannot delete purchase items after receiving';
    end if;
    return old;
  end if;

  if (new.quantity is distinct from old.quantity)
    or (new.unit_cost is distinct from old.unit_cost)
    or (new.item_id is distinct from old.item_id)
    or (new.purchase_order_id is distinct from old.purchase_order_id)
  then
    if v_status <> 'draft' or coalesce(v_has_receipts, false) or coalesce(old.received_quantity, 0) > 0 then
      raise exception 'cannot modify purchase items after receiving';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."enforce_purchase_items_editability"() OWNER TO "postgres";

--
-- Name: enforce_purchase_orders_status_transition(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enforce_purchase_orders_status_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_has_receipts boolean;
  v_has_payments boolean;
  v_has_movements boolean;
begin
  if new.status is not distinct from old.status then
    return new;
  end if;

  if old.status = 'cancelled' then
    raise exception 'cannot change status from cancelled';
  end if;

  if new.status = 'draft' then
    raise exception 'cannot revert to draft';
  end if;

  if old.status = 'completed' and new.status is distinct from 'completed' then
    raise exception 'cannot change status from completed';
  end if;

  if not (
    (old.status = 'draft' and new.status in ('partial', 'completed', 'cancelled'))
    or (old.status = 'partial' and new.status = 'completed')
  ) then
    raise exception 'invalid status transition';
  end if;

  if new.status = 'cancelled' then
    select exists(select 1 from public.purchase_receipts pr where pr.purchase_order_id = new.id) into v_has_receipts;
    select exists(
      select 1
      from public.payments p
      where p.reference_table = 'purchase_orders'
        and p.reference_id::text = new.id::text
    ) into v_has_payments;
    select exists(
      select 1
      from public.inventory_movements im
      where (im.reference_table = 'purchase_orders' and im.reference_id::text = new.id::text)
         or (im.data ? 'purchaseOrderId' and im.data->>'purchaseOrderId' = new.id::text)
    ) into v_has_movements;

    if coalesce(v_has_receipts, false)
      or coalesce(v_has_payments, false)
      or coalesce(v_has_movements, false)
      or coalesce(old.paid_amount, 0) > 0
    then
      raise exception 'cannot cancel posted purchase order';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."enforce_purchase_orders_status_transition"() OWNER TO "postgres";

--
-- Name: enqueue_accounting_job("text", "jsonb", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enqueue_accounting_job"("p_job_type" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_scheduled_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_job_type is null or btrim(p_job_type) = '' then
    raise exception 'job_type required';
  end if;
  insert into public.accounting_jobs(job_type, status, payload, scheduled_at, created_by)
  values (lower(p_job_type), 'queued', coalesce(p_payload,'{}'::jsonb), coalesce(p_scheduled_at, now()), auth.uid())
  returning id into v_id;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'accounting_jobs.enqueue',
    'accounting',
    v_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('jobId', v_id::text, 'jobType', lower(p_job_type)),
    'LOW',
    'JOB_ENQUEUE'
  );

  return v_id;
end;
$$;


ALTER FUNCTION "public"."enqueue_accounting_job"("p_job_type" "text", "p_payload" "jsonb", "p_scheduled_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: ensure_accounting_document_number("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."ensure_accounting_document_number"("p_document_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc record;
  v_num text;
  v_date date;
begin
  if not public.has_admin_permission('accounting.view') then
    raise exception 'not allowed';
  end if;

  if p_document_id is null then
    raise exception 'document id is required';
  end if;

  select * into v_doc
  from public.accounting_documents
  where id = p_document_id
  for update;

  if not found then
    raise exception 'accounting document not found';
  end if;

  if v_doc.document_number is not null and length(btrim(v_doc.document_number)) > 0 then
    return v_doc.document_number;
  end if;

  if v_doc.document_type = 'invoice' and v_doc.source_table = 'orders' then
    select nullif(o.invoice_number,'') into v_num
    from public.orders o
    where o.id = v_doc.source_id::uuid;
    if v_num is not null and length(btrim(v_num)) > 0 then
      update public.accounting_documents set document_number = v_num where id = v_doc.id;
      return v_num;
    end if;
  end if;

  v_date := current_date;
  if v_doc.source_table = 'purchase_orders' then
    select coalesce(po.purchase_date, current_date) into v_date
    from public.purchase_orders po
    where po.id = v_doc.source_id::uuid;
  elsif v_doc.source_table = 'purchase_receipts' then
    select coalesce(pr.received_at::date, current_date) into v_date
    from public.purchase_receipts pr
    where pr.id = v_doc.source_id::uuid;
  elsif v_doc.source_table = 'payments' then
    select coalesce(p.occurred_at::date, current_date) into v_date
    from public.payments p
    where p.id = v_doc.source_id::uuid;
  elsif v_doc.source_table = 'warehouse_transfers' then
    select coalesce(wt.transfer_date, current_date) into v_date
    from public.warehouse_transfers wt
    where wt.id = v_doc.source_id::uuid;
  elsif v_doc.source_table = 'inventory_transfers' then
    select coalesce(it.transfer_date, current_date) into v_date
    from public.inventory_transfers it
    where it.id = v_doc.source_id::uuid;
  elsif v_doc.source_table = 'inventory_movements' then
    select coalesce(im.occurred_at::date, current_date) into v_date
    from public.inventory_movements im
    where im.id = v_doc.source_id::uuid;
  end if;

  v_num := public.next_document_number(v_doc.document_type, v_doc.branch_id, v_date);
  update public.accounting_documents set document_number = v_num where id = v_doc.id;
  return v_num;
end;
$$;


ALTER FUNCTION "public"."ensure_accounting_document_number"("p_document_id" "uuid") OWNER TO "postgres";

--
-- Name: ensure_financial_party_for_customer("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."ensure_financial_party_for_customer"("p_customer_auth_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_party_id uuid;
  v_name text;
  v_currency text;
begin
  if p_customer_auth_user_id is null then
    return null;
  end if;

  select fpl.party_id
  into v_party_id
  from public.financial_party_links fpl
  where fpl.linked_entity_type = 'customers'
    and fpl.linked_entity_id = p_customer_auth_user_id::text
    and fpl.role = 'customer'
  limit 1;

  if v_party_id is not null then
    return v_party_id;
  end if;

  select
    coalesce(nullif(trim(c.full_name), ''), nullif(trim(c.email), ''), nullif(trim(c.phone_number), ''), p_customer_auth_user_id::text),
    nullif(trim(coalesce(c.preferred_currency, '')), '')
  into v_name, v_currency
  from public.customers c
  where c.auth_user_id = p_customer_auth_user_id;

  insert into public.financial_parties(name, party_type, linked_entity_type, linked_entity_id, currency_preference, created_by, updated_by)
  values (coalesce(v_name, p_customer_auth_user_id::text), 'customer', 'customers', p_customer_auth_user_id::text, v_currency, auth.uid(), auth.uid())
  returning id into v_party_id;

  insert into public.financial_party_links(party_id, role, linked_entity_type, linked_entity_id, created_by)
  values (v_party_id, 'customer', 'customers', p_customer_auth_user_id::text, auth.uid())
  on conflict (linked_entity_type, linked_entity_id, role) do nothing;

  return v_party_id;
end;
$$;


ALTER FUNCTION "public"."ensure_financial_party_for_customer"("p_customer_auth_user_id" "uuid") OWNER TO "postgres";

