--
-- Name: enterprise_trial_balance_drilldown("text", "date", "date", "uuid", "uuid", "uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enterprise_trial_balance_drilldown"("p_account_code" "text", "p_start" "date" DEFAULT NULL::"date", "p_end" "date" DEFAULT NULL::"date", "p_company_id" "uuid" DEFAULT NULL::"uuid", "p_branch_id" "uuid" DEFAULT NULL::"uuid", "p_cost_center_id" "uuid" DEFAULT NULL::"uuid", "p_dept_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("entry_date" "date", "journal_entry_id" "uuid", "journal_line_id" "uuid", "memo" "text", "source_table" "text", "source_id" "text", "source_event" "text", "debit" numeric, "credit" numeric, "currency_code" "text", "foreign_amount" numeric, "fx_rate" numeric, "party_id" "uuid", "cost_center_id" "uuid", "dept_id" "uuid", "project_id" "uuid")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    l.entry_date,
    l.journal_entry_id,
    l.journal_line_id,
    l.entry_memo as memo,
    l.source_table,
    l.source_id,
    l.source_event,
    l.debit,
    l.credit,
    l.currency_code,
    l.foreign_amount,
    l.fx_rate,
    l.party_id,
    l.cost_center_id,
    l.dept_id,
    l.project_id
  from public.enterprise_gl_lines l
  where public.can_view_enterprise_financial_reports()
    and l.account_code = p_account_code
    and (p_start is null or l.entry_date >= p_start)
    and (p_end is null or l.entry_date <= p_end)
    and (p_company_id is null or l.company_id = p_company_id)
    and (p_branch_id is null or l.branch_id = p_branch_id)
    and (p_cost_center_id is null or l.cost_center_id = p_cost_center_id)
    and (p_dept_id is null or l.dept_id = p_dept_id)
    and (p_project_id is null or l.project_id = p_project_id)
  order by l.entry_date asc, l.journal_entry_id asc, l.journal_line_id asc;
$$;


