--
-- Name: finalize_purchase_orders_without_shortages(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."finalize_purchase_orders_without_shortages"("p_limit" integer DEFAULT 100000) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
  v_n int := 0;
begin
  for v_id in
    select po.id
    from public.purchase_orders po
    where po.status not in ('cancelled','completed')
      and exists (select 1 from public.purchase_receipts pr where pr.purchase_order_id = po.id)
    order by po.updated_at desc nulls last
    limit greatest(coalesce(p_limit, 0), 0)
  loop
    begin
      if to_regprocedure('public.report_partial_purchase_orders(integer)') is not null then
        perform 1;
      end if;

      with ordered_sum as (
        select sum(
          coalesce(
            nullif(pi.qty_base, 0),
            case
              when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
              else pi.quantity
            end,
            0
          )
        ) as ordered_base
        from public.purchase_items pi
        where pi.purchase_order_id = v_id
      ),
      received_sum as (
        select sum(
          coalesce(
            nullif(pri.qty_base, 0),
            case
              when pri.uom_id is not null then public.item_qty_to_base_safe(pri.item_id, pri.quantity, pri.uom_id)
              else pri.quantity
            end,
            0
          )
        ) as received_base
        from public.purchase_receipts pr
        join public.purchase_receipt_items pri on pri.receipt_id = pr.id
        where pr.purchase_order_id = v_id
      )
      update public.purchase_orders po
      set status = 'completed',
          approval_status = 'approved',
          approval_request_id = null,
          updated_at = now()
      from ordered_sum o, received_sum r
      where po.id = v_id
        and po.status not in ('cancelled','completed')
        and coalesce(o.ordered_base, 0) > 0
        and coalesce(r.received_base, 0) + 0.000000001 >= coalesce(o.ordered_base, 0);

      if found then
        v_n := v_n + 1;
      end if;
    exception when others then
      null;
    end;
  end loop;
  return v_n;
end;
$$;


ALTER FUNCTION "public"."finalize_purchase_orders_without_shortages"("p_limit" integer) OWNER TO "postgres";

--
-- Name: flag_payment_allocation_status("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."flag_payment_allocation_status"("p_payment_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_pay record;
  v_order record;
  v_delivered_at timestamptz;
  v_is_cod boolean := false;
  v_eligible boolean := false;
begin
  if p_payment_id is null then
    raise exception 'p_payment_id is required';
  end if;
  select *
  into v_pay
  from public.payments p
  where p.id = p_payment_id;
  if not found then
    raise exception 'payment not found';
  end if;
  if v_pay.direction <> 'in' or v_pay.reference_table <> 'orders' then
    return;
  end if;
  select *
  into v_order
  from public.orders o
  where o.id = (v_pay.reference_id)::uuid;
  if not found then
    return;
  end if;
  begin
    select public.order_delivered_at((v_pay.reference_id)::uuid) into v_delivered_at;
  exception when others then
    v_delivered_at := null;
  end;
  v_is_cod := public._is_cod_delivery_order(coalesce(v_order.data,'{}'::jsonb), v_order.delivery_zone_id);
  v_eligible := (v_delivered_at is not null) and (v_pay.occurred_at >= v_delivered_at) and (not v_is_cod);
  insert into public.ar_payment_status(payment_id, order_id, eligible, allocated, created_at, updated_at)
  values (p_payment_id, (v_pay.reference_id)::uuid, v_eligible, false, now(), now())
  on conflict (payment_id) do update
    set eligible = excluded.eligible,
        updated_at = now();
end;
$$;


ALTER FUNCTION "public"."flag_payment_allocation_status"("p_payment_id" "uuid") OWNER TO "postgres";

--
-- Name: force_complete_purchase_orders_from_receipts(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."force_complete_purchase_orders_from_receipts"("p_limit" integer DEFAULT 100000) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
  v_n int := 0;
  v_has_batches boolean := false;
begin
  begin
    if to_regclass('public.batches') is not null then
      v_has_batches := true;
    end if;
  exception when others then
    v_has_batches := false;
  end;

  for v_id in
    select po.id
    from public.purchase_orders po
    where po.status <> 'cancelled'
      and exists (select 1 from public.purchase_receipts pr where pr.purchase_order_id = po.id)
    order by po.updated_at desc nulls last
    limit greatest(coalesce(p_limit, 0), 0)
  loop
    begin
      if v_has_batches then
        with totals as (
          select b.item_id::text as item_id, sum(coalesce(b.quantity_received, 0)) as received_base
          from public.purchase_receipts pr
          join public.batches b on b.receipt_id = pr.id
          where pr.purchase_order_id = v_id
          group by b.item_id::text
        ),
        ordered as (
          select
            pi.id,
            pi.item_id::text as item_id,
            coalesce(
              nullif(pi.qty_base, 0),
              case
                when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
                else pi.quantity
              end,
              0
            ) as ordered_base
          from public.purchase_items pi
          where pi.purchase_order_id = v_id
        )
        update public.purchase_items pi
        set received_quantity = least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0))
        from totals t
        join ordered o on o.id = pi.id
        where pi.purchase_order_id = v_id
          and pi.item_id::text = t.item_id
          and coalesce(pi.received_quantity, 0) is distinct from least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0));
      else
        with totals as (
          select
            pri.item_id::text as item_id,
            sum(
              coalesce(
                nullif(pri.qty_base, 0),
                case
                  when pri.uom_id is not null then public.item_qty_to_base_safe(pri.item_id, pri.quantity, pri.uom_id)
                  else pri.quantity
                end,
                0
              )
            ) as received_base
          from public.purchase_receipts pr
          join public.purchase_receipt_items pri on pri.receipt_id = pr.id
          where pr.purchase_order_id = v_id
          group by pri.item_id::text
        ),
        ordered as (
          select
            pi.id,
            pi.item_id::text as item_id,
            coalesce(
              nullif(pi.qty_base, 0),
              case
                when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
                else pi.quantity
              end,
              0
            ) as ordered_base
          from public.purchase_items pi
          where pi.purchase_order_id = v_id
        )
        update public.purchase_items pi
        set received_quantity = least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0))
        from totals t
        join ordered o on o.id = pi.id
        where pi.purchase_order_id = v_id
          and pi.item_id::text = t.item_id
          and coalesce(pi.received_quantity, 0) is distinct from least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0));
      end if;

      with ordered_sum as (
        select sum(
          coalesce(
            nullif(pi.qty_base, 0),
            case
              when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
              else pi.quantity
            end,
            0
          )
        ) as ordered_base
        from public.purchase_items pi
        where pi.purchase_order_id = v_id
      ),
      received_sum as (
        select sum(
          coalesce(
            nullif(pri.qty_base, 0),
            case
              when pri.uom_id is not null then public.item_qty_to_base_safe(pri.item_id, pri.quantity, pri.uom_id)
              else pri.quantity
            end,
            0
          )
        ) as received_base
        from public.purchase_receipts pr
        join public.purchase_receipt_items pri on pri.receipt_id = pr.id
        where pr.purchase_order_id = v_id
      )
      update public.purchase_orders po
      set status = 'completed',
          approval_status = 'approved',
          approval_request_id = null,
          updated_at = now()
      from ordered_sum o, received_sum r
      where po.id = v_id
        and po.status <> 'cancelled'
        and (
          (coalesce(o.ordered_base, 0) > 0 and coalesce(r.received_base, 0) + 0.000000001 >= coalesce(o.ordered_base, 0))
          or (coalesce(o.ordered_base, 0) = 0 and coalesce(r.received_base, 0) > 0)
        )
        and po.status is distinct from 'completed';

      if found then
        v_n := v_n + 1;
      end if;
    exception when others then
      null;
    end;
  end loop;

  begin
    update public.purchase_orders po
    set approval_status = 'approved',
        approval_request_id = null,
        updated_at = now()
    where po.status = 'completed'
      and exists (select 1 from public.purchase_receipts pr where pr.purchase_order_id = po.id);
  exception when others then
    null;
  end;

  return v_n;
end;
$$;


ALTER FUNCTION "public"."force_complete_purchase_orders_from_receipts"("p_limit" integer) OWNER TO "postgres";

--
-- Name: force_complete_purchase_orders_status_only(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."force_complete_purchase_orders_status_only"("p_limit" integer DEFAULT 100000) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
  v_n int := 0;
begin
  for v_id in
    select po.id
    from public.purchase_orders po
    where po.status <> 'cancelled'
      and exists (select 1 from public.purchase_receipts pr where pr.purchase_order_id = po.id)
    order by po.updated_at desc nulls last
    limit greatest(coalesce(p_limit, 0), 0)
  loop
    begin
      update public.purchase_orders po
      set status = 'completed',
          approval_status = 'approved',
          approval_request_id = null,
          updated_at = now()
      where po.id = v_id
        and po.status is distinct from 'completed';
      if found then
        v_n := v_n + 1;
      end if;
    exception when others then
      null;
    end;
  end loop;
  return v_n;
end;
$$;


ALTER FUNCTION "public"."force_complete_purchase_orders_status_only"("p_limit" integer) OWNER TO "postgres";

--
-- Name: format_document_number("text", "uuid", "date", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."format_document_number"("p_doc_type" "text", "p_branch_id" "uuid", "p_doc_date" "date", "p_seq" integer) RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_prefix text;
  v_branch_code text;
  v_year text;
begin
  v_prefix := public._doc_prefix(p_doc_type);
  select b.code into v_branch_code from public.branches b where b.id = p_branch_id;
  v_branch_code := upper(coalesce(nullif(trim(v_branch_code), ''), 'BR'));
  v_year := to_char(coalesce(p_doc_date, current_date), 'YYYY');
  return concat(v_prefix, '-', v_branch_code, '-', v_year, '-', lpad(greatest(coalesce(p_seq, 0), 0)::text, 6, '0'));
end;
$$;


ALTER FUNCTION "public"."format_document_number"("p_doc_type" "text", "p_branch_id" "uuid", "p_doc_date" "date", "p_seq" integer) OWNER TO "postgres";

--
-- Name: fx_convert(numeric, "text", "text", "date", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."fx_convert"("p_amount" numeric, "p_from_currency" "text", "p_to_currency" "text", "p_date" "date", "p_rate_type" "text" DEFAULT 'accounting'::"text") RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text := upper(nullif(btrim(coalesce(public.get_base_currency(), '')), ''));
  v_from text := upper(nullif(btrim(coalesce(p_from_currency, '')), ''));
  v_to text := upper(nullif(btrim(coalesce(p_to_currency, '')), ''));
  v_date date := coalesce(p_date, current_date);
  v_type text := lower(nullif(btrim(coalesce(p_rate_type, '')), ''));
  v_amt numeric := coalesce(p_amount, 0);
  v_r_from numeric;
  v_r_to numeric;
begin
  if v_type is null then
    v_type := 'accounting';
  end if;
  if v_from is null then
    v_from := v_base;
  end if;
  if v_to is null then
    v_to := v_base;
  end if;
  if v_from = v_to then
    return v_amt;
  end if;
  if v_from = v_base then
    v_r_to := public.get_fx_rate(v_to, v_date, v_type);
    if v_r_to is null or v_r_to <= 0 then
      raise exception 'fx rate missing for %', v_to;
    end if;
    return v_amt / v_r_to;
  end if;
  if v_to = v_base then
    v_r_from := public.get_fx_rate(v_from, v_date, v_type);
    if v_r_from is null or v_r_from <= 0 then
      raise exception 'fx rate missing for %', v_from;
    end if;
    return v_amt * v_r_from;
  end if;
  v_r_from := public.get_fx_rate(v_from, v_date, v_type);
  v_r_to := public.get_fx_rate(v_to, v_date, v_type);
  if v_r_from is null or v_r_from <= 0 then
    raise exception 'fx rate missing for %', v_from;
  end if;
  if v_r_to is null or v_r_to <= 0 then
    raise exception 'fx rate missing for %', v_to;
  end if;
  return (v_amt * v_r_from) / v_r_to;
end;
$$;


ALTER FUNCTION "public"."fx_convert"("p_amount" numeric, "p_from_currency" "text", "p_to_currency" "text", "p_date" "date", "p_rate_type" "text") OWNER TO "postgres";

--
-- Name: general_ledger("text", "date", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."general_ledger"("p_account_code" "text", "p_start" "date", "p_end" "date", "p_cost_center_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("entry_date" "date", "journal_entry_id" "uuid", "memo" "text", "source_table" "text", "source_id" "text", "source_event" "text", "debit" numeric, "credit" numeric, "amount" numeric, "running_balance" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with state as (
    select
      public.get_base_currency() as base,
      s.old_base_currency as old_base,
      s.locked_at::date as lock_date
    from public.base_currency_restatement_state s
    where s.id = 'sar_base_lock'
    limit 1
  ),
  acct as (
    select coa.id, coa.normal_balance
    from public.chart_of_accounts coa
    where coa.code = p_account_code
    limit 1
  ),
  opening as (
    select coalesce(sum(
      case
        when a.normal_balance = 'credit' then (x.credit - x.debit)
        else (x.debit - x.credit)
      end
    ), 0) as opening_balance
    from (
      select
        case
          when jl.currency_code is not null
            and upper(jl.currency_code) <> upper(st.base)
            and jl.foreign_amount is not null
            and coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')) is not null
            and jl.debit > 0
            then public._money_round(jl.foreign_amount * coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')))
          when jl.currency_code is null
            and st.old_base is not null
            and st.lock_date is not null
            and je.entry_date::date < st.lock_date
            and not exists (
              select 1
              from public.base_currency_restatement_entry_map m
              where m.original_journal_entry_id = je.id
                and m.status = 'restated'
                and m.restated_journal_entry_id is not null
            )
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) is not null
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) > 0
            and jl.debit > 0
            then public._money_round(jl.debit * coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ))
          else jl.debit
        end as debit,
        case
          when jl.currency_code is not null
            and upper(jl.currency_code) <> upper(st.base)
            and jl.foreign_amount is not null
            and coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')) is not null
            and jl.credit > 0
            then public._money_round(jl.foreign_amount * coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')))
          when jl.currency_code is null
            and st.old_base is not null
            and st.lock_date is not null
            and je.entry_date::date < st.lock_date
            and not exists (
              select 1
              from public.base_currency_restatement_entry_map m
              where m.original_journal_entry_id = je.id
                and m.status = 'restated'
                and m.restated_journal_entry_id is not null
            )
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) is not null
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) > 0
            and jl.credit > 0
            then public._money_round(jl.credit * coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ))
          else jl.credit
        end as credit
      from public.journal_lines jl
      join public.journal_entries je on je.id = jl.journal_entry_id
      join acct a on a.id = jl.account_id
      cross join state st
      where public.can_view_reports()
        and p_start is not null
        and je.entry_date::date < p_start
        and (p_cost_center_id is null or jl.cost_center_id = p_cost_center_id)
    ) x
    join acct a on true
  ),
  lines as (
    select
      je.entry_date::date as entry_date,
      je.id as journal_entry_id,
      je.memo,
      je.source_table,
      je.source_id,
      je.source_event,
      x.debit,
      x.credit,
      case
        when a.normal_balance = 'credit' then (x.credit - x.debit)
        else (x.debit - x.credit)
      end as amount,
      je.created_at as entry_created_at,
      jl.created_at as line_created_at
    from public.journal_lines jl
    join public.journal_entries je on je.id = jl.journal_entry_id
    join acct a on a.id = jl.account_id
    cross join state st
    left join lateral (
      select
        case
          when jl.currency_code is not null
            and upper(jl.currency_code) <> upper(st.base)
            and jl.foreign_amount is not null
            and coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')) is not null
            and jl.debit > 0
            then public._money_round(jl.foreign_amount * coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')))
          when jl.currency_code is null
            and st.old_base is not null
            and st.lock_date is not null
            and je.entry_date::date < st.lock_date
            and not exists (
              select 1
              from public.base_currency_restatement_entry_map m
              where m.original_journal_entry_id = je.id
                and m.status = 'restated'
                and m.restated_journal_entry_id is not null
            )
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) is not null
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) > 0
            and jl.debit > 0
            then public._money_round(jl.debit * coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ))
          else jl.debit
        end as debit,
        case
          when jl.currency_code is not null
            and upper(jl.currency_code) <> upper(st.base)
            and jl.foreign_amount is not null
            and coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')) is not null
            and jl.credit > 0
            then public._money_round(jl.foreign_amount * coalesce(jl.fx_rate, public.get_fx_rate(jl.currency_code, je.entry_date::date, 'accounting')))
          when jl.currency_code is null
            and st.old_base is not null
            and st.lock_date is not null
            and je.entry_date::date < st.lock_date
            and not exists (
              select 1
              from public.base_currency_restatement_entry_map m
              where m.original_journal_entry_id = je.id
                and m.status = 'restated'
                and m.restated_journal_entry_id is not null
            )
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) is not null
            and coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ) > 0
            and jl.credit > 0
            then public._money_round(jl.credit * coalesce(
              public.get_fx_rate(st.old_base, je.entry_date::date, 'accounting'),
              public.get_fx_rate(st.old_base, je.entry_date::date, 'operational'),
              public.get_fx_rate(st.old_base, st.lock_date, 'accounting'),
              public.get_fx_rate(st.old_base, st.lock_date, 'operational')
            ))
          else jl.credit
        end as credit
    ) x on true
    where public.can_view_reports()
      and (p_start is null or je.entry_date::date >= p_start)
      and (p_end is null or je.entry_date::date <= p_end)
      and (p_cost_center_id is null or jl.cost_center_id = p_cost_center_id)
  )
  select
    l.entry_date,
    l.journal_entry_id,
    l.memo,
    l.source_table,
    l.source_id,
    l.source_event,
    l.debit,
    l.credit,
    l.amount,
    (select opening_balance from opening)
      + sum(l.amount) over (order by l.entry_date, l.entry_created_at, l.line_created_at, l.journal_entry_id) as running_balance
  from lines l
  order by l.entry_date, l.entry_created_at, l.line_created_at, l.journal_entry_id;
$$;


ALTER FUNCTION "public"."general_ledger"("p_account_code" "text", "p_start" "date", "p_end" "date", "p_cost_center_id" "uuid") OWNER TO "postgres";

--
-- Name: general_ledger("text", "date", "date", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."general_ledger"("p_account_code" "text", "p_start" "date", "p_end" "date", "p_cost_center_id" "uuid" DEFAULT NULL::"uuid", "p_journal_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("entry_date" "date", "journal_entry_id" "uuid", "memo" "text", "source_table" "text", "source_id" "text", "source_event" "text", "debit" numeric, "credit" numeric, "amount" numeric, "running_balance" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not public.can_view_accounting_reports() then
    raise exception 'not allowed';
  end if;

  return query
  with acct as (
    select coa.id, coa.normal_balance
    from public.chart_of_accounts coa
    where coa.code = p_account_code
    limit 1
  ),
  opening as (
    select coalesce(sum(
      case
        when a.normal_balance = 'credit' then (jl.credit - jl.debit)
        else (jl.debit - jl.credit)
      end
    ), 0) as opening_balance
    from public.journal_lines jl
    join public.journal_entries je on je.id = jl.journal_entry_id
    join acct a on a.id = jl.account_id
    where p_start is not null
      and je.entry_date::date < p_start
      and (p_cost_center_id is null or jl.cost_center_id = p_cost_center_id)
      and (p_journal_id is null or je.journal_id = p_journal_id)
  ),
  lines as (
    select
      je.entry_date::date as entry_date,
      je.id as journal_entry_id,
      je.memo,
      je.source_table,
      je.source_id,
      je.source_event,
      jl.debit,
      jl.credit,
      case
        when a.normal_balance = 'credit' then (jl.credit - jl.debit)
        else (jl.debit - jl.credit)
      end as amount,
      je.created_at as entry_created_at,
      jl.created_at as line_created_at
    from public.journal_lines jl
    join public.journal_entries je on je.id = jl.journal_entry_id
    join acct a on a.id = jl.account_id
    where (p_start is null or je.entry_date::date >= p_start)
      and (p_end is null or je.entry_date::date <= p_end)
      and (p_cost_center_id is null or jl.cost_center_id = p_cost_center_id)
      and (p_journal_id is null or je.journal_id = p_journal_id)
  )
  select
    l.entry_date,
    l.journal_entry_id,
    l.memo,
    l.source_table,
    l.source_id,
    l.source_event,
    l.debit,
    l.credit,
    l.amount,
    (select opening_balance from opening)
      + sum(l.amount) over (order by l.entry_date, l.entry_created_at, l.line_created_at, l.journal_entry_id) as running_balance
  from lines l
  order by l.entry_date, l.entry_created_at, l.line_created_at, l.journal_entry_id;
end;
$$;


ALTER FUNCTION "public"."general_ledger"("p_account_code" "text", "p_start" "date", "p_end" "date", "p_cost_center_id" "uuid", "p_journal_id" "uuid") OWNER TO "postgres";

--
-- Name: generate_accounting_period_snapshot("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_accounting_period_snapshot"("p_period_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_period record;
  v_as_of timestamptz;
begin
  if p_period_id is null then
    raise exception 'p_period_id is required';
  end if;

  if not public._is_migration_actor() and not public.has_admin_permission('accounting.periods.close') then
    raise exception 'not allowed';
  end if;

  select *
  into v_period
  from public.accounting_periods ap
  where ap.id = p_period_id
  for update;

  if not found then
    raise exception 'period not found';
  end if;

  if v_period.status <> 'closed' then
    raise exception 'period must be closed before snapshot';
  end if;

  v_as_of := ((v_period.end_date + 1)::timestamptz);

  insert into public.accounting_period_snapshots(period_id, account_id, closing_balance, created_by)
  select
    v_period.id,
    coa.id,
    coalesce(sum(
      case
        when coa.normal_balance = 'debit' then jl.debit - jl.credit
        else jl.credit - jl.debit
      end
    ), 0) as closing_balance,
    auth.uid()
  from public.chart_of_accounts coa
  left join public.journal_lines jl on jl.account_id = coa.id
  left join public.journal_entries je
    on je.id = jl.journal_entry_id
   and je.entry_date < v_as_of
  where coa.is_active = true
  group by coa.id
  on conflict (period_id, account_id) do nothing;
end;
$$;


ALTER FUNCTION "public"."generate_accounting_period_snapshot"("p_period_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "generate_accounting_period_snapshot"("p_period_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."generate_accounting_period_snapshot"("p_period_id" "uuid") IS 'Purpose: create snapshot rows for a closed accounting period. Source of truth: journal_entries/journal_lines up to (end_date + 1 day). Expected output: one row per active account in accounting_period_snapshots.';


