  BEGIN
    RETURN 'INV-' || lpad(nextval('public.invoice_seq')::text, 6, '0');
  END;
  $$;


ALTER FUNCTION "public"."generate_invoice_number"() OWNER TO "postgres";

--
-- Name: generate_party_document_number("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_party_document_number"("p_doc_type" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_prefix text;
  v_year text;
  v_seq bigint;
begin
  v_prefix := case lower(coalesce(p_doc_type,''))
    when 'ar_invoice' then 'ARI'
    when 'ap_bill' then 'APB'
    when 'ar_receipt' then 'ARR'
    when 'ap_payment' then 'APP'
    when 'advance' then 'ADV'
    when 'custodian' then 'CST'
    when 'ar_credit_note' then 'ARC'
    when 'ap_credit_note' then 'APC'
    when 'ar_debit_note' then 'ARD'
    when 'ap_debit_note' then 'APD'
    else 'PD'
  end;
  v_year := to_char(current_date, 'YYYY');
  v_seq := nextval('public.party_document_seq');
  return v_prefix || '-' || v_year || '-' || lpad(v_seq::text, 6, '0');
end;
$$;


ALTER FUNCTION "public"."generate_party_document_number"("p_doc_type" "text") OWNER TO "postgres";

--
-- Name: generate_transfer_number(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_transfer_number"() RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_date TEXT;
  v_seq INT;
  v_number TEXT;
BEGIN
  v_date := TO_CHAR(CURRENT_DATE, 'YYYYMMDD');
  
  SELECT COALESCE(MAX(
    CASE 
      WHEN transfer_number LIKE 'TRF-' || v_date || '-%' 
      THEN SUBSTRING(transfer_number FROM LENGTH('TRF-' || v_date || '-') + 1)::INT
      ELSE 0
    END
  ), 0) + 1
  INTO v_seq
  FROM public.warehouse_transfers;
  
  v_number := 'TRF-' || v_date || '-' || LPAD(v_seq::TEXT, 4, '0');
  
  RETURN v_number;
END;
$$;


ALTER FUNCTION "public"."generate_transfer_number"() OWNER TO "postgres";

--
-- Name: generate_transfer_number_v2("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_transfer_number_v2"("p_from_warehouse_id" "uuid", "p_transfer_date" "date" DEFAULT CURRENT_DATE) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_branch_id uuid;
begin
  v_branch_id := public.branch_from_warehouse(p_from_warehouse_id);
  v_branch_id := coalesce(v_branch_id, public.get_default_branch_id());
  return public.next_document_number('transfer', v_branch_id, coalesce(p_transfer_date, current_date));
end;
$$;


