--
-- Name: guard_admin_users_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."guard_admin_users_update"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if auth.uid() is null then
    return new;
  end if;

  if auth.uid() = old.auth_user_id and not public.is_owner() then
    if new.role is distinct from old.role then
      raise exception 'ليس لديك صلاحية لتغيير الدور.';
    end if;
    if new.permissions is distinct from old.permissions then
      raise exception 'ليس لديك صلاحية لتغيير الصلاحيات.';
    end if;
    if new.is_active is distinct from old.is_active then
      raise exception 'ليس لديك صلاحية لتغيير حالة الحساب.';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."guard_admin_users_update"() OWNER TO "postgres";

--
-- Name: has_admin_permission("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."has_admin_permission"("p" "text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role text;
  v_perms text[];
begin
  select au.role, au.permissions
  into v_role, v_perms
  from public.admin_users au
  where au.auth_user_id = auth.uid()
    and au.is_active = true;

  if v_role is null then
    return false;
  end if;

  if v_role in ('owner', 'manager') then
    return true;
  end if;

  if v_perms is not null and p = any(v_perms) then
    return true;
  end if;

  if v_role = 'cashier' then
    return p = any(array[
      'dashboard.view',
      'profile.view',
      'orders.view',
      'orders.markPaid',
      'orders.createInStore',
      'cashShifts.open',
      'cashShifts.viewOwn',
      'cashShifts.closeSelf',
      'cashShifts.cashIn',
      'cashShifts.cashOut'
    ]);
  end if;

  if v_role = 'delivery' then
    return p = any(array[
      'profile.view',
      'orders.view',
      'orders.updateStatus.delivery'
    ]);
  end if;

  if v_role = 'employee' then
    return p = any(array[
      'dashboard.view',
      'profile.view',
      'orders.view',
      'orders.markPaid'
    ]);
  end if;

  if v_role = 'accountant' then
    return p = any(array[
      'dashboard.view',
      'profile.view',
      'reports.view',
      'expenses.manage',
      'accounting.view',
      'accounting.periods.close',
      'accounting.approve'
    ]);
  end if;

  return false;
end;
$$;


ALTER FUNCTION "public"."has_admin_permission"("p" "text") OWNER TO "postgres";

--
-- Name: hash_payload("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."hash_payload"("p_payload" "jsonb") RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_text text;
begin
  v_text := coalesce(p_payload::text, '');
  begin
    return encode(digest(v_text, 'sha256'), 'hex');
  exception when others then
    return md5(v_text);
  end;
end;
$$;


ALTER FUNCTION "public"."hash_payload"("p_payload" "jsonb") OWNER TO "postgres";

--
-- Name: haversine_distance_meters(double precision, double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."haversine_distance_meters"("lat1" double precision, "lng1" double precision, "lat2" double precision, "lng2" double precision) RETURNS double precision
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select 2 * 6371000.0 * asin(
    sqrt(
      power(sin(radians((lat2 - lat1) / 2.0)), 2)
      + cos(radians(lat1)) * cos(radians(lat2))
      * power(sin(radians((lng2 - lng1) / 2.0)), 2)
    )
  );
$$;


ALTER FUNCTION "public"."haversine_distance_meters"("lat1" double precision, "lng1" double precision, "lat2" double precision, "lng2" double precision) OWNER TO "postgres";

--
-- Name: import_bank_statement("uuid", "date", "date", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."import_bank_statement"("p_bank_account_id" "uuid", "p_period_start" "date", "p_period_end" "date", "p_lines" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_batch_id uuid;
  v_line jsonb;
  v_cnt int := 0;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_bank_account_id is null then
    raise exception 'bank_account_id required';
  end if;
  insert into public.bank_statement_batches(bank_account_id, period_start, period_end, status, created_by)
  values (p_bank_account_id, p_period_start, p_period_end, 'open', auth.uid())
  returning id into v_batch_id;

  for v_line in select value from jsonb_array_elements(coalesce(p_lines, '[]'::jsonb))
  loop
    insert into public.bank_statement_lines(batch_id, txn_date, amount, currency, description, reference, external_id)
    values (
      v_batch_id,
      coalesce(nullif(v_line->>'date','')::date, current_date),
      coalesce(nullif(v_line->>'amount','')::numeric, 0),
      coalesce(nullif(v_line->>'currency',''),'YER'),
      nullif(v_line->>'description',''),
      nullif(v_line->>'reference',''),
      nullif(v_line->>'externalId','')
    )
    on conflict (batch_id, external_id) do nothing;
    v_cnt := v_cnt + 1;
  end loop;
  return v_batch_id;
end;
$$;


ALTER FUNCTION "public"."import_bank_statement"("p_bank_account_id" "uuid", "p_period_start" "date", "p_period_end" "date", "p_lines" "jsonb") OWNER TO "postgres";

--
-- Name: income_statement("date", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."income_statement"("p_start" "date", "p_end" "date", "p_cost_center_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("income" numeric, "expenses" numeric, "net_profit" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with tb as (
    select *
    from public.trial_balance(p_start, p_end, p_cost_center_id)
  )
  select
    coalesce(sum(case when tb.account_type = 'income' then (tb.credit - tb.debit) else 0 end), 0) as income,
    coalesce(sum(case when tb.account_type = 'expense' then (tb.debit - tb.credit) else 0 end), 0) as expenses,
    coalesce(sum(case when tb.account_type = 'income' then (tb.credit - tb.debit) else 0 end), 0)
      - coalesce(sum(case when tb.account_type = 'expense' then (tb.debit - tb.credit) else 0 end), 0) as net_profit
  from tb;
$$;


ALTER FUNCTION "public"."income_statement"("p_start" "date", "p_end" "date", "p_cost_center_id" "uuid") OWNER TO "postgres";

