--
-- Name: insert_party_ledger_for_entry("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."insert_party_ledger_for_entry"("p_entry_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_entry record;
  v_line record;
  v_party_id uuid;
  v_is_party_account boolean := false;
  v_dir text;
  v_amt numeric;
  v_curr text;
  v_prev numeric;
  v_delta numeric;
  v_lock_key bigint;
begin
  if p_entry_id is null then
    raise exception 'p_entry_id is required';
  end if;

  select je.id, je.entry_date, je.source_table, je.source_id, je.status
  into v_entry
  from public.journal_entries je
  where je.id = p_entry_id;

  if v_entry.id is null then
    raise exception 'journal entry not found';
  end if;

  if coalesce(v_entry.status, 'posted') <> 'posted' then
    return;
  end if;

  for v_line in
    select jl.id, jl.account_id, jl.debit, jl.credit, jl.party_id, jl.currency_code, jl.fx_rate, jl.foreign_amount
    from public.journal_lines jl
    where jl.journal_entry_id = p_entry_id
  loop
    select exists(
      select 1 from public.party_subledger_accounts psa
      where psa.account_id = v_line.account_id and psa.is_active = true
      limit 1
    ) into v_is_party_account;
    if v_is_party_account is not true then
      continue;
    end if;

    v_party_id := v_line.party_id;
    if v_party_id is null then
      v_party_id := public._resolve_party_for_entry(coalesce(v_entry.source_table,''), coalesce(v_entry.source_id,''));
    end if;
    if v_party_id is null then
      continue;
    end if;

    v_dir := case when coalesce(v_line.debit, 0) > 0 then 'debit' else 'credit' end;
    v_amt := greatest(coalesce(v_line.debit, 0), coalesce(v_line.credit, 0));
    if v_amt <= 0 then
      continue;
    end if;

    v_curr := upper(nullif(btrim(coalesce(v_line.currency_code, '')), ''));
    if v_curr is null then
      v_curr := public.get_base_currency();
    end if;

    v_lock_key := hashtextextended(v_party_id::text || '|' || v_line.account_id::text || '|' || v_curr, 0);
    perform pg_advisory_xact_lock(v_lock_key);

    select ple.running_balance
    into v_prev
    from public.party_ledger_entries ple
    where ple.party_id = v_party_id
      and ple.account_id = v_line.account_id
      and ple.currency_code = v_curr
    order by ple.occurred_at desc, ple.created_at desc, ple.id desc
    limit 1;

    v_delta := public._party_ledger_delta(v_line.account_id, v_dir, v_amt);

    insert into public.party_ledger_entries(
      party_id, account_id, journal_entry_id, journal_line_id,
      occurred_at, direction, foreign_amount, base_amount, currency_code, fx_rate, running_balance
    )
    values (
      v_party_id,
      v_line.account_id,
      p_entry_id,
      v_line.id,
      v_entry.entry_date,
      v_dir,
      v_line.foreign_amount,
      v_amt,
      v_curr,
      v_line.fx_rate,
      coalesce(v_prev, 0) + coalesce(v_delta, 0)
    )
    on conflict (journal_line_id) do nothing;
  end loop;
end;
$$;


ALTER FUNCTION "public"."insert_party_ledger_for_entry"("p_entry_id" "uuid") OWNER TO "postgres";

--
-- Name: inv_batch_vs_stock_invariant(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."inv_batch_vs_stock_invariant"() RETURNS TABLE("item_id" "text", "warehouse_id" "uuid", "batch_qty" numeric, "stock_qty" numeric)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with batch_totals as (
    select
      b.item_id::text as item_id,
      b.warehouse_id,
      sum(
        greatest(
          coalesce(b.quantity_received,0)
          - coalesce(b.quantity_consumed,0)
          - coalesce(b.quantity_transferred,0),
          0
        )
      ) as batch_qty
    from public.batches b
    where b.warehouse_id is not null
    group by 1,2
  ),
  stock_totals as (
    select
      sm.item_id::text as item_id,
      sm.warehouse_id,
      sum(coalesce(sm.available_quantity,0)) as stock_qty
    from public.stock_management sm
    where sm.warehouse_id is not null
    group by 1,2
  )
  select
    coalesce(bt.item_id, st.item_id) as item_id,
    coalesce(bt.warehouse_id, st.warehouse_id) as warehouse_id,
    coalesce(bt.batch_qty,0) as batch_qty,
    coalesce(st.stock_qty,0) as stock_qty
  from batch_totals bt
  full join stock_totals st
    on st.item_id = bt.item_id
   and st.warehouse_id = bt.warehouse_id
  where abs(coalesce(bt.batch_qty,0) - coalesce(st.stock_qty,0)) > 0.0001;
$$;


ALTER FUNCTION "public"."inv_batch_vs_stock_invariant"() OWNER TO "postgres";

--
-- Name: inv_cogs_outside_inventory_movements(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."inv_cogs_outside_inventory_movements"() RETURNS TABLE("journal_entry_id" "uuid", "movement_id" "uuid", "movement_type" "text", "cogs_account_id" "uuid")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cogs as (
    select public.get_account_id_by_code('5010') as account_id
  )
  select
    je.id as journal_entry_id,
    im.id as movement_id,
    im.movement_type,
    c.account_id as cogs_account_id
  from public.journal_entries je
  join public.inventory_movements im
    on je.source_table = 'inventory_movements'
   and je.source_id = im.id::text
  join public.journal_lines jl
    on jl.journal_entry_id = je.id
  cross join cogs c
  where c.account_id is not null
    and jl.account_id = c.account_id
    and im.movement_type not in ('sale_out','expired_out','wastage_out');
$$;


ALTER FUNCTION "public"."inv_cogs_outside_inventory_movements"() OWNER TO "postgres";

