--
-- Name: is_multi_currency_pricing_enabled(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."is_multi_currency_pricing_enabled"() RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_settings jsonb;
  v_flag boolean;
begin
  v_flag := false;
  if to_regclass('public.app_settings') is not null then
    select s.data into v_settings
    from public.app_settings s
    where s.id in ('singleton','app')
    order by (s.id = 'singleton') desc
    limit 1;
    begin
      v_flag := coalesce((v_settings->'settings'->>'ENABLE_MULTI_CURRENCY_PRICING')::boolean, false);
    exception when others then
      v_flag := false;
    end;
  end if;
  return coalesce(v_flag, false);
end;
$$;


ALTER FUNCTION "public"."is_multi_currency_pricing_enabled"() OWNER TO "postgres";

