-- Name: is_production_environment(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."is_production_environment"() RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_settings jsonb;
  v_env text;
begin
  v_env := null;
  if to_regclass('public.app_settings') is not null then
    select s.data into v_settings
    from public.app_settings s
    where s.id in ('singleton','app')
    order by (s.id = 'singleton') desc
    limit 1;
    begin
      v_env := nullif(btrim(coalesce(v_settings->'settings'->>'environment','')), '');
    exception when others then
      v_env := null;
    end;
  end if;
  return coalesce(lower(v_env) = 'production', false);
end;
$$;


