--
-- Name: item_unit_cost_to_base("text", numeric, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."item_unit_cost_to_base"("p_item_id" "text", "p_unit_cost" numeric, "p_uom_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base uuid;
  v_factor numeric;
begin
  if nullif(btrim(coalesce(p_item_id, '')), '') is null then
    raise exception 'item_id required';
  end if;
  if p_unit_cost is null then
    return 0;
  end if;

  select base_uom_id into v_base
  from public.item_uom
  where item_id = p_item_id
  limit 1;

  if v_base is null then
    raise exception 'base uom missing for item';
  end if;

  if p_uom_id is null or p_uom_id = v_base then
    return p_unit_cost;
  end if;

  select qty_in_base into v_factor
  from public.item_uom_units
  where item_id = p_item_id
    and uom_id = p_uom_id
    and is_active = true
    and (start_date is null or start_date <= current_date)
    and (end_date is null or end_date >= current_date)
  limit 1;

  if v_factor is not null and v_factor > 0 then
    return p_unit_cost / v_factor;
  end if;

  select (numerator::numeric / denominator::numeric) into v_factor
  from public.uom_conversions
  where from_uom_id = p_uom_id and to_uom_id = v_base
  limit 1;

  if v_factor is not null and v_factor > 0 then
    return p_unit_cost / v_factor;
  end if;

  raise exception 'missing item uom factor';
end;
$$;


ALTER FUNCTION "public"."item_unit_cost_to_base"("p_item_id" "text", "p_unit_cost" numeric, "p_uom_id" "uuid") OWNER TO "postgres";

