--
-- Name: list_item_cost_layers("text", "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_item_cost_layers"("p_item_id" "text", "p_warehouse_id" "uuid", "p_limit" integer DEFAULT 12) RETURNS TABLE("batch_id" "uuid", "batch_code" "text", "expiry_date" "date", "remaining_qty" numeric, "unit_cost" numeric, "received_at" timestamp with time zone, "receipt_id" "uuid", "purchase_order_id" "uuid", "purchase_order_ref" "text", "import_shipment_id" "uuid", "import_shipment_ref" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_is_food boolean;
begin
  perform public._require_staff('list_item_cost_layers');
  if p_item_id is null or btrim(p_item_id) = '' then
    raise exception 'item_id is required';
  end if;
  if p_warehouse_id is null then
    raise exception 'warehouse_id is required';
  end if;
  p_limit := greatest(1, least(coalesce(p_limit, 12), 100));

  select (coalesce(mi.category,'') = 'food')
  into v_is_food
  from public.menu_items mi
  where mi.id::text = p_item_id::text;
  v_is_food := coalesce(v_is_food, false);

  return query
  select
    b.id as batch_id,
    coalesce(nullif(btrim(b.batch_code), ''), b.id::text) as batch_code,
    b.expiry_date,
    greatest(
      coalesce(b.quantity_received,0)
      - coalesce(b.quantity_consumed,0)
      - coalesce(b.quantity_transferred,0),
      0
    )::numeric as remaining_qty,
    coalesce(b.unit_cost, 0)::numeric as unit_cost,
    pr.received_at,
    b.receipt_id,
    pr.purchase_order_id,
    coalesce(po.reference_number, pr.purchase_order_id::text) as purchase_order_ref,
    pr.import_shipment_id,
    coalesce(s.reference_number, pr.import_shipment_id::text) as import_shipment_ref
  from public.batches b
  left join public.purchase_receipts pr on pr.id = b.receipt_id
  left join public.purchase_orders po on po.id = pr.purchase_order_id
  left join public.import_shipments s on s.id = pr.import_shipment_id
  where b.item_id::text = p_item_id::text
    and b.warehouse_id = p_warehouse_id
    and coalesce(b.status,'active') = 'active'
    and coalesce(b.qc_status,'') = 'released'
    and not exists (
      select 1 from public.batch_recalls br
      where br.batch_id = b.id and br.status = 'active'
    )
    and greatest(
      coalesce(b.quantity_received,0)
      - coalesce(b.quantity_consumed,0)
      - coalesce(b.quantity_transferred,0),
      0
    ) > 0
    and (
      not v_is_food
      or (b.expiry_date is not null and b.expiry_date >= current_date)
    )
  order by b.expiry_date asc nulls last, b.created_at asc, b.id asc
  limit p_limit;
end;
$$;


ALTER FUNCTION "public"."list_item_cost_layers"("p_item_id" "text", "p_warehouse_id" "uuid", "p_limit" integer) OWNER TO "postgres";

--
-- Name: list_item_uom_units("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_item_uom_units"("p_item_id" "text") RETURNS TABLE("uom_id" "uuid", "uom_code" "text", "uom_name" "text", "qty_in_base" numeric, "is_active" boolean, "is_default_purchase" boolean, "is_default_sales" boolean)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    iuu.uom_id,
    u.code as uom_code,
    u.name as uom_name,
    iuu.qty_in_base,
    iuu.is_active,
    iuu.is_default_purchase,
    iuu.is_default_sales
  from public.item_uom_units iuu
  join public.uom u on u.id = iuu.uom_id
  where iuu.item_id = p_item_id
  order by
    case when iuu.qty_in_base = 1 then 0 else 1 end,
    lower(u.code);
$$;


