--
-- Name: list_party_open_items("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_party_open_items"("p_party_id" "uuid", "p_currency" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "party_id" "uuid", "journal_entry_id" "uuid", "journal_line_id" "uuid", "account_code" "text", "account_name" "text", "direction" "text", "occurred_at" timestamp with time zone, "due_date" "date", "item_role" "text", "item_type" "text", "source_table" "text", "source_id" "text", "source_event" "text", "currency_code" "text", "foreign_amount" numeric, "base_amount" numeric, "open_foreign_amount" numeric, "open_base_amount" numeric, "status" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    poi.id,
    poi.party_id,
    poi.journal_entry_id,
    poi.journal_line_id,
    coa.code as account_code,
    coa.name as account_name,
    poi.direction,
    poi.occurred_at,
    poi.due_date,
    poi.item_role,
    poi.item_type,
    poi.source_table,
    poi.source_id,
    poi.source_event,
    poi.currency_code,
    poi.foreign_amount,
    poi.base_amount,
    poi.open_foreign_amount,
    poi.open_base_amount,
    poi.status
  from public.party_open_items poi
  join public.chart_of_accounts coa on coa.id = poi.account_id
  where public.has_admin_permission('accounting.view')
    and poi.party_id = p_party_id
    and (p_currency is null or upper(poi.currency_code) = upper(p_currency))
    and (p_status is null or poi.status = p_status or (p_status = 'open_active' and poi.status in ('open','partially_settled')))
  order by poi.occurred_at asc, poi.created_at asc;
$$;


