--
-- Name: lock_batch_foreign_snapshot(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."lock_batch_foreign_snapshot"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if old.foreign_unit_cost is distinct from new.foreign_unit_cost
     or old.foreign_currency is distinct from new.foreign_currency
     or old.fx_rate_at_receipt is distinct from new.fx_rate_at_receipt then
    raise exception 'Foreign cost snapshot cannot be modified after receipt';
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."lock_batch_foreign_snapshot"() OWNER TO "postgres";

--
-- Name: log_admin_changes(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."log_admin_changes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
    VALUES (
      'create',
      'admin_users',
      concat('Created admin user ', COALESCE(NEW.full_name, NEW.username), ' with role ', NEW.role),
      auth.uid(),
      now(),
      jsonb_build_object(
        'user_id', NEW.auth_user_id,
        'username', NEW.username,
        'full_name', NEW.full_name,
        'role', NEW.role,
        'permissions', NEW.permissions
      )
    );
    
  ELSIF TG_OP = 'UPDATE' THEN
    -- Log role changes
    IF OLD.role IS DISTINCT FROM NEW.role THEN
      INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
      VALUES (
        'role_change',
        'admin_users',
        concat('Role changed for user ', COALESCE(NEW.full_name, NEW.username), ' from ', OLD.role, ' to ', NEW.role),
        auth.uid(),
        now(),
        jsonb_build_object(
          'user_id', NEW.auth_user_id,
          'username', NEW.username,
          'full_name', NEW.full_name,
          'old_role', OLD.role,
          'new_role', NEW.role
        )
      );
    END IF;
    
    -- Log permission changes
    IF OLD.permissions IS DISTINCT FROM NEW.permissions THEN
      INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
      VALUES (
        'permission_change',
        'admin_users',
        concat('Permissions changed for user ', COALESCE(NEW.full_name, NEW.username)),
        auth.uid(),
        now(),
        jsonb_build_object(
          'user_id', NEW.auth_user_id,
          'username', NEW.username,
          'full_name', NEW.full_name,
          'old_permissions', OLD.permissions,
          'new_permissions', NEW.permissions
        )
      );
    END IF;
    
    -- Log activation/deactivation
    IF OLD.is_active IS DISTINCT FROM NEW.is_active THEN
      INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
      VALUES (
        CASE WHEN NEW.is_active THEN 'activate' ELSE 'deactivate' END,
        'admin_users',
        concat(
          CASE WHEN NEW.is_active THEN 'Activated' ELSE 'Deactivated' END,
          ' user ', COALESCE(NEW.full_name, NEW.username)
        ),
        auth.uid(),
        now(),
        jsonb_build_object(
          'user_id', NEW.auth_user_id,
          'username', NEW.username,
          'full_name', NEW.full_name,
          'is_active', NEW.is_active
        )
      );
    END IF;
    
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
    VALUES (
      'delete',
      'admin_users',
      concat('Deleted admin user ', COALESCE(OLD.full_name, OLD.username)),
      auth.uid(),
      now(),
      jsonb_build_object(
        'user_id', OLD.auth_user_id,
        'username', OLD.username,
        'full_name', OLD.full_name,
        'role', OLD.role,
        'permissions', OLD.permissions
      )
    );
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."log_admin_changes"() OWNER TO "postgres";

--
-- Name: FUNCTION "log_admin_changes"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."log_admin_changes"() IS 'Audit trigger: Logs all admin user role and permission changes';


--
-- Name: log_coa_changes(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."log_coa_changes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
    VALUES (
      'create',
      'chart_of_accounts',
      concat('Created account ', NEW.code, ' - ', NEW.name),
      auth.uid(),
      now(),
      jsonb_build_object(
        'account_id', NEW.id,
        'code', NEW.code,
        'name', NEW.name,
        'account_type', NEW.account_type,
        'normal_balance', NEW.normal_balance
      )
    );
    
  ELSIF TG_OP = 'UPDATE' THEN
    INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
    VALUES (
      'update',
      'chart_of_accounts',
      concat('Updated account ', NEW.code, ' - ', NEW.name),
      auth.uid(),
      now(),
      jsonb_build_object(
        'account_id', NEW.id,
        'code', NEW.code,
        'old_name', OLD.name,
        'new_name', NEW.name,
        'old_active', OLD.is_active,
        'new_active', NEW.is_active
      )
    );
    
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
    VALUES (
      'delete',
      'chart_of_accounts',
      concat('Deleted account ', OLD.code, ' - ', OLD.name),
      auth.uid(),
      now(),
      jsonb_build_object(
        'account_id', OLD.id,
        'code', OLD.code,
        'name', OLD.name
      )
    );
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


