--
-- Name: manage_menu_item_stock("uuid", numeric, "text", "text", "uuid", numeric, boolean, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."manage_menu_item_stock"("p_item_id" "uuid", "p_quantity" numeric, "p_unit" "text", "p_reason" "text", "p_user_id" "uuid" DEFAULT "auth"."uid"(), "p_low_stock_threshold" numeric DEFAULT 5, "p_is_wastage" boolean DEFAULT false, "p_batch_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_wh uuid;
  v_current record;
  v_old_qty numeric;
  v_old_avg numeric;
  v_diff numeric;
  v_batch record;
  v_reserved_other numeric;
  v_available numeric;
  v_needed numeric;
  v_alloc numeric;
  v_unit_cost numeric;
  v_total_cost numeric;
  v_movement_id uuid;
  v_history_id uuid;
  v_movement_type text;
  v_new_batch_id uuid;
begin
  if p_reason is null or btrim(p_reason) = '' then
    raise exception 'reason is required';
  end if;
  if auth.uid() is null then
    raise exception 'not authenticated';
  end if;
  if not public.has_admin_permission('stock.manage') then
    raise exception 'not allowed';
  end if;

  if p_item_id is null then
    raise exception 'item_id is required';
  end if;
  if p_quantity is null or p_quantity < 0 then
    raise exception 'invalid quantity';
  end if;

  v_wh := public._resolve_default_warehouse_id();
  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  insert into public.stock_management(item_id, warehouse_id, available_quantity, reserved_quantity, unit, low_stock_threshold, avg_cost, last_updated, updated_at, data)
  select p_item_id::text, v_wh, 0, 0, coalesce(p_unit, 'piece'), coalesce(p_low_stock_threshold, 5), 0, now(), now(), '{}'::jsonb
  on conflict (item_id, warehouse_id) do nothing;

  select coalesce(sm.available_quantity, 0), coalesce(sm.avg_cost, 0)
  into v_old_qty, v_old_avg
  from public.stock_management sm
  where sm.item_id::text = p_item_id::text
    and sm.warehouse_id = v_wh
  for update;

  v_diff := p_quantity - v_old_qty;

  if v_diff = 0 then
    update public.stock_management
    set unit = coalesce(p_unit, unit),
        low_stock_threshold = coalesce(p_low_stock_threshold, low_stock_threshold),
        updated_at = now(),
        last_updated = now()
    where item_id::text = p_item_id::text
      and warehouse_id = v_wh;
    return;
  end if;

  if v_diff > 0 then
    v_movement_type := 'adjust_in';
    v_new_batch_id := coalesce(p_batch_id, gen_random_uuid());

    insert into public.batch_balances(item_id, batch_id, warehouse_id, quantity, expiry_date)
    values (p_item_id::text, v_new_batch_id, v_wh, v_diff, null)
    on conflict (item_id, batch_id, warehouse_id)
    do update set
      quantity = public.batch_balances.quantity + excluded.quantity,
      updated_at = now();

    v_unit_cost := v_old_avg;
    v_total_cost := v_diff * v_unit_cost;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      p_item_id::text, v_movement_type, v_diff, v_unit_cost, v_total_cost,
      'stock_history', null, now(), p_user_id,
      jsonb_build_object('reason', p_reason, 'warehouseId', v_wh, 'batchId', v_new_batch_id),
      v_new_batch_id, v_wh
    )
    returning id into v_movement_id;
    perform public.post_inventory_movement(v_movement_id);
  else
    v_movement_type := case when p_is_wastage then 'wastage_out' else 'adjust_out' end;
    v_needed := abs(v_diff);

    for v_batch in
      select bb.batch_id, bb.quantity, bb.expiry_date
      from public.batch_balances bb
      where bb.item_id = p_item_id::text
        and bb.warehouse_id = v_wh
        and bb.quantity > 0
        and (p_batch_id is null or bb.batch_id = p_batch_id)
      order by bb.expiry_date asc nulls last, bb.batch_id asc
    loop
      exit when v_needed <= 0;

      select coalesce(sum(br.quantity), 0)
      into v_reserved_other
      from public.batch_reservations br
      where br.item_id = p_item_id::text
        and br.warehouse_id = v_wh
        and br.batch_id = v_batch.batch_id;

      v_available := greatest(coalesce(v_batch.quantity, 0) - coalesce(v_reserved_other, 0), 0);
      if v_available <= 0 then
        continue;
      end if;

      v_alloc := least(v_needed, v_available);
      if v_alloc <= 0 then
        continue;
      end if;

      update public.batch_balances
      set quantity = quantity - v_alloc,
          updated_at = now()
      where item_id = p_item_id::text
        and batch_id = v_batch.batch_id
        and warehouse_id = v_wh;

      select im.unit_cost
      into v_unit_cost
      from public.inventory_movements im
      where im.batch_id = v_batch.batch_id
        and im.item_id::text = p_item_id::text
        and im.movement_type = 'purchase_in'
      order by im.occurred_at asc
      limit 1;
      v_unit_cost := coalesce(v_unit_cost, v_old_avg);
      v_total_cost := v_alloc * v_unit_cost;

      insert into public.inventory_movements(
        item_id, movement_type, quantity, unit_cost, total_cost,
        reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
      )
      values (
        p_item_id::text, v_movement_type, v_alloc, v_unit_cost, v_total_cost,
        'stock_history', null, now(), p_user_id,
        jsonb_build_object('reason', p_reason, 'warehouseId', v_wh, 'batchId', v_batch.batch_id, 'expiryDate', v_batch.expiry_date),
        v_batch.batch_id, v_wh
      )
      returning id into v_movement_id;

      perform public.post_inventory_movement(v_movement_id);

      v_needed := v_needed - v_alloc;
    end loop;

    if v_needed > 0 then
      raise exception 'insufficient unreserved stock for adjustment';
    end if;
  end if;

  v_history_id := gen_random_uuid();
  insert into public.stock_history(id, item_id, date, data)
  values (v_history_id, p_item_id::text, now()::date, jsonb_build_object('reason', p_reason, 'changedBy', p_user_id, 'fromQuantity', v_old_qty, 'toQuantity', p_quantity));

  update public.stock_management
  set available_quantity = coalesce((
        select sum(bb.quantity)
        from public.batch_balances bb
        where bb.item_id = p_item_id::text
          and bb.warehouse_id = v_wh
      ), 0),
      reserved_quantity = coalesce((
        select sum(br.quantity)
        from public.batch_reservations br
        where br.item_id = p_item_id::text
          and br.warehouse_id = v_wh
      ), 0),
      unit = coalesce(p_unit, unit),
      low_stock_threshold = coalesce(p_low_stock_threshold, low_stock_threshold),
      avg_cost = v_old_avg,
      last_updated = now(),
      updated_at = now()
  where item_id::text = p_item_id::text
    and warehouse_id = v_wh;

  update public.menu_items
  set data = jsonb_set(data, '{availableStock}', to_jsonb(p_quantity), true),
      updated_at = now()
  where id = p_item_id::text;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    case when p_is_wastage then 'wastage_recorded' else 'stock_update' end,
    'stock',
    p_reason,
    p_user_id,
    now(),
    jsonb_build_object('itemId', p_item_id::text, 'warehouseId', v_wh, 'fromQuantity', v_old_qty, 'toQuantity', p_quantity, 'delta', v_diff)
  );
end;
$$;


ALTER FUNCTION "public"."manage_menu_item_stock"("p_item_id" "uuid", "p_quantity" numeric, "p_unit" "text", "p_reason" "text", "p_user_id" "uuid", "p_low_stock_threshold" numeric, "p_is_wastage" boolean, "p_batch_id" "uuid") OWNER TO "postgres";

--
-- Name: mark_accounting_document_printed("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."mark_accounting_document_printed"("p_document_id" "uuid", "p_template" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc record;
begin
  if not public.has_admin_permission('accounting.view') then
    raise exception 'not allowed';
  end if;

  update public.accounting_documents
  set print_count = print_count + 1,
      last_printed_at = now(),
      last_printed_template = nullif(btrim(coalesce(p_template,'')),'')
  where id = p_document_id;

  select * into v_doc from public.accounting_documents where id = p_document_id;
  if found then
    insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
    values (
      'print',
      'documents',
      concat('Printed document ', coalesce(v_doc.document_number, v_doc.id::text)),
      auth.uid(),
      now(),
      jsonb_build_object(
        'documentId', v_doc.id,
        'documentType', v_doc.document_type,
        'documentNumber', v_doc.document_number,
        'sourceTable', v_doc.source_table,
        'sourceId', v_doc.source_id,
        'template', nullif(btrim(coalesce(p_template,'')),'')
      )
    );
  end if;
end;
$$;


ALTER FUNCTION "public"."mark_accounting_document_printed"("p_document_id" "uuid", "p_template" "text") OWNER TO "postgres";

--
-- Name: next_document_number("text", "uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."next_document_number"("p_doc_type" "text", "p_branch_id" "uuid", "p_doc_date" "date") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_seq integer;
begin
  v_seq := public.next_document_sequence(p_doc_type, p_branch_id, p_doc_date);
  return public.format_document_number(p_doc_type, p_branch_id, p_doc_date, v_seq);
end;
$$;


ALTER FUNCTION "public"."next_document_number"("p_doc_type" "text", "p_branch_id" "uuid", "p_doc_date" "date") OWNER TO "postgres";

--
-- Name: next_document_sequence("text", "uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."next_document_sequence"("p_doc_type" "text", "p_branch_id" "uuid", "p_doc_date" "date") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_year integer;
  v_new integer;
begin
  if p_branch_id is null then
    raise exception 'branch_id is required';
  end if;
  v_year := extract(year from coalesce(p_doc_date, current_date))::integer;

  insert into public.document_sequences(doc_type, branch_id, year, last_number, updated_at)
  values (lower(coalesce(p_doc_type, 'doc')), p_branch_id, v_year, 1, now())
  on conflict (doc_type, branch_id, year)
  do update set
    last_number = public.document_sequences.last_number + 1,
    updated_at = now()
  returning last_number into v_new;

  return v_new;
end;
$$;


ALTER FUNCTION "public"."next_document_sequence"("p_doc_type" "text", "p_branch_id" "uuid", "p_doc_date" "date") OWNER TO "postgres";

--
-- Name: normalize_menu_item_costs(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."normalize_menu_item_costs"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_cnt int := 0;
  v_item record;
  v_last_base numeric;
  v_avg numeric;
begin
  for v_item in
    select mi.id as item_id
    from public.menu_items mi
    where coalesce(mi.status, 'active') = 'active'
  loop
    select
      coalesce(pi.unit_cost_base,
               coalesce(pi.unit_cost_foreign, pi.unit_cost, 0)
                 * coalesce(po.fx_rate, public.get_fx_rate(coalesce(po.currency,'SAR'), coalesce(po.created_at, now())::date, 'accounting')))
    into v_last_base
    from public.purchase_items pi
    join public.purchase_orders po on po.id = pi.purchase_order_id
    where pi.item_id = v_item.item_id
    order by coalesce(po.updated_at, po.created_at) desc
    limit 1;

    if v_last_base is null then
      select im.unit_cost
      into v_last_base
      from public.inventory_movements im
      where im.item_id::text = v_item.item_id::text
        and im.movement_type = 'purchase_in'
      order by im.occurred_at desc
      limit 1;
    end if;

    select sm.avg_cost
    into v_avg
    from public.stock_management sm
    where sm.item_id::text = v_item.item_id::text
    order by sm.updated_at desc
    limit 1;

    update public.menu_items
    set buying_price = public._money_round(greatest(0, coalesce(v_last_base, buying_price))),
        cost_price = public._money_round(greatest(0, coalesce(v_avg, coalesce(v_last_base, cost_price)))),
        updated_at = now()
    where id = v_item.item_id;
    v_cnt := v_cnt + 1;
  end loop;

  return v_cnt;
end;
$$;


ALTER FUNCTION "public"."normalize_menu_item_costs"() OWNER TO "postgres";

--
-- Name: notify_delivery_assignment_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."notify_delivery_assignment_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_old text;
  v_new text;
  v_link text;
BEGIN
  v_old := COALESCE(NULLIF(OLD.data->>'assignedDeliveryUserId',''), NULL);
  v_new := COALESCE(NULLIF(NEW.data->>'assignedDeliveryUserId',''), NULL);
  v_link := '/admin/orders';
  
  IF v_old IS DISTINCT FROM v_new THEN
    IF v_new IS NOT NULL THEN
      INSERT INTO public.notifications (user_id, title, message, type, link)
      VALUES (v_new::uuid, 'تم إسناد طلب إليك 🛵', 'طلب #' || substring(NEW.id::text, 1, 6), 'order_update', v_link);
    END IF;
    IF v_old IS NOT NULL AND v_new IS NULL THEN
      INSERT INTO public.notifications (user_id, title, message, type, link)
      VALUES (v_old::uuid, 'أُلغي إسناد أحد الطلبات', 'طلب #' || substring(NEW.id::text, 1, 6), 'order_update', v_link);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_delivery_assignment_change"() OWNER TO "postgres";

--
-- Name: notify_order_created(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."notify_order_created"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_title text;
  v_message text;
  v_link text;
  r_admin record;
BEGIN
  v_link := '/order/' || NEW.id::text;
  
  IF NEW.customer_auth_user_id IS NOT NULL THEN
    v_title := 'تم استلام طلبك ✅';
    v_message := 'جارٍ معالجة طلبك رقم #' || substring(NEW.id::text, 1, 6);
    INSERT INTO public.notifications (user_id, title, message, type, link)
    VALUES (NEW.customer_auth_user_id, v_title, v_message, 'order_update', v_link);
  END IF;
  
  FOR r_admin IN
    SELECT au.auth_user_id
    FROM public.admin_users au
    WHERE au.is_active = true
      AND au.role IN ('owner','manager')
  LOOP
    INSERT INTO public.notifications (user_id, title, message, type, link)
    VALUES (r_admin.auth_user_id, 'طلب جديد وصل 🧾', 'طلب جديد #' || substring(NEW.id::text, 1, 6), 'order_update', v_link);
  END LOOP;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_order_created"() OWNER TO "postgres";

--
-- Name: notify_order_status_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."notify_order_status_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_title text;
  v_message text;
  v_link text;
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    v_link := '/order/' || NEW.id::text;
    CASE NEW.status
      WHEN 'preparing' THEN
        v_title := 'طلبك قيد التحضير 🍳';
        v_message := 'بدأنا في تجهيز طلبك رقم #' || substring(NEW.id::text, 1, 6);
      WHEN 'out_for_delivery' THEN
        v_title := 'طلبك في الطريق 🛵';
        v_message := 'خرج المندوب لتوصيل طلبك رقم #' || substring(NEW.id::text, 1, 6);
      WHEN 'delivered' THEN
        v_title := 'تم التوصيل 🎉';
        v_message := 'نتمنى لك تجربة ممتعة! تم توصيل الطلب #' || substring(NEW.id::text, 1, 6);
      WHEN 'cancelled' THEN
        v_title := 'تم إلغاء الطلب ❌';
        v_message := 'عذراً، تم إلغاء طلبك رقم #' || substring(NEW.id::text, 1, 6);
      WHEN 'scheduled' THEN
        v_title := 'تم جدولة الطلب 📅';
        v_message := 'تم تأكيد جدولة طلبك رقم #' || substring(NEW.id::text, 1, 6);
      ELSE
        RETURN NEW;
    END CASE;
    IF NEW.customer_auth_user_id IS NOT NULL THEN
      BEGIN
        INSERT INTO public.notifications (user_id, title, message, type, link)
        VALUES (NEW.customer_auth_user_id, v_title, v_message, 'order_update', v_link);
      EXCEPTION WHEN others THEN
        PERFORM NULL;
      END;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_order_status_change"() OWNER TO "postgres";

--
-- Name: open_cash_shift_for_cashier("uuid", numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."open_cash_shift_for_cashier"("p_cashier_id" "uuid", "p_start_amount" numeric) RETURNS "public"."cash_shifts"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_role text;
  v_exists int;
  v_shift public.cash_shifts%rowtype;
begin
  if auth.uid() is null then
    raise exception 'not allowed';
  end if;

  select au.role
  into v_actor_role
  from public.admin_users au
  where au.auth_user_id = auth.uid()
    and au.is_active = true;

  if v_actor_role is null or v_actor_role not in ('owner','manager') then
    raise exception 'not allowed';
  end if;

  if p_cashier_id is null then
    raise exception 'p_cashier_id is required';
  end if;

  if coalesce(p_start_amount, 0) < 0 then
    raise exception 'invalid start amount';
  end if;

  select count(1)
  into v_exists
  from public.cash_shifts s
  where s.cashier_id = p_cashier_id
    and coalesce(s.status, 'open') = 'open';

  if v_exists > 0 then
    raise exception 'cashier already has an open shift';
  end if;

  insert into public.cash_shifts(cashier_id, opened_at, start_amount, status)
  values (p_cashier_id, now(), coalesce(p_start_amount, 0), 'open')
  returning * into v_shift;

  return v_shift;
end;
$$;


ALTER FUNCTION "public"."open_cash_shift_for_cashier"("p_cashier_id" "uuid", "p_start_amount" numeric) OWNER TO "postgres";

--
-- Name: order_delivered_at("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."order_delivered_at"("p_order_id" "uuid") RETURNS timestamp with time zone
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select coalesce(
    (
      select min(oe.created_at)
      from public.order_events oe
      where oe.order_id = p_order_id
        and oe.to_status = 'delivered'
    ),
    (
      select case when o.status = 'delivered' then o.updated_at else null end
      from public.orders o
      where o.id = p_order_id
      limit 1
    )
  );
$$;


ALTER FUNCTION "public"."order_delivered_at"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: order_fx_rate("text", timestamp with time zone, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."order_fx_rate"("p_currency" "text", "p_date" timestamp with time zone, "p_fx_rate" numeric) RETURNS numeric
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select coalesce(
    nullif(p_fx_rate, 0),
    public.get_fx_rate(
      coalesce(nullif(btrim(coalesce(p_currency, '')), ''), public.get_base_currency()),
      p_date::date,
      'operational'
    ),
    1
  );
$$;


ALTER FUNCTION "public"."order_fx_rate"("p_currency" "text", "p_date" timestamp with time zone, "p_fx_rate" numeric) OWNER TO "postgres";

--
-- Name: orders_validate_delivery_zone_radius(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."orders_validate_delivery_zone_radius"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_source text;
  v_zone_id uuid;
  v_lat double precision;
  v_lng double precision;
  v_zone_lat double precision;
  v_zone_lng double precision;
  v_radius double precision;
  v_is_active boolean;
  v_dist double precision;
begin
  v_source := coalesce(nullif(new.data->>'orderSource',''), '');
  if v_source = 'in_store' then
    return new;
  end if;

  v_zone_id := new.delivery_zone_id;
  if v_zone_id is null
     and nullif(new.data->>'deliveryZoneId','') is not null
     and (new.data->>'deliveryZoneId') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$'
  then
    v_zone_id := (new.data->>'deliveryZoneId')::uuid;
  end if;

  if v_zone_id is null then
    raise exception 'يرجى اختيار منطقة توصيل صحيحة.' using errcode = 'P0001';
  end if;

  if jsonb_typeof(new.data->'location') <> 'object' then
    raise exception 'عذرًا، لا يمكن إرسال الطلب بدون تحديد موقعك على الخريطة.' using errcode = 'P0001';
  end if;

  v_lat := nullif(new.data->'location'->>'lat','')::double precision;
  v_lng := nullif(new.data->'location'->>'lng','')::double precision;
  if v_lat is null or v_lng is null then
    raise exception 'عذرًا، تعذر قراءة إحداثيات موقعك.' using errcode = 'P0001';
  end if;

  select
    nullif(dz.data->'coordinates'->>'lat','')::double precision,
    nullif(dz.data->'coordinates'->>'lng','')::double precision,
    nullif(dz.data->'coordinates'->>'radius','')::double precision,
    dz.is_active
  into v_zone_lat, v_zone_lng, v_radius, v_is_active
  from public.delivery_zones dz
  where dz.id = v_zone_id;

  if not found then
    raise exception 'منطقة التوصيل غير موجودة.' using errcode = 'P0001';
  end if;

  if not coalesce(v_is_active, false) then
    raise exception 'منطقة التوصيل غير مفعلة.' using errcode = 'P0001';
  end if;

  if v_zone_lat is null or v_zone_lng is null or v_radius is null or v_radius <= 0 then
    raise exception 'تعذر التحقق من نطاق منطقة التوصيل. يرجى التواصل مع الإدارة.' using errcode = 'P0001';
  end if;

  v_dist := public.haversine_distance_meters(v_lat, v_lng, v_zone_lat, v_zone_lng);
  if v_dist > v_radius then
    raise exception 'عذرًا، موقعك خارج نطاق منطقة التوصيل.' using errcode = 'P0001';
  end if;

  new.delivery_zone_id := v_zone_id;
  new.data := jsonb_set(new.data, '{deliveryZoneId}', to_jsonb(v_zone_id::text), true);
  return new;
end;
$_$;


ALTER FUNCTION "public"."orders_validate_delivery_zone_radius"() OWNER TO "postgres";

--
-- Name: owner_finalize_approval_request("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."owner_finalize_approval_request"("p_request_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_req record;
begin
  if not public.is_owner() then
    raise exception 'not authorized';
  end if;
  select *
  into v_req
  from public.approval_requests
  where id = p_request_id
  for update;
  if not found then
    raise exception 'approval request not found';
  end if;
  if v_req.status <> 'pending' then
    return;
  end if;
  update public.approval_steps
  set status = 'approved',
      action_by = auth.uid(),
      action_at = now()
  where request_id = p_request_id
    and status = 'pending';
  update public.approval_requests
  set status = 'approved',
      approved_by = auth.uid(),
      approved_at = now()
  where id = p_request_id
    and status = 'pending';
end;
$$;


ALTER FUNCTION "public"."owner_finalize_approval_request"("p_request_id" "uuid") OWNER TO "postgres";

--
-- Name: party_ledger_statement("uuid", "text", "text", "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."party_ledger_statement"("p_party_id" "uuid", "p_account_code" "text" DEFAULT NULL::"text", "p_currency" "text" DEFAULT NULL::"text", "p_start" "date" DEFAULT NULL::"date", "p_end" "date" DEFAULT NULL::"date") RETURNS TABLE("occurred_at" timestamp with time zone, "journal_entry_id" "uuid", "journal_line_id" "uuid", "account_code" "text", "account_name" "text", "direction" "text", "foreign_amount" numeric, "base_amount" numeric, "currency_code" "text", "fx_rate" numeric, "memo" "text", "source_table" "text", "source_id" "text", "source_event" "text", "running_balance" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with acct as (
    select coa.id
    from public.chart_of_accounts coa
    where p_account_code is null or coa.code = p_account_code
  )
  select
    ple.occurred_at,
    ple.journal_entry_id,
    ple.journal_line_id,
    coa.code as account_code,
    coa.name as account_name,
    ple.direction,
    ple.foreign_amount,
    ple.base_amount,
    ple.currency_code,
    ple.fx_rate,
    jl.line_memo as memo,
    je.source_table,
    je.source_id,
    je.source_event,
    ple.running_balance
  from public.party_ledger_entries ple
  join public.journal_entries je on je.id = ple.journal_entry_id
  join public.journal_lines jl on jl.id = ple.journal_line_id
  join public.chart_of_accounts coa on coa.id = ple.account_id
  where public.has_admin_permission('accounting.view')
    and ple.party_id = p_party_id
    and (p_currency is null or upper(ple.currency_code) = upper(p_currency))
    and (p_start is null or ple.occurred_at::date >= p_start)
    and (p_end is null or ple.occurred_at::date <= p_end)
    and (p_account_code is null or ple.account_id in (select id from acct))
  order by ple.occurred_at asc, ple.created_at asc, ple.id asc;
$$;


ALTER FUNCTION "public"."party_ledger_statement"("p_party_id" "uuid", "p_account_code" "text", "p_currency" "text", "p_start" "date", "p_end" "date") OWNER TO "postgres";

--
-- Name: party_ledger_statement_v2("uuid", "text", "text", "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."party_ledger_statement_v2"("p_party_id" "uuid", "p_account_code" "text" DEFAULT NULL::"text", "p_currency" "text" DEFAULT NULL::"text", "p_start" "date" DEFAULT NULL::"date", "p_end" "date" DEFAULT NULL::"date") RETURNS TABLE("occurred_at" timestamp with time zone, "journal_entry_id" "uuid", "journal_line_id" "uuid", "account_code" "text", "account_name" "text", "direction" "text", "foreign_amount" numeric, "base_amount" numeric, "currency_code" "text", "fx_rate" numeric, "memo" "text", "source_table" "text", "source_id" "text", "source_event" "text", "running_balance" numeric, "open_base_amount" numeric, "open_foreign_amount" numeric, "open_status" "text", "allocations" "jsonb")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with acct as (
    select coa.id
    from public.chart_of_accounts coa
    where p_account_code is null or coa.code = p_account_code
  ),
  base_ple as (
    select
      ple.occurred_at,
      ple.journal_entry_id,
      ple.journal_line_id,
      coa.code as account_code,
      coa.name as account_name,
      ple.direction,
      ple.foreign_amount,
      ple.base_amount,
      ple.currency_code,
      ple.fx_rate,
      jl.line_memo as memo,
      je.source_table,
      je.source_id,
      je.source_event,
      ple.running_balance
    from public.party_ledger_entries ple
    join public.journal_entries je on je.id = ple.journal_entry_id
    join public.journal_lines jl on jl.id = ple.journal_line_id
    join public.chart_of_accounts coa on coa.id = ple.account_id
    where public.has_admin_permission('accounting.view')
      and ple.party_id = p_party_id
      and (p_currency is null or upper(ple.currency_code) = upper(p_currency))
      and (p_start is null or ple.occurred_at::date >= p_start)
      and (p_end is null or ple.occurred_at::date <= p_end)
      and (p_account_code is null or ple.account_id in (select id from acct))
  ),
  use_fallback as (
    select not exists(select 1 from base_ple) as use_fallback
  ),
  party_links as (
    select fpl.linked_entity_type, fpl.linked_entity_id, fpl.role
    from public.financial_party_links fpl
    where fpl.party_id = p_party_id
  ),
  supplier_ids as (
    select linked_entity_id::uuid as supplier_id
    from party_links
    where role = 'supplier' and linked_entity_type = 'suppliers'
  ),
  customer_ids as (
    select linked_entity_id::uuid as customer_id
    from party_links
    where role = 'customer' and linked_entity_type = 'customers'
  ),
  base_currency as (
    select public.get_base_currency() as code
  ),
  ap_account as (
    select coa.code, coa.name
    from public.chart_of_accounts coa
    where coa.code = '2010'
    limit 1
  ),
  ar_account as (
    select coa.code, coa.name
    from public.chart_of_accounts coa
    where coa.code = '1200'
    limit 1
  ),
  ap_orders as (
    select
      coalesce(po.purchase_date::timestamptz, po.created_at, now()) as occurred_at,
      po.id as journal_entry_id,
      po.id as journal_line_id,
      coalesce(ap_account.code, '2010') as account_code,
      coalesce(ap_account.name, 'Accounts Payable') as account_name,
      'credit' as direction,
      case
        when upper(coalesce(po.currency, base_currency.code)) <> upper(base_currency.code) then coalesce(po.total_amount, 0)
        else null
      end as foreign_amount,
      coalesce(
        po.base_total,
        case when upper(coalesce(po.currency, base_currency.code)) = upper(base_currency.code) then po.total_amount else null end,
        0
      ) as base_amount,
      upper(coalesce(po.currency, base_currency.code)) as currency_code,
      coalesce(po.fx_rate, 1) as fx_rate,
      po.reference_number as memo,
      'purchase_orders' as source_table,
      po.id::text as source_id,
      'purchase' as source_event,
      null::numeric as running_balance
    from public.purchase_orders po
    join supplier_ids s on s.supplier_id = po.supplier_id
    cross join base_currency
    left join ap_account on true
    where (p_currency is null or upper(coalesce(po.currency, base_currency.code)) = upper(p_currency))
      and (p_start is null or coalesce(po.purchase_date::date, po.created_at::date) >= p_start)
      and (p_end is null or coalesce(po.purchase_date::date, po.created_at::date) <= p_end)
  ),
  ap_payments as (
    select
      p.occurred_at as occurred_at,
      p.id as journal_entry_id,
      p.id as journal_line_id,
      coalesce(ap_account.code, '2010') as account_code,
      coalesce(ap_account.name, 'Accounts Payable') as account_name,
      'debit' as direction,
      case
        when upper(coalesce(p.currency, base_currency.code)) <> upper(base_currency.code) then coalesce(p.amount, 0)
        else null
      end as foreign_amount,
      coalesce(
        p.base_amount,
        case when upper(coalesce(p.currency, base_currency.code)) = upper(base_currency.code) then p.amount else null end,
        0
      ) as base_amount,
      upper(coalesce(p.currency, base_currency.code)) as currency_code,
      coalesce(p.fx_rate, 1) as fx_rate,
      null::text as memo,
      'payments' as source_table,
      p.id::text as source_id,
      'payment' as source_event,
      null::numeric as running_balance
    from public.payments p
    join public.purchase_orders po on po.id = p.reference_id::uuid
    join supplier_ids s on s.supplier_id = po.supplier_id
    cross join base_currency
    left join ap_account on true
    where p.reference_table = 'purchase_orders'
      and p.direction = 'out'
      and (p_currency is null or upper(coalesce(p.currency, base_currency.code)) = upper(p_currency))
      and (p_start is null or p.occurred_at::date >= p_start)
      and (p_end is null or p.occurred_at::date <= p_end)
  ),
  ar_orders as (
    select
      coalesce(o.data->>'deliveredAt', o.data->>'paidAt', o.updated_at::text, o.created_at::text)::timestamptz as occurred_at,
      o.id as journal_entry_id,
      o.id as journal_line_id,
      coalesce(ar_account.code, '1200') as account_code,
      coalesce(ar_account.name, 'Accounts Receivable') as account_name,
      'debit' as direction,
      case
        when upper(coalesce(o.currency, base_currency.code)) <> upper(base_currency.code) then coalesce(o.total, 0)
        else null
      end as foreign_amount,
      coalesce(
        o.base_total,
        case when upper(coalesce(o.currency, base_currency.code)) = upper(base_currency.code) then o.total else null end,
        0
      ) as base_amount,
      upper(coalesce(o.currency, base_currency.code)) as currency_code,
      coalesce(o.fx_rate, 1) as fx_rate,
      null::text as memo,
      'orders' as source_table,
      o.id::text as source_id,
      'sale' as source_event,
      null::numeric as running_balance
    from public.orders o
    join customer_ids c on c.customer_id = o.customer_auth_user_id
    cross join base_currency
    left join ar_account on true
    where (p_currency is null or upper(coalesce(o.currency, base_currency.code)) = upper(p_currency))
      and (p_start is null or o.created_at::date >= p_start)
      and (p_end is null or o.created_at::date <= p_end)
  ),
  ar_payments as (
    select
      p.occurred_at as occurred_at,
      p.id as journal_entry_id,
      p.id as journal_line_id,
      coalesce(ar_account.code, '1200') as account_code,
      coalesce(ar_account.name, 'Accounts Receivable') as account_name,
      'credit' as direction,
      case
        when upper(coalesce(p.currency, base_currency.code)) <> upper(base_currency.code) then coalesce(p.amount, 0)
        else null
      end as foreign_amount,
      coalesce(
        p.base_amount,
        case when upper(coalesce(p.currency, base_currency.code)) = upper(base_currency.code) then p.amount else null end,
        0
      ) as base_amount,
      upper(coalesce(p.currency, base_currency.code)) as currency_code,
      coalesce(p.fx_rate, 1) as fx_rate,
      null::text as memo,
      'payments' as source_table,
      p.id::text as source_id,
      'payment' as source_event,
      null::numeric as running_balance
    from public.payments p
    join public.orders o on o.id = p.reference_id::uuid
    join customer_ids c on c.customer_id = o.customer_auth_user_id
    cross join base_currency
    left join ar_account on true
    where p.reference_table = 'orders'
      and p.direction = 'in'
      and (p_currency is null or upper(coalesce(p.currency, base_currency.code)) = upper(p_currency))
      and (p_start is null or p.occurred_at::date >= p_start)
      and (p_end is null or p.occurred_at::date <= p_end)
  ),
  fallback as (
    select * from ap_orders
    union all
    select * from ap_payments
    union all
    select * from ar_orders
    union all
    select * from ar_payments
  ),
  base as (
    select * from base_ple where (select use_fallback from use_fallback) = false
    union all
    select * from fallback where (select use_fallback from use_fallback) = true
  ),
  alloc as (
    select
      poi.journal_line_id,
      jsonb_agg(
        jsonb_build_object(
          'settlementId', sl.settlement_id::text,
          'fromOpenItemId', sl.from_open_item_id::text,
          'toOpenItemId', sl.to_open_item_id::text,
          'allocatedBase', sl.allocated_base_amount,
          'allocatedCounterBase', sl.allocated_counter_base_amount,
          'allocatedForeign', sl.allocated_foreign_amount,
          'realizedFx', sl.realized_fx_amount
        )
        order by sl.created_at asc
      ) as allocations
    from public.party_open_items poi
    join public.settlement_lines sl
      on sl.from_open_item_id = poi.id or sl.to_open_item_id = poi.id
    group by poi.journal_line_id
  )
  select
    b.occurred_at,
    b.journal_entry_id,
    b.journal_line_id,
    b.account_code,
    b.account_name,
    b.direction,
    b.foreign_amount,
    b.base_amount,
    b.currency_code,
    b.fx_rate,
    b.memo,
    b.source_table,
    b.source_id,
    b.source_event,
    case
      when (select use_fallback from use_fallback) = true then
        sum(case when b.direction = 'debit' then coalesce(b.base_amount, 0) else -coalesce(b.base_amount, 0) end)
        over (order by b.occurred_at asc, b.journal_entry_id asc, b.journal_line_id asc)
      else b.running_balance
    end as running_balance,
    poi.open_base_amount,
    poi.open_foreign_amount,
    poi.status as open_status,
    coalesce(a.allocations, '[]'::jsonb) as allocations
  from base b
  left join public.party_open_items poi on poi.journal_line_id = b.journal_line_id
  left join alloc a on a.journal_line_id = b.journal_line_id
  order by b.occurred_at asc, b.journal_entry_id asc, b.journal_line_id asc;
$$;


ALTER FUNCTION "public"."party_ledger_statement_v2"("p_party_id" "uuid", "p_account_code" "text", "p_currency" "text", "p_start" "date", "p_end" "date") OWNER TO "postgres";

--
-- Name: pgrst_ddl_watch(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pgrst_ddl_watch"() RETURNS "event_trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  cmd record;
begin
  for cmd in select * from pg_event_trigger_ddl_commands()
  loop
    if cmd.command_tag in (
      'CREATE FUNCTION','ALTER FUNCTION','DROP FUNCTION',
      'CREATE TABLE','ALTER TABLE','DROP TABLE',
      'CREATE VIEW','ALTER VIEW','DROP VIEW',
      'COMMENT'
    ) and cmd.schema_name is distinct from 'pg_temp' then
      perform pg_notify('pgrst','reload schema');
    end if;
  end loop;
end; $$;


ALTER FUNCTION "public"."pgrst_ddl_watch"() OWNER TO "postgres";

--
-- Name: pgrst_drop_watch(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pgrst_drop_watch"() RETURNS "event_trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  obj record;
begin
  for obj in select * from pg_event_trigger_dropped_objects()
  loop
    if obj.object_type in ('function','table','view','type','trigger','schema','rule')
       and obj.is_temporary is false then
      perform pg_notify('pgrst','reload schema');
    end if;
  end loop;
end; $$;


ALTER FUNCTION "public"."pgrst_drop_watch"() OWNER TO "postgres";

--
-- Name: post_cash_shift_close("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_cash_shift_close"("p_shift_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_shift record;
  v_entry_id uuid;
  v_cash uuid;
  v_over_short uuid;
  v_diff numeric;
begin
  if p_shift_id is null then
    raise exception 'p_shift_id is required';
  end if;
  select *
  into v_shift
  from public.cash_shifts s
  where s.id = p_shift_id;
  if not found then
    raise exception 'cash shift not found';
  end if;
  if coalesce(v_shift.status, 'open') <> 'closed' then
    return;
  end if;
  v_cash := public.get_account_id_by_code('1010');
  v_over_short := public.get_account_id_by_code('6110');
  v_diff := coalesce(v_shift.difference, coalesce(v_shift.end_amount, 0) - coalesce(v_shift.expected_amount, 0));
  if abs(v_diff) <= 1e-9 then
    return;
  end if;
  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    coalesce(v_shift.closed_at, now()),
    concat('Cash shift close ', v_shift.id::text),
    'cash_shifts',
    v_shift.id::text,
    'closed',
    auth.uid()
  )
  on conflict (source_table, source_id, source_event)
  do update set entry_date = excluded.entry_date, memo = excluded.memo
  returning id into v_entry_id;
  delete from public.journal_lines jl where jl.journal_entry_id = v_entry_id;
  if v_diff < 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_over_short, abs(v_diff), 0, 'Cash shortage'),
      (v_entry_id, v_cash, 0, abs(v_diff), 'Adjust cash to counted');
  else
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_cash, v_diff, 0, 'Adjust cash to counted'),
      (v_entry_id, v_over_short, 0, v_diff, 'Cash overage');
  end if;
end;
$$;


ALTER FUNCTION "public"."post_cash_shift_close"("p_shift_id" "uuid") OWNER TO "postgres";

--
-- Name: post_import_expense("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_import_expense"("p_import_expense_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_ie record;
  v_amount numeric;
  v_settings jsonb;
  v_accounts jsonb;
  v_entry_id uuid;
  v_ap uuid;
  v_cash uuid;
  v_bank uuid;
  v_clearing uuid;
  v_credit_account uuid;
  v_event text;
  v_occurred_at timestamptz;
begin
  if p_import_expense_id is null then
    raise exception 'p_import_expense_id is required';
  end if;

  select *
  into v_ie
  from public.import_expenses
  where id = p_import_expense_id;

  if not found then
    raise exception 'import expense not found';
  end if;

  v_amount := coalesce(v_ie.amount, 0) * coalesce(v_ie.exchange_rate, 1);
  if v_amount <= 0 then
    return;
  end if;

  v_occurred_at := coalesce(v_ie.paid_at::timestamptz, v_ie.created_at, now());

  v_ap := public.get_account_id_by_code('2010');
  v_cash := public.get_account_id_by_code('1010');
  v_bank := public.get_account_id_by_code('1020');
  v_clearing := public.get_account_id_by_code('2060');

  if to_regclass('public.app_settings') is not null then
    select s.data
    into v_settings
    from public.app_settings s
    where s.id in ('singleton','app')
    order by (s.id = 'singleton') desc
    limit 1;

    v_accounts := coalesce(v_settings->'settings'->'accounting_accounts', v_settings->'accounting_accounts', '{}'::jsonb);
    begin
      v_clearing := coalesce(nullif(v_accounts->>'landed_cost_clearing', '')::uuid, v_clearing);
    exception when others then
      null;
    end;
  end if;

  if v_clearing is null then
    raise exception 'landed cost clearing account not found';
  end if;

  if v_ie.paid_at is not null then
    v_event := 'paid';
    v_credit_account := case when coalesce(v_ie.payment_method, 'cash') = 'bank' then v_bank else v_cash end;
  else
    v_event := 'accrual';
    v_credit_account := v_ap;
  end if;

  if v_event = 'paid' then
    delete from public.journal_lines jl
    using public.journal_entries je
    where jl.journal_entry_id = je.id
      and je.source_table = 'import_expenses'
      and je.source_id = p_import_expense_id::text
      and je.source_event = 'accrual';
    delete from public.journal_entries je
    where je.source_table = 'import_expenses'
      and je.source_id = p_import_expense_id::text
      and je.source_event = 'accrual';
  else
    delete from public.journal_lines jl
    using public.journal_entries je
    where jl.journal_entry_id = je.id
      and je.source_table = 'import_expenses'
      and je.source_id = p_import_expense_id::text
      and je.source_event = 'paid';
    delete from public.journal_entries je
    where je.source_table = 'import_expenses'
      and je.source_id = p_import_expense_id::text
      and je.source_event = 'paid';
  end if;

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    v_occurred_at,
    concat('Import expense ', coalesce(v_ie.invoice_number, v_ie.id::text)),
    'import_expenses',
    p_import_expense_id::text,
    v_event,
    coalesce(v_ie.created_by, auth.uid())
  )
  on conflict (source_table, source_id, source_event)
  do update set entry_date = excluded.entry_date, memo = excluded.memo
  returning id into v_entry_id;

  delete from public.journal_lines jl where jl.journal_entry_id = v_entry_id;

  insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
  values
    (v_entry_id, v_clearing, v_amount, 0, 'Landed cost service'),
    (v_entry_id, v_credit_account, 0, v_amount, case when v_event = 'paid' then 'Cash/Bank paid' else 'Accounts payable' end);

  perform public.check_journal_entry_balance(v_entry_id);
end;
$$;


ALTER FUNCTION "public"."post_import_expense"("p_import_expense_id" "uuid") OWNER TO "postgres";

--
-- Name: post_inventory_movement("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_inventory_movement"("p_movement_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_mv record;
  v_entry_id uuid;
  v_existing_id uuid;
  v_inventory uuid;
  v_cogs uuid;
  v_ap uuid;
  v_shrinkage uuid;
  v_gain uuid;
  v_vat_input uuid;
  v_supplier_tax_total numeric := 0;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.post') or public.has_admin_permission('accounting.manage')) then
    raise exception 'not allowed';
  end if;
  if p_movement_id is null then
    raise exception 'p_movement_id is required';
  end if;

  select * into v_mv
  from public.inventory_movements im
  where im.id = p_movement_id;
  if not found then
    raise exception 'inventory movement not found';
  end if;

  if v_mv.movement_type = 'sale_out' and v_mv.batch_id is null then
    raise exception 'SALE_OUT_REQUIRES_BATCH';
  end if;

  if v_mv.reference_table = 'production_orders' then
    return;
  end if;

  if v_mv.movement_type in ('transfer_out','transfer_in') then
    return;
  end if;

  select je.id into v_existing_id
  from public.journal_entries je
  where je.source_table = 'inventory_movements'
    and je.source_id = v_mv.id::text
    and je.source_event = v_mv.movement_type
  limit 1;

  if v_existing_id is not null then
    if exists (select 1 from public.journal_lines jl where jl.journal_entry_id = v_existing_id limit 1) then
      update public.journal_entries
      set status = 'posted'
      where id = v_existing_id
        and coalesce(status, '') <> 'posted';
      return;
    end if;
    v_entry_id := v_existing_id;
    update public.journal_entries
    set entry_date = v_mv.occurred_at,
        memo = concat('Inventory movement ', v_mv.movement_type, ' ', v_mv.item_id),
        status = 'posted'
    where id = v_entry_id;
  else
    insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, status)
    values (
      v_mv.occurred_at,
      concat('Inventory movement ', v_mv.movement_type, ' ', v_mv.item_id),
      'inventory_movements',
      v_mv.id::text,
      v_mv.movement_type,
      v_mv.created_by,
      'posted'
    )
    returning id into v_entry_id;
  end if;

  v_inventory := public.get_account_id_by_code('1410');
  v_cogs := public.get_account_id_by_code('5010');
  v_ap := public.get_account_id_by_code('2010');
  v_shrinkage := public.get_account_id_by_code('5020');
  v_gain := public.get_account_id_by_code('4021');
  v_vat_input := public.get_account_id_by_code('1420');
  v_supplier_tax_total := coalesce(nullif((v_mv.data->>'supplier_tax_total')::numeric, null), 0);

  if v_mv.movement_type = 'purchase_in' then
    if v_supplier_tax_total > 0 and v_vat_input is not null then
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
      values
        (v_entry_id, v_inventory, v_mv.total_cost - v_supplier_tax_total, 0, 'Inventory increase (net)'),
        (v_entry_id, v_vat_input, v_supplier_tax_total, 0, 'VAT input'),
        (v_entry_id, v_ap, 0, v_mv.total_cost, 'Supplier payable');
    else
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
      values
        (v_entry_id, v_inventory, v_mv.total_cost, 0, 'Inventory increase'),
        (v_entry_id, v_ap, 0, v_mv.total_cost, 'Supplier payable');
    end if;
  elsif v_mv.movement_type in ('sale_out','expired_out','wastage_out') then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_cogs, v_mv.total_cost, 0, case when v_mv.movement_type = 'sale_out' then 'COGS' else concat(v_mv.movement_type, ' (COGS)') end),
      (v_entry_id, v_inventory, 0, v_mv.total_cost, 'Inventory decrease');
  elsif v_mv.movement_type = 'adjust_out' then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_shrinkage, v_mv.total_cost, 0, 'Adjustment out'),
      (v_entry_id, v_inventory, 0, v_mv.total_cost, 'Inventory decrease');
  elsif v_mv.movement_type = 'adjust_in' then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_inventory, v_mv.total_cost, 0, 'Adjustment in'),
      (v_entry_id, v_gain, 0, v_mv.total_cost, 'Inventory gain');
  elsif v_mv.movement_type = 'return_out' then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_ap, v_mv.total_cost, 0, 'Vendor credit'),
      (v_entry_id, v_inventory, 0, v_mv.total_cost, 'Inventory decrease');
  elsif v_mv.movement_type = 'return_in' then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_inventory, v_mv.total_cost, 0, 'Inventory restore (return)'),
      (v_entry_id, v_cogs, 0, v_mv.total_cost, 'Reverse COGS');
  end if;

  perform public.check_journal_entry_balance(v_entry_id);
end;
$$;


ALTER FUNCTION "public"."post_inventory_movement"("p_movement_id" "uuid") OWNER TO "postgres";

--
-- Name: post_invoice_issued("uuid", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_invoice_issued"("p_order_id" "uuid", "p_issued_at" timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order record;
  v_data jsonb;
  v_is_cod boolean := false;
  v_entry_id uuid;
  v_total_foreign numeric := 0;
  v_total_base numeric := 0;
  v_subtotal_base numeric := 0;
  v_discount_base numeric := 0;
  v_delivery_base numeric := 0;
  v_tax_base numeric := 0;
  v_deposits_paid_base numeric := 0;
  v_ar_amount_base numeric := 0;
  v_accounts jsonb;
  v_ar uuid;
  v_deposits uuid;
  v_sales uuid;
  v_delivery_income uuid;
  v_vat_payable uuid;
  v_base text;
  v_currency text;
  v_fx numeric;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.manage')) then
    raise exception 'not authorized to post accounting entries';
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;

  select *
  into v_order
  from public.orders o
  where o.id = p_order_id
  for update;
  if not found then
    raise exception 'order not found';
  end if;

  v_base := public.get_base_currency();
  v_currency := upper(nullif(btrim(coalesce(v_order.currency, v_order.data->>'currency', v_base)), ''));
  if v_currency is null then
    v_currency := v_base;
  end if;
  v_fx := coalesce(v_order.fx_rate, nullif((v_order.data->>'fxRate')::numeric, null), 1);
  if v_fx is null or v_fx <= 0 then
    raise exception 'invalid fx_rate on order';
  end if;

  v_data := coalesce(v_order.data, '{}'::jsonb);
  v_is_cod := public._is_cod_delivery_order(v_data, v_order.delivery_zone_id);
  if v_is_cod then
    return;
  end if;

  if v_order.base_total is null then
    raise exception 'orders.base_total is required for GL posting';
  end if;
  v_total_base := coalesce(v_order.base_total, 0);

  v_total_foreign := coalesce(
    nullif((v_data->'invoiceSnapshot'->>'total')::numeric, null),
    nullif((v_data->>'total')::numeric, null),
    coalesce(v_order.total, 0),
    0
  );
  if v_total_foreign <= 0 or v_total_base <= 0 then
    return;
  end if;

  v_subtotal_base := coalesce(nullif((v_data->'invoiceSnapshot'->>'subtotal')::numeric, null), nullif((v_data->>'subtotal')::numeric, null), coalesce(v_order.subtotal, 0), 0) * v_fx;
  v_discount_base := coalesce(nullif((v_data->'invoiceSnapshot'->>'discountAmount')::numeric, null), nullif((v_data->>'discountAmount')::numeric, null), coalesce(v_order.discount, 0), 0) * v_fx;
  v_delivery_base := coalesce(nullif((v_data->'invoiceSnapshot'->>'deliveryFee')::numeric, null), nullif((v_data->>'deliveryFee')::numeric, null), coalesce(v_order.delivery_fee, 0), 0) * v_fx;
  v_tax_base := coalesce(nullif((v_data->'invoiceSnapshot'->>'taxAmount')::numeric, null), nullif((v_data->>'taxAmount')::numeric, null), coalesce(v_order.tax, 0), 0) * v_fx;

  v_tax_base := least(greatest(0, v_tax_base), v_total_base);
  v_delivery_base := least(greatest(0, v_delivery_base), v_total_base - v_tax_base);

  select coalesce(sum(coalesce(p.base_amount, 0)), 0)
  into v_deposits_paid_base
  from public.payments p
  where p.reference_table = 'orders'
    and p.reference_id = p_order_id::text
    and p.direction = 'in'
    and p.occurred_at < coalesce(p_issued_at, now());

  v_deposits_paid_base := least(v_total_base, greatest(0, coalesce(v_deposits_paid_base, 0)));
  v_ar_amount_base := greatest(0, v_total_base - v_deposits_paid_base);

  select s.data->'accounting_accounts' into v_accounts from public.app_settings s where s.id = 'singleton';
  v_ar := public.get_account_id_by_code(coalesce(v_accounts->>'ar','1200'));
  v_deposits := public.get_account_id_by_code(coalesce(v_accounts->>'deposits','2050'));
  v_sales := public.get_account_id_by_code(coalesce(v_accounts->>'sales','4010'));
  v_delivery_income := public.get_account_id_by_code(coalesce(v_accounts->>'delivery_income','4020'));
  v_vat_payable := public.get_account_id_by_code(coalesce(v_accounts->>'vat_payable','2020'));

  begin
    insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, currency_code, fx_rate, foreign_amount)
    values (
      coalesce(p_issued_at, now()),
      concat('Order invoiced ', p_order_id::text),
      'orders',
      p_order_id::text,
      'invoiced',
      auth.uid(),
      case when v_currency <> v_base then v_currency else null end,
      case when v_currency <> v_base then v_fx else null end,
      case when v_currency <> v_base then v_total_foreign else null end
    )
    returning id into v_entry_id;
  exception
    when unique_violation then
      raise exception 'posting already exists for this source; create a reversal instead';
  end;

  if v_deposits_paid_base > 0 and v_deposits is not null then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_deposits, v_deposits_paid_base, 0, 'Apply customer deposit');
  end if;
  if v_ar_amount_base > 0 and v_ar is not null then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_ar, v_ar_amount_base, 0, 'Accounts receivable');
  end if;
  if (v_total_base - v_delivery_base - v_tax_base) > 0 and v_sales is not null then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_sales, 0, (v_total_base - v_delivery_base - v_tax_base), 'Sales revenue');
  end if;
  if v_delivery_base > 0 and v_delivery_income is not null then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_delivery_income, 0, v_delivery_base, 'Delivery income');
  end if;
  if v_tax_base > 0 and v_vat_payable is not null then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_vat_payable, 0, v_tax_base, 'VAT payable');
  end if;

  perform public.check_journal_entry_balance(v_entry_id);
  perform public.sync_ar_on_invoice(p_order_id);
end;
$$;


ALTER FUNCTION "public"."post_invoice_issued"("p_order_id" "uuid", "p_issued_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: FUNCTION "post_invoice_issued"("p_order_id" "uuid", "p_issued_at" timestamp with time zone); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."post_invoice_issued"("p_order_id" "uuid", "p_issued_at" timestamp with time zone) IS 'GL posting uses base currency only (journal_lines in base); order.base_total is authoritative.';


--
-- Name: post_order_delivery("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_order_delivery"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order record;
  v_entry_id uuid;
  v_total_base numeric := 0;
  v_ar uuid;
  v_deposits uuid;
  v_sales uuid;
  v_delivery_income uuid;
  v_vat_payable uuid;
  v_delivered_at timestamptz;
  v_deposits_paid_base numeric := 0;
  v_ar_amount_base numeric := 0;
  v_delivery_base numeric := 0;
  v_tax_base numeric := 0;
  v_items_revenue_base numeric := 0;
  v_accounts jsonb;
  v_base text;
  v_currency text;
  v_fx numeric;
  v_data jsonb;
begin
  perform public._require_staff('accounting.post');

  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;

  select o.*
  into v_order
  from public.orders o
  where o.id = p_order_id;
  if not found then
    raise exception 'order not found';
  end if;

  v_base := public.get_base_currency();
  v_data := coalesce(v_order.data, '{}'::jsonb);
  v_currency := upper(nullif(btrim(coalesce(v_order.currency, v_data->>'currency', v_base)), ''));
  if v_currency is null then
    v_currency := v_base;
  end if;
  v_fx := coalesce(v_order.fx_rate, nullif((v_data->>'fxRate')::numeric, null), 1);
  if v_fx is null or v_fx <= 0 then
    raise exception 'invalid fx_rate on order';
  end if;

  if v_order.base_total is null then
    raise exception 'orders.base_total is required for GL posting';
  end if;
  v_total_base := coalesce(v_order.base_total, 0);
  if v_total_base <= 0 then
    return;
  end if;

  select s.data->'accounting_accounts' into v_accounts from public.app_settings s where s.id = 'singleton';
  v_ar := public.get_account_id_by_code(coalesce(v_accounts->>'ar','1200'));
  v_deposits := public.get_account_id_by_code(coalesce(v_accounts->>'deposits','2050'));
  v_sales := public.get_account_id_by_code(coalesce(v_accounts->>'sales','4010'));
  v_delivery_income := public.get_account_id_by_code(coalesce(v_accounts->>'delivery_income','4020'));
  v_vat_payable := public.get_account_id_by_code(coalesce(v_accounts->>'vat_payable','2020'));

  v_delivered_at := public.order_delivered_at(p_order_id);
  if v_delivered_at is null then
    v_delivered_at := coalesce(v_order.updated_at, now());
  end if;

  if (v_data ? 'invoiceSnapshot') then
    v_delivery_base := coalesce(nullif((v_data->'invoiceSnapshot'->>'deliveryFee')::numeric, null), 0) * v_fx;
    v_tax_base := coalesce(nullif((v_data->'invoiceSnapshot'->>'taxAmount')::numeric, null), 0) * v_fx;
  else
    v_delivery_base := coalesce(nullif((v_data->>'deliveryFee')::numeric, null), coalesce(v_order.delivery_fee, 0), 0) * v_fx;
    v_tax_base := coalesce(nullif((v_data->>'taxAmount')::numeric, null), coalesce(v_order.tax, 0), 0) * v_fx;
  end if;

  v_tax_base := least(greatest(0, v_tax_base), v_total_base);
  v_delivery_base := least(greatest(0, v_delivery_base), v_total_base - v_tax_base);
  v_items_revenue_base := greatest(0, v_total_base - v_delivery_base - v_tax_base);

  select coalesce(sum(coalesce(p.base_amount, 0)), 0)
  into v_deposits_paid_base
  from public.payments p
  where p.reference_table = 'orders'
    and p.reference_id = p_order_id::text
    and p.direction = 'in'
    and p.occurred_at < v_delivered_at;

  v_deposits_paid_base := least(v_total_base, greatest(0, coalesce(v_deposits_paid_base, 0)));
  v_ar_amount_base := greatest(0, v_total_base - v_deposits_paid_base);

  begin
    insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, currency_code, fx_rate, foreign_amount)
    values (
      v_delivered_at,
      concat('Order delivered ', v_order.id::text),
      'orders',
      v_order.id::text,
      'delivered',
      auth.uid(),
      case when v_currency <> v_base then v_currency else null end,
      case when v_currency <> v_base then v_fx else null end,
      case
        when v_currency <> v_base then coalesce(nullif((v_data->>'total')::numeric, null), coalesce(v_order.total, 0), 0)
        else null
      end
    )
    returning id into v_entry_id;
  exception
    when unique_violation then
      raise exception 'posting already exists for this source; create a reversal instead';
  end;

  if v_deposits_paid_base > 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_deposits, v_deposits_paid_base, 0, 'Apply customer deposit');
  end if;

  if v_ar_amount_base > 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_ar, v_ar_amount_base, 0, 'Accounts receivable');
  end if;

  if v_items_revenue_base > 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_sales, 0, v_items_revenue_base, 'Sales revenue');
  end if;

  if v_delivery_base > 0 and v_delivery_income is not null then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_delivery_income, 0, v_delivery_base, 'Delivery income');
  end if;

  if v_tax_base > 0 and v_vat_payable is not null then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_vat_payable, 0, v_tax_base, 'VAT payable');
  end if;

  perform public.check_journal_entry_balance(v_entry_id);
end;
$$;


ALTER FUNCTION "public"."post_order_delivery"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "post_order_delivery"("p_order_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."post_order_delivery"("p_order_id" "uuid") IS 'GL posting uses base currency only (journal_lines in base); order.base_total is authoritative.';


--
-- Name: post_payment("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_payment"("p_payment_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_pay record;
  v_entry_id uuid;
  v_cash uuid;
  v_bank uuid;
  v_ar uuid;
  v_deposits uuid;
  v_ap uuid;
  v_expenses uuid;
  v_clearing uuid;
  v_fx_gain uuid;
  v_fx_loss uuid;
  v_debit_account uuid;
  v_credit_account uuid;
  v_amount_base numeric;
  v_amount_fx numeric;
  v_currency text;
  v_base text;
  v_rate numeric;
  v_order_id uuid;
  v_delivered_at timestamptz;
  v_has_accrual boolean := false;
  v_outstanding_base numeric := 0;
  v_settle_base numeric := 0;
  v_diff numeric := 0;
  v_po_id uuid;
  v_cash_fx_code text;
  v_cash_fx_rate numeric;
  v_cash_fx_amount numeric;
  v_source_entry_id uuid;
  v_original_ar_base numeric := 0;
  v_settled_ar_base numeric := 0;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
 
  if p_payment_id is null then
    raise exception 'p_payment_id is required';
  end if;
 
  select *
  into v_pay
  from public.payments p
  where p.id = p_payment_id
  for update;
  if not found then
    raise exception 'payment not found';
  end if;
 
  if exists (
    select 1
    from public.journal_entries je
    where je.source_table = 'payments'
      and je.source_id = p_payment_id::text
  ) then
    return;
  end if;

  if coalesce(v_pay.reference_table, '') = 'sales_returns' then
    return;
  end if;
 
  v_base := public.get_base_currency();
  v_currency := upper(nullif(btrim(coalesce(v_pay.currency, v_base)), ''));
  if v_currency is null then
    v_currency := v_base;
  end if;
  v_rate := coalesce(v_pay.fx_rate, 1);
  v_amount_fx := coalesce(v_pay.amount, 0);
  v_amount_base := coalesce(v_pay.base_amount, 0);
  if v_amount_base <= 0 then
    raise exception 'invalid base_amount';
  end if;
 
  v_cash_fx_code := null;
  v_cash_fx_rate := null;
  v_cash_fx_amount := null;
  if v_currency <> v_base then
    v_cash_fx_code := v_currency;
    v_cash_fx_rate := v_rate;
    v_cash_fx_amount := v_amount_fx;
  end if;
 
  v_cash := public.get_account_id_by_code('1010');
  v_bank := public.get_account_id_by_code('1020');
  v_ar := public.get_account_id_by_code('1200');
  v_deposits := public.get_account_id_by_code('2050');
  v_ap := public.get_account_id_by_code('2010');
  v_expenses := public.get_account_id_by_code('6100');
  v_clearing := public.get_account_id_by_code('2060');
  v_fx_gain := public.get_account_id_by_code('6200');
  v_fx_loss := public.get_account_id_by_code('6201');
 
  if v_cash is null or v_bank is null or v_ar is null or v_deposits is null or v_ap is null or v_expenses is null or v_fx_gain is null or v_fx_loss is null then
    raise exception 'required accounts not found';
  end if;
 
  if v_pay.method = 'cash' then
    v_debit_account := v_cash;
    v_credit_account := v_cash;
  else
    v_debit_account := v_bank;
    v_credit_account := v_bank;
  end if;
 
  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, status, currency_code, fx_rate, foreign_amount)
  values (
    v_pay.occurred_at,
    concat('Payment ', v_pay.direction, ' ', v_pay.reference_table, ':', v_pay.reference_id),
    'payments',
    v_pay.id::text,
    concat(v_pay.direction, ':', v_pay.reference_table, ':', coalesce(v_pay.reference_id, '')),
    auth.uid(),
    'posted',
    case when v_currency <> v_base then v_currency else null end,
    case when v_currency <> v_base then v_rate else null end,
    case when v_currency <> v_base then v_amount_fx else null end
  )
  returning id into v_entry_id;
 
  if v_pay.direction = 'in' and v_pay.reference_table = 'orders' then
    v_order_id := nullif(v_pay.reference_id, '')::uuid;
    if v_order_id is null then
      raise exception 'invalid order reference_id';
    end if;
 
    v_delivered_at := public.order_delivered_at(v_order_id);
    if v_delivered_at is null or v_pay.occurred_at < v_delivered_at then
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
      values
        (v_entry_id, v_debit_account, v_amount_base, 0, 'Cash/Bank received', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount),
        (v_entry_id, v_deposits, 0, v_amount_base, 'Customer deposit', null, null, null);
      perform public.check_journal_entry_balance(v_entry_id);
      return;
    end if;
 
    select je.id
    into v_source_entry_id
    from public.journal_entries je
    where je.source_table = 'orders'
      and je.source_id = v_order_id::text
      and je.source_event in ('invoiced','delivered')
    order by
      case when je.source_event = 'invoiced' then 0 else 1 end asc,
      je.entry_date desc
    limit 1;
 
    if v_source_entry_id is null then
      select coalesce(o.base_total, 0)
      into v_original_ar_base
      from public.orders o
      where o.id = v_order_id;
    else
      select coalesce(sum(jl.debit), 0) - coalesce(sum(jl.credit), 0)
      into v_original_ar_base
      from public.journal_lines jl
      where jl.journal_entry_id = v_source_entry_id
        and jl.account_id = v_ar;
    end if;
 
    select coalesce(sum(jl.credit), 0) - coalesce(sum(jl.debit), 0)
    into v_settled_ar_base
    from public.payments p
    join public.journal_entries je
      on je.source_table = 'payments'
     and je.source_id = p.id::text
    join public.journal_lines jl
      on jl.journal_entry_id = je.id
    where p.reference_table = 'orders'
      and p.direction = 'in'
      and p.reference_id = v_order_id::text
      and p.id <> v_pay.id
      and jl.account_id = v_ar;
 
    v_outstanding_base := greatest(0, coalesce(v_original_ar_base, 0) - coalesce(v_settled_ar_base, 0));
 
    if v_outstanding_base <= 0 then
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
      values
        (v_entry_id, v_debit_account, v_amount_base, 0, 'Cash/Bank received', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount),
        (v_entry_id, v_deposits, 0, v_amount_base, 'Customer deposit', null, null, null);
      perform public.check_journal_entry_balance(v_entry_id);
      return;
    end if;
 
    v_settle_base := v_outstanding_base;
    v_diff := v_amount_base - v_settle_base;
 
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
    values
      (v_entry_id, v_debit_account, v_amount_base, 0, 'Receive payment', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount),
      (v_entry_id, v_ar, 0, v_settle_base, 'Settle receivable', null, null, null);
 
    if abs(v_diff) > 0.0000001 then
      if v_diff > 0 then
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_entry_id, v_fx_gain, 0, abs(v_diff), 'FX Gain realized');
      else
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_entry_id, v_fx_loss, abs(v_diff), 0, 'FX Loss realized');
      end if;
    end if;
 
    perform public.check_journal_entry_balance(v_entry_id);
    return;
  end if;
 
  if v_pay.direction = 'out' and v_pay.reference_table = 'purchase_orders' then
    v_po_id := nullif(v_pay.reference_id, '')::uuid;
    if v_po_id is null then
      raise exception 'invalid purchase order reference_id';
    end if;
 
    select greatest(0, coalesce(po.base_total, 0) - coalesce((
      select sum(coalesce(p.base_amount, 0))
      from public.payments p
      where p.reference_table = 'purchase_orders'
        and p.direction = 'out'
        and p.reference_id = v_po_id::text
        and p.id <> v_pay.id
        and p.occurred_at <= v_pay.occurred_at
    ), 0))
    into v_outstanding_base
    from public.purchase_orders po
    where po.id = v_po_id;
 
    v_settle_base := least(greatest(0, v_outstanding_base), v_amount_base);
    v_diff := 0;
    if v_outstanding_base > 0 and (v_amount_base + 0.0000001) >= v_outstanding_base then
      v_diff := v_amount_base - v_outstanding_base;
      v_settle_base := v_outstanding_base;
    end if;
 
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
    values
      (v_entry_id, v_ap, v_settle_base, 0, 'Settle payable', null, null, null),
      (v_entry_id, v_credit_account, 0, v_amount_base, 'Pay supplier', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
 
    if abs(v_diff) > 0.0000001 then
      if v_diff > 0 then
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_entry_id, v_fx_loss, abs(v_diff), 0, 'FX Loss realized');
      else
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_entry_id, v_fx_gain, 0, abs(v_diff), 'FX Gain realized');
      end if;
    end if;
 
    perform public.check_journal_entry_balance(v_entry_id);
    return;
  end if;
 
  if v_pay.direction = 'out' and v_pay.reference_table = 'expenses' then
    v_has_accrual := exists(
      select 1 from public.journal_entries je
      where je.source_table = 'expenses'
        and je.source_id = coalesce(v_pay.reference_id, '')
        and je.source_event = 'accrual'
    );
    if v_has_accrual then
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
      values
        (v_entry_id, v_ap, v_amount_base, 0, 'Settle payable', null, null, null),
        (v_entry_id, v_credit_account, 0, v_amount_base, 'Cash/Bank paid', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
    else
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
      values
        (v_entry_id, v_expenses, v_amount_base, 0, 'Operating expense', null, null, null),
        (v_entry_id, v_credit_account, 0, v_amount_base, 'Cash/Bank paid', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
    end if;
    perform public.check_journal_entry_balance(v_entry_id);
    return;
  end if;
 
  if v_pay.direction = 'out' and v_pay.reference_table = 'import_expenses' then
    v_has_accrual := exists(
      select 1 from public.journal_entries je
      where je.source_table = 'import_expenses'
        and je.source_id = coalesce(v_pay.reference_id, '')
        and je.source_event = 'accrual'
    );
    if v_clearing is null then
      raise exception 'landed cost clearing account missing';
    end if;
    if v_has_accrual then
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
      values
        (v_entry_id, v_ap, v_amount_base, 0, 'Settle payable', null, null, null),
        (v_entry_id, v_credit_account, 0, v_amount_base, 'Cash/Bank paid', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
    else
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
      values
        (v_entry_id, v_clearing, v_amount_base, 0, 'Landed cost service', null, null, null),
        (v_entry_id, v_credit_account, 0, v_amount_base, 'Cash/Bank paid', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
    end if;
    perform public.check_journal_entry_balance(v_entry_id);
    return;
  end if;
 
  raise exception 'unsupported payment reference';
end;
$$;


ALTER FUNCTION "public"."post_payment"("p_payment_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "post_payment"("p_payment_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."post_payment"("p_payment_id" "uuid") IS 'GL posting uses base currency only (journal_lines in base) and uses stored payments.base_amount; realized FX uses 6200/6201.';


--
-- Name: post_production_order("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_production_order"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_entry_id uuid;
  v_inventory uuid;
  v_shrinkage uuid;
  v_gain uuid;
  v_inputs_total numeric;
  v_outputs_total numeric;
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  v_inventory := public.get_account_id_by_code('1410');
  v_shrinkage := public.get_account_id_by_code('5020');
  v_gain := public.get_account_id_by_code('4021');

  select coalesce(sum(total_cost), 0) into v_inputs_total
  from public.production_order_inputs where order_id = p_order_id;
  select coalesce(sum(total_cost), 0) into v_outputs_total
  from public.production_order_outputs where order_id = p_order_id;

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    coalesce((select occurred_at from public.production_orders where id = p_order_id), now()),
    concat('Production order ', p_order_id::text),
    'production_orders',
    p_order_id::text,
    'posted',
    auth.uid()
  )
  on conflict (source_table, source_id, source_event)
  do update set entry_date = excluded.entry_date, memo = excluded.memo
  returning id into v_entry_id;

  delete from public.journal_lines jl where jl.journal_entry_id = v_entry_id;

  if v_outputs_total > 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_inventory, v_outputs_total, 0, 'Production outputs to inventory');
  end if;
  if v_inputs_total > 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_inventory, 0, v_inputs_total, 'Production inputs from inventory');
  end if;

  if abs(v_outputs_total - v_inputs_total) > 1e-6 then
    if v_outputs_total > v_inputs_total then
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
      values (v_entry_id, v_gain, 0, v_outputs_total - v_inputs_total, 'Production variance (gain)');
    else
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
      values (v_entry_id, v_shrinkage, v_inputs_total - v_outputs_total, 0, 'Production variance (loss)');
    end if;
  end if;
end;
$$;


ALTER FUNCTION "public"."post_production_order"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: post_purchase_receipt("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_purchase_receipt"("p_receipt_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_receipt record;
  v_mv record;
  v_errors text := '';
  v_failed boolean := false;
  v_count int := 0;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.post') or public.has_admin_permission('accounting.manage')) then
    raise exception 'not allowed';
  end if;
  if p_receipt_id is null then
    raise exception 'p_receipt_id is required';
  end if;

  select *
  into v_receipt
  from public.purchase_receipts pr
  where pr.id = p_receipt_id
  for update;
  if not found then
    raise exception 'purchase receipt not found';
  end if;

  for v_mv in
    select im.id
    from public.inventory_movements im
    where im.reference_table = 'purchase_receipts'
      and im.reference_id = p_receipt_id::text
    order by im.occurred_at asc, im.created_at asc
  loop
    begin
      perform public.post_inventory_movement(v_mv.id);
      v_count := v_count + 1;
    exception when others then
      v_failed := true;
      v_errors := left(
        trim(both from (v_errors || case when v_errors = '' then '' else E'\n' end || sqlerrm)),
        2000
      );
    end;
  end loop;

  if v_failed then
    update public.purchase_receipts
    set posting_status = 'failed',
        posting_error = nullif(v_errors, ''),
        posted_at = null
    where id = p_receipt_id;
    return jsonb_build_object(
      'status', 'failed',
      'postedCount', v_count,
      'error', nullif(v_errors, '')
    );
  end if;

  update public.purchase_receipts
  set posting_status = 'posted',
      posting_error = null,
      posted_at = now()
  where id = p_receipt_id;

  return jsonb_build_object(
    'status', 'posted',
    'postedCount', v_count
  );
end;
$$;


ALTER FUNCTION "public"."post_purchase_receipt"("p_receipt_id" "uuid") OWNER TO "postgres";

--
-- Name: post_supplier_invoice_variance("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."post_supplier_invoice_variance"("p_invoice_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_inv record;
  v_variance numeric;
  v_entry_id uuid;
  v_ap uuid;
  v_ppv uuid;
begin
  select * into v_inv from public.supplier_invoices where id = p_invoice_id;
  if not found then
    raise exception 'supplier invoice not found';
  end if;
  if v_inv.status <> 'matched' then
    raise exception 'invoice is not matched';
  end if;

  select coalesce(sum(line_total), 0) into v_variance
  from public.supplier_invoice_lines
  where invoice_id = p_invoice_id;

  v_variance := v_variance - coalesce(v_inv.total_amount, 0);
  if abs(v_variance) < 0.0001 then
    update public.supplier_invoices set status = 'posted' where id = p_invoice_id;
    return;
  end if;

  v_ap := public.get_account_id_by_code('2010');
  v_ppv := public.get_account_id_by_code('5030');

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    now(),
    concat('Supplier invoice variance ', v_inv.invoice_number),
    'supplier_invoices',
    v_inv.id::text,
    'variance',
    auth.uid()
  )
  returning id into v_entry_id;

  if v_variance > 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_ppv, v_variance, 0, 'Price variance'),
      (v_entry_id, v_ap, 0, v_variance, 'Increase payable');
  else
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values
      (v_entry_id, v_ap, abs(v_variance), 0, 'Decrease payable'),
      (v_entry_id, v_ppv, 0, abs(v_variance), 'Price variance');
  end if;

  perform public.check_journal_entry_balance(v_entry_id);
  update public.supplier_invoices set status = 'posted' where id = p_invoice_id;
end;
$$;


ALTER FUNCTION "public"."post_supplier_invoice_variance"("p_invoice_id" "uuid") OWNER TO "postgres";

--
-- Name: prevent_audit_log_modification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prevent_audit_log_modification"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF (TG_OP = 'UPDATE' OR TG_OP = 'DELETE') THEN
    RAISE EXCEPTION 'Modification of audit logs is strictly prohibited.';
  END IF;
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."prevent_audit_log_modification"() OWNER TO "postgres";

--
-- Name: prevent_foreign_cost_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prevent_foreign_cost_update"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if old.foreign_unit_cost is distinct from new.foreign_unit_cost then
    raise exception 'foreign_unit_cost cannot be modified after insert';
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."prevent_foreign_cost_update"() OWNER TO "postgres";

--
-- Name: prevent_multiple_owners(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prevent_multiple_owners"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if new.role = 'owner' then
    if exists (
      select 1
      from public.admin_users au
      where au.auth_user_id <> coalesce(new.auth_user_id, old.auth_user_id)
        and au.role = 'owner'
    ) then
      raise exception 'only_one_owner';
    end if;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."prevent_multiple_owners"() OWNER TO "postgres";

--
-- Name: process_accounting_jobs(integer, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_accounting_jobs"("p_limit" integer DEFAULT 50, "p_job_type" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_n int := 0;
  v_id uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  loop
    exit when v_n >= greatest(coalesce(p_limit,50),1);
    begin
      v_id := public.process_next_accounting_job(p_job_type);
      if v_id is null then
        exit;
      end if;
      v_n := v_n + 1;
    exception when others then
      v_n := v_n + 1;
    end;
  end loop;
  return v_n;
end;
$$;


ALTER FUNCTION "public"."process_accounting_jobs"("p_limit" integer, "p_job_type" "text") OWNER TO "postgres";

--
-- Name: process_expired_items(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_expired_items"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  processed_count integer := 0;
  v_wh_id uuid;
  v_has_warehouse boolean := false;
  v_batch record;
  v_stock record;
  v_wastage_qty numeric;
  v_effective_wastage_qty numeric;
  v_wastage_id uuid;
  v_reserved_batches jsonb;
  v_reserved_entry jsonb;
  v_reserved_list jsonb;
  v_order_id uuid;
  v_order_id_text text;
  v_unit_cost numeric;
  v_movement_id uuid;
  v_new_available numeric;
  v_new_reserved numeric;
  v_expired_batch_key text;
  v_reserved_cancel_total numeric;
  v_order_reserved_qty numeric;
  v_need numeric;
  v_candidate record;
  v_candidate_key text;
  v_candidate_entry jsonb;
  v_candidate_list jsonb;
  v_candidate_reserved numeric;
  v_free numeric;
  v_alloc numeric;
  v_list_new jsonb;
  v_key text;
  v_tmp_list jsonb;
  v_tmp_list_new jsonb;
  v_total_available numeric;
  v_qr numeric;
  v_qc numeric;
  v_batch_expiry date;
begin
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;

  v_has_warehouse := (to_regclass('public.warehouses') is not null);

  for v_batch in
    select *
    from public.v_food_batch_balances v
    where v.expiry_date is not null
      and v.expiry_date < current_date
      and greatest(coalesce(v.remaining_qty, 0), 0) > 0
    order by v.expiry_date asc, v.batch_id asc
  loop
    processed_count := processed_count + 1;
    v_wh_id := v_batch.warehouse_id;

    if v_has_warehouse then
      if v_wh_id is null then
        select w.id
        into v_wh_id
        from public.warehouses w
        order by w.code asc
        limit 1;
      end if;
      if v_wh_id is null then
        raise exception 'No warehouse found for expiry processing';
      end if;
    end if;

    v_wastage_qty := greatest(coalesce(v_batch.remaining_qty, 0), 0);
    if v_wastage_qty <= 0 then
      continue;
    end if;

    if v_has_warehouse and v_wh_id is not null then
      select *
      into v_stock
      from public.stock_management sm
      where sm.item_id::text = v_batch.item_id
        and sm.warehouse_id = v_wh_id
      for update;
    else
      select *
      into v_stock
      from public.stock_management sm
      where sm.item_id::text = v_batch.item_id
      for update;
    end if;

    if not found then
      continue;
    end if;

    v_effective_wastage_qty := v_wastage_qty;

    select
      b.quantity_received,
      b.quantity_consumed,
      b.unit_cost,
      b.expiry_date
    into v_qr, v_qc, v_unit_cost, v_batch_expiry
    from public.batches b
    where b.id = v_batch.batch_id
      and b.item_id::text = v_batch.item_id::text
      and (not v_has_warehouse or b.warehouse_id is not distinct from v_wh_id)
    for update;

    if not found then
      continue;
    end if;

    v_unit_cost := coalesce(v_unit_cost, v_stock.avg_cost, 0);

    v_reserved_batches := coalesce(v_stock.data->'reservedBatches', '{}'::jsonb);
    v_expired_batch_key := v_batch.batch_id::text;

    v_reserved_entry := v_reserved_batches->v_expired_batch_key;
    v_reserved_list :=
      case
        when v_reserved_entry is null then '[]'::jsonb
        when jsonb_typeof(v_reserved_entry) = 'array' then v_reserved_entry
        when jsonb_typeof(v_reserved_entry) = 'object' then jsonb_build_array(v_reserved_entry)
        else '[]'::jsonb
      end;

    v_reserved_cancel_total := 0;

    for v_order_id_text, v_order_reserved_qty in
      select
        (e->>'orderId') as order_id_text,
        coalesce(nullif(e->>'qty','')::numeric, 0) as qty
      from jsonb_array_elements(v_reserved_list) e
    loop
      if v_order_id_text is null or v_order_id_text = '' then
        continue;
      end if;
      begin
        v_order_id := v_order_id_text::uuid;
      exception when others then
        v_order_id := null;
      end;
      if v_order_id is null then
        continue;
      end if;

      v_need := greatest(coalesce(v_order_reserved_qty, 0), 0);
      if v_need <= 0 then
        continue;
      end if;

      v_reserved_cancel_total := v_reserved_cancel_total + v_need;

      for v_candidate in
        select
          b2.batch_id,
          b2.expiry_date,
          b2.remaining_qty
        from public.v_food_batch_balances b2
        where b2.item_id = v_batch.item_id
          and b2.warehouse_id is not distinct from v_wh_id
          and b2.batch_id <> v_batch.batch_id
          and (b2.expiry_date is null or b2.expiry_date >= current_date)
          and greatest(coalesce(b2.remaining_qty, 0), 0) > 0
        order by b2.expiry_date asc nulls last, b2.batch_id asc
      loop
        exit when v_need <= 0;

        v_candidate_key := v_candidate.batch_id::text;
        v_candidate_entry := v_reserved_batches->v_candidate_key;
        v_candidate_list :=
          case
            when v_candidate_entry is null then '[]'::jsonb
            when jsonb_typeof(v_candidate_entry) = 'array' then v_candidate_entry
            when jsonb_typeof(v_candidate_entry) = 'object' then jsonb_build_array(v_candidate_entry)
            else '[]'::jsonb
          end;

        select coalesce(sum(coalesce(nullif(x->>'qty','')::numeric, 0)), 0)
        into v_candidate_reserved
        from jsonb_array_elements(v_candidate_list) as x;

        v_free := greatest(coalesce(v_candidate.remaining_qty, 0) - coalesce(v_candidate_reserved, 0), 0);
        if v_free <= 0 then
          continue;
        end if;

        v_alloc := least(v_need, v_free);
        if v_alloc <= 0 then
          continue;
        end if;

        with elems as (
          select value, ordinality
          from jsonb_array_elements(v_candidate_list) with ordinality
        )
        select
          case
            when exists (select 1 from elems where (value->>'orderId') = v_order_id::text) then (
              select coalesce(
                jsonb_agg(
                  case
                    when (value->>'orderId') = v_order_id::text then
                      jsonb_set(
                        value,
                        '{qty}',
                        to_jsonb(coalesce(nullif(value->>'qty','')::numeric, 0) + v_alloc),
                        true
                      )
                    else value
                  end
                  order by ordinality
                ),
                '[]'::jsonb
              )
            )
            else (
              (select coalesce(jsonb_agg(value order by ordinality), '[]'::jsonb) from elems)
              || jsonb_build_array(jsonb_build_object('orderId', v_order_id, 'batchId', v_candidate_key, 'qty', v_alloc))
            )
          end
        into v_list_new;

        v_reserved_batches := jsonb_set(v_reserved_batches, array[v_candidate_key], v_list_new, true);

        v_need := v_need - v_alloc;
      end loop;
    end loop;

    v_tmp_list := '[]'::jsonb;
    for v_key in
      select key
      from jsonb_each(v_reserved_batches)
    loop
      if v_key <> v_expired_batch_key then
        continue;
      end if;
      v_tmp_list := coalesce(v_reserved_batches->v_key, '[]'::jsonb);
    end loop;

    v_reserved_batches := v_reserved_batches - v_expired_batch_key;

    v_new_available := greatest(0, coalesce(v_stock.available_quantity, 0) - v_effective_wastage_qty);
    v_new_reserved := greatest(0, coalesce(v_stock.reserved_quantity, 0) - least(greatest(coalesce(v_reserved_cancel_total, 0), 0), greatest(coalesce(v_stock.reserved_quantity, 0), 0)));

    update public.batches
    set quantity_consumed = quantity_consumed + v_effective_wastage_qty
    where id = v_batch.batch_id
    returning quantity_received, quantity_consumed into v_qr, v_qc;

    if coalesce(v_qc, 0) > coalesce(v_qr, 0) then
      raise exception 'Over-consumption detected for expired batch %', v_batch.batch_id;
    end if;

    update public.stock_management
    set available_quantity = v_new_available,
        reserved_quantity = v_new_reserved,
        last_updated = now(),
        updated_at = now(),
        data = jsonb_set(
          jsonb_set(
            jsonb_set(coalesce(data, '{}'::jsonb), '{availableQuantity}', to_jsonb(v_new_available), true),
            '{reservedQuantity}',
            to_jsonb(v_new_reserved),
            true
          ),
          '{reservedBatches}',
          v_reserved_batches,
          true
        )
    where item_id::text = v_batch.item_id
      and (not v_has_warehouse or warehouse_id = v_wh_id);

    insert into public.stock_wastage (
      item_id,
      quantity,
      unit_type,
      cost_at_time,
      reason,
      notes,
      reported_by,
      created_at,
      batch_id,
      warehouse_id
    )
    select
      mi.id,
      v_effective_wastage_qty,
      mi.unit_type,
      v_unit_cost,
      'auto_expired',
      'Auto-processed batch expiry detection',
      auth.uid(),
      now(),
      v_batch.batch_id,
      v_wh_id
    from public.menu_items mi
    where mi.id = v_batch.item_id
    returning id into v_wastage_id;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_batch.item_id,
      'expired_out',
      v_effective_wastage_qty,
      v_unit_cost,
      v_effective_wastage_qty * v_unit_cost,
      'batches',
      v_batch.batch_id::text,
      now(),
      auth.uid(),
      jsonb_build_object(
        'reason', 'expiry',
        'expiryDate', coalesce(v_batch_expiry, v_batch.expiry_date),
        'warehouseId', v_wh_id,
        'batchId', v_batch.batch_id
      ),
      v_batch.batch_id,
      v_wh_id
    )
    returning id into v_movement_id;

    perform public.post_inventory_movement(v_movement_id);
  end loop;

  return json_build_object('success', true, 'processed_count', processed_count);
end;
$$;


ALTER FUNCTION "public"."process_expired_items"() OWNER TO "postgres";

--
-- Name: process_expiry_light("uuid", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_expiry_light"("p_warehouse_id" "uuid" DEFAULT NULL::"uuid", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_wh uuid;
  v_processed integer := 0;
  v_row record;
  v_reserved numeric;
  v_unit_cost numeric;
  v_movement_id uuid;
  v_total_cost numeric;
begin
  perform public._require_stock_manager('process_expiry_light');

  v_actor := auth.uid();
  v_wh := coalesce(p_warehouse_id, public._resolve_default_warehouse_id());
  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  for v_row in
    select bb.item_id, bb.batch_id, bb.quantity, bb.expiry_date
    from public.batch_balances bb
    where bb.warehouse_id = v_wh
      and bb.quantity > 0
      and bb.expiry_date is not null
      and bb.expiry_date < current_date
    order by bb.expiry_date asc, bb.batch_id asc
  loop
    select coalesce(sum(br.quantity), 0)
    into v_reserved
    from public.batch_reservations br
    where br.item_id = v_row.item_id
      and br.batch_id = v_row.batch_id
      and br.warehouse_id = v_wh;

    if v_reserved > 0 then
      raise exception 'cannot process expiry for reserved batch %', v_row.batch_id;
    end if;

    select im.unit_cost
    into v_unit_cost
    from public.inventory_movements im
    where im.batch_id = v_row.batch_id
      and im.item_id::text = v_row.item_id
      and im.movement_type = 'purchase_in'
    order by im.occurred_at asc
    limit 1;
    v_unit_cost := coalesce(v_unit_cost, 0);
    v_total_cost := coalesce(v_row.quantity, 0) * v_unit_cost;

    update public.batch_balances
    set quantity = 0,
        updated_at = now()
    where item_id = v_row.item_id
      and batch_id = v_row.batch_id
      and warehouse_id = v_wh;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_row.item_id, 'wastage_out', v_row.quantity, v_unit_cost, v_total_cost,
      'accounting_light_entries', null, coalesce(p_now, now()), v_actor,
      jsonb_build_object('reason','expiry','warehouseId', v_wh, 'batchId', v_row.batch_id, 'expiredOn', v_row.expiry_date),
      v_row.batch_id, v_wh
    )
    returning id into v_movement_id;
    perform public.post_inventory_movement(v_movement_id);

    insert into public.accounting_light_entries(
      entry_type, item_id, warehouse_id, batch_id, quantity, unit, unit_cost, total_cost,
      occurred_at, debit_account, credit_account, created_by, notes, source_ref
    )
    values (
      'expiry', v_row.item_id, v_wh, v_row.batch_id, v_row.quantity, null,
      v_unit_cost, v_total_cost, coalesce(p_now, now()),
      'shrinkage', 'inventory', v_actor, 'expiry', v_movement_id::text
    );

    update public.stock_management sm
    set available_quantity = coalesce((
          select sum(bb.quantity)
          from public.batch_balances bb
          where bb.item_id = v_row.item_id
            and bb.warehouse_id = v_wh
        ), 0),
        reserved_quantity = coalesce((
          select sum(br.quantity)
          from public.batch_reservations br
          where br.item_id = v_row.item_id
            and br.warehouse_id = v_wh
        ), 0),
        updated_at = now(),
        last_updated = now()
    where sm.item_id::text = v_row.item_id
      and sm.warehouse_id = v_wh;

    insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
    values (
      'expiry.processed',
      'stock',
      'batch expired',
      v_actor,
      now(),
      jsonb_build_object('itemId', v_row.item_id, 'warehouseId', v_wh, 'batchId', v_row.batch_id, 'quantity', v_row.quantity, 'unitCost', v_unit_cost)
    );

    v_processed := v_processed + 1;
  end loop;

  return v_processed;
end;
$$;


ALTER FUNCTION "public"."process_expiry_light"("p_warehouse_id" "uuid", "p_now" timestamp with time zone) OWNER TO "postgres";

--
-- Name: process_next_accounting_job("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_next_accounting_job"("p_job_type" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
  v_now timestamptz := clock_timestamp();
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  select j.id into v_id
  from public.accounting_jobs j
  where j.status in ('queued','failed')
    and j.scheduled_at <= v_now
    and (p_job_type is null or lower(j.job_type) = lower(p_job_type))
  order by j.scheduled_at asc, j.created_at asc
  limit 1
  for update skip locked;

  if v_id is null then
    return null;
  end if;

  perform public._run_accounting_job(v_id);
  return v_id;
end;
$$;


ALTER FUNCTION "public"."process_next_accounting_job"("p_job_type" "text") OWNER TO "postgres";

--
-- Name: process_sales_return("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_sales_return"("p_return_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_ret record;
  v_order record;
  v_entry_id uuid;
  v_cash uuid;
  v_bank uuid;
  v_ar uuid;
  v_deposits uuid;
  v_sales_returns uuid;
  v_vat_payable uuid;
  v_order_subtotal numeric;
  v_order_discount numeric;
  v_order_net_subtotal numeric;
  v_order_tax numeric;
  v_return_subtotal_fx numeric;
  v_tax_refund_fx numeric;
  v_total_refund_fx numeric;
  v_return_subtotal_base numeric;
  v_tax_refund_base numeric;
  v_total_refund_base numeric;
  v_refund_method text;
  v_shift_id uuid;
  v_item jsonb;
  v_item_id text;
  v_qty numeric;
  v_needed numeric;
  v_sale record;
  v_already numeric;
  v_free numeric;
  v_alloc numeric;
  v_ret_batch_id uuid;
  v_source_batch record;
  v_movement_id uuid;
  v_wh uuid;
  v_ar_reduction_base numeric := 0;
  v_paid_total_base numeric := 0;
  v_prev_refunded_total_base numeric := 0;
  v_base text;
  v_currency text;
  v_fx numeric;
  v_cash_fx_code text;
  v_cash_fx_rate numeric;
  v_cash_fx_amount numeric;
begin
  perform public._require_staff('process_sales_return');
  if not (
    auth.role() = 'service_role'
    or public.has_admin_permission('accounting.manage')
    or public.can_manage_orders()
  ) then
    raise exception 'not authorized';
  end if;

  if p_return_id is null then
    raise exception 'p_return_id is required';
  end if;

  select *
  into v_ret
  from public.sales_returns r
  where r.id = p_return_id
  for update;
  if not found then
    raise exception 'sales return not found';
  end if;
  if v_ret.status = 'completed' then
    return;
  end if;
  if v_ret.status = 'cancelled' then
    raise exception 'sales return is cancelled';
  end if;

  select *
  into v_order
  from public.orders o
  where o.id = v_ret.order_id;
  if not found then
    raise exception 'order not found';
  end if;
  if coalesce(v_order.status,'') <> 'delivered' then
    raise exception 'sales return requires delivered order';
  end if;
  if nullif(trim(coalesce(v_order.data->>'voidedAt','')), '') is not null then
    raise exception 'order already voided';
  end if;

  v_base := public.get_base_currency();
  v_currency := upper(coalesce(nullif(btrim(coalesce(v_order.currency, v_order.data->>'currency', v_base)), ''), v_base));
  begin
    v_fx := coalesce(v_order.fx_rate, nullif((v_order.data->>'fxRate')::numeric, null), 1);
  exception when others then
    v_fx := 1;
  end;
  if v_fx is null or v_fx <= 0 then
    raise exception 'invalid fx_rate on order';
  end if;

  v_cash_fx_code := null;
  v_cash_fx_rate := null;
  v_cash_fx_amount := null;
  if v_currency <> v_base then
    v_cash_fx_code := v_currency;
    v_cash_fx_rate := v_fx;
  end if;

  v_cash := public.get_account_id_by_code('1010');
  v_bank := public.get_account_id_by_code('1020');
  v_ar := public.get_account_id_by_code('1200');
  v_deposits := public.get_account_id_by_code('2050');
  v_sales_returns := public.get_account_id_by_code('4026');
  v_vat_payable := public.get_account_id_by_code('2020');

  v_order_subtotal := coalesce(nullif((v_order.data->>'subtotal')::numeric, null), coalesce(v_order.subtotal, 0), 0);
  v_order_discount := coalesce(nullif((v_order.data->>'discountAmount')::numeric, null), coalesce(v_order.discount, 0), 0);
  v_order_net_subtotal := greatest(0, v_order_subtotal - v_order_discount);
  v_order_tax := coalesce(nullif((v_order.data->>'taxAmount')::numeric, null), coalesce(v_order.tax_amount, 0), 0);

  v_return_subtotal_fx := coalesce(nullif(v_ret.total_refund_amount, null), 0);
  if v_return_subtotal_fx <= 0 then
    raise exception 'invalid return amount';
  end if;
  if v_return_subtotal_fx > (v_order_net_subtotal + 0.000000001) then
    raise exception 'return amount exceeds order net subtotal';
  end if;

  v_tax_refund_fx := 0;
  if v_order_net_subtotal > 0 and v_order_tax > 0 then
    v_tax_refund_fx := least(v_order_tax, (v_return_subtotal_fx / v_order_net_subtotal) * v_order_tax);
  end if;

  v_total_refund_fx := public._money_round(v_return_subtotal_fx + v_tax_refund_fx);
  if v_currency <> v_base then
    v_cash_fx_amount := v_total_refund_fx;
  end if;

  v_return_subtotal_base := case when v_currency = v_base then v_return_subtotal_fx else (v_return_subtotal_fx * v_fx) end;
  v_tax_refund_base := case when v_currency = v_base then v_tax_refund_fx else (v_tax_refund_fx * v_fx) end;
  v_total_refund_base := public._money_round(v_return_subtotal_base + v_tax_refund_base);

  v_refund_method := coalesce(nullif(trim(coalesce(v_ret.refund_method, '')), ''), 'cash');
  if v_refund_method in ('bank', 'bank_transfer') then
    v_refund_method := 'kuraimi';
  elsif v_refund_method in ('card', 'online') then
    v_refund_method := 'network';
  end if;

  if to_regclass('public.payments') is not null then
    begin
      select coalesce(sum(coalesce(p.base_amount, 0)), 0)
      into v_paid_total_base
      from public.payments p
      where p.direction = 'in'
        and p.reference_table = 'orders'
        and p.reference_id = v_order.id::text;
    exception when others then
      v_paid_total_base := 0;
    end;

    begin
      select coalesce(sum(coalesce(p.base_amount, 0)), 0)
      into v_prev_refunded_total_base
      from public.payments p
      where p.direction = 'out'
        and p.reference_table = 'sales_returns'
        and (p.data->>'orderId') = v_order.id::text;
    exception when others then
      v_prev_refunded_total_base := 0;
    end;
  end if;

  if v_refund_method in ('cash','network','kuraimi') then
    if v_paid_total_base > 0 and (v_prev_refunded_total_base + v_total_refund_base) > (v_paid_total_base + 0.000000001) then
      raise exception 'refund exceeds paid amount for this order';
    end if;
  end if;

  begin
    insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, status, currency_code, fx_rate, foreign_amount)
    values (
      coalesce(v_ret.return_date, now()),
      concat('Sales return ', v_ret.id::text),
      'sales_returns',
      v_ret.id::text,
      'processed',
      auth.uid(),
      'posted',
      case when v_currency <> v_base then v_currency else null end,
      case when v_currency <> v_base then v_fx else null end,
      case when v_currency <> v_base then v_total_refund_fx else null end
    )
    returning id into v_entry_id;
  exception
    when unique_violation then
      raise exception 'sales return already posted; create a reversal instead';
  end;

  insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
  values (v_entry_id, v_sales_returns, public._money_round(v_return_subtotal_base), 0, 'Sales return');

  if v_tax_refund_base > 0 then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_vat_payable, public._money_round(v_tax_refund_base), 0, 'Reverse VAT payable');
  end if;

  if v_refund_method = 'cash' then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
    values (v_entry_id, v_cash, 0, v_total_refund_base, 'Cash refund', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
  elsif v_refund_method in ('network','kuraimi') then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
    values (v_entry_id, v_bank, 0, v_total_refund_base, 'Bank refund', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
  elsif v_refund_method = 'ar' then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_ar, 0, v_total_refund_base, 'Reduce accounts receivable');
    v_ar_reduction_base := v_total_refund_base;
  elsif v_refund_method = 'store_credit' then
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
    values (v_entry_id, v_deposits, 0, v_total_refund_base, 'Increase customer deposit');
  else
    v_refund_method := 'cash';
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, currency_code, fx_rate, foreign_amount)
    values (v_entry_id, v_cash, 0, v_total_refund_base, 'Cash refund', v_cash_fx_code, v_cash_fx_rate, v_cash_fx_amount);
  end if;

  for v_item in select value from jsonb_array_elements(coalesce(v_ret.items, '[]'::jsonb))
  loop
    v_item_id := nullif(trim(coalesce(v_item->>'itemId', '')), '');
    v_qty := coalesce(nullif(v_item->>'quantity','')::numeric, 0);
    if v_item_id is null or v_qty <= 0 then
      continue;
    end if;

    v_needed := v_qty;

    for v_sale in
      select im.id, im.item_id, im.quantity, im.unit_cost, im.total_cost, im.batch_id, im.warehouse_id, im.occurred_at
      from public.inventory_movements im
      where im.reference_table = 'orders'
        and im.reference_id = v_ret.order_id::text
        and im.movement_type = 'sale_out'
        and im.item_id::text = v_item_id::text
      order by im.occurred_at asc, im.id asc
    loop
      exit when v_needed <= 0;

      select coalesce(sum(imr.quantity), 0)
      into v_already
      from public.inventory_movements imr
      where imr.reference_table = 'sales_returns'
        and imr.movement_type = 'return_in'
        and (imr.data->>'orderId') = v_ret.order_id::text
        and (imr.data->>'sourceMovementId') = v_sale.id::text;

      v_free := greatest(coalesce(v_sale.quantity, 0) - coalesce(v_already, 0), 0);
      if v_free <= 0 then
        continue;
      end if;

      v_alloc := least(v_needed, v_free);
      if v_alloc <= 0 then
        continue;
      end if;

      select b.expiry_date, b.production_date, b.unit_cost
      into v_source_batch
      from public.batches b
      where b.id = v_sale.batch_id;

      v_wh := v_sale.warehouse_id;
      if v_wh is null then
        v_wh := coalesce(v_order.warehouse_id, public._resolve_default_admin_warehouse_id());
      end if;
      if v_wh is null then
        raise exception 'warehouse_id is required';
      end if;

      v_ret_batch_id := gen_random_uuid();
      insert into public.batches(
        id,
        item_id,
        receipt_item_id,
        receipt_id,
        warehouse_id,
        batch_code,
        production_date,
        expiry_date,
        quantity_received,
        quantity_consumed,
        unit_cost,
        qc_status,
        data
      )
      values (
        v_ret_batch_id,
        v_item_id::text,
        null,
        null,
        v_wh,
        null,
        v_source_batch.production_date,
        v_source_batch.expiry_date,
        v_alloc,
        0,
        coalesce(v_sale.unit_cost, v_source_batch.unit_cost, 0),
        'pending',
        jsonb_build_object(
          'source', 'sales_returns',
          'salesReturnId', v_ret.id::text,
          'orderId', v_ret.order_id::text,
          'sourceBatchId', v_sale.batch_id::text,
          'sourceMovementId', v_sale.id::text
        )
      );

      insert into public.inventory_movements(
        item_id, movement_type, quantity, unit_cost, total_cost,
        reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
      )
      values (
        v_item_id::text,
        'return_in',
        v_alloc,
        coalesce(v_sale.unit_cost, v_source_batch.unit_cost, 0),
        v_alloc * coalesce(v_sale.unit_cost, v_source_batch.unit_cost, 0),
        'sales_returns',
        v_ret.id::text,
        coalesce(v_ret.return_date, now()),
        auth.uid(),
        jsonb_build_object(
          'orderId', v_ret.order_id::text,
          'warehouseId', v_wh::text,
          'salesReturnId', v_ret.id::text,
          'sourceBatchId', v_sale.batch_id::text,
          'sourceMovementId', v_sale.id::text
        ),
        v_ret_batch_id,
        v_wh
      )
      returning id into v_movement_id;

      perform public.post_inventory_movement(v_movement_id);
      perform public.recompute_stock_for_item(v_item_id::text, v_wh);

      v_needed := v_needed - v_alloc;
    end loop;

    if v_needed > 1e-9 then
      raise exception 'return exceeds sold quantity for item %', v_item_id;
    end if;
  end loop;

  update public.sales_returns
  set status = 'completed',
      updated_at = now()
  where id = p_return_id;

  v_shift_id := public._resolve_open_shift_for_cash(auth.uid());
  if v_refund_method = 'cash' and v_shift_id is null then
    raise exception 'cash refund requires an open cash shift';
  end if;

  if v_refund_method in ('cash','network','kuraimi') then
    insert into public.payments(direction, method, amount, currency, fx_rate, base_amount, reference_table, reference_id, occurred_at, created_by, data, shift_id)
    values (
      'out',
      v_refund_method,
      v_total_refund_fx,
      v_currency,
      case when v_currency <> v_base then v_fx else 1 end,
      v_total_refund_base,
      'sales_returns',
      v_ret.id::text,
      coalesce(v_ret.return_date, now()),
      auth.uid(),
      jsonb_build_object('orderId', v_ret.order_id::text),
      v_shift_id
    );
  end if;

  if v_ar_reduction_base > 0 then
    perform public._apply_ar_open_item_credit(v_ret.order_id, v_ar_reduction_base);
  end if;
end;
$$;


ALTER FUNCTION "public"."process_sales_return"("p_return_id" "uuid") OWNER TO "postgres";

--
-- Name: process_workflow_escalations(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_workflow_escalations"("p_limit" integer DEFAULT 200) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_cnt int := 0;
  v_row record;
  v_step jsonb;
  v_rule public.workflow_rules%rowtype;
  v_inst public.workflow_instances%rowtype;
  v_escalation public.workflow_escalation_rules%rowtype;
  v_new_permission text;
  v_new_assignee uuid;
  v_now timestamptz := clock_timestamp();
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  for v_row in
    select a.*
    from public.workflow_current_assignments a
    join public.workflow_instances wi on wi.id = a.instance_id
    where wi.status = 'pending'
      and a.due_at is not null
      and a.due_at <= v_now
    order by a.due_at asc
    limit greatest(coalesce(p_limit, 200), 1)
  loop
    select * into v_inst from public.workflow_instances wi where wi.id = v_row.instance_id;
    select * into v_rule from public.workflow_rules wr where wr.id = v_inst.rule_id;
    select value into v_step
    from jsonb_array_elements(coalesce(v_rule.steps,'[]'::jsonb))
    where (value->>'stepNo')::int = v_row.step_no
    limit 1;

    select * into v_escalation
    from public.workflow_escalation_rules er
    where er.definition_id = v_inst.definition_id
      and er.step_no = v_row.step_no
      and er.is_active = true
    limit 1;

    v_new_permission := nullif(coalesce(v_escalation.escalate_to_permission, v_step->>'escalateToPermission',''), '');
    v_new_assignee := v_escalation.fallback_to_user_id;

    if v_new_permission is null then
      v_new_permission := 'accounting.manage';
    end if;

    if coalesce(v_row.escalation_level,0) >= coalesce(v_escalation.max_escalations, 3) then
      continue;
    end if;

    perform public._workflow_insert_assignment(
      v_row.instance_id,
      v_inst.definition_id,
      v_row.step_no,
      coalesce(v_step,'{}'::jsonb),
      coalesce(v_row.escalation_level,0) + 1,
      'timeout',
      v_new_permission,
      v_new_assignee
    );
    perform public._workflow_log_event(v_row.instance_id, 'workflow.escalated', jsonb_build_object('stepNo', v_row.step_no, 'fromPermission', v_row.assigned_permission, 'toPermission', v_new_permission, 'level', coalesce(v_row.escalation_level,0) + 1));
    v_cnt := v_cnt + 1;
  end loop;

  return v_cnt;
end;
$$;


ALTER FUNCTION "public"."process_workflow_escalations"("p_limit" integer) OWNER TO "postgres";

--
-- Name: profit_and_loss_by_period("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."profit_and_loss_by_period"("p_period_id" "uuid") RETURNS TABLE("statement_section" "text", "account_code" "text", "account_name" "text", "amount" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select *
  from public.profit_and_loss_by_range(
    (select ap.start_date from public.accounting_periods ap where ap.id = p_period_id),
    (select ap.end_date from public.accounting_periods ap where ap.id = p_period_id)
  );
$$;


ALTER FUNCTION "public"."profit_and_loss_by_period"("p_period_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "profit_and_loss_by_period"("p_period_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."profit_and_loss_by_period"("p_period_id" "uuid") IS 'Purpose: P&L by accounting_periods.id. Source of truth: profit_and_loss_by_range using period start_date/end_date.';


--
-- Name: profit_and_loss_by_range("date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."profit_and_loss_by_range"("p_start" "date", "p_end" "date") RETURNS TABLE("statement_section" "text", "account_code" "text", "account_name" "text", "amount" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.view')) then
    raise exception 'not allowed';
  end if;

  return query
  with lines as (
    select
      coa.code,
      coa.name,
      coa.account_type,
      coa.normal_balance,
      coalesce(sum(jl.debit), 0) as debit,
      coalesce(sum(jl.credit), 0) as credit
    from public.chart_of_accounts coa
    left join public.journal_lines jl on jl.account_id = coa.id
    left join public.journal_entries je
      on je.id = jl.journal_entry_id
     and (p_start is null or je.entry_date::date >= p_start)
     and (p_end is null or je.entry_date::date <= p_end)
    where coa.account_type in ('income','expense')
      and coa.is_active = true
    group by coa.code, coa.name, coa.account_type, coa.normal_balance
  ),
  amounts as (
    select
      case
        when l.account_type = 'income' then 'Revenue'
        when l.code = '5010' then 'COGS'
        else 'Operating Expenses'
      end as statement_section,
      l.code as account_code,
      l.name as account_name,
      case
        when l.normal_balance = 'debit' then (l.debit - l.credit)
        else (l.credit - l.debit)
      end as amount
    from lines l
  )
  select a.statement_section, a.account_code, a.account_name, a.amount
  from amounts a
  where abs(a.amount) > 1e-9
  order by
    case a.statement_section when 'Revenue' then 1 when 'COGS' then 2 else 3 end,
    a.account_code;
end;
$$;


ALTER FUNCTION "public"."profit_and_loss_by_range"("p_start" "date", "p_end" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "profit_and_loss_by_range"("p_start" "date", "p_end" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."profit_and_loss_by_range"("p_start" "date", "p_end" "date") IS 'Purpose: compute P&L over a date range from journal_entries/journal_lines grouped by chart_of_accounts. Source of truth: journal_entries/journal_lines; period lock enforced by Phase 10.';


--
-- Name: purchase_items_after_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."purchase_items_after_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if tg_op = 'DELETE' then
    perform public.recalc_purchase_order_totals(old.purchase_order_id);
    return old;
  end if;

  if tg_op = 'UPDATE' and (new.purchase_order_id is distinct from old.purchase_order_id) then
    perform public.recalc_purchase_order_totals(old.purchase_order_id);
    perform public.recalc_purchase_order_totals(new.purchase_order_id);
    return new;
  end if;

  perform public.recalc_purchase_order_totals(new.purchase_order_id);
  return new;
end;
$$;


ALTER FUNCTION "public"."purchase_items_after_change"() OWNER TO "postgres";

--
-- Name: purchase_items_set_total_cost(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."purchase_items_set_total_cost"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  new.total_cost := coalesce(new.quantity, 0) * coalesce(new.unit_cost, 0);
  return new;
end;
$$;


