--
-- Name: purge_non_core_data(boolean, boolean, boolean, boolean, boolean, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."purge_non_core_data"("p_keep_users" boolean DEFAULT true, "p_keep_settings" boolean DEFAULT true, "p_keep_items" boolean DEFAULT true, "p_keep_suppliers" boolean DEFAULT true, "p_keep_purchase_orders" boolean DEFAULT true, "p_force" boolean DEFAULT false) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not p_force and not public.has_admin_permission('settings.manage') then
    raise exception 'not allowed';
  end if;

  perform set_config('app.allow_ledger_ddl', '1', true);

  -- Purge ledger first to allow movement deletes
  execute 'truncate table public.journal_lines, public.journal_entries restart identity cascade';
  execute 'truncate table public.ledger_entry_hash_chain restart identity cascade';
  execute 'truncate table public.ledger_snapshot_lines, public.ledger_snapshot_headers restart identity cascade';
  execute 'truncate table public.party_ledger_entries restart identity cascade';
  execute 'truncate table public.financial_report_snapshots restart identity cascade';
  execute 'truncate table public.open_item_snapshots restart identity cascade';
  execute 'truncate table public.party_balance_snapshots restart identity cascade';

  -- Then purge movements and stock
  execute 'truncate table public.inventory_movements restart identity cascade';
  execute 'truncate table public.stock_management restart identity cascade';

  -- Operational docs
  execute 'truncate table public.payments restart identity cascade';
  execute 'truncate table public.orders restart identity cascade';
  execute 'truncate table public.sales_returns restart identity cascade';

  -- Now remove receipts if keeping POs
  if p_keep_purchase_orders then
    execute 'truncate table public.purchase_receipts restart identity cascade';
  end if;

  -- Banking/Workflow/Approvals
  execute 'truncate table public.cash_shifts restart identity cascade';
  if to_regclass('public.bank_statement_batches') is not null then
    execute 'truncate table public.bank_statement_batches restart identity cascade';
  end if;
  if to_regclass('public.bank_statement_lines') is not null then
    execute 'truncate table public.bank_statement_lines restart identity cascade';
  end if;
  if to_regclass('public.bank_reconciliation_batches') is not null then
    execute 'truncate table public.bank_reconciliation_batches restart identity cascade';
  end if;

  execute 'truncate table public.workflow_instances restart identity cascade';
  execute 'truncate table public.workflow_approvals restart identity cascade';
  execute 'truncate table public.workflow_event_logs restart identity cascade';
  execute 'truncate table public.approval_requests restart identity cascade';

  -- Expenses / import
  execute 'truncate table public.expenses restart identity cascade';
  execute 'truncate table public.import_shipments restart identity cascade';
  execute 'truncate table public.import_shipments_items restart identity cascade';
  execute 'truncate table public.import_expenses restart identity cascade';

  if to_regclass('public.audit_logs') is not null then
    execute 'truncate table public.audit_logs restart identity cascade';
  end if;

  if not p_keep_items then
    execute 'truncate table public.menu_items restart identity cascade';
    execute 'truncate table public.item_batches restart identity cascade';
    execute 'truncate table public.menu_item_prices restart identity cascade';
  end if;

  if not p_keep_suppliers then
    execute 'truncate table public.suppliers restart identity cascade';
  end if;

  if not p_keep_settings then
    execute 'truncate table public.app_settings restart identity cascade';
  end if;

  if not p_keep_users then
    execute 'truncate table public.customers restart identity cascade';
    execute 'truncate table public.admin_users restart identity cascade';
  end if;
end;
$$;


ALTER FUNCTION "public"."purge_non_core_data"("p_keep_users" boolean, "p_keep_settings" boolean, "p_keep_items" boolean, "p_keep_suppliers" boolean, "p_keep_purchase_orders" boolean, "p_force" boolean) OWNER TO "postgres";

--
-- Name: purge_purchase_order("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."purge_purchase_order"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_is_owner boolean;
  v_has_receipts boolean;
  v_has_payments boolean;
  v_has_movements boolean;
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;

  -- Only Owner can purge
  select exists(
    select 1
    from public.admin_users au
    where au.auth_user_id = auth.uid()
      and au.is_active = true
      and au.role = 'owner'
  ) into v_is_owner;

  if not coalesce(v_is_owner, false) then
    raise exception 'not allowed';
  end if;

  -- Validation: Cannot purge if it has related records (receipts, payments, movements)
  select exists(select 1 from public.purchase_receipts pr where pr.purchase_order_id = p_order_id)
  into v_has_receipts;

  select exists(
    select 1
    from public.payments p
    where p.reference_table = 'purchase_orders'
    and p.reference_id::text = p_order_id::text
  ) into v_has_payments;

  select exists(
    select 1
    from public.inventory_movements im
    where (im.reference_table = 'purchase_orders' and im.reference_id::text = p_order_id::text)
       or (im.data ? 'purchaseOrderId' and im.data->>'purchaseOrderId' = p_order_id::text)
  ) into v_has_movements;

  if coalesce(v_has_receipts, false) or coalesce(v_has_payments, false) or coalesce(v_has_movements, false) then
    raise exception 'cannot purge posted purchase order - void it instead';
  end if;

  -- Audit Log
  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    'soft_delete',
    'purchases',
    concat('Soft deleted (purged) purchase order ', p_order_id::text),
    auth.uid(),
    now(),
    jsonb_build_object('purchaseOrderId', p_order_id::text)
  );

  -- Perform Soft Delete
  update public.purchase_orders
  set deleted_at = now(),
      updated_at = now(),
      status = 'cancelled' -- Also mark as cancelled for visual clarity
  where id = p_order_id;
end;
$$;


ALTER FUNCTION "public"."purge_purchase_order"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: qc_inspect_batch("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."qc_inspect_batch"("p_batch_id" "uuid", "p_result" "text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_batch record;
begin
  perform public._require_staff('qc_inspect_batch');
  if not public.has_admin_permission('qc.inspect') then
    raise exception 'ليس لديك صلاحية فحص QC';
  end if;
  if p_batch_id is null then
    raise exception 'batch_id is required';
  end if;
  if coalesce(p_result,'') not in ('pass','fail') then
    raise exception 'result must be pass or fail';
  end if;

  select b.id, b.item_id, b.warehouse_id, coalesce(b.qc_status,'') as qc_status
  into v_batch
  from public.batches b
  where b.id = p_batch_id
  for update;
  if not found then
    raise exception 'batch not found';
  end if;

  if v_batch.qc_status not in ('pending','quarantined') then
    raise exception 'batch qc_status must be pending';
  end if;

  insert into public.qc_checks(batch_id, check_type, result, checked_by, checked_at, notes)
  values (p_batch_id, 'inspection', p_result, auth.uid(), now(), nullif(p_notes,''));

  update public.batches
  set qc_status = 'inspected',
      updated_at = now()
  where id = p_batch_id;

  perform public.recompute_stock_for_item(v_batch.item_id, v_batch.warehouse_id);
end;
$$;


ALTER FUNCTION "public"."qc_inspect_batch"("p_batch_id" "uuid", "p_result" "text", "p_notes" "text") OWNER TO "postgres";

--
-- Name: qc_release_batch("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."qc_release_batch"("p_batch_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_batch record;
  v_last_result text;
begin
  perform public._require_staff('qc_release_batch');
  if not public.has_admin_permission('qc.release') then
    raise exception 'ليس لديك صلاحية إفراج QC';
  end if;
  if p_batch_id is null then
    raise exception 'batch_id is required';
  end if;

  select b.id, b.item_id, b.warehouse_id, coalesce(b.qc_status,'') as qc_status
  into v_batch
  from public.batches b
  where b.id = p_batch_id
  for update;
  if not found then
    raise exception 'batch not found';
  end if;

  if v_batch.qc_status <> 'inspected' then
    raise exception 'batch qc_status must be inspected';
  end if;

  select qc.result
  into v_last_result
  from public.qc_checks qc
  where qc.batch_id = p_batch_id
    and qc.check_type = 'inspection'
  order by qc.checked_at desc
  limit 1;

  if coalesce(v_last_result,'') <> 'pass' then
    raise exception 'QC inspection must pass before release';
  end if;

  update public.batches
  set qc_status = 'released',
      updated_at = now()
  where id = p_batch_id;

  perform public.recompute_stock_for_item(v_batch.item_id, v_batch.warehouse_id);
end;
$$;


ALTER FUNCTION "public"."qc_release_batch"("p_batch_id" "uuid") OWNER TO "postgres";

--
-- Name: rebase_purchase_receipt_to_base("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."rebase_purchase_receipt_to_base"("p_receipt_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_receipt record;
  v_po record;
  v_wh uuid;
  v_fx numeric;
  v_item record;
  v_prev record;
  v_batch uuid;
  v_removed int := 0;
  v_reposted int := 0;
  v_errors text := '';
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.manage')) then
    raise exception 'not authenticated';
  end if;
  if p_receipt_id is null then
    raise exception 'p_receipt_id is required';
  end if;

  select *
  into v_receipt
  from public.purchase_receipts pr
  where pr.id = p_receipt_id
  for update;
  if not found then
    raise exception 'purchase receipt not found';
  end if;

  select *
  into v_po
  from public.purchase_orders po
  where po.id = v_receipt.purchase_order_id
  for update;
  if not found then
    raise exception 'purchase order not found';
  end if;

  v_wh := coalesce(v_receipt.warehouse_id, v_po.warehouse_id, public._resolve_default_warehouse_id());
  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  v_fx := null;
  begin
    v_fx := coalesce(v_po.fx_rate, null);
    if not (v_fx is not null and v_fx > 0) then
      v_fx := public.get_fx_rate(coalesce(v_po.currency,'SAR'), coalesce(v_receipt.received_at, now())::date, 'accounting');
    end if;
  exception when others then
    v_fx := null;
  end;
  if v_fx is null or v_fx <= 0 then
    raise exception 'cannot resolve fx_rate';
  end if;

  for v_item in
    select 
      pri.id as receipt_item_id,
      pri.item_id::text as item_id,
      coalesce(pri.quantity, 0) as quantity,
      coalesce(pi.unit_cost_base, coalesce(pi.unit_cost_foreign, pi.unit_cost, 0) * v_fx, 0) as unit_cost_base,
      coalesce(pri.transport_cost, 0) as transport_cost,
      coalesce(pri.supply_tax_cost, 0) as supply_tax_cost
    from public.purchase_receipt_items pri
    join public.purchase_items pi on pi.purchase_order_id = v_po.id and pi.item_id::text = pri.item_id::text
    where pri.receipt_id = p_receipt_id
  loop
    update public.purchase_receipt_items
    set unit_cost = greatest(0, coalesce(v_item.unit_cost_base, 0) + coalesce(v_item.transport_cost, 0) + coalesce(v_item.supply_tax_cost, 0)),
        total_cost = greatest(0, coalesce(v_item.quantity, 0)) * greatest(0, coalesce(v_item.unit_cost_base, 0) + coalesce(v_item.transport_cost, 0) + coalesce(v_item.supply_tax_cost, 0))
    where id = v_item.receipt_item_id;
  end loop;

  for v_prev in
    select im.id, im.item_id::text as item_id, im.quantity, im.unit_cost, im.warehouse_id
    from public.inventory_movements im
    where im.reference_table = 'purchase_receipts'
      and im.reference_id = p_receipt_id::text
      and im.movement_type = 'purchase_in'
  loop
    begin
      select b.id into v_batch
      from public.batches b
      where b.receipt_id = p_receipt_id
        and b.item_id::text = v_prev.item_id
      order by b.created_at asc
      limit 1;
      insert into public.inventory_movements(
        item_id, movement_type, quantity, unit_cost, total_cost,
        reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
      )
      values (
        v_prev.item_id,
        'return_out',
        v_prev.quantity,
        v_prev.unit_cost,
        (v_prev.quantity * v_prev.unit_cost),
        'purchase_receipts',
        p_receipt_id::text,
        coalesce(v_receipt.received_at, now()),
        coalesce(v_receipt.created_by, auth.uid()),
        jsonb_build_object('source','rebase_receipt_to_base','reversalOfMovementId', v_prev.id::text),
        v_batch,
        coalesce(v_prev.warehouse_id, v_wh)
      )
      returning id into v_prev.id;
      perform public.post_inventory_movement(v_prev.id);
      v_removed := v_removed + 1;
    exception when others then
      v_errors := left(trim(both from (v_errors || case when v_errors = '' then '' else E'\n' end || sqlerrm)), 2000);
    end;
  end loop;

  for v_item in
    select 
      pri.item_id::text as item_id,
      coalesce(pri.quantity, 0) as quantity,
      greatest(0, coalesce(pri.unit_cost, 0)) as unit_cost
    from public.purchase_receipt_items pri
    where pri.receipt_id = p_receipt_id
      and coalesce(pri.quantity, 0) > 0
  loop
    begin
      insert into public.inventory_movements(
        item_id, movement_type, quantity, unit_cost, total_cost,
        reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
      )
      values (
        v_item.item_id,
        'purchase_in',
        v_item.quantity,
        v_item.unit_cost,
        (v_item.quantity * v_item.unit_cost),
        'purchase_receipts',
        p_receipt_id::text,
        coalesce(v_receipt.received_at, now()),
        coalesce(v_receipt.created_by, auth.uid()),
        jsonb_build_object('purchaseOrderId', v_po.id, 'purchaseReceiptId', p_receipt_id, 'warehouseId', v_wh),
        gen_random_uuid(),
        v_wh
      )
      returning id into v_prev.id;

      perform public.post_inventory_movement(v_prev.id);
      v_reposted := v_reposted + 1;
    exception when others then
      v_errors := left(trim(both from (v_errors || case when v_errors = '' then '' else E'\n' end || sqlerrm)), 2000);
    end;
  end loop;

  begin
    update public.purchase_receipts
    set posting_status = case when v_errors = '' then 'posted' else 'failed' end,
        posting_error = nullif(v_errors, ''),
        posted_at = case when v_errors = '' then now() else null end
    where id = p_receipt_id;
  exception when others then
    null;
  end;
  begin
    perform public.reconcile_purchase_order_receipt_status(v_receipt.purchase_order_id);
  exception when others then
    null;
  end;

  return jsonb_build_object(
    'status', case when v_errors = '' then 'ok' else 'failed' end,
    'receiptId', p_receipt_id::text,
    'removedMovements', v_removed,
    'repostedMovements', v_reposted,
    'errors', nullif(v_errors, '')
  );
end;
$$;


ALTER FUNCTION "public"."rebase_purchase_receipt_to_base"("p_receipt_id" "uuid") OWNER TO "postgres";

--
-- Name: rebuild_order_line_items("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."rebuild_order_line_items"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order record;
  v_item jsonb;
  v_item_id text;
  v_qty numeric;
  v_price numeric;
begin
  select * into v_order from public.orders where id = p_order_id;
  if not found then
    raise exception 'order not found';
  end if;
  delete from public.order_line_items where order_id = p_order_id;
  for v_item in select value from jsonb_array_elements(coalesce(v_order.items, v_order.data->'items', '[]'::jsonb))
  loop
    v_item_id := coalesce(v_item->>'itemId', v_item->>'id');
    v_qty := coalesce((v_item->>'quantity')::numeric, 0);
    v_price := coalesce((v_item->>'price')::numeric, 0);
    insert into public.order_line_items(order_id, item_id, quantity, unit_price, total, data)
    values (p_order_id, v_item_id, v_qty, v_price, v_qty * v_price, v_item);
  end loop;
end;
$$;


ALTER FUNCTION "public"."rebuild_order_line_items"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: recalc_payroll_run_totals("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."recalc_payroll_run_totals"("p_run_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_gross numeric;
  v_ded numeric;
  v_net numeric;
  v_run record;
  v_current_cc uuid;
begin
  if p_run_id is null then
    raise exception 'run_id is required';
  end if;

  select *
  into v_run
  from public.payroll_runs
  where id = p_run_id
  for update;

  if not found then
    raise exception 'run not found';
  end if;

  select
    coalesce(sum(coalesce(l.gross,0) + coalesce(l.allowances,0)), 0),
    coalesce(sum(coalesce(l.deductions,0)), 0),
    coalesce(sum(coalesce(l.net,0)), 0)
  into v_gross, v_ded, v_net
  from public.payroll_run_lines l
  where l.run_id = p_run_id;

  update public.payroll_runs
  set total_gross = v_gross,
      total_deductions = v_ded,
      total_net = v_net
  where id = p_run_id;

  if v_run.expense_id is not null then
    update public.expenses
    set amount = v_net
    where id = v_run.expense_id;

    if v_run.cost_center_id is not null then
      select e.cost_center_id
      into v_current_cc
      from public.expenses e
      where e.id = v_run.expense_id;

      if v_current_cc is distinct from v_run.cost_center_id then
        update public.expenses
        set cost_center_id = v_run.cost_center_id
        where id = v_run.expense_id;
      end if;
    end if;
  end if;
end;
$$;


ALTER FUNCTION "public"."recalc_payroll_run_totals"("p_run_id" "uuid") OWNER TO "postgres";

--
-- Name: recalc_purchase_order_totals("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."recalc_purchase_order_totals"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_items_total numeric;
  v_returns_total numeric;
  v_net_total numeric;
begin
  if p_order_id is null then
    return;
  end if;

  select coalesce(sum(coalesce(pi.total_cost, coalesce(pi.quantity, 0) * coalesce(pi.unit_cost, 0))), 0)
  into v_items_total
  from public.purchase_items pi
  where pi.purchase_order_id = p_order_id;

  select coalesce(sum(coalesce(pri.total_cost, coalesce(pri.quantity, 0) * coalesce(pri.unit_cost, 0))), 0)
  into v_returns_total
  from public.purchase_returns pr
  join public.purchase_return_items pri on pri.return_id = pr.id
  where pr.purchase_order_id = p_order_id;

  v_net_total := greatest(0, coalesce(v_items_total, 0) - coalesce(v_returns_total, 0));

  update public.purchase_orders po
  set
    total_amount = v_net_total,
    items_count = coalesce((
      select count(*)
      from public.purchase_items pi
      where pi.purchase_order_id = p_order_id
    ), 0),
    paid_amount = least(coalesce(po.paid_amount, 0), v_net_total),
    updated_at = now()
  where po.id = p_order_id;
end;
$$;


ALTER FUNCTION "public"."recalc_purchase_order_totals"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: receive_inventory_transfer("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."receive_inventory_transfer"("p_transfer_id" "uuid", "p_idempotency_key" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_transfer record;
  v_item record;
  v_source_batch record;
  v_dest_batch_id uuid;
  v_old_qty numeric;
  v_old_avg numeric;
  v_new_qty numeric;
  v_new_avg numeric;
  v_movement_id uuid;
begin
  v_actor := auth.uid();
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;
  if p_transfer_id is null then
    raise exception 'p_transfer_id is required';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_transfer_id::text));

  select *
  into v_transfer
  from public.inventory_transfers it
  where it.id = p_transfer_id
  for update;

  if not found then
    raise exception 'transfer not found';
  end if;

  if p_idempotency_key is not null and btrim(p_idempotency_key) <> '' then
    if v_transfer.receive_idempotency_key is not null and v_transfer.receive_idempotency_key = p_idempotency_key then
      return jsonb_build_object('status', v_transfer.state, 'transferId', p_transfer_id::text);
    end if;
  end if;

  if v_transfer.state = 'RECEIVED' then
    return jsonb_build_object('status', 'RECEIVED', 'transferId', p_transfer_id::text);
  end if;

  if v_transfer.state <> 'IN_TRANSIT' then
    raise exception 'cannot receive transfer in state %', v_transfer.state;
  end if;

  for v_item in
    select *
    from public.inventory_transfer_items iti
    where iti.transfer_id = p_transfer_id
    order by iti.created_at asc, iti.id asc
    for update
  loop
    if coalesce(v_item.received_qty, 0) > 0 then
      continue;
    end if;

    if v_item.received_batch_id is null then
      update public.inventory_transfer_items
      set received_batch_id = gen_random_uuid()
      where id = v_item.id
        and received_batch_id is null
      returning received_batch_id into v_dest_batch_id;

      if v_dest_batch_id is null then
        continue;
      end if;
    else
      v_dest_batch_id := v_item.received_batch_id;
    end if;

    if exists (
      select 1
      from public.inventory_movements im
      where im.reference_table = 'inventory_transfers'
        and im.reference_id = p_transfer_id::text
        and im.movement_type = 'transfer_in'
        and im.item_id = v_item.item_id
        and im.batch_id = v_dest_batch_id
        and im.warehouse_id is not distinct from v_transfer.to_warehouse_id
    ) then
      update public.inventory_transfer_items
      set received_qty = quantity,
          received_batch_id = v_dest_batch_id,
          updated_at = now()
      where id = v_item.id;
      continue;
    end if;

    select *
    into v_source_batch
    from public.batches b
    where b.id = v_item.source_batch_id
    for update;

    if not found then
      raise exception 'source batch not found';
    end if;

    insert into public.batches(
      id,
      item_id,
      receipt_item_id,
      receipt_id,
      warehouse_id,
      batch_code,
      production_date,
      expiry_date,
      quantity_received,
      quantity_consumed,
      quantity_transferred,
      unit_cost,
      data
    )
    values (
      v_dest_batch_id,
      v_item.item_id,
      null,
      null,
      v_transfer.to_warehouse_id,
      v_source_batch.batch_code,
      v_source_batch.production_date,
      v_source_batch.expiry_date,
      v_item.quantity,
      0,
      0,
      v_item.unit_cost,
      jsonb_build_object(
        'source', 'inventory_transfer',
        'transferId', p_transfer_id,
        'sourceBatchId', v_item.source_batch_id,
        'fromWarehouseId', v_transfer.from_warehouse_id
      )
    )
    on conflict (id) do nothing;

    select coalesce(sm.available_quantity,0), coalesce(sm.avg_cost,0)
    into v_old_qty, v_old_avg
    from public.stock_management sm
    where sm.item_id::text = v_item.item_id
      and sm.warehouse_id = v_transfer.to_warehouse_id
    for update;

    if not found then
      insert into public.stock_management(item_id, warehouse_id, available_quantity, reserved_quantity, unit, low_stock_threshold, avg_cost, last_updated, updated_at, data)
      select mi.id, v_transfer.to_warehouse_id, 0, 0, coalesce(mi.unit_type,'piece'), 5, 0, now(), now(), '{}'::jsonb
      from public.menu_items mi
      where mi.id = v_item.item_id
      on conflict (item_id, warehouse_id) do nothing;

      select coalesce(sm.available_quantity,0), coalesce(sm.avg_cost,0)
      into v_old_qty, v_old_avg
      from public.stock_management sm
      where sm.item_id::text = v_item.item_id
        and sm.warehouse_id = v_transfer.to_warehouse_id
      for update;
    end if;

    v_new_qty := v_old_qty + v_item.quantity;
    if v_new_qty <= 0 then
      v_new_avg := v_item.unit_cost;
    else
      v_new_avg := ((v_old_qty * v_old_avg) + (v_item.quantity * v_item.unit_cost)) / v_new_qty;
    end if;

    update public.stock_management
    set available_quantity = available_quantity + v_item.quantity,
        avg_cost = v_new_avg,
        last_updated = now(),
        updated_at = now()
    where item_id::text = v_item.item_id
      and warehouse_id = v_transfer.to_warehouse_id;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_item.item_id,
      'transfer_in',
      v_item.quantity,
      v_item.unit_cost,
      0,
      'inventory_transfers',
      p_transfer_id::text,
      now(),
      v_actor,
      jsonb_build_object(
        'transferId', p_transfer_id,
        'direction', 'in',
        'fromWarehouseId', v_transfer.from_warehouse_id,
        'toWarehouseId', v_transfer.to_warehouse_id,
        'sourceBatchId', v_item.source_batch_id
      ),
      v_dest_batch_id,
      v_transfer.to_warehouse_id
    )
    returning id into v_movement_id;

    perform public.post_inventory_movement(v_movement_id);

    update public.inventory_transfer_items
    set received_qty = quantity,
        received_batch_id = v_dest_batch_id,
        updated_at = now()
    where id = v_item.id;
  end loop;

  update public.inventory_transfers
  set state = 'RECEIVED',
      received_by = v_actor,
      received_at = now(),
      updated_at = now(),
      receive_idempotency_key = nullif(btrim(p_idempotency_key), '')
  where id = p_transfer_id;

  return jsonb_build_object('status', 'RECEIVED', 'transferId', p_transfer_id::text);
end;
$$;


ALTER FUNCTION "public"."receive_inventory_transfer"("p_transfer_id" "uuid", "p_idempotency_key" "text") OWNER TO "postgres";

--
-- Name: receive_purchase_order("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."receive_purchase_order"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_po record;
  v_wh uuid;
  v_fx numeric;
  v_pi record;
  v_old_qty numeric;
  v_old_avg numeric;
  v_new_qty numeric;
  v_new_avg numeric;
  v_unit_cost_base numeric;
  v_effective_unit_cost numeric;
  v_used_transport_cost numeric;
  v_used_supply_tax_cost numeric;
  v_effective_unit_cost_base numeric;
  v_qty_base numeric;
  v_batch_id uuid;
  v_expiry_iso text;
  v_harvest_iso text;
  v_movement_id uuid;
begin
  if p_order_id is null then
    raise exception 'order_id is required';
  end if;

  select *
  into v_po
  from public.purchase_orders po
  where po.id = p_order_id
  for update;
  if not found then
    raise exception 'purchase order not found';
  end if;
  if v_po.status = 'cancelled' then
    raise exception 'cannot receive cancelled purchase order';
  end if;

  v_wh := coalesce(v_po.warehouse_id, public._resolve_default_warehouse_id());
  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  v_fx := coalesce(v_po.fx_rate, null);
  if not (v_fx is not null and v_fx > 0) then
    v_fx := public.get_fx_rate(coalesce(v_po.currency,'SAR'), coalesce(v_po.created_at, now())::date, 'accounting');
  end if;
  if v_fx is null or v_fx <= 0 then
    raise exception 'cannot resolve fx_rate';
  end if;

  for v_pi in
    select
      pi.item_id,
      pi.quantity,
      pi.uom_id,
      pi.qty_base,
      pi.unit_cost,
      pi.unit_cost_base,
      pi.unit_cost_foreign
    from public.purchase_items pi
    where pi.purchase_order_id = p_order_id
  loop
    select coalesce(sm.available_quantity, 0), coalesce(sm.avg_cost, 0)
    into v_old_qty, v_old_avg
    from public.stock_management sm
    where sm.item_id::text = v_pi.item_id::text
      and sm.warehouse_id = v_wh
    for update;

    v_unit_cost_base := greatest(0, coalesce(v_pi.unit_cost_base, coalesce(v_pi.unit_cost_foreign, v_pi.unit_cost, 0) * v_fx));
    select coalesce(mi.transport_cost, 0), coalesce(mi.supply_tax_cost, 0)
    into v_used_transport_cost, v_used_supply_tax_cost
    from public.menu_items mi
    where mi.id = v_pi.item_id;
    v_effective_unit_cost := greatest(0, v_unit_cost_base + coalesce(v_used_transport_cost, 0) + coalesce(v_used_supply_tax_cost, 0));

    v_qty_base := coalesce(v_pi.qty_base, public.item_qty_to_base(v_pi.item_id, coalesce(v_pi.quantity, 0), v_pi.uom_id));
    v_effective_unit_cost_base := public.item_unit_cost_to_base(v_pi.item_id, v_effective_unit_cost, coalesce(v_pi.uom_id, (select base_uom_id from public.item_uom where item_id = v_pi.item_id limit 1)));

    v_new_qty := coalesce(v_old_qty, 0) + coalesce(v_qty_base, 0);
    if v_new_qty <= 0 then
      v_new_avg := v_effective_unit_cost_base;
    else
      v_new_avg := ((coalesce(v_old_qty, 0) * coalesce(v_old_avg, 0)) + (coalesce(v_qty_base, 0) * v_effective_unit_cost_base)) / v_new_qty;
    end if;

    update public.stock_management
    set available_quantity = coalesce(available_quantity, 0) + coalesce(v_qty_base, 0),
        avg_cost = v_new_avg,
        last_updated = now(),
        updated_at = now()
    where item_id::text = v_pi.item_id::text
      and warehouse_id = v_wh;

    v_batch_id := gen_random_uuid();
    insert into public.batches(
      id, item_id, receipt_item_id, receipt_id, warehouse_id, batch_code,
      production_date, expiry_date, quantity_received, quantity_consumed, quantity_transferred,
      unit_cost, qc_status, status, data
    )
    values (
      v_batch_id,
      v_pi.item_id,
      null,
      null,
      v_wh,
      null,
      case when v_harvest_iso is null then null else v_harvest_iso::date end,
      case when v_expiry_iso is null then null else v_expiry_iso::date end,
      v_qty_base,
      0,
      0,
      v_effective_unit_cost_base,
      'released',
      'active',
      jsonb_build_object('purchaseOrderId', p_order_id, 'warehouseId', v_wh)
    )
    on conflict (id) do nothing;

    update public.menu_items
    set buying_price = v_unit_cost_base,
        cost_price = v_new_avg,
        updated_at = now()
    where id = v_pi.item_id;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_pi.item_id, 'purchase_in', coalesce(v_qty_base, 0), v_effective_unit_cost_base, (coalesce(v_qty_base, 0) * v_effective_unit_cost_base),
      'purchase_orders', p_order_id::text, now(), auth.uid(), jsonb_build_object('purchaseOrderId', p_order_id, 'warehouseId', v_wh, 'trxQty', coalesce(v_pi.quantity, null), 'trxUomId', case when v_pi.uom_id is null then null else v_pi.uom_id::text end),
      v_batch_id,
      v_wh
    )
    returning id into v_movement_id;
    perform public.post_inventory_movement(v_movement_id);
  end loop;

  -- skip status update in local smoke to avoid approval trigger
end;
$$;


ALTER FUNCTION "public"."receive_purchase_order"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: receive_purchase_order_partial("uuid", "jsonb", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."receive_purchase_order_partial"("p_order_id" "uuid", "p_items" "jsonb", "p_occurred_at" timestamp with time zone DEFAULT "now"()) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_id uuid;
  v_constraint text;
  v_detail text;
  v_message text;
begin
  v_id := public._receive_purchase_order_partial_impl(p_order_id, p_items, p_occurred_at);

  begin
    perform public.reconcile_purchase_order_receipt_status(p_order_id);
  exception
    when undefined_function then
      null;
    when others then
      null;
  end;

  return v_id;
exception
  when unique_violation then
    get stacked diagnostics
      v_constraint = constraint_name,
      v_detail = pg_exception_detail,
      v_message = message_text;
    raise exception 'DUPLICATE_CONSTRAINT:%:%', coalesce(v_constraint, ''), coalesce(v_detail, v_message, '')
      using errcode = 'P0001';
end;
$$;


ALTER FUNCTION "public"."receive_purchase_order_partial"("p_order_id" "uuid", "p_items" "jsonb", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: reclass_return_out_to_ap("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reclass_return_out_to_ap"("p_receipt_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_mv record;
  v_entry uuid;
  v_done int := 0;
begin
  if not (public.has_admin_permission('accounting.manage') and public.has_admin_permission('accounting.approve')) then
    raise exception 'not allowed';
  end if;
  if p_receipt_id is null then
    raise exception 'p_receipt_id required';
  end if;

  for v_mv in
    select im.id, im.total_cost
    from public.inventory_movements im
    where im.reference_table = 'purchase_receipts'
      and im.reference_id = p_receipt_id::text
      and im.movement_type = 'return_out'
  loop
    v_entry := public.create_manual_journal_entry(
      now(),
      concat('Reclass return_out to AP for receipt ', p_receipt_id::text),
      jsonb_build_array(
        jsonb_build_object('accountCode','2010','debit', coalesce(v_mv.total_cost,0)),
        jsonb_build_object('accountCode','5020','credit', coalesce(v_mv.total_cost,0))
      )
    );
    perform public.approve_journal_entry(v_entry);
    v_done := v_done + 1;
  end loop;

  return jsonb_build_object('reclassCount', v_done);
end;
$$;


ALTER FUNCTION "public"."reclass_return_out_to_ap"("p_receipt_id" "uuid") OWNER TO "postgres";

--
-- Name: recompute_stock_for_item("text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."recompute_stock_for_item"("p_item_id" "text", "p_warehouse_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_is_food boolean := false;
begin
  perform public._require_staff('recompute_stock_for_item');

  if p_item_id is null or btrim(p_item_id) = '' then
    raise exception 'item_id is required';
  end if;
  if p_warehouse_id is null then
    raise exception 'warehouse_id is required';
  end if;

  select (coalesce(mi.category,'') = 'food')
  into v_is_food
  from public.menu_items mi
  where mi.id::text = p_item_id::text;

  insert into public.stock_management(item_id, warehouse_id, available_quantity, qc_hold_quantity, reserved_quantity, unit, low_stock_threshold, last_updated, data)
  select p_item_id, p_warehouse_id, 0, 0, 0, coalesce(mi.unit_type, 'piece'), 5, now(), '{}'::jsonb
  from public.menu_items mi
  where mi.id::text = p_item_id::text
  on conflict (item_id, warehouse_id) do nothing;

  update public.stock_management sm
  set
    reserved_quantity = coalesce((
      select sum(r.quantity)
      from public.order_item_reservations r
      where r.item_id::text = p_item_id::text
        and r.warehouse_id = p_warehouse_id
    ), 0),
    available_quantity = coalesce((
      select sum(
        greatest(
          coalesce(b.quantity_received,0)
          - coalesce(b.quantity_consumed,0)
          - coalesce(b.quantity_transferred,0),
          0
        )
      )
      from public.batches b
      where b.item_id::text = p_item_id::text
        and b.warehouse_id = p_warehouse_id
        and coalesce(b.status,'active') = 'active'
        and coalesce(b.qc_status,'') = 'released'
        and not exists (
          select 1 from public.batch_recalls br
          where br.batch_id = b.id and br.status = 'active'
        )
        and (
          not coalesce(v_is_food, false)
          or (b.expiry_date is not null and b.expiry_date >= current_date)
        )
    ), 0),
    qc_hold_quantity = coalesce((
      select sum(
        greatest(
          coalesce(b.quantity_received,0)
          - coalesce(b.quantity_consumed,0)
          - coalesce(b.quantity_transferred,0),
          0
        )
      )
      from public.batches b
      where b.item_id::text = p_item_id::text
        and b.warehouse_id = p_warehouse_id
        and coalesce(b.status,'active') = 'active'
        and coalesce(b.qc_status,'') <> 'released'
        and not exists (
          select 1 from public.batch_recalls br
          where br.batch_id = b.id and br.status = 'active'
        )
        and (
          not coalesce(v_is_food, false)
          or (b.expiry_date is not null and b.expiry_date >= current_date)
        )
    ), 0),
    last_updated = now(),
    updated_at = now()
  where sm.item_id::text = p_item_id::text
    and sm.warehouse_id = p_warehouse_id;
end;
$$;


ALTER FUNCTION "public"."recompute_stock_for_item"("p_item_id" "text", "p_warehouse_id" "uuid") OWNER TO "postgres";

--
-- Name: reconcile_all_purchase_orders(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reconcile_all_purchase_orders"("p_limit" integer DEFAULT 10000) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
  v_n int := 0;
begin
  for v_id in
    select po.id
    from public.purchase_orders po
    where po.status <> 'cancelled'
      and exists (select 1 from public.purchase_receipts pr where pr.purchase_order_id = po.id)
    order by po.updated_at desc nulls last
    limit greatest(coalesce(p_limit, 0), 0)
  loop
    begin
      perform public.reconcile_purchase_order_receipt_status(v_id);
      v_n := v_n + 1;
    exception when others then
      null;
    end;
  end loop;

  return v_n;
end;
$$;


ALTER FUNCTION "public"."reconcile_all_purchase_orders"("p_limit" integer) OWNER TO "postgres";

--
-- Name: reconcile_bank_batch("uuid", integer, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reconcile_bank_batch"("p_batch_id" "uuid", "p_tolerance_days" integer DEFAULT 3, "p_tolerance_amount" numeric DEFAULT 0.01) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_line record;
  v_pay record;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  for v_line in
    select * from public.bank_statement_lines
    where batch_id = p_batch_id and matched = false
  loop
    select *
    into v_pay
    from public.payments p
    where abs(coalesce(p.base_amount, p.amount, 0) - coalesce(v_line.amount, 0)) <= coalesce(p_tolerance_amount, 0.01)
      and p.occurred_at::date between (v_line.txn_date - coalesce(p_tolerance_days,3)) and (v_line.txn_date + coalesce(p_tolerance_days,3))
      and p.method <> 'cash'
    order by abs(coalesce(p.base_amount, p.amount, 0) - coalesce(v_line.amount, 0)) asc,
             abs((p.occurred_at::date - v_line.txn_date)) asc
    limit 1;

    if found then
      insert into public.bank_reconciliation_matches(statement_line_id, payment_id, matched_by, status)
      values (v_line.id, v_pay.id, auth.uid(), 'matched');
      update public.bank_statement_lines set matched = true where id = v_line.id;
    end if;
  end loop;
end;
$$;


ALTER FUNCTION "public"."reconcile_bank_batch"("p_batch_id" "uuid", "p_tolerance_days" integer, "p_tolerance_amount" numeric) OWNER TO "postgres";

--
-- Name: reconcile_po_full_fix(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reconcile_po_full_fix"("p_limit" integer DEFAULT 100000) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_r int := 0;
  v_p int := 0;
  v_n int := 0;
  v_f int := 0;
begin
  begin
    v_r := coalesce(public.backfill_receipt_items_qty_base(), 0);
  exception when others then
    v_r := 0;
  end;
  begin
    v_p := coalesce(public.backfill_purchase_items_qty_base(), 0);
  exception when others then
    v_p := 0;
  end;
  begin
    if to_regprocedure('public.reconcile_all_purchase_orders(integer)') is not null then
      v_n := coalesce(public.reconcile_all_purchase_orders(greatest(coalesce(p_limit, 0), 0)), 0);
    else
      v_n := 0;
    end if;
  exception when others then
    v_n := 0;
  end;
  begin
    if to_regprocedure('public.force_complete_purchase_orders_from_receipts(integer)') is not null then
      v_f := coalesce(public.force_complete_purchase_orders_from_receipts(greatest(coalesce(p_limit, 0), 0)), 0);
    else
      v_f := 0;
    end if;
  exception when others then
    v_f := 0;
  end;
  notify pgrst, 'reload schema';
  return jsonb_build_object(
    'receiptItemsUpdated', coalesce(v_r, 0),
    'purchaseItemsUpdated', coalesce(v_p, 0),
    'ordersReconciled', coalesce(v_n, 0),
    'ordersForced', coalesce(v_f, 0)
  );
end;
$$;


ALTER FUNCTION "public"."reconcile_po_full_fix"("p_limit" integer) OWNER TO "postgres";

--
-- Name: reconcile_purchase_order_receipt_status("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reconcile_purchase_order_receipt_status"("p_order_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_status text;
  v_has_receipts boolean;
  v_all_received boolean;
  v_has_batches boolean := false;
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;

  select po.status
  into v_status
  from public.purchase_orders po
  where po.id = p_order_id
  for update;

  if not found then
    raise exception 'purchase order not found';
  end if;

  if v_status = 'cancelled' then
    return 'cancelled';
  end if;

  select exists(select 1 from public.purchase_receipts pr where pr.purchase_order_id = p_order_id)
  into v_has_receipts;

  if not coalesce(v_has_receipts, false) then
    return coalesce(v_status, 'draft');
  end if;

  begin
    if to_regclass('public.batches') is not null then
      select exists(
        select 1
        from public.purchase_receipts pr
        join public.batches b on b.receipt_id = pr.id
        where pr.purchase_order_id = p_order_id
      )
      into v_has_batches;
    end if;
  exception when others then
    v_has_batches := false;
  end;

  if coalesce(v_has_batches, false) then
    with totals as (
      select b.item_id::text as item_id, sum(coalesce(b.quantity_received, 0)) as received_base
      from public.purchase_receipts pr
      join public.batches b on b.receipt_id = pr.id
      where pr.purchase_order_id = p_order_id
      group by b.item_id::text
    ),
    ordered as (
      select
        pi.id,
        pi.item_id::text as item_id,
        coalesce(
          nullif(pi.qty_base, 0),
          case
            when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
            else pi.quantity
          end,
          0
        ) as ordered_base
      from public.purchase_items pi
      where pi.purchase_order_id = p_order_id
    )
    update public.purchase_items pi
    set received_quantity = least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0))
    from totals t
    join ordered o on o.id = pi.id
    where pi.purchase_order_id = p_order_id
      and pi.item_id::text = t.item_id
      and coalesce(pi.received_quantity, 0) is distinct from least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0));
  else
    with totals as (
      select
        pri.item_id::text as item_id,
        sum(
          coalesce(
            nullif(pri.qty_base, 0),
            case
              when pri.uom_id is not null then public.item_qty_to_base_safe(pri.item_id, pri.quantity, pri.uom_id)
              else pri.quantity
            end,
            0
          )
        ) as received_base
      from public.purchase_receipts pr
      join public.purchase_receipt_items pri on pri.receipt_id = pr.id
      where pr.purchase_order_id = p_order_id
      group by pri.item_id::text
    ),
    ordered as (
      select
        pi.id,
        pi.item_id::text as item_id,
        coalesce(
          nullif(pi.qty_base, 0),
          case
            when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
            else pi.quantity
          end,
          0
        ) as ordered_base
      from public.purchase_items pi
      where pi.purchase_order_id = p_order_id
    )
    update public.purchase_items pi
    set received_quantity = least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0))
    from totals t
    join ordered o on o.id = pi.id
    where pi.purchase_order_id = p_order_id
      and pi.item_id::text = t.item_id
      and coalesce(pi.received_quantity, 0) is distinct from least(coalesce(t.received_base, 0), coalesce(o.ordered_base, 0));
  end if;

  select not exists (
    select 1
    from public.purchase_items pi
    where pi.purchase_order_id = p_order_id
      and (coalesce(pi.received_quantity, 0) + 0.000000001) < coalesce(
        nullif(pi.qty_base, 0),
        case
          when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
          else pi.quantity
        end,
        0
      )
  )
  into v_all_received;

  if coalesce(v_all_received, false) then
    update public.purchase_orders
    set status = 'completed',
        updated_at = now()
    where id = p_order_id
      and status is distinct from 'completed';
    return 'completed';
  end if;

  if v_status = 'draft' then
    update public.purchase_orders
    set status = 'partial',
        updated_at = now()
    where id = p_order_id;
    return 'partial';
  end if;

  return coalesce(v_status, 'partial');
end;
$$;


ALTER FUNCTION "public"."reconcile_purchase_order_receipt_status"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: record_expense_accrual("uuid", numeric, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_expense_accrual"("p_expense_id" "uuid", "p_amount" numeric, "p_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_entry_id uuid;
  v_expenses uuid;
  v_ap uuid;
  v_override text;
begin
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;

  if p_amount <= 0 then
    raise exception 'amount must be positive';
  end if;

  v_expenses := public.get_account_id_by_code('6100');
  v_ap := public.get_account_id_by_code('2010');
  if v_expenses is null or v_ap is null then
    raise exception 'required accounts not found';
  end if;

  select nullif(trim(coalesce(e.data->>'overrideAccountId','')), '')
  into v_override
  from public.expenses e
  where e.id = p_expense_id;

  v_ap := public.resolve_override_account(v_ap, v_override, array['liability','equity']);

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    coalesce(p_occurred_at, now()),
    concat('Expense accrual: ', p_expense_id),
    'expenses',
    p_expense_id::text,
    'accrual',
    auth.uid()
  )
  returning id into v_entry_id;

  insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
  values
    (v_entry_id, v_expenses, p_amount, 0, 'Expense accrual'),
    (v_entry_id, v_ap, 0, p_amount, 'Expense payable');

  perform public.check_journal_entry_balance(v_entry_id);
end;
$$;


ALTER FUNCTION "public"."record_expense_accrual"("p_expense_id" "uuid", "p_amount" numeric, "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_expense_payment("uuid", numeric, "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_expense_payment"("p_expense_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
    v_method text;
    v_occurred_at timestamptz;
    v_shift_id uuid;
    v_data jsonb := '{}'::jsonb;
    v_override text;
begin
    if not public.can_manage_expenses() then
        raise exception 'not allowed';
    end if;
    if p_amount <= 0 then
        raise exception 'amount must be positive';
    end if;

    v_method := nullif(trim(p_method), '');
    if v_method is null then
      v_method := 'cash';
    end if;

    if v_method = 'card' then
      v_method := 'network';
    elsif v_method = 'bank' then
      v_method := 'kuraimi';
    end if;

    v_occurred_at := coalesce(p_occurred_at, now());
    v_shift_id := public._resolve_open_shift_for_cash(auth.uid());
    if v_method = 'cash' and v_shift_id is null then
        raise exception 'cash payment requires an open shift';
    end if;

    select nullif(trim(coalesce(e.data->>'overrideAccountId','')), '')
    into v_override
    from public.expenses e
    where e.id = p_expense_id;

    v_data := jsonb_strip_nulls(jsonb_build_object('expenseId', p_expense_id::text, 'overrideAccountId', v_override));

    insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, shift_id, data)
    values (
        'out',
        v_method,
        p_amount,
        'YER',
        'expenses',
        p_expense_id::text,
        v_occurred_at,
        auth.uid(),
        v_shift_id,
        v_data
    );
end;
$$;


ALTER FUNCTION "public"."record_expense_payment"("p_expense_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_import_expense_payment("uuid", numeric, "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_import_expense_payment"("p_import_expense_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_amount numeric;
  v_method text;
  v_occurred_at timestamptz;
  v_payment_id uuid;
begin
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;

  if p_import_expense_id is null then
    raise exception 'p_import_expense_id is required';
  end if;

  v_amount := coalesce(p_amount, 0);
  if v_amount <= 0 then
    select coalesce(ie.amount, 0) * coalesce(ie.exchange_rate, 1)
    into v_amount
    from public.import_expenses ie
    where ie.id = p_import_expense_id;
  end if;
  if v_amount <= 0 then
    raise exception 'invalid amount';
  end if;

  v_method := nullif(trim(coalesce(p_method, '')), '');
  if v_method is null then
    v_method := 'cash';
  end if;

  v_occurred_at := coalesce(p_occurred_at, now());

  insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data)
  values (
    'out',
    v_method,
    v_amount,
    'YER',
    'import_expenses',
    p_import_expense_id::text,
    v_occurred_at,
    auth.uid(),
    jsonb_build_object('importExpenseId', p_import_expense_id::text)
  )
  returning id into v_payment_id;

  perform public.post_payment(v_payment_id);
end;
$$;


ALTER FUNCTION "public"."record_import_expense_payment"("p_import_expense_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_order_payment("uuid", numeric, "text", timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_order_payment"("p_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone, "p_idempotency_key" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_amount numeric;
  v_method text;
  v_occurred_at timestamptz;
  v_total numeric;
  v_paid numeric;
  v_idempotency text;
  v_shift_id uuid;
begin
  if auth.role() <> 'service_role' then
    if not public.is_staff() then
      raise exception 'not allowed';
    end if;
    if not public.has_admin_permission('orders.markPaid') then
      raise exception 'not allowed';
    end if;
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  select coalesce(nullif((o.data->>'total')::numeric, null), 0)
  into v_total
  from public.orders o
  where o.id = p_order_id;
  if not found then
    raise exception 'order not found';
  end if;
  v_amount := coalesce(p_amount, 0);
  if v_amount <= 0 then
    raise exception 'invalid amount';
  end if;
  select coalesce(sum(p.amount), 0)
  into v_paid
  from public.payments p
  where p.reference_table = 'orders'
    and p.reference_id = p_order_id::text
    and p.direction = 'in';
  if v_total > 0 and (v_paid + v_amount) > (v_total + 1e-9) then
    raise exception 'paid amount exceeds total';
  end if;
  v_method := nullif(trim(coalesce(p_method, '')), '');
  if v_method is null then
    v_method := 'cash';
  end if;
  v_occurred_at := coalesce(p_occurred_at, now());
  v_idempotency := nullif(trim(coalesce(p_idempotency_key, '')), '');
  select s.id
  into v_shift_id
  from public.cash_shifts s
  where s.cashier_id = auth.uid()
    and coalesce(s.status, 'open') = 'open'
  order by s.opened_at desc
  limit 1;
  if v_method = 'cash' and v_shift_id is null then
    raise exception 'cash method requires an open cash shift';
  end if;
  if v_idempotency is null then
    insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, shift_id)
    values (
      'in',
      v_method,
      v_amount,
      'YER',
      'orders',
      p_order_id::text,
      v_occurred_at,
      auth.uid(),
      jsonb_build_object('orderId', p_order_id::text),
      v_shift_id
    );
  else
    insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, idempotency_key, shift_id)
    values (
      'in',
      v_method,
      v_amount,
      'YER',
      'orders',
      p_order_id::text,
      v_occurred_at,
      auth.uid(),
      jsonb_build_object('orderId', p_order_id::text),
      v_idempotency,
      v_shift_id
    )
    on conflict (reference_table, reference_id, direction, idempotency_key)
    do update set
      method = excluded.method,
      amount = excluded.amount,
      occurred_at = excluded.occurred_at,
      created_by = coalesce(public.payments.created_by, excluded.created_by),
      data = excluded.data,
      shift_id = coalesce(public.payments.shift_id, excluded.shift_id);
  end if;
end;
$$;


ALTER FUNCTION "public"."record_order_payment"("p_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone, "p_idempotency_key" "text") OWNER TO "postgres";

--
-- Name: record_order_payment("uuid", numeric, "text", timestamp with time zone, "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_order_payment"("p_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone, "p_idempotency_key" "text" DEFAULT NULL::"text", "p_currency" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_amount numeric;
  v_method text;
  v_occurred_at timestamptz;
  v_total numeric;
  v_paid numeric;
  v_idempotency text;
  v_shift_id uuid;
  v_base text;
  v_currency text;
begin
  if not public.is_staff() then
    raise exception 'not allowed';
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  v_base := public.get_base_currency();

  select coalesce(o.total, coalesce(nullif((o.data->>'total')::numeric, null), 0)),
         coalesce(nullif(btrim(coalesce(o.currency, '')), ''), nullif(btrim(coalesce(o.data->>'currency', '')), ''), v_base)
  into v_total, v_currency
  from public.orders o
  where o.id = p_order_id;

  if not found then
    raise exception 'order not found';
  end if;

  v_amount := coalesce(p_amount, 0);
  if v_amount <= 0 then
    raise exception 'invalid amount';
  end if;

  select coalesce(sum(p.amount), 0)
  into v_paid
  from public.payments p
  where p.reference_table = 'orders'
    and p.reference_id = p_order_id::text
    and p.direction = 'in';

  if v_total > 0 and (v_paid + v_amount) > (v_total + 1e-9) then
    raise exception 'paid amount exceeds total';
  end if;

  v_method := nullif(trim(coalesce(p_method, '')), '');
  if v_method is null then
    v_method := 'cash';
  end if;
  v_occurred_at := coalesce(p_occurred_at, now());
  v_idempotency := nullif(trim(coalesce(p_idempotency_key, '')), '');

  v_currency := upper(nullif(btrim(coalesce(p_currency, '')), ''));
  if v_currency is null then
    v_currency := upper(nullif(btrim(coalesce(v_currency, '')), ''));
  end if;
  if v_currency is null then
    v_currency := v_base;
  end if;

  select s.id
  into v_shift_id
  from public.cash_shifts s
  where s.cashier_id = auth.uid()
    and coalesce(s.status, 'open') = 'open'
  order by s.opened_at desc
  limit 1;

  if v_method = 'cash' and v_shift_id is null then
    raise exception 'cash method requires an open cash shift';
  end if;

  if v_idempotency is null then
    insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, shift_id)
    values (
      'in',
      v_method,
      v_amount,
      v_currency,
      'orders',
      p_order_id::text,
      v_occurred_at,
      auth.uid(),
      jsonb_build_object('orderId', p_order_id::text),
      v_shift_id
    );
  else
    insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, idempotency_key, shift_id)
    values (
      'in',
      v_method,
      v_amount,
      v_currency,
      'orders',
      p_order_id::text,
      v_occurred_at,
      auth.uid(),
      jsonb_build_object('orderId', p_order_id::text),
      v_idempotency,
      v_shift_id
    )
    on conflict (reference_table, reference_id, direction, idempotency_key)
    do update set
      method = excluded.method,
      amount = excluded.amount,
      currency = excluded.currency,
      occurred_at = excluded.occurred_at,
      created_by = coalesce(public.payments.created_by, excluded.created_by),
      data = excluded.data,
      shift_id = coalesce(public.payments.shift_id, excluded.shift_id);
  end if;
end;
$$;


ALTER FUNCTION "public"."record_order_payment"("p_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone, "p_idempotency_key" "text", "p_currency" "text") OWNER TO "postgres";

--
-- Name: record_order_payment_v2("uuid", numeric, "text", timestamp with time zone, "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_order_payment_v2"("p_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_idempotency_key" "text" DEFAULT NULL::"text", "p_currency" "text" DEFAULT NULL::"text", "p_data" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_method text;
  v_occurred_at timestamptz;
  v_currency text;
  v_shift_id uuid;
  v_data jsonb;
  v_idempotency text;
begin
  if not public.can_manage_orders() then
    raise exception 'not allowed';
  end if;
  if p_amount <= 0 then
    raise exception 'amount must be positive';
  end if;

  v_method := nullif(trim(p_method), '');
  if v_method is null then
    v_method := 'cash';
  end if;
  if v_method = 'card' then
    v_method := 'network';
  elsif v_method = 'bank' then
    v_method := 'kuraimi';
  end if;

  v_occurred_at := coalesce(p_occurred_at, now());

  v_currency := nullif(trim(coalesce(p_currency, '')), '');
  if v_currency is null then
    v_currency := public.get_base_currency();
  end if;
  v_currency := upper(v_currency);

  v_shift_id := public._resolve_open_shift_for_cash(auth.uid());
  if v_method = 'cash' and v_shift_id is null then
    raise exception 'cash payment requires an open shift';
  end if;

  v_data := jsonb_strip_nulls(jsonb_build_object('orderId', p_order_id::text) || coalesce(p_data, '{}'::jsonb));
  v_idempotency := nullif(trim(coalesce(p_idempotency_key, '')), '');

  insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, idempotency_key, shift_id)
  values (
    'in',
    v_method,
    p_amount,
    v_currency,
    'orders',
    p_order_id::text,
    v_occurred_at,
    auth.uid(),
    v_data,
    v_idempotency,
    v_shift_id
  )
  on conflict (reference_table, reference_id, direction, idempotency_key) where idempotency_key is not null
  do update set
    method = excluded.method,
    amount = excluded.amount,
    currency = excluded.currency,
    occurred_at = excluded.occurred_at,
    created_by = excluded.created_by,
    data = excluded.data,
    shift_id = excluded.shift_id;
end;
$$;


ALTER FUNCTION "public"."record_order_payment_v2"("p_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone, "p_idempotency_key" "text", "p_currency" "text", "p_data" "jsonb") OWNER TO "postgres";

--
-- Name: record_payroll_run_accrual("uuid", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_payroll_run_accrual"("p_run_id" "uuid", "p_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_run record;
  v_entry_id uuid;
begin
  if not (public.can_manage_expenses() or public.has_admin_permission('accounting.manage') or public.is_admin()) then
    raise exception 'not allowed';
  end if;

  select *
  into v_run
  from public.payroll_runs
  where id = p_run_id
  for update;

  if not found then
    raise exception 'run not found';
  end if;
  if v_run.expense_id is null then
    raise exception 'run has no expense_id';
  end if;

  perform public.record_expense_accrual(v_run.expense_id, v_run.total_net, coalesce(p_occurred_at, now()));

  select id into v_entry_id
  from public.journal_entries
  where source_table = 'expenses'
    and source_id = v_run.expense_id::text
    and source_event = 'accrual'
  order by entry_date desc
  limit 1;

  update public.payroll_runs
  set status = 'accrued',
      accrued_at = coalesce(p_occurred_at, now())
  where id = p_run_id;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    'payroll_run_accrued',
    'payroll',
    concat('Payroll run accrued ', v_run.period_ym),
    auth.uid(),
    now(),
    jsonb_build_object('runId', p_run_id::text, 'period', v_run.period_ym, 'expenseId', v_run.expense_id::text, 'journalEntryId', coalesce(v_entry_id::text,''))
  );

  return v_entry_id;
end;
$$;


ALTER FUNCTION "public"."record_payroll_run_accrual"("p_run_id" "uuid", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_payroll_run_accrual_v2("uuid", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_payroll_run_accrual_v2"("p_run_id" "uuid", "p_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_run record;
  v_entry_id uuid;
  v_expense_account uuid;
  v_payable_account uuid;
  v_amount numeric;
  v_occurred_at timestamptz;
  v_settings record;
begin
  if not (public.can_manage_expenses() or public.has_admin_permission('accounting.manage') or public.is_admin()) then
    raise exception 'not allowed';
  end if;

  if p_run_id is null then
    raise exception 'run_id is required';
  end if;

  v_occurred_at := coalesce(p_occurred_at, now());

  select *
  into v_run
  from public.payroll_runs
  where id = p_run_id
  for update;

  if not found then
    raise exception 'run not found';
  end if;
  if v_run.expense_id is null then
    raise exception 'run has no expense_id';
  end if;
  if coalesce(v_run.status,'') = 'voided' then
    raise exception 'run is voided';
  end if;

  if coalesce(v_run.status,'') in ('accrued','paid') then
    select je.id into v_entry_id
    from public.journal_entries je
    where je.source_table = 'expenses'
      and je.source_id = v_run.expense_id::text
      and je.source_event = 'accrual'
    order by je.entry_date desc
    limit 1;
    return v_entry_id;
  end if;

  perform public.recalc_payroll_run_totals(p_run_id);

  select total_net, cost_center_id, period_ym, memo, expense_id
  into v_amount, v_run.cost_center_id, v_run.period_ym, v_run.memo, v_run.expense_id
  from public.payroll_runs
  where id = p_run_id;

  v_amount := coalesce(v_amount, 0);
  if v_amount <= 0 then
    raise exception 'invalid amount';
  end if;

  select *
  into v_settings
  from public.payroll_settings
  where id = 'app';

  v_expense_account := coalesce(v_settings.salary_expense_account_id, public.get_account_id_by_code('6120'));
  v_payable_account := coalesce(v_settings.salary_payable_account_id, public.get_account_id_by_code('2120'));
  if v_expense_account is null or v_payable_account is null then
    raise exception 'required accounts not found';
  end if;

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    v_occurred_at,
    concat('Payroll accrual ', coalesce(v_run.period_ym, p_run_id::text)),
    'expenses',
    v_run.expense_id::text,
    'accrual',
    auth.uid()
  )
  returning id into v_entry_id;

  insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, cost_center_id)
  values
    (v_entry_id, v_expense_account, v_amount, 0, 'Payroll expense', v_run.cost_center_id),
    (v_entry_id, v_payable_account, 0, v_amount, 'Payroll payable', v_run.cost_center_id);

  perform public.check_journal_entry_balance(v_entry_id);

  update public.payroll_runs
  set status = 'accrued',
      accrued_at = v_occurred_at
  where id = p_run_id;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    'payroll_run_accrued',
    'payroll',
    concat('Payroll run accrued ', v_run.period_ym),
    auth.uid(),
    now(),
    jsonb_build_object('runId', p_run_id::text, 'period', v_run.period_ym, 'expenseId', v_run.expense_id::text, 'journalEntryId', v_entry_id::text, 'amount', v_amount)
  );

  return v_entry_id;
end;
$$;


ALTER FUNCTION "public"."record_payroll_run_accrual_v2"("p_run_id" "uuid", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_payroll_run_payment("uuid", numeric, "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_payroll_run_payment"("p_run_id" "uuid", "p_amount" numeric DEFAULT NULL::numeric, "p_method" "text" DEFAULT 'cash'::"text", "p_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_run record;
  v_method text;
  v_occurred_at timestamptz;
  v_paid numeric := 0;
  v_amount numeric := 0;
  v_payment_id uuid;
  v_shift_id uuid;
begin
  if not (public.can_manage_expenses() or public.has_admin_permission('accounting.manage') or public.is_admin()) then
    raise exception 'not allowed';
  end if;

  select *
  into v_run
  from public.payroll_runs
  where id = p_run_id
  for update;

  if not found then
    raise exception 'run not found';
  end if;
  if v_run.expense_id is null then
    raise exception 'run has no expense_id';
  end if;

  select coalesce(sum(p.amount), 0)
  into v_paid
  from public.payments p
  where p.reference_table = 'expenses'
    and p.reference_id = v_run.expense_id::text
    and p.direction = 'out';

  v_amount := coalesce(p_amount, 0);
  if v_amount <= 0 then
    v_amount := greatest(0, coalesce(v_run.total_net, 0) - v_paid);
  end if;
  if v_amount <= 0 then
    raise exception 'nothing to pay';
  end if;
  if (v_paid + v_amount) > (coalesce(v_run.total_net, 0) + 1e-9) then
    raise exception 'paid amount exceeds total';
  end if;

  v_method := nullif(trim(coalesce(p_method, '')), '');
  if v_method is null then
    v_method := 'cash';
  end if;
  if v_method = 'card' then
    v_method := 'network';
  elsif v_method = 'bank' then
    v_method := 'kuraimi';
  end if;

  v_occurred_at := coalesce(p_occurred_at, now());
  v_shift_id := public._resolve_open_shift_for_cash(auth.uid());
  if v_method = 'cash' and v_shift_id is null then
    raise exception 'cash method requires an open cash shift';
  end if;

  insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, shift_id)
  values (
    'out',
    v_method,
    v_amount,
    'YER',
    'expenses',
    v_run.expense_id::text,
    v_occurred_at,
    auth.uid(),
    jsonb_strip_nulls(jsonb_build_object('expenseId', v_run.expense_id::text, 'payrollRunId', p_run_id::text, 'kind', 'payroll')),
    v_shift_id
  )
  returning id into v_payment_id;

  perform public.post_payment(v_payment_id);

  if (v_paid + v_amount) >= (coalesce(v_run.total_net, 0) - 1e-9) then
    update public.payroll_runs
    set status = 'paid',
        paid_at = v_occurred_at
    where id = p_run_id;
  else
    update public.payroll_runs
    set status = 'accrued'
    where id = p_run_id;
  end if;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    'payroll_run_paid',
    'payroll',
    concat('Payroll run payment ', v_run.period_ym),
    auth.uid(),
    now(),
    jsonb_build_object('runId', p_run_id::text, 'period', v_run.period_ym, 'expenseId', v_run.expense_id::text, 'paymentId', v_payment_id::text, 'amount', v_amount, 'method', v_method)
  );

  return v_payment_id;
end;
$$;


ALTER FUNCTION "public"."record_payroll_run_payment"("p_run_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_purchase_order_payment("uuid", numeric, "text", timestamp with time zone, "jsonb", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_purchase_order_payment"("p_purchase_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone, "p_data" "jsonb" DEFAULT '{}'::"jsonb", "p_currency" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_amount numeric;
  v_total numeric;
  v_status text;
  v_method text;
  v_occurred_at timestamptz;
  v_payment_id uuid;
  v_data jsonb;
  v_idempotency_key text;
  v_shift_id uuid;
  v_paid_sum numeric;
  v_currency text;
  v_base text;
begin
  if not public.can_manage_stock() then
    raise exception 'not allowed';
  end if;
  if p_purchase_order_id is null then
    raise exception 'p_purchase_order_id is required';
  end if;
  select coalesce(po.total_amount, 0), po.status
  into v_total, v_status
  from public.purchase_orders po
  where po.id = p_purchase_order_id
  for update;
  if not found then
    raise exception 'purchase order not found';
  end if;
  if v_status = 'cancelled' then
    raise exception 'cannot pay cancelled purchase order';
  end if;
  v_total := coalesce(v_total, 0);
  if v_total <= 0 then
    raise exception 'purchase order total is zero';
  end if;
  v_amount := coalesce(p_amount, 0);
  if v_amount <= 0 then
    raise exception 'invalid amount';
  end if;
  select coalesce(sum(p.amount), 0)
  into v_paid_sum
  from public.payments p
  where p.reference_table = 'purchase_orders'
    and p.direction = 'out'
    and p.reference_id = p_purchase_order_id::text;
  if (v_total - coalesce(v_paid_sum, 0)) <= 0.000000001 then
    raise exception 'purchase order already fully paid';
  end if;
  if (coalesce(v_paid_sum, 0) + v_amount) > (v_total + 0.000000001) then
    raise exception 'paid amount exceeds total';
  end if;
  v_method := nullif(trim(coalesce(p_method, '')), '');
  if v_method is null then
    v_method := 'cash';
  end if;
  v_occurred_at := coalesce(p_occurred_at, now());
  v_data := jsonb_strip_nulls(jsonb_build_object('purchaseOrderId', p_purchase_order_id::text) || coalesce(p_data, '{}'::jsonb));
  v_idempotency_key := nullif(trim(coalesce(v_data->>'idempotencyKey', '')), '');
  v_shift_id := public._resolve_open_shift_for_cash(auth.uid());
  if v_method = 'cash' and v_shift_id is null then
    raise exception 'cash method requires an open cash shift';
  end if;
  v_base := public.get_base_currency();
  v_currency := upper(nullif(btrim(coalesce(p_currency, '')), ''));
  if v_currency is null then
    v_currency := v_base;
  end if;
  if v_idempotency_key is null then
    insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, shift_id)
    values (
      'out',
      v_method,
      v_amount,
      v_currency,
      'purchase_orders',
      p_purchase_order_id::text,
      v_occurred_at,
      auth.uid(),
      v_data,
      v_shift_id
    )
    returning id into v_payment_id;
  else
    insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, idempotency_key, shift_id)
    values (
      'out',
      v_method,
      v_amount,
      v_currency,
      'purchase_orders',
      p_purchase_order_id::text,
      v_occurred_at,
      auth.uid(),
      v_data,
      v_idempotency_key,
      v_shift_id
    )
    on conflict (reference_table, reference_id, direction, idempotency_key)
    do nothing
    returning id into v_payment_id;
    if v_payment_id is null then
      return;
    end if;
  end if;
end;
$$;


ALTER FUNCTION "public"."record_purchase_order_payment"("p_purchase_order_id" "uuid", "p_amount" numeric, "p_method" "text", "p_occurred_at" timestamp with time zone, "p_data" "jsonb", "p_currency" "text") OWNER TO "postgres";

--
-- Name: record_shift_cash_movement("uuid", "text", numeric, "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_shift_cash_movement"("p_shift_id" "uuid", "p_direction" "text", "p_amount" numeric, "p_reason" "text" DEFAULT NULL::"text", "p_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_shift public.cash_shifts%rowtype;
  v_amount numeric;
  v_dir text;
  v_actor_role text;
  v_payment_id uuid;
  v_reason text;
begin
  if auth.uid() is null then
    raise exception 'not allowed';
  end if;

  if p_shift_id is null then
    raise exception 'p_shift_id is required';
  end if;

  select au.role
  into v_actor_role
  from public.admin_users au
  where au.auth_user_id = auth.uid()
    and au.is_active = true;

  if v_actor_role is null then
    raise exception 'not allowed';
  end if;

  select *
  into v_shift
  from public.cash_shifts s
  where s.id = p_shift_id
  for update;

  if not found then
    raise exception 'cash shift not found';
  end if;

  if coalesce(v_shift.status, 'open') <> 'open' then
    raise exception 'cash shift is not open';
  end if;

  if auth.uid() <> v_shift.cashier_id and (v_actor_role not in ('owner', 'manager') and not public.has_admin_permission('cashShifts.manage')) then
    raise exception 'not allowed';
  end if;

  v_dir := lower(nullif(trim(coalesce(p_direction, '')), ''));
  if v_dir not in ('in', 'out') then
    raise exception 'invalid direction';
  end if;

  if auth.uid() = v_shift.cashier_id then
    if v_dir = 'in' and not public.has_admin_permission('cashShifts.cashIn') then
      raise exception 'not allowed';
    end if;
    if v_dir = 'out' and not public.has_admin_permission('cashShifts.cashOut') then
      raise exception 'not allowed';
    end if;
  end if;

  v_amount := coalesce(p_amount, 0);
  if v_amount <= 0 then
    raise exception 'invalid amount';
  end if;

  v_reason := nullif(trim(coalesce(p_reason, '')), '');
  if v_dir = 'out' and v_reason is null then
    raise exception 'يرجى إدخال سبب الصرف.';
  end if;

  insert into public.payments(direction, method, amount, currency, reference_table, reference_id, occurred_at, created_by, data, shift_id)
  values (
    v_dir,
    'cash',
    v_amount,
    'YER',
    'cash_shifts',
    p_shift_id::text,
    coalesce(p_occurred_at, now()),
    auth.uid(),
    jsonb_strip_nulls(jsonb_build_object('shiftId', p_shift_id::text, 'reason', v_reason, 'kind', 'cash_movement')),
    p_shift_id
  )
  returning id into v_payment_id;

  perform public.post_payment(v_payment_id);

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    case when v_dir = 'in' then 'cash_shift_cash_in' else 'cash_shift_cash_out' end,
    'cash_shifts',
    case when v_dir = 'in' then 'Cash movement in' else 'Cash movement out' end,
    auth.uid(),
    now(),
    jsonb_strip_nulls(jsonb_build_object('shiftId', p_shift_id::text, 'paymentId', v_payment_id::text, 'amount', v_amount, 'direction', v_dir, 'reason', v_reason)),
    'MEDIUM',
    'SHIFT_CASH_MOVE'
  );
end;
$$;


ALTER FUNCTION "public"."record_shift_cash_movement"("p_shift_id" "uuid", "p_direction" "text", "p_amount" numeric, "p_reason" "text", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_wastage_light("uuid", "uuid", numeric, "uuid", "text", "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_wastage_light"("p_item_id" "uuid", "p_warehouse_id" "uuid", "p_quantity" numeric, "p_batch_id" "uuid" DEFAULT NULL::"uuid", "p_unit" "text" DEFAULT 'piece'::"text", "p_reason" "text" DEFAULT NULL::"text", "p_occurred_at" timestamp with time zone DEFAULT "now"()) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_wh uuid;
  v_item_id text;
  v_needed numeric;
  v_batch record;
  v_reserved_other numeric;
  v_available numeric;
  v_alloc numeric;
  v_unit_cost numeric;
  v_total_cost numeric;
  v_movement_id uuid;
begin
  perform public._require_stock_manager('record_wastage_light');

  v_actor := auth.uid();
  if p_item_id is null or p_quantity is null or p_quantity <= 0 then
    raise exception 'invalid params';
  end if;

  v_item_id := p_item_id::text;
  v_wh := coalesce(p_warehouse_id, public._resolve_default_warehouse_id());
  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  v_needed := p_quantity;

  if p_batch_id is not null then
    select bb.batch_id, bb.quantity, bb.expiry_date
    into v_batch
    from public.batch_balances bb
    where bb.item_id = v_item_id
      and bb.warehouse_id = v_wh
      and bb.batch_id = p_batch_id
    for update;
    if not found then
      raise exception 'batch not found for item %', v_item_id;
    end if;

    select coalesce(sum(br.quantity), 0)
    into v_reserved_other
    from public.batch_reservations br
    where br.item_id = v_item_id
      and br.warehouse_id = v_wh
      and br.batch_id = p_batch_id;

    v_available := greatest(coalesce(v_batch.quantity, 0) - coalesce(v_reserved_other, 0), 0);
    if v_available + 1e-9 < v_needed then
      raise exception 'insufficient unreserved stock for wastage';
    end if;
  end if;

  for v_batch in
    select bb.batch_id, bb.quantity, bb.expiry_date
    from public.batch_balances bb
    where bb.item_id = v_item_id
      and bb.warehouse_id = v_wh
      and bb.quantity > 0
      and (p_batch_id is null or bb.batch_id = p_batch_id)
    order by bb.expiry_date asc nulls last, bb.batch_id asc
  loop
    exit when v_needed <= 0;

    select coalesce(sum(br.quantity), 0)
    into v_reserved_other
    from public.batch_reservations br
    where br.item_id = v_item_id
      and br.warehouse_id = v_wh
      and br.batch_id = v_batch.batch_id;

    v_available := greatest(coalesce(v_batch.quantity, 0) - coalesce(v_reserved_other, 0), 0);
    if v_available <= 0 then
      continue;
    end if;

    v_alloc := least(v_needed, v_available);
    if v_alloc <= 0 then
      continue;
    end if;

    update public.batch_balances
    set quantity = quantity - v_alloc,
        updated_at = now()
    where item_id = v_item_id
      and batch_id = v_batch.batch_id
      and warehouse_id = v_wh;

    select im.unit_cost
    into v_unit_cost
    from public.inventory_movements im
    where im.batch_id = v_batch.batch_id
      and im.item_id::text = v_item_id
      and im.movement_type = 'purchase_in'
    order by im.occurred_at asc
    limit 1;
    v_unit_cost := coalesce(v_unit_cost, 0);
    v_total_cost := v_alloc * v_unit_cost;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_item_id, 'wastage_out', v_alloc, v_unit_cost, v_total_cost,
      'accounting_light_entries', null, coalesce(p_occurred_at, now()), v_actor,
      jsonb_build_object('reason', coalesce(p_reason,''), 'warehouseId', v_wh, 'batchId', v_batch.batch_id, 'expiryDate', v_batch.expiry_date),
      v_batch.batch_id, v_wh
    )
    returning id into v_movement_id;
    perform public.post_inventory_movement(v_movement_id);

    insert into public.accounting_light_entries(
      entry_type, item_id, warehouse_id, batch_id, quantity, unit, unit_cost, total_cost,
      occurred_at, debit_account, credit_account, created_by, notes, source_ref
    )
    values (
      'wastage', v_item_id, v_wh, v_batch.batch_id, v_alloc, p_unit,
      coalesce(v_unit_cost,0), v_total_cost, coalesce(p_occurred_at, now()),
      'shrinkage', 'inventory', v_actor, p_reason, v_movement_id::text
    );

    v_needed := v_needed - v_alloc;
  end loop;

  if v_needed > 0 then
    raise exception 'insufficient unreserved stock for wastage';
  end if;

  update public.stock_management sm
  set available_quantity = coalesce((
        select sum(bb.quantity)
        from public.batch_balances bb
        where bb.item_id = v_item_id
          and bb.warehouse_id = v_wh
      ), 0),
      reserved_quantity = coalesce((
        select sum(br.quantity)
        from public.batch_reservations br
        where br.item_id = v_item_id
          and br.warehouse_id = v_wh
      ), 0),
      updated_at = now(),
      last_updated = now()
  where sm.item_id::text = v_item_id
    and sm.warehouse_id = v_wh;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
  values (
    'wastage.recorded',
    'stock',
    coalesce(p_reason,''),
    v_actor,
    now(),
    jsonb_build_object('itemId', v_item_id, 'warehouseId', v_wh, 'batchId', p_batch_id, 'quantity', p_quantity, 'unitCost', null)
  );
end;
$$;


ALTER FUNCTION "public"."record_wastage_light"("p_item_id" "uuid", "p_warehouse_id" "uuid", "p_quantity" numeric, "p_batch_id" "uuid", "p_unit" "text", "p_reason" "text", "p_occurred_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: register_pos_offline_sale_created("text", "uuid", timestamp with time zone, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."register_pos_offline_sale_created"("p_offline_id" "text", "p_order_id" "uuid", "p_created_at" timestamp with time zone, "p_warehouse_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
begin
  v_actor := auth.uid();
  if v_actor is null then
    raise exception 'not authenticated';
  end if;
  if not public.is_staff() then
    raise exception 'not allowed';
  end if;

  if p_offline_id is null or btrim(p_offline_id) = '' then
    raise exception 'p_offline_id is required';
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if p_warehouse_id is null then
    raise exception 'p_warehouse_id is required';
  end if;

  insert into public.pos_offline_sales(offline_id, order_id, warehouse_id, state, payload, created_by, created_at, updated_at)
  values (p_offline_id, p_order_id, p_warehouse_id, 'CREATED_OFFLINE', '{}'::jsonb, v_actor, coalesce(p_created_at, now()), now())
  on conflict (offline_id)
  do update set
    order_id = excluded.order_id,
    warehouse_id = excluded.warehouse_id,
    created_by = coalesce(public.pos_offline_sales.created_by, excluded.created_by),
    created_at = least(public.pos_offline_sales.created_at, excluded.created_at),
    updated_at = now();

  return jsonb_build_object('status', 'OK', 'offlineId', p_offline_id, 'orderId', p_order_id::text);
end;
$$;


ALTER FUNCTION "public"."register_pos_offline_sale_created"("p_offline_id" "text", "p_order_id" "uuid", "p_created_at" timestamp with time zone, "p_warehouse_id" "uuid") OWNER TO "postgres";

--
-- Name: reject_approval_request("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reject_approval_request"("p_request_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  update public.approval_requests
  set status = 'rejected', rejected_by = auth.uid(), rejected_at = now()
  where id = p_request_id;
  update public.approval_steps
  set status = 'rejected', action_by = auth.uid(), action_at = now()
  where request_id = p_request_id and status = 'pending';
end;
$$;


