--
-- Name: release_reserved_stock_for_order("jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."release_reserved_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_wh uuid;
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  select
    coalesce(
      o.warehouse_id,
      case
        when nullif(o.data->>'warehouseId','') is not null
             and (o.data->>'warehouseId') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$'
          then (o.data->>'warehouseId')::uuid
        else null
      end
    )
  into v_wh
  from public.orders o
  where o.id = p_order_id;

  if v_wh is null then
    begin
      v_wh := public._resolve_default_warehouse_id();
    exception when others then
      v_wh := null;
    end;
  end if;

  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  perform public.release_reserved_stock_for_order(p_items, p_order_id, v_wh);
end;
$_$;


ALTER FUNCTION "public"."release_reserved_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: release_reserved_stock_for_order("jsonb", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."release_reserved_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid" DEFAULT NULL::"uuid", "p_warehouse_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_item jsonb;
  v_item_id text;
  v_qty numeric;
  v_to_release numeric;
  v_row record;
  v_take numeric;
  v_is_food boolean;
begin
  v_actor := auth.uid();
  if v_actor is null then
    raise exception 'not authenticated';
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if p_warehouse_id is null then
    raise exception 'warehouse_id is required';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;

  if not exists (select 1 from public.orders o where o.id = p_order_id) then
    raise exception 'order not found';
  end if;

  if not public.is_staff() then
    if not exists (
      select 1
      from public.orders o
      where o.id = p_order_id
        and o.customer_auth_user_id = v_actor
    ) then
      raise exception 'not allowed';
    end if;
  end if;

  for v_item in select value from jsonb_array_elements(coalesce(p_items, '[]'::jsonb))
  loop
    v_item_id := nullif(trim(coalesce(v_item->>'itemId', v_item->>'id')), '');
    v_qty := coalesce(nullif(v_item->>'quantity','')::numeric, nullif(v_item->>'qty','')::numeric, 0);
    if v_item_id is null or v_qty <= 0 then
      continue;
    end if;

    v_to_release := v_qty;
    for v_row in
      select r.id, r.quantity
      from public.order_item_reservations r
      where r.order_id = p_order_id
        and r.item_id::text = v_item_id::text
        and r.warehouse_id = p_warehouse_id
        and r.quantity > 0
      order by r.created_at asc, r.id asc
    loop
      exit when v_to_release <= 0;
      v_take := least(v_to_release, coalesce(v_row.quantity, 0));
      if v_take <= 0 then
        continue;
      end if;
      if coalesce(v_row.quantity, 0) - v_take <= 0 then
        delete from public.order_item_reservations r
        where r.id = v_row.id;
      else
        update public.order_item_reservations
        set quantity = quantity - v_take,
            updated_at = now()
        where id = v_row.id;
      end if;
      v_to_release := v_to_release - v_take;
    end loop;

    select (coalesce(mi.category,'') = 'food')
    into v_is_food
    from public.menu_items mi
    where mi.id::text = v_item_id::text;

    update public.stock_management sm
    set reserved_quantity = coalesce((
          select sum(r2.quantity)
          from public.order_item_reservations r2
          where r2.item_id::text = v_item_id::text
            and r2.warehouse_id = p_warehouse_id
        ), 0),
        available_quantity = coalesce((
          select sum(
            greatest(
              coalesce(b.quantity_received,0)
              - coalesce(b.quantity_consumed,0)
              - coalesce(b.quantity_transferred,0),
              0
            )
          )
          from public.batches b
          where b.item_id::text = v_item_id::text
            and b.warehouse_id = p_warehouse_id
            and coalesce(b.status,'active') = 'active'
            and coalesce(b.qc_status,'') = 'released'
            and not exists (
              select 1 from public.batch_recalls br
              where br.batch_id = b.id and br.status = 'active'
            )
            and (
              not coalesce(v_is_food, false)
              or (b.expiry_date is not null and b.expiry_date >= current_date)
            )
        ), 0),
        last_updated = now(),
        updated_at = now()
    where sm.item_id::text = v_item_id::text
      and sm.warehouse_id = p_warehouse_id;
  end loop;
end;
$$;


ALTER FUNCTION "public"."release_reserved_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid", "p_warehouse_id" "uuid") OWNER TO "postgres";

--
-- Name: repair_all_batches_costs(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."repair_all_batches_costs"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_cnt int := 0;
begin
  update public.batches
  set cost_per_unit = case
        when coalesce(cost_per_unit, 0) <= 0 then coalesce(unit_cost, 0)
        else cost_per_unit
      end,
      min_margin_pct = greatest(0, coalesce(min_margin_pct, 0)),
      min_selling_price = public._money_round(
        case
          when greatest(0, coalesce(min_margin_pct, 0)) > 0 then coalesce(case when coalesce(cost_per_unit,0) > 0 then cost_per_unit else unit_cost end, 0) * (1 + (greatest(0, coalesce(min_margin_pct, 0)) / 100))
          else coalesce(case when coalesce(cost_per_unit,0) > 0 then cost_per_unit else unit_cost end, 0)
        end
      )
  where coalesce(status, 'active') = 'active';
  get diagnostics v_cnt = row_count;
  return v_cnt;
end;
$$;


ALTER FUNCTION "public"."repair_all_batches_costs"() OWNER TO "postgres";

--
-- Name: repair_item_batches_pricing("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."repair_item_batches_pricing"("p_item_id" "text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_count int := 0;
begin
  if nullif(btrim(coalesce(p_item_id, '')), '') is null then
    raise exception 'p_item_id required';
  end if;

  update public.batches
  set
    cost_per_unit = case
      when cost_per_unit <= 0 then coalesce(unit_cost, 0)
      else cost_per_unit
    end,
    min_margin_pct = greatest(0, coalesce(min_margin_pct, 0)),
    min_selling_price = public._money_round(
      case
        when greatest(0, coalesce(min_margin_pct, 0)) > 0 then
          coalesce(case when cost_per_unit > 0 then cost_per_unit else unit_cost end, 0) * (1 + (greatest(0, coalesce(min_margin_pct, 0)) / 100))
        else
          coalesce(case when cost_per_unit > 0 then cost_per_unit else unit_cost end, 0)
      end
    )
  where item_id::text = p_item_id::text
    and coalesce(status, 'active') = 'active';
  get diagnostics v_count = row_count;
  return v_count;
end;
$$;


ALTER FUNCTION "public"."repair_item_batches_pricing"("p_item_id" "text") OWNER TO "postgres";

--
-- Name: repair_purchase_in_uom_inflation(timestamp with time zone, timestamp with time zone, integer, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."repair_purchase_in_uom_inflation"("p_start" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_end" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_limit" integer DEFAULT 200, "p_dry_run" boolean DEFAULT true) RETURNS TABLE("movement_id" "uuid", "occurred_at" timestamp with time zone, "item_id" "text", "posted_total_cost" numeric, "expected_total_cost" numeric, "delta" numeric, "journal_entry_id" "uuid", "action" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  r record;
  v_fix_source_uuid uuid;
  v_entry_id uuid;
  v_inventory uuid;
  v_ap uuid;
  v_wh uuid;
  v_branch uuid;
  v_company uuid;
  v_delta numeric;
  v_mv record;
begin
  perform public._require_staff('repair_purchase_in_uom_inflation');
  p_limit := greatest(1, least(coalesce(p_limit, 200), 2000));

  v_inventory := public.get_account_id_by_code('1410');
  v_ap := public.get_account_id_by_code('2010');
  if v_inventory is null or v_ap is null then
    raise exception 'required accounts not found (inventory 1410 / AP 2010)';
  end if;

  for r in
    select *
    from public.detect_purchase_in_uom_inflation(p_start, p_end, p_limit)
  loop
    v_fix_source_uuid := public.uuid_from_text(concat('uomfix:purchase_in:', r.movement_id::text));
    v_delta := public._money_round(coalesce(r.total_cost, 0) - coalesce(r.expected_total_cost, 0));

    if abs(coalesce(v_delta, 0)) <= 0.01 then
      continue;
    end if;

    if exists (
      select 1
      from public.journal_entries je
      where je.source_table = 'ledger_repairs'
        and je.source_id = v_fix_source_uuid::text
        and je.source_event = 'fix_purchase_in_uom'
    ) then
      return query
      select r.movement_id, r.occurred_at, r.item_id, r.total_cost, r.expected_total_cost, v_delta, null::uuid, 'skipped_already_fixed';
      continue;
    end if;

    if p_dry_run then
      return query
      select r.movement_id, r.occurred_at, r.item_id, r.total_cost, r.expected_total_cost, v_delta, null::uuid, 'dry_run';
      continue;
    end if;

    select im.* into v_mv
    from public.inventory_movements im
    where im.id = r.movement_id;

    v_wh := null;
    if v_mv.warehouse_id is not null then
      v_wh := v_mv.warehouse_id;
    else
      begin
        if (v_mv.data->>'warehouseId') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then
          v_wh := (v_mv.data->>'warehouseId')::uuid;
        end if;
      exception when others then
        v_wh := null;
      end;
    end if;

    v_branch := coalesce(public.branch_from_warehouse(v_wh), public.get_default_branch_id());
    v_company := coalesce(public.company_from_branch(v_branch), public.get_default_company_id());

    insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, status, branch_id, company_id)
    values (
      r.occurred_at,
      concat('Fix purchase_in UOM inflation ', r.item_id, ' movement ', r.movement_id::text),
      'ledger_repairs',
      v_fix_source_uuid::text,
      'fix_purchase_in_uom',
      auth.uid(),
      'posted',
      v_branch,
      v_company
    )
    returning id into v_entry_id;

    if v_delta > 0 then
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
      values
        (v_entry_id, v_ap, v_delta, 0, 'Reduce supplier payable (UOM fix)'),
        (v_entry_id, v_inventory, 0, v_delta, 'Reduce inventory (UOM fix)');
    else
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
      values
        (v_entry_id, v_inventory, -v_delta, 0, 'Increase inventory (UOM fix)'),
        (v_entry_id, v_ap, 0, -v_delta, 'Increase supplier payable (UOM fix)');
    end if;

    perform public.check_journal_entry_balance(v_entry_id);

    return query
    select r.movement_id, r.occurred_at, r.item_id, r.total_cost, r.expected_total_cost, v_delta, v_entry_id, 'fixed';
  end loop;
end;
$_$;


ALTER FUNCTION "public"."repair_purchase_in_uom_inflation"("p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_limit" integer, "p_dry_run" boolean) OWNER TO "postgres";

--
-- Name: repair_purchase_order("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."repair_purchase_order"("p_order_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_receipt record;
  v_fixed int := 0;
  v_skipped int := 0;
  v_res jsonb;
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if not public.can_manage_stock() then
    raise exception 'not allowed';
  end if;

  for v_receipt in
    select pr.id
    from public.purchase_receipts pr
    where pr.purchase_order_id = p_order_id
    order by pr.received_at asc, pr.created_at asc
  loop
    begin
      v_res := public.repair_purchase_receipt_stock(v_receipt.id);
      if coalesce(v_res->>'status','') = 'ok' then
        v_fixed := v_fixed + 1;
      else
        v_skipped := v_skipped + 1;
      end if;
    exception when others then
      v_skipped := v_skipped + 1;
    end;
  end loop;

  perform public.reconcile_purchase_order_receipt_status(p_order_id);
  return jsonb_build_object('purchaseOrderId', p_order_id::text, 'receiptsFixed', v_fixed, 'receiptsSkipped', v_skipped);
end;
$$;


ALTER FUNCTION "public"."repair_purchase_order"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: repair_purchase_orders_bulk(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."repair_purchase_orders_bulk"("p_limit" integer DEFAULT 500) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_po_id uuid;
  v_done int := 0;
  v_failed int := 0;
begin
  if not public.can_manage_stock() then
    raise exception 'not allowed';
  end if;

  for v_po_id in
    select po.id
    from public.purchase_orders po
    where po.status in ('draft','partial')
      and po.status is distinct from 'cancelled'
      and exists(select 1 from public.purchase_receipts pr where pr.purchase_order_id = po.id)
    order by po.created_at desc
    limit greatest(coalesce(p_limit, 0), 0)
  loop
    begin
      perform public.repair_purchase_order(v_po_id);
      v_done := v_done + 1;
    exception when others then
      v_failed := v_failed + 1;
    end;
  end loop;

  return jsonb_build_object('processed', v_done, 'failed', v_failed);
end;
$$;


ALTER FUNCTION "public"."repair_purchase_orders_bulk"("p_limit" integer) OWNER TO "postgres";

--
-- Name: repair_purchase_receipt_stock("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."repair_purchase_receipt_stock"("p_receipt_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_receipt record;
  v_po record;
  v_wh uuid;
  v_main uuid;
  v_has_movements boolean;
  v_has_batches boolean;
  v_items_fixed int := 0;
  v_items_skipped int := 0;
  v_item record;
  v_old_qty numeric;
  v_old_avg numeric;
  v_new_qty numeric;
  v_new_avg numeric;
  v_qty numeric;
  v_unit_cost numeric;
  v_batch_id uuid;
  v_expiry date;
  v_production date;
  v_is_food boolean;
  v_expiry_required boolean;
  v_qc_status text;
  v_status text;
  v_movement_id uuid;
begin
  if p_receipt_id is null then
    raise exception 'p_receipt_id is required';
  end if;

  if not public.can_manage_stock() then
    raise exception 'not allowed';
  end if;

  select *
  into v_receipt
  from public.purchase_receipts pr
  where pr.id = p_receipt_id
  for update;

  if not found then
    raise exception 'purchase receipt not found';
  end if;

  select *
  into v_po
  from public.purchase_orders po
  where po.id = v_receipt.purchase_order_id
  for update;

  if not found then
    raise exception 'purchase order not found';
  end if;

  select public._resolve_default_warehouse_id() into v_main;
  v_wh := coalesce(v_receipt.warehouse_id, v_po.warehouse_id, v_main);
  if v_wh is null then
    raise exception 'warehouse_id is required';
  end if;

  select exists(
    select 1
    from public.inventory_movements im
    where im.reference_table = 'purchase_receipts'
      and im.reference_id = p_receipt_id::text
      and im.movement_type = 'purchase_in'
  )
  into v_has_movements;

  select exists(select 1 from public.batches b where b.receipt_id = p_receipt_id)
  into v_has_batches;

  if coalesce(v_has_movements, false) or coalesce(v_has_batches, false) then
    return jsonb_build_object(
      'status', 'skipped',
      'reason', 'already_has_stock',
      'receiptId', p_receipt_id::text,
      'warehouseId', v_wh::text
    );
  end if;

  for v_item in
    select pri.id as receipt_item_id, pri.item_id::text as item_id, coalesce(pri.quantity, 0) as quantity,
           coalesce(pri.unit_cost, 0) as unit_cost,
           coalesce(pri.transport_cost, 0) as transport_cost,
           coalesce(pri.supply_tax_cost, 0) as supply_tax_cost,
           coalesce(mi.is_food, false) as is_food,
           coalesce(mi.expiry_required, false) as expiry_required
    from public.purchase_receipt_items pri
    join public.menu_items mi on mi.id::text = pri.item_id::text
    where pri.receipt_id = p_receipt_id
  loop
    v_qty := coalesce(v_item.quantity, 0);
    if v_qty <= 0 then
      v_items_skipped := v_items_skipped + 1;
      continue;
    end if;

    v_unit_cost := coalesce(v_item.unit_cost, 0) + coalesce(v_item.transport_cost, 0) + coalesce(v_item.supply_tax_cost, 0);

    v_is_food := coalesce(v_item.is_food, false);
    v_expiry_required := coalesce(v_item.expiry_required, v_is_food, false);

    v_expiry := null;
    v_production := null;

    v_qc_status := case when v_expiry_required then 'pending' else 'released' end;
    v_status := 'active';

    insert into public.stock_management(item_id, warehouse_id, available_quantity, qc_hold_quantity, reserved_quantity, unit, low_stock_threshold, last_updated, data)
    select v_item.item_id, v_wh, 0, 0, 0, coalesce(mi.unit_type, 'piece'), 5, now(), '{}'::jsonb
    from public.menu_items mi
    where mi.id = v_item.item_id
    on conflict (item_id, warehouse_id) do nothing;

    select coalesce(sm.available_quantity, 0) + coalesce(sm.qc_hold_quantity, 0), coalesce(sm.avg_cost, 0)
    into v_old_qty, v_old_avg
    from public.stock_management sm
    where sm.item_id::text = v_item.item_id::text
      and sm.warehouse_id = v_wh
    for update;

    if v_old_qty < 0 then v_old_qty := 0; end if;
    if v_unit_cost < 0 then v_unit_cost := 0; end if;

    v_new_qty := v_old_qty + v_qty;
    v_new_avg := case when v_new_qty > 0 then ((v_old_qty * v_old_avg) + (v_qty * v_unit_cost)) / v_new_qty else v_old_avg end;

    update public.stock_management
    set available_quantity = available_quantity + v_qty,
        avg_cost = v_new_avg,
        last_updated = now(),
        updated_at = now()
    where item_id::text = v_item.item_id::text
      and warehouse_id = v_wh;

    v_batch_id := gen_random_uuid();

    insert into public.batch_balances(item_id, batch_id, warehouse_id, quantity, expiry_date)
    values (v_item.item_id::text, v_batch_id, v_wh, v_qty, v_expiry)
    on conflict (item_id, batch_id, warehouse_id)
    do update set
      quantity = public.batch_balances.quantity + excluded.quantity,
      expiry_date = coalesce(excluded.expiry_date, public.batch_balances.expiry_date),
      updated_at = now();

    insert into public.batches(
      id,
      item_id,
      receipt_item_id,
      receipt_id,
      warehouse_id,
      batch_code,
      production_date,
      expiry_date,
      quantity_received,
      quantity_consumed,
      quantity_transferred,
      unit_cost,
      qc_status,
      status,
      data
    )
    values (
      v_batch_id,
      v_item.item_id::text,
      v_item.receipt_item_id,
      p_receipt_id,
      v_wh,
      null,
      v_production,
      v_expiry,
      v_qty,
      0,
      0,
      v_unit_cost,
      v_qc_status,
      v_status,
      jsonb_build_object('source', 'repair_purchase_receipt_stock')
    )
    on conflict (id) do nothing;

    update public.menu_items
    set buying_price = greatest(0, v_unit_cost),
        cost_price = greatest(0, v_new_avg),
        updated_at = now()
    where id::text = v_item.item_id::text;

    update public.purchase_items
    set received_quantity = least(coalesce(received_quantity, 0) + v_qty, coalesce(quantity, 0)),
        updated_at = now()
    where purchase_order_id = v_receipt.purchase_order_id
      and item_id::text = v_item.item_id::text;

    insert into public.inventory_movements(
      item_id, movement_type, quantity, unit_cost, total_cost,
      reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
    )
    values (
      v_item.item_id::text,
      'purchase_in',
      v_qty,
      v_unit_cost,
      (v_qty * v_unit_cost),
      'purchase_receipts',
      p_receipt_id::text,
      coalesce(v_receipt.received_at, now()),
      coalesce(v_receipt.created_by, auth.uid()),
      jsonb_build_object(
        'purchaseOrderId', v_receipt.purchase_order_id::text,
        'purchaseReceiptId', p_receipt_id::text,
        'batchId', v_batch_id::text,
        'warehouseId', v_wh::text,
        'expiryDate', null,
        'harvestDate', null,
        'qcStatus', v_qc_status,
        'source', 'repair_purchase_receipt_stock'
      ),
      v_batch_id,
      v_wh
    )
    returning id into v_movement_id;

    begin
      perform public.post_inventory_movement(v_movement_id);
    exception when others then
      null;
    end;

    v_items_fixed := v_items_fixed + 1;
  end loop;

  perform public.reconcile_purchase_order_receipt_status(v_receipt.purchase_order_id);

  return jsonb_build_object(
    'status', 'ok',
    'receiptId', p_receipt_id::text,
    'purchaseOrderId', v_receipt.purchase_order_id::text,
    'warehouseId', v_wh::text,
    'itemsFixed', v_items_fixed,
    'itemsSkipped', v_items_skipped
  );
end;
$$;


ALTER FUNCTION "public"."repair_purchase_receipt_stock"("p_receipt_id" "uuid") OWNER TO "postgres";

--
-- Name: report_partial_purchase_orders(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."report_partial_purchase_orders"("p_limit" integer DEFAULT 2000) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_rows jsonb;
  v_n int := 0;
begin
  with po_base as (
    select
      po.id,
      po.po_number,
      po.reference_number,
      s.name as supplier_name
    from public.purchase_orders po
    left join public.suppliers s on s.id = po.supplier_id
    where po.status <> 'cancelled'
      and exists (select 1 from public.purchase_receipts pr where pr.purchase_order_id = po.id)
    order by po.updated_at desc nulls last
    limit greatest(coalesce(p_limit, 0), 0)
  ),
  ordered as (
    select
      pi.purchase_order_id,
      pi.item_id::text as item_id,
      sum(
        coalesce(
          nullif(pi.qty_base, 0),
          case
            when pi.uom_id is not null then public.item_qty_to_base_safe(pi.item_id, pi.quantity, pi.uom_id)
            else pi.quantity
          end,
          0
        )
      ) as ordered_base
    from public.purchase_items pi
    join po_base pb on pb.id = pi.purchase_order_id
    group by pi.purchase_order_id, pi.item_id::text
  ),
  received as (
    select
      pr.purchase_order_id,
      pri.item_id::text as item_id,
      sum(
        coalesce(
          nullif(pri.qty_base, 0),
          case
            when pri.uom_id is not null then public.item_qty_to_base_safe(pri.item_id, pri.quantity, pri.uom_id)
            else pri.quantity
          end,
          0
        )
      ) as received_base
    from public.purchase_receipts pr
    join public.purchase_receipt_items pri on pri.receipt_id = pr.id
    where pr.purchase_order_id in (select id from po_base)
    group by pr.purchase_order_id, pri.item_id::text
  ),
  rows as (
    select
      pb.id as order_id,
      coalesce(pb.po_number::text, pb.reference_number, pb.id::text) as reference,
      coalesce(pb.supplier_name, '') as supplier_name,
      jsonb_agg(
        jsonb_build_object(
          'itemId', o.item_id,
          'ordered', o.ordered_base,
          'received', coalesce(r.received_base, 0),
          'remaining', greatest(o.ordered_base - coalesce(r.received_base, 0), 0)
        )
        order by o.item_id
      ) filter (where greatest(o.ordered_base - coalesce(r.received_base, 0), 0) > 0.000000001) as items
    from po_base pb
    join ordered o on o.purchase_order_id = pb.id
    left join received r on r.purchase_order_id = pb.id and r.item_id = o.item_id
    group by pb.id, pb.po_number, pb.reference_number, pb.supplier_name
  )
  select jsonb_agg(
    jsonb_build_object(
      'orderId', order_id,
      'reference', reference,
      'supplierName', supplier_name,
      'items', items
    )
  ) filter (where items is not null)
  into v_rows
  from rows;

  v_n := coalesce(jsonb_array_length(v_rows), 0);
  return jsonb_build_object(
    'count', v_n,
    'rows', coalesce(v_rows, '[]'::jsonb)
  );
end;
$$;


ALTER FUNCTION "public"."report_partial_purchase_orders"("p_limit" integer) OWNER TO "postgres";

--
-- Name: request_offline_reconciliation("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."request_offline_reconciliation"("p_offline_id" "text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_row record;
  v_req_id uuid;
  v_reason text;
begin
  v_actor := auth.uid();
  if v_actor is null then
    raise exception 'not authenticated';
  end if;
  if not public.is_staff() then
    raise exception 'not allowed';
  end if;

  v_reason := nullif(trim(coalesce(p_reason, '')), '');

  select *
  into v_row
  from public.pos_offline_sales s
  where s.offline_id = p_offline_id
  for update;

  if not found then
    raise exception 'offline sale not found';
  end if;

  if v_row.state not in ('CONFLICT','FAILED') then
    return jsonb_build_object('status', 'NOT_REQUIRED', 'offlineId', p_offline_id, 'state', v_row.state);
  end if;

  if v_row.reconciliation_status = 'PENDING'
     and v_row.reconciliation_approval_request_id is not null then
    return jsonb_build_object(
      'status', 'PENDING',
      'offlineId', p_offline_id,
      'approvalRequestId', v_row.reconciliation_approval_request_id::text
    );
  end if;

  v_req_id := public.create_approval_request(
    'pos_offline_sales',
    p_offline_id,
    'offline_reconciliation',
    0,
    jsonb_build_object(
      'offlineId', p_offline_id,
      'orderId', v_row.order_id::text,
      'state', v_row.state,
      'lastError', v_row.last_error,
      'reason', v_reason
    )
  );

  update public.pos_offline_sales
  set reconciliation_status = 'PENDING',
      reconciliation_approval_request_id = v_req_id,
      reconciliation_note = v_reason,
      updated_at = now()
  where offline_id = p_offline_id;

  return jsonb_build_object(
    'status', 'PENDING',
    'offlineId', p_offline_id,
    'approvalRequestId', v_req_id::text
  );
end;
$$;


ALTER FUNCTION "public"."request_offline_reconciliation"("p_offline_id" "text", "p_reason" "text") OWNER TO "postgres";

--
-- Name: reserve_stock_for_order("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reserve_stock_for_order"("p_payload" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_items jsonb;
  v_order_id_text text;
  v_warehouse_id_text text;
  v_order_id uuid;
  v_warehouse_id uuid;
begin
  if p_payload is null or jsonb_typeof(p_payload) <> 'object' then
    raise exception 'p_payload must be a json object';
  end if;

  v_items := p_payload->'p_items';
  if v_items is null then
    v_items := p_payload->'items';
  end if;
  if v_items is null then
    v_items := '[]'::jsonb;
  end if;

  v_order_id_text := nullif(coalesce(p_payload->>'p_order_id', p_payload->>'order_id', p_payload->>'orderId'), '');
  if v_order_id_text is not null and v_order_id_text ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$' then
    v_order_id := v_order_id_text::uuid;
  else
    v_order_id := null;
  end if;

  v_warehouse_id_text := nullif(coalesce(p_payload->>'p_warehouse_id', p_payload->>'warehouse_id', p_payload->>'warehouseId'), '');
  if v_warehouse_id_text is not null and v_warehouse_id_text ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$' then
    v_warehouse_id := v_warehouse_id_text::uuid;
  else
    v_warehouse_id := null;
  end if;

  perform public.reserve_stock_for_order(v_items, v_order_id, v_warehouse_id);
end;
$_$;


ALTER FUNCTION "public"."reserve_stock_for_order"("p_payload" "jsonb") OWNER TO "postgres";

