-- Name: reserve_stock_for_order("jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reserve_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  raise exception 'warehouse_id is required';
end;
$$;


ALTER FUNCTION "public"."reserve_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: reserve_stock_for_order("jsonb", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reserve_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid" DEFAULT NULL::"uuid", "p_warehouse_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item jsonb;
  v_item_id text;
  v_requested numeric;
  v_needed numeric;
  v_is_food boolean;
  v_batch record;
  v_reserved_other numeric;
  v_free numeric;
  v_alloc numeric;
begin
  if auth.uid() is null then
    raise exception 'not authenticated';
  end if;
  if p_order_id is null or p_warehouse_id is null then
    raise exception 'order_id and warehouse_id are required';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;

  for v_item in select value from jsonb_array_elements(coalesce(p_items, '[]'::jsonb))
  loop
    v_item_id := coalesce(nullif(v_item->>'itemId',''), nullif(v_item->>'id',''));
    v_requested := coalesce(nullif(v_item->>'quantity','')::numeric, nullif(v_item->>'qty','')::numeric, 0);
    if v_item_id is null or v_item_id = '' or v_requested <= 0 then
      continue;
    end if;

    select (coalesce(mi.category,'') = 'food')
    into v_is_food
    from public.menu_items mi
    where mi.id::text = v_item_id::text;

    delete from public.order_item_reservations r
    where r.order_id = p_order_id
      and r.item_id = v_item_id::text
      and r.warehouse_id = p_warehouse_id;

    v_needed := v_requested;

    for v_batch in
      select
        b.id as batch_id,
        b.expiry_date,
        b.unit_cost,
        greatest(
          coalesce(b.quantity_received,0)
          - coalesce(b.quantity_consumed,0)
          - coalesce(b.quantity_transferred,0),
          0
        ) as remaining_qty
      from public.batches b
      where b.item_id::text = v_item_id::text
        and b.warehouse_id = p_warehouse_id
        and coalesce(b.status, 'active') = 'active'
        and coalesce(b.qc_status,'') = 'released'
        and not exists (
          select 1 from public.batch_recalls br
          where br.batch_id = b.id and br.status = 'active'
        )
        and (
          not coalesce(v_is_food, false)
          or (b.expiry_date is not null and b.expiry_date >= current_date)
        )
      order by b.expiry_date asc nulls last, b.created_at asc, b.id asc
      for update
    loop
      exit when v_needed <= 0;
      if coalesce(v_batch.remaining_qty, 0) <= 0 then
        continue;
      end if;

      select coalesce(sum(r2.quantity), 0)
      into v_reserved_other
      from public.order_item_reservations r2
      where r2.batch_id = v_batch.batch_id
        and r2.warehouse_id = p_warehouse_id
        and r2.order_id <> p_order_id;

      v_free := greatest(coalesce(v_batch.remaining_qty, 0) - coalesce(v_reserved_other, 0), 0);
      if v_free <= 0 then
        continue;
      end if;

      v_alloc := least(v_needed, v_free);
      if v_alloc <= 0 then
        continue;
      end if;

      insert into public.order_item_reservations(order_id, item_id, warehouse_id, batch_id, quantity, created_at, updated_at)
      values (p_order_id, v_item_id::text, p_warehouse_id, v_batch.batch_id, v_alloc, now(), now());

      v_needed := v_needed - v_alloc;
    end loop;

    if v_needed > 0 then
      raise exception 'INSUFFICIENT_FEFO_BATCH_STOCK_FOR_ITEM_%', v_item_id;
    end if;

    update public.stock_management sm
    set reserved_quantity = coalesce((
          select sum(r.quantity)
          from public.order_item_reservations r
          where r.item_id = v_item_id::text
            and r.warehouse_id = p_warehouse_id
        ), 0),
        available_quantity = coalesce((
          select sum(
            greatest(coalesce(b.quantity_received,0) - coalesce(b.quantity_consumed,0) - coalesce(b.quantity_transferred,0), 0)
          )
          from public.batches b
          where b.item_id::text = v_item_id::text
            and b.warehouse_id = p_warehouse_id
            and coalesce(b.status,'active') = 'active'
            and coalesce(b.qc_status,'') = 'released'
            and not exists (
              select 1 from public.batch_recalls br
              where br.batch_id = b.id and br.status = 'active'
            )
            and (
              not coalesce(v_is_food, false)
              or (b.expiry_date is not null and b.expiry_date >= current_date)
            )
        ), 0),
        last_updated = now(),
        updated_at = now()
    where sm.item_id::text = v_item_id::text
      and sm.warehouse_id = p_warehouse_id;
  end loop;
end;
$$;


ALTER FUNCTION "public"."reserve_stock_for_order"("p_items" "jsonb", "p_order_id" "uuid", "p_warehouse_id" "uuid") OWNER TO "postgres";

--
-- Name: resolve_account_ref("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_account_ref"("p_value" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  declare
    v_text text;
    v_id uuid;
  begin
    v_text := nullif(btrim(coalesce(p_value, '')), '');
    if v_text is null then
      return null;
    end if;

    begin
      v_id := v_text::uuid;
      return v_id;
    exception when others then
      v_id := null;
    end;

    return public.get_account_id_by_code(v_text);
  end;
  $$;


ALTER FUNCTION "public"."resolve_account_ref"("p_value" "text") OWNER TO "postgres";

--
-- Name: resolve_item_price("text", "text", numeric, "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_item_price"("p_item_id" "text", "p_currency_code" "text", "p_quantity" numeric, "p_price_date" "date") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  return public.resolve_item_price(p_item_id, p_currency_code, p_quantity, p_price_date, null);
end;
$$;


ALTER FUNCTION "public"."resolve_item_price"("p_item_id" "text", "p_currency_code" "text", "p_quantity" numeric, "p_price_date" "date") OWNER TO "postgres";

--
-- Name: resolve_item_price("text", "text", numeric, "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_item_price"("p_item_id" "text", "p_currency_code" "text", "p_quantity" numeric, "p_price_date" "date", "p_customer_id" "uuid" DEFAULT NULL::"uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
  v_currency text;
  v_date date;
  v_qty numeric;
  v_price numeric;
  v_row record;
  v_cost_base numeric;
  v_fallback_cost numeric;
  v_fx numeric;
  v_fx_cache numeric;
  v_foreign_cost numeric;
  v_enabled boolean;
  v_margin numeric;
  v_fx_source public.pricing_fx_source_enum;
  v_fallback_base numeric;
  v_batch_currency text;
  v_batch_fx numeric;
begin
  if p_item_id is null or btrim(p_item_id) = '' then
    raise exception 'p_item_id is required';
  end if;
  v_base := public.get_base_currency();
  v_currency := upper(nullif(btrim(coalesce(p_currency_code, '')), ''));
  if v_currency is null then
    v_currency := v_base;
  end if;
  v_date := coalesce(p_price_date, current_date);
  v_qty := coalesce(p_quantity, 1);
  if v_qty <= 0 then
    v_qty := 1;
  end if;

  v_enabled := public.is_multi_currency_pricing_enabled();
  if v_enabled then
    select *
    into v_row
    from public.product_prices_multi_currency ppmc
    where ppmc.item_id = p_item_id
      and upper(ppmc.currency_code) = v_currency
      and ppmc.is_active = true
      and (ppmc.effective_from is null or ppmc.effective_from <= v_date)
      and (ppmc.effective_to is null or ppmc.effective_to >= v_date)
    order by coalesce(ppmc.effective_from, v_date) desc, ppmc.updated_at desc, ppmc.created_at desc
    limit 1;

    if found then
      v_margin := coalesce(v_row.margin_percent, 0);
      v_fx_source := coalesce(v_row.fx_source, 'NONE');

      if v_row.pricing_method in ('FIXED','MANUAL_OVERRIDE') then
        v_price := coalesce(v_row.price_value, null);
        if v_price is not null and v_price >= 0 then
          return round(v_price, 4);
        end if;
      elsif v_row.pricing_method = 'BASE_PLUS_MARGIN' then
        select coalesce(mi.cost_price, 0), coalesce(mi.buying_price, 0)
        into v_cost_base, v_fallback_cost
        from public.menu_items mi
        where mi.id = p_item_id;
        if v_cost_base is null or v_cost_base <= 0 then
          v_cost_base := coalesce(v_fallback_cost, 0);
        end if;
        v_price := coalesce(v_cost_base, 0) * (1 + (greatest(v_margin, 0) / 100));
        if upper(v_currency) = upper(v_base) then
          return round(v_price, 4);
        end if;
        select b.fx_rate_at_receipt, upper(coalesce(b.foreign_currency, ''))
        into v_fx, v_batch_currency
        from public.batches b
        where b.item_id = p_item_id
          and coalesce(b.status,'active')='active'
          and coalesce(b.qc_status,'released')='released'
          and greatest(coalesce(b.quantity_received,0) - coalesce(b.quantity_consumed,0) - coalesce(b.quantity_transferred,0),0) > 0
        order by b.expiry_date asc nulls last, b.created_at asc
        limit 1;
        if v_fx is not null and v_fx > 0 and v_batch_currency is not null and v_batch_currency <> '' and upper(v_batch_currency) = upper(v_currency) then
          return round(v_price / v_fx, 4);
        end if;
        if v_fx_cache is null then
          v_fx_cache := public.get_fx_rate(v_currency, v_date, 'operational');
        end if;
        v_fx := v_fx_cache;
        if v_fx is null or v_fx <= 0 then
          raise exception 'FX rate not available for currency % on %', v_currency, v_date;
        end if;
        return round(v_price / v_fx, 4);
      elsif v_row.pricing_method = 'FOREIGN_COST_PLUS_MARGIN' then
        select
          b.foreign_unit_cost,
          upper(b.foreign_currency),
          b.fx_rate_at_receipt
        into
          v_foreign_cost,
          v_batch_currency,
          v_batch_fx
        from public.batches b
        where b.item_id = p_item_id
          and coalesce(b.status,'active')='active'
          and coalesce(b.qc_status,'released')='released'
          and greatest(
              coalesce(b.quantity_received,0)
            - coalesce(b.quantity_consumed,0)
            - coalesce(b.quantity_transferred,0),0) > 0
        order by b.expiry_date asc nulls last, b.created_at asc
        limit 1;

        if v_batch_currency is null then
          raise exception 'Batch currency undefined for item %', p_item_id;
        end if;

        if v_foreign_cost is not null and v_foreign_cost > 0 then
          v_price := v_foreign_cost * (1 + (greatest(v_margin,0)/100));

          if upper(v_currency) = upper(v_batch_currency) then
            return round(v_price,4);
          end if;

          if v_batch_fx is null or v_batch_fx <= 0 then
            raise exception 'Batch FX snapshot missing for item %', p_item_id;
          end if;

          if upper(v_batch_currency) = upper(v_base) then
            if v_fx_cache is null then
              v_fx_cache := public.get_fx_rate(v_currency,v_date,'operational');
            end if;
            v_fx := v_fx_cache;
            if v_fx is null or v_fx <= 0 then
              raise exception 'FX rate not available for %', v_currency;
            end if;
            return round(v_price / v_fx,4);
          else
            v_price := v_price / v_batch_fx;

            if upper(v_currency) = upper(v_base) then
              return round(v_price,4);
            end if;

            if v_fx_cache is null then
              v_fx_cache := public.get_fx_rate(v_currency,v_date,'operational');
            end if;
            v_fx := v_fx_cache;
            if v_fx is null or v_fx <= 0 then
              raise exception 'FX rate not available for %', v_currency;
            end if;

            return round(v_price / v_fx,4);
          end if;
        end if;
      elsif v_row.pricing_method = 'LIVE_FX_BASE' then
        if public.is_production_environment() then
          raise exception 'LIVE_FX_BASE disabled in production';
        end if;
        v_price := public.get_item_price_with_discount(p_item_id, p_customer_id, v_qty);
        if upper(v_currency) = upper(v_base) then
          return round(v_price, 4);
        end if;
        if v_fx_cache is null then
          v_fx_cache := public.get_fx_rate(v_currency, v_date, 'operational');
        end if;
        v_fx := v_fx_cache;
        if v_fx is null or v_fx <= 0 then
          raise exception 'FX rate not available for currency % on %', v_currency, v_date;
        end if;
        return round(v_price / v_fx, 4);
      end if;
    end if;
  end if;

  v_price := public.get_item_price_with_discount(p_item_id, p_customer_id, v_qty);
  if upper(v_currency) = upper(v_base) then
    return round(v_price, 4);
  end if;
  if v_fx_cache is null then
    v_fx_cache := public.get_fx_rate(v_currency, v_date, 'operational');
  end if;
  v_fx := v_fx_cache;
  if v_fx is null or v_fx <= 0 then
    raise exception 'FX rate not available for currency % on %', v_currency, v_date;
  end if;
  v_price := v_price / v_fx;
  if v_price is null then
    raise exception 'Pricing resolution failed for item %', p_item_id;
  end if;
  return round(v_price, 4);
end;
$$;


ALTER FUNCTION "public"."resolve_item_price"("p_item_id" "text", "p_currency_code" "text", "p_quantity" numeric, "p_price_date" "date", "p_customer_id" "uuid") OWNER TO "postgres";

--
-- Name: resolve_item_price("text", "uuid", "text", numeric, "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_item_price"("p_item_id" "text", "p_warehouse_id" "uuid", "p_currency_code" "text", "p_quantity" numeric, "p_price_date" "date", "p_customer_id" "uuid" DEFAULT NULL::"uuid") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
  v_currency text;
  v_date date;
  v_qty numeric;
  v_price numeric;
  v_batch record;
  v_margin numeric := 0;
  v_row record;
  v_fx numeric;
  v_fx_cache numeric;
begin
  if p_item_id is null or btrim(p_item_id) = '' then
    raise exception 'p_item_id is required';
  end if;

  if p_warehouse_id is null then
    raise exception 'p_warehouse_id is required';
  end if;

  v_base := public.get_base_currency();
  v_currency := upper(coalesce(nullif(btrim(p_currency_code),''), v_base));
  v_date := coalesce(p_price_date, current_date);
  v_qty := greatest(coalesce(p_quantity,1),1);

  select *
  into v_row
  from public.product_prices_multi_currency ppmc
  where ppmc.item_id = p_item_id
    and upper(ppmc.currency_code) = v_currency
    and ppmc.is_active = true
    and (ppmc.effective_from is null or ppmc.effective_from <= v_date)
    and (ppmc.effective_to is null or ppmc.effective_to >= v_date)
  order by coalesce(ppmc.effective_from,v_date) desc, ppmc.updated_at desc
  limit 1;

  select *
  into v_batch
  from public.batches b
  where b.item_id = p_item_id
    and b.warehouse_id = p_warehouse_id
    and coalesce(b.status,'active')='active'
    and coalesce(b.qc_status,'released')='released'
    and greatest(
      coalesce(b.quantity_received,0)
      - coalesce(b.quantity_consumed,0)
      - coalesce(b.quantity_transferred,0),0) > 0
  order by b.expiry_date asc nulls last, b.created_at asc
  limit 1;

  if v_batch.id is null then
    raise exception 'No sellable batch in warehouse % for item %',
      p_warehouse_id, p_item_id;
  end if;

  v_margin := coalesce(v_row.margin_percent,0);

  if v_row.pricing_method = 'FOREIGN_COST_PLUS_MARGIN' then

    if v_batch.foreign_currency is null then
      raise exception 'Batch currency missing for item %', p_item_id;
    end if;

    v_price := v_batch.foreign_unit_cost
               * (1 + (v_margin/100));

    if upper(v_currency) = upper(v_batch.foreign_currency) then
      return round(v_price,4);
    end if;

    if v_batch.fx_rate_at_receipt is null
       or v_batch.fx_rate_at_receipt <= 0 then
       raise exception 'Batch FX snapshot missing';
    end if;

    v_price := v_price / v_batch.fx_rate_at_receipt;

    if upper(v_currency) = upper(v_base) then
      return round(v_price,4);
    end if;

    if v_fx_cache is null then
      v_fx_cache := public.get_fx_rate(v_currency,v_date,'operational');
    end if;

    v_fx := v_fx_cache;

    if v_fx is null or v_fx <= 0 then
      raise exception 'FX rate not available';
    end if;

    return round(v_price / v_fx,4);

  end if;

  if v_row.pricing_method = 'BASE_PLUS_MARGIN' then

    v_price := coalesce(v_batch.cost_per_unit,0)
               * (1 + (v_margin/100));

    if upper(v_currency) = upper(v_base) then
      return round(v_price,4);
    end if;

    if v_fx_cache is null then
      v_fx_cache := public.get_fx_rate(v_currency,v_date,'operational');
    end if;

    v_fx := v_fx_cache;

    if v_fx is null or v_fx <= 0 then
      raise exception 'FX rate not available';
    end if;

    return round(v_price / v_fx,4);

  end if;

  raise exception 'Unsupported pricing method for warehouse-bound pricing';

end;
$$;


ALTER FUNCTION "public"."resolve_item_price"("p_item_id" "text", "p_warehouse_id" "uuid", "p_currency_code" "text", "p_quantity" numeric, "p_price_date" "date", "p_customer_id" "uuid") OWNER TO "postgres";

--
-- Name: resolve_override_account("uuid", "text", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_override_account"("p_default_account_id" "uuid", "p_override_account_id_text" "text", "p_allowed_account_types" "text"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_text text;
  v_id uuid;
  v_type text;
  v_active boolean;
begin
  if p_default_account_id is null then
    raise exception 'default account id is null';
  end if;

  v_text := nullif(trim(coalesce(p_override_account_id_text, '')), '');
  if v_text is null then
    return p_default_account_id;
  end if;

  begin
    v_id := v_text::uuid;
  exception when others then
    raise exception 'invalid overrideAccountId';
  end;

  select account_type, is_active
  into v_type, v_active
  from public.chart_of_accounts
  where id = v_id;

  if v_type is null then
    raise exception 'override account not found';
  end if;
  if coalesce(v_active, false) = false then
    raise exception 'override account is inactive';
  end if;

  if p_allowed_account_types is not null and array_length(p_allowed_account_types, 1) is not null then
    if not (v_type = any(p_allowed_account_types)) then
      raise exception 'override account type not allowed';
    end if;
  end if;

  return v_id;
end;
$$;


ALTER FUNCTION "public"."resolve_override_account"("p_default_account_id" "uuid", "p_override_account_id_text" "text", "p_allowed_account_types" "text"[]) OWNER TO "postgres";

--
-- Name: retry_offline_pos_sale("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."retry_offline_pos_sale"("p_offline_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_sale record;
  v_err text;
  v_result jsonb;
  v_i int := 0;
  v_payment jsonb;
begin
  if p_offline_id is null or btrim(p_offline_id) = '' then
    raise exception 'p_offline_id is required';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_offline_id));

  select *
  into v_sale
  from public.pos_offline_sales s
  where s.offline_id = p_offline_id
  for update;

  if not found then
    raise exception 'offline_sale_not_found';
  end if;

  if coalesce(v_sale.state, 'SYNCED') = 'DELIVERED' then
    return jsonb_build_object('status','DELIVERED','orderId', v_sale.order_id::text, 'offlineId', p_offline_id);
  end if;

  begin
    perform public.confirm_order_delivery(
      v_sale.order_id,
      coalesce(v_sale.payload->'items','[]'::jsonb),
      coalesce(v_sale.payload, '{}'::jsonb),
      coalesce(nullif(v_sale.payload->>'warehouseId','')::uuid, public._resolve_default_warehouse_id())
    );
  exception when others then
    v_err := sqlerrm;
    update public.pos_offline_sales
    set state = case
          when v_err ilike '%insufficient%' then 'CONFLICT'
          when v_err ilike '%expired%' then 'CONFLICT'
          when v_err ilike '%reservation%' then 'CONFLICT'
          when v_err ilike '%delivery_driver_required%' then 'CONFLICT'
          else 'FAILED'
        end,
        last_error = v_err,
        updated_at = now()
    where offline_id = p_offline_id;
    update public.orders
    set data = jsonb_set(coalesce(data, '{}'::jsonb), '{offlineState}', to_jsonb('CONFLICT'::text), true),
        updated_at = now()
    where id = v_sale.order_id;
    return jsonb_build_object('status', 'CONFLICT', 'orderId', v_sale.order_id::text, 'offlineId', p_offline_id, 'error', v_err);
  end;

  for v_payment in
    select value
    from jsonb_array_elements(coalesce(v_sale.payload->'payments','[]'::jsonb))
  loop
    begin
      perform public.record_order_payment(
        v_sale.order_id,
        coalesce(nullif(v_payment->>'amount','')::numeric, 0),
        coalesce(nullif(v_payment->>'method',''), ''),
        coalesce(nullif(v_payment->>'occurredAt','')::timestamptz, now()),
        'offline:' || p_offline_id || ':retry:' || v_i::text
      );
    exception when others then
      null;
    end;
    v_i := v_i + 1;
  end loop;

  update public.pos_offline_sales
  set state = 'DELIVERED',
      last_error = null,
      updated_at = now()
  where offline_id = p_offline_id;

  update public.orders
  set data = jsonb_set(coalesce(data, '{}'::jsonb), '{offlineState}', to_jsonb('DELIVERED'::text), true),
      updated_at = now()
  where id = v_sale.order_id;

  v_result := jsonb_build_object('status', 'DELIVERED', 'orderId', v_sale.order_id::text, 'offlineId', p_offline_id);
  return v_result;
end;
$$;


ALTER FUNCTION "public"."retry_offline_pos_sale"("p_offline_id" "text") OWNER TO "postgres";

--
-- Name: reverse_journal_entry("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reverse_journal_entry"("p_journal_entry_id" "uuid", "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_src public.journal_entries%rowtype;
  v_new_entry_id uuid;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.manage')) then
    raise exception 'not authorized to post accounting entries';
  end if;
  if p_journal_entry_id is null then
    raise exception 'p_journal_entry_id is required';
  end if;

  select *
  into v_src
  from public.journal_entries je
  where je.id = p_journal_entry_id
  for update;

  if not found then
    raise exception 'journal entry not found';
  end if;

  if coalesce(v_src.source_table, '') = '' then
    raise exception 'not allowed';
  end if;

  if exists (
    select 1
    from public.journal_entries je
    where je.source_table = 'journal_entries'
      and je.source_id = p_journal_entry_id::text
      and je.source_event = 'reversal'
  ) then
    raise exception 'already reversed';
  end if;

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (
    now(),
    concat('REVERSAL of ', p_journal_entry_id::text, ': ', coalesce(nullif(p_reason,''), '')),
    'journal_entries',
    p_journal_entry_id::text,
    'reversal',
    auth.uid()
  )
  returning id into v_new_entry_id;

  insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
  select
    v_new_entry_id,
    jl.account_id,
    jl.credit,
    jl.debit,
    concat('Reversal: ', coalesce(jl.line_memo,''))
  from public.journal_lines jl
  where jl.journal_entry_id = p_journal_entry_id;

  perform public.check_journal_entry_balance(v_new_entry_id);

  return v_new_entry_id;
end;
$$;


ALTER FUNCTION "public"."reverse_journal_entry"("p_journal_entry_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: reverse_payment_journal("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reverse_payment_journal"("p_payment_id" "uuid", "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_reason text;
  v_existing_id uuid;
  v_new_entry_id uuid;
begin
  if not public.is_owner_or_manager() then
    raise exception 'not allowed';
  end if;
  if p_payment_id is null then
    raise exception 'p_payment_id is required';
  end if;
  v_reason := nullif(trim(coalesce(p_reason,'')), '');
  if v_reason is null then
    raise exception 'reason required';
  end if;
  perform public.set_audit_reason(v_reason);
  select id into v_existing_id
  from public.journal_entries
  where source_table = 'payments' and source_id = p_payment_id::text
  order by created_at desc
  limit 1;
  if v_existing_id is null then
    raise exception 'payment journal not found';
  end if;
  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (now(), concat('Void payment ', p_payment_id::text), 'payments', p_payment_id::text, 'void', auth.uid())
  returning id into v_new_entry_id;
  insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
  select v_new_entry_id, account_id, credit, debit, coalesce(line_memo,'') || ' (reversal)'
  from public.journal_lines
  where journal_entry_id = v_existing_id;
  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values ('payments.void', 'payments', p_payment_id::text, auth.uid(), now(),
          jsonb_build_object('voidOfJournal', v_existing_id::text, 'newEntryId', v_new_entry_id::text),
          'HIGH', v_reason);
  return v_new_entry_id;
end;
$$;


ALTER FUNCTION "public"."reverse_payment_journal"("p_payment_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: roll_budget_forward("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."roll_budget_forward"("p_budget_id" "uuid", "p_months" integer DEFAULT 1) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_last date;
  v_n int := 0;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_budget_id is null then
    raise exception 'budget_id required';
  end if;
  select max(period_start) into v_last from public.budget_lines where budget_id = p_budget_id;
  if v_last is null then
    return 0;
  end if;

  with src as (
    select * from public.budget_lines where budget_id = p_budget_id and period_start = v_last
  ),
  months as (
    select (date_trunc('month', v_last) + make_interval(months => gs))::date as period_start
    from generate_series(1, greatest(coalesce(p_months,1),1)) gs
  ),
  ins as (
    insert into public.budget_lines(budget_id, period_start, account_id, cost_center_id, party_id, amount_base, currency_code, notes, created_by)
    select
      p_budget_id,
      m.period_start,
      s.account_id,
      s.cost_center_id,
      s.party_id,
      s.amount_base,
      s.currency_code,
      s.notes,
      auth.uid()
    from src s
    cross join months m
    on conflict (budget_id, period_start, account_id, cost_center_id, party_id) do nothing
    returning 1
  )
  select count(*) into v_n from ins;

  return v_n;
end;
$$;


