--
-- Name: run_accounting_scheduler(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."run_accounting_scheduler"("p_limit" integer DEFAULT 50) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_n int := 0;
  v_row record;
  v_now timestamptz := clock_timestamp();
  v_next timestamptz;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  for v_row in
    select *
    from public.accounting_job_schedules s
    where s.is_active = true
      and s.next_run_at <= v_now
    order by s.next_run_at asc
    limit greatest(coalesce(p_limit,50),1)
    for update skip locked
  loop
    perform public.enqueue_accounting_job(v_row.job_type, v_row.payload, v_now);
    v_next := v_row.next_run_at + make_interval(mins => greatest(v_row.every_minutes,1));
    update public.accounting_job_schedules
    set next_run_at = v_next
    where id = v_row.id;
    v_n := v_n + 1;
  end loop;

  return v_n;
end;
$$;


ALTER FUNCTION "public"."run_accounting_scheduler"("p_limit" integer) OWNER TO "postgres";

--
-- Name: run_base_currency_historical_restatement(integer, "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."run_base_currency_historical_restatement"("p_batch" integer DEFAULT 50, "p_before_entry_date" "date" DEFAULT NULL::"date") RETURNS TABLE("processed" integer, "restated" integer, "skipped" integer, "settlements_created" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_old_base text;
  v_new_base text;
  v_row record;
  v_entry public.journal_entries%rowtype;
  v_new_entry_id uuid;
  v_rate_old_to_new numeric;
  v_fx_gain uuid := public.get_account_id_by_code('6200');
  v_fx_loss uuid := public.get_account_id_by_code('6201');
  v_debit_sum numeric;
  v_credit_sum numeric;
  v_diff numeric;
  v_settlements int := 0;
  v_processed int := 0;
  v_restated int := 0;
  v_skipped int := 0;
  v_rev_line_id uuid;
  v_orig_poi uuid;
  v_rev_poi uuid;
  v_party_id uuid;
  v_alloc jsonb;
  v_alloc_amt numeric;
  v_alloc_foreign numeric;
  v_from public.party_open_items%rowtype;
  v_to public.party_open_items%rowtype;
  v_tmp public.party_open_items%rowtype;
  v_item_currency text;
  v_fx numeric;
  v_amt_base numeric;
  v_before date := coalesce(p_before_entry_date, current_date);
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  select old_base_currency, new_base_currency
  into v_old_base, v_new_base
  from public.base_currency_migration_state
  where id = 'sar_base_lock'
  limit 1;

  if v_old_base is null or v_new_base is null then
    raise exception 'migration state missing';
  end if;

  processed := 0;
  restated := 0;
  skipped := 0;
  settlements_created := 0;

  for v_row in
    select je.id as journal_entry_id
    from public.journal_entries je
    left join public.base_currency_migration_entry_map m
      on m.original_journal_entry_id = je.id
    where m.original_journal_entry_id is null
      and je.source_table is distinct from 'base_currency_migration'
      and je.entry_date < v_before
    order by je.entry_date asc, je.created_at asc
    limit greatest(coalesce(p_batch, 0), 0)
  loop
    v_processed := v_processed + 1;
    processed := v_processed;

    select * into v_entry
    from public.journal_entries je
    where je.id = v_row.journal_entry_id
    limit 1;

    if not found then
      insert into public.base_currency_migration_entry_map(original_journal_entry_id, status, notes)
      values (v_row.journal_entry_id, 'skipped', 'journal entry not found');
      v_skipped := v_skipped + 1;
      skipped := v_skipped;
      continue;
    end if;

    if public.is_in_closed_period(v_entry.entry_date) then
      insert into public.base_currency_migration_entry_map(original_journal_entry_id, status, notes)
      values (v_entry.id, 'skipped', 'entry in closed period');
      v_skipped := v_skipped + 1;
      skipped := v_skipped;
      continue;
    end if;

    v_rate_old_to_new := public.get_fx_rate(v_old_base, v_entry.entry_date::date, 'accounting');
    if v_rate_old_to_new is null or v_rate_old_to_new <= 0 or v_rate_old_to_new >= 1 then
      insert into public.base_currency_migration_entry_map(original_journal_entry_id, status, notes)
      values (v_entry.id, 'skipped', 'missing/invalid old_base->new_base accounting rate');
      v_skipped := v_skipped + 1;
      skipped := v_skipped;
      continue;
    end if;

    insert into public.journal_entries(
      entry_date,
      memo,
      source_table,
      source_id,
      source_event,
      created_by,
      journal_id,
      document_id,
      branch_id,
      company_id
    )
    values (
      v_entry.entry_date,
      concat('Historical base currency restatement (', v_old_base, '→', v_new_base, ') for JE ', v_entry.id::text),
      'base_currency_migration',
      v_entry.id::text,
      'historical_base_currency_correction',
      auth.uid(),
      v_entry.journal_id,
      v_entry.document_id,
      v_entry.branch_id,
      v_entry.company_id
    )
    returning id into v_new_entry_id;

    for v_row in
      select jl.*
      from public.journal_lines jl
      where jl.journal_entry_id = v_entry.id
      order by jl.created_at asc, jl.id asc
    loop
      insert into public.journal_lines(
        journal_entry_id,
        account_id,
        debit,
        credit,
        line_memo,
        cost_center_id,
        party_id,
        currency_code,
        fx_rate,
        foreign_amount,
        dept_id,
        project_id
      )
      values (
        v_new_entry_id,
        v_row.account_id,
        coalesce(v_row.credit, 0),
        coalesce(v_row.debit, 0),
        concat('Restatement reversal: ', coalesce(v_row.line_memo,'')),
        v_row.cost_center_id,
        v_row.party_id,
        v_row.currency_code,
        v_row.fx_rate,
        v_row.foreign_amount,
        v_row.dept_id,
        v_row.project_id
      )
      returning id into v_rev_line_id;

      v_item_currency := upper(nullif(btrim(coalesce(v_row.currency_code, '')), ''));
      v_fx := null;

      if v_item_currency is not null and v_item_currency <> upper(v_new_base) and v_row.foreign_amount is not null and v_row.foreign_amount > 0 then
        v_fx := public.get_fx_rate(v_item_currency, v_entry.entry_date::date, 'accounting');
        if v_fx is null or v_fx <= 0 then
          v_fx := public.get_fx_rate(v_item_currency, v_entry.entry_date::date, 'operational');
        end if;
        if v_fx is null or v_fx <= 0 then
          v_item_currency := null;
          v_fx := null;
        end if;
      else
        v_item_currency := null;
        v_fx := null;
      end if;

      if v_item_currency is null then
        v_amt_base := public._money_round(greatest(coalesce(v_row.debit, 0), coalesce(v_row.credit, 0)) * v_rate_old_to_new);

        insert into public.journal_lines(
          journal_entry_id,
          account_id,
          debit,
          credit,
          line_memo,
          cost_center_id,
          party_id,
          currency_code,
          fx_rate,
          foreign_amount,
          dept_id,
          project_id
        )
        values (
          v_new_entry_id,
          v_row.account_id,
          case when coalesce(v_row.debit, 0) > 0 then v_amt_base else 0 end,
          case when coalesce(v_row.credit, 0) > 0 then v_amt_base else 0 end,
          concat('Restated base (', v_new_base, ') from old base ', v_old_base),
          v_row.cost_center_id,
          v_row.party_id,
          null,
          null,
          null,
          v_row.dept_id,
          v_row.project_id
        );
      else
        v_amt_base := public._money_round(coalesce(v_row.foreign_amount, 0) * v_fx);

        insert into public.journal_lines(
          journal_entry_id,
          account_id,
          debit,
          credit,
          line_memo,
          cost_center_id,
          party_id,
          currency_code,
          fx_rate,
          foreign_amount,
          dept_id,
          project_id
        )
        values (
          v_new_entry_id,
          v_row.account_id,
          case when coalesce(v_row.debit, 0) > 0 then v_amt_base else 0 end,
          case when coalesce(v_row.credit, 0) > 0 then v_amt_base else 0 end,
          concat('Restated FX (', v_item_currency, '→', v_new_base, ')'),
          v_row.cost_center_id,
          v_row.party_id,
          v_item_currency,
          v_fx,
          v_row.foreign_amount,
          v_row.dept_id,
          v_row.project_id
        );
      end if;

      begin
        select poi.id, poi.party_id into v_orig_poi, v_party_id
        from public.party_open_items poi
        where poi.journal_line_id = v_row.id
        limit 1;
      exception when others then
        v_orig_poi := null;
        v_party_id := null;
      end;

      begin
        select poi.id into v_rev_poi
        from public.party_open_items poi
        where poi.journal_line_id = v_rev_line_id
        limit 1;
      exception when others then
        v_rev_poi := null;
      end;

      if v_party_id is not null and v_orig_poi is not null and v_rev_poi is not null then
        select * into v_from from public.party_open_items where id = v_orig_poi limit 1;
        select * into v_to from public.party_open_items where id = v_rev_poi limit 1;
        if v_from.id is not null and v_to.id is not null then
          if v_from.direction = 'credit' and v_to.direction = 'debit' then
            v_tmp := v_from;
            v_from := v_to;
            v_to := v_tmp;
          end if;

          if v_from.direction = 'debit' and v_to.direction = 'credit' then
            if v_from.open_foreign_amount is not null and v_to.open_foreign_amount is not null then
              v_alloc_foreign := least(coalesce(v_from.open_foreign_amount,0), coalesce(v_to.open_foreign_amount,0));
              if v_alloc_foreign > 0 then
                v_alloc := jsonb_build_array(jsonb_build_object('fromOpenItemId', v_from.id::text, 'toOpenItemId', v_to.id::text, 'allocatedForeignAmount', v_alloc_foreign));
                perform public.create_settlement(v_party_id, v_entry.entry_date, v_alloc, 'Auto settle: base currency restatement reversal');
                v_settlements := v_settlements + 1;
                settlements_created := v_settlements;
              end if;
            else
              v_alloc_amt := least(coalesce(v_from.open_base_amount,0), coalesce(v_to.open_base_amount,0));
              if v_alloc_amt > 0 then
                v_alloc := jsonb_build_array(jsonb_build_object('fromOpenItemId', v_from.id::text, 'toOpenItemId', v_to.id::text, 'allocatedBaseAmount', v_alloc_amt));
                perform public.create_settlement(v_party_id, v_entry.entry_date, v_alloc, 'Auto settle: base currency restatement reversal');
                v_settlements := v_settlements + 1;
                settlements_created := v_settlements;
              end if;
            end if;
          end if;
        end if;
      end if;
    end loop;

    select coalesce(sum(coalesce(jl.debit,0)),0), coalesce(sum(coalesce(jl.credit,0)),0)
    into v_debit_sum, v_credit_sum
    from public.journal_lines jl
    where jl.journal_entry_id = v_new_entry_id;

    v_diff := coalesce(v_debit_sum,0) - coalesce(v_credit_sum,0);
    if abs(v_diff) > 0.02 then
      if v_fx_gain is null or v_fx_loss is null then
        raise exception 'missing fx gain/loss accounts';
      end if;

      if v_diff > 0 then
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_new_entry_id, v_fx_gain, 0, abs(v_diff), 'Restatement balancing (credit)');
      else
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_new_entry_id, v_fx_loss, abs(v_diff), 0, 'Restatement balancing (debit)');
      end if;
    end if;

    perform public.check_journal_entry_balance(v_new_entry_id);

    insert into public.base_currency_migration_entry_map(original_journal_entry_id, restated_journal_entry_id, status, notes)
    values (v_entry.id, v_new_entry_id, 'restated', null);

    v_restated := v_restated + 1;
    restated := v_restated;
  end loop;

  skipped := v_skipped;
  processed := v_processed;
  settlements_created := v_settlements;

  return query
  select processed, restated, skipped, settlements_created;
end;
$$;


ALTER FUNCTION "public"."run_base_currency_historical_restatement"("p_batch" integer, "p_before_entry_date" "date") OWNER TO "postgres";

--
-- Name: run_base_currency_historical_restatement(integer, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."run_base_currency_historical_restatement"("p_batch" integer DEFAULT 20, "p_posting_date" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("batch_id" "uuid", "processed" integer, "restated" integer, "skipped" integer, "settlements_created" integer, "original_entry_ids" "uuid"[], "restated_entry_ids" "uuid"[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_old_base text;
  v_new_base text;
  v_lock_at timestamptz;
  v_post_ts timestamptz;
  v_row record;
  v_entry public.journal_entries%rowtype;
  v_new_entry_id uuid;
  v_rate_old_to_new numeric;
  v_fx_gain uuid := public.get_account_id_by_code('6200');
  v_fx_loss uuid := public.get_account_id_by_code('6201');
  v_debit_sum numeric;
  v_credit_sum numeric;
  v_diff numeric;
  v_processed int := 0;
  v_restated int := 0;
  v_skipped int := 0;
  v_item_currency text;
  v_fx numeric;
  v_amt_base numeric;
  v_batch uuid := gen_random_uuid();
  v_orig_ids uuid[] := '{}'::uuid[];
  v_new_ids uuid[] := '{}'::uuid[];
begin
  if session_user not in ('postgres','supabase_admin')
     and auth.role() <> 'service_role'
     and not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  select old_base_currency, new_base_currency, locked_at
  into v_old_base, v_new_base, v_lock_at
  from public.base_currency_restatement_state
  where id = 'sar_base_lock'
  limit 1;

  if v_old_base is null or v_new_base is null then
    raise exception 'restatement state missing';
  end if;

  v_post_ts := coalesce(p_posting_date, v_lock_at);
  if public.is_in_closed_period(v_post_ts) then
    raise exception 'posting date in closed period';
  end if;

  batch_id := v_batch;
  processed := 0;
  restated := 0;
  skipped := 0;
  settlements_created := 0;
  original_entry_ids := '{}'::uuid[];
  restated_entry_ids := '{}'::uuid[];

  for v_row in
    select t.journal_entry_id
    from public.historical_base_currency_restatement_targets t
    left join public.base_currency_restatement_entry_map m
      on m.original_journal_entry_id = t.journal_entry_id
    where m.original_journal_entry_id is null
    order by t.entry_date asc, t.created_at asc, t.journal_entry_id asc
    limit greatest(coalesce(p_batch, 0), 0)
  loop
    v_processed := v_processed + 1;
    processed := v_processed;

    v_orig_ids := array_append(v_orig_ids, v_row.journal_entry_id::uuid);

    select * into v_entry
    from public.journal_entries je
    where je.id = v_row.journal_entry_id
    limit 1;

    if not found then
      insert into public.base_currency_restatement_entry_map(original_journal_entry_id, status, notes, batch_id)
      values (v_row.journal_entry_id, 'skipped', 'journal entry not found', v_batch);
      v_skipped := v_skipped + 1;
      skipped := v_skipped;
      continue;
    end if;

    v_rate_old_to_new := public.get_fx_rate(v_old_base, v_entry.entry_date::date, 'accounting');
    if v_rate_old_to_new is null or v_rate_old_to_new <= 0 then
      insert into public.base_currency_restatement_entry_map(original_journal_entry_id, status, notes, batch_id)
      values (v_entry.id, 'skipped', 'missing/invalid old_base->new_base accounting rate', v_batch);
      v_skipped := v_skipped + 1;
      skipped := v_skipped;
      continue;
    end if;

    insert into public.journal_entries(
      entry_date,
      memo,
      source_table,
      source_id,
      source_event,
      created_by,
      journal_id,
      document_id,
      branch_id,
      company_id,
      reference_entry_id
    )
    values (
      v_post_ts,
      concat('Historical base currency restatement (SAR)', E'\n', 'Original JE: ', v_entry.id::text),
      'base_currency_restatement',
      v_entry.id::text,
      'historical_base_currency_restatement',
      auth.uid(),
      v_entry.journal_id,
      v_entry.document_id,
      v_entry.branch_id,
      v_entry.company_id,
      v_entry.id
    )
    returning id into v_new_entry_id;

    v_new_ids := array_append(v_new_ids, v_new_entry_id);

    for v_row in
      select jl.*
      from public.journal_lines jl
      where jl.journal_entry_id = v_entry.id
      order by jl.created_at asc, jl.id asc
    loop
      insert into public.journal_lines(
        journal_entry_id,
        account_id,
        debit,
        credit,
        line_memo,
        cost_center_id,
        party_id,
        currency_code,
        fx_rate,
        foreign_amount,
        dept_id,
        project_id
      )
      values (
        v_new_entry_id,
        v_row.account_id,
        coalesce(v_row.credit, 0),
        coalesce(v_row.debit, 0),
        concat('Restatement reversal: ', coalesce(v_row.line_memo,'')),
        v_row.cost_center_id,
        v_row.party_id,
        v_row.currency_code,
        v_row.fx_rate,
        v_row.foreign_amount,
        v_row.dept_id,
        v_row.project_id
      );

      v_item_currency := upper(nullif(btrim(coalesce(v_row.currency_code, '')), ''));
      v_fx := null;

      if v_item_currency is not null and v_item_currency <> upper(v_new_base) and v_row.foreign_amount is not null and v_row.foreign_amount > 0 then
        v_fx := public.get_fx_rate(v_item_currency, v_entry.entry_date::date, 'accounting');
        if v_fx is null or v_fx <= 0 then
          v_fx := public.get_fx_rate(v_item_currency, v_entry.entry_date::date, 'operational');
        end if;
        if v_fx is null or v_fx <= 0 then
          v_item_currency := null;
          v_fx := null;
        end if;
      else
        v_item_currency := null;
        v_fx := null;
      end if;

      if v_item_currency is null then
        v_amt_base := public._money_round(greatest(coalesce(v_row.debit, 0), coalesce(v_row.credit, 0)) * v_rate_old_to_new);

        insert into public.journal_lines(
          journal_entry_id,
          account_id,
          debit,
          credit,
          line_memo,
          cost_center_id,
          party_id,
          currency_code,
          fx_rate,
          foreign_amount,
          dept_id,
          project_id
        )
        values (
          v_new_entry_id,
          v_row.account_id,
          case when coalesce(v_row.debit, 0) > 0 then v_amt_base else 0 end,
          case when coalesce(v_row.credit, 0) > 0 then v_amt_base else 0 end,
          concat('Restated base (SAR) from old base ', upper(v_old_base)),
          v_row.cost_center_id,
          v_row.party_id,
          null,
          null,
          null,
          v_row.dept_id,
          v_row.project_id
        );
      else
        v_amt_base := public._money_round(coalesce(v_row.foreign_amount, 0) * v_fx);

        insert into public.journal_lines(
          journal_entry_id,
          account_id,
          debit,
          credit,
          line_memo,
          cost_center_id,
          party_id,
          currency_code,
          fx_rate,
          foreign_amount,
          dept_id,
          project_id
        )
        values (
          v_new_entry_id,
          v_row.account_id,
          case when coalesce(v_row.debit, 0) > 0 then v_amt_base else 0 end,
          case when coalesce(v_row.credit, 0) > 0 then v_amt_base else 0 end,
          concat('Restated FX (', v_item_currency, '→', upper(v_new_base), ')'),
          v_row.cost_center_id,
          v_row.party_id,
          v_item_currency,
          v_fx,
          v_row.foreign_amount,
          v_row.dept_id,
          v_row.project_id
        );
      end if;
    end loop;

    select coalesce(sum(coalesce(jl.debit,0)),0), coalesce(sum(coalesce(jl.credit,0)),0)
    into v_debit_sum, v_credit_sum
    from public.journal_lines jl
    where jl.journal_entry_id = v_new_entry_id;

    v_diff := coalesce(v_debit_sum,0) - coalesce(v_credit_sum,0);
    if abs(v_diff) > 0.02 then
      if v_fx_gain is null or v_fx_loss is null then
        raise exception 'missing fx gain/loss accounts';
      end if;
      if v_diff > 0 then
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_new_entry_id, v_fx_gain, 0, abs(v_diff), 'Restatement balancing (credit)');
      else
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_new_entry_id, v_fx_loss, abs(v_diff), 0, 'Restatement balancing (debit)');
      end if;
    end if;

    perform public.check_journal_entry_balance(v_new_entry_id);

    insert into public.base_currency_restatement_entry_map(original_journal_entry_id, restated_journal_entry_id, status, notes, batch_id)
    values (v_entry.id, v_new_entry_id, 'restated', null, v_batch);

    v_restated := v_restated + 1;
    restated := v_restated;
  end loop;

  skipped := v_skipped;
  processed := v_processed;
  settlements_created := 0;
  original_entry_ids := v_orig_ids;
  restated_entry_ids := v_new_ids;

  return query
  select batch_id, processed, restated, skipped, settlements_created, original_entry_ids, restated_entry_ids;
end;
$$;


ALTER FUNCTION "public"."run_base_currency_historical_restatement"("p_batch" integer, "p_posting_date" timestamp with time zone) OWNER TO "postgres";

--
-- Name: run_base_currency_historical_restatement_v2(integer, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."run_base_currency_historical_restatement_v2"("p_batch" integer DEFAULT 20, "p_posting_date" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("batch_id" "uuid", "processed" integer, "restated" integer, "skipped" integer, "settlements_created" integer, "original_entry_ids" "uuid"[], "restated_entry_ids" "uuid"[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_old_base text;
  v_new_base text;
  v_lock_at timestamptz;
  v_post_ts timestamptz;
  v_row record;
  v_entry public.journal_entries%rowtype;
  v_new_entry_id uuid;
  v_rate_old_to_new numeric;
  v_fx_gain uuid := public.get_account_id_by_code('6200');
  v_fx_loss uuid := public.get_account_id_by_code('6201');
  v_debit_sum numeric;
  v_credit_sum numeric;
  v_diff numeric;
  v_processed int := 0;
  v_restated int := 0;
  v_skipped int := 0;
  v_item_currency text;
  v_fx numeric;
  v_amt_base numeric;
  v_batch uuid := gen_random_uuid();
  v_orig_ids uuid[] := '{}'::uuid[];
  v_new_ids uuid[] := '{}'::uuid[];
begin
  if session_user not in ('postgres','supabase_admin')
     and auth.role() <> 'service_role'
     and not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;

  select old_base_currency, new_base_currency, locked_at
  into v_old_base, v_new_base, v_lock_at
  from public.base_currency_restatement_state
  where id = 'sar_base_lock'
  limit 1;

  if v_old_base is null or v_new_base is null then
    raise exception 'restatement state missing';
  end if;

  v_post_ts := coalesce(p_posting_date, v_lock_at);
  if public.is_in_closed_period(v_post_ts) then
    raise exception 'posting date in closed period';
  end if;

  batch_id := v_batch;
  processed := 0;
  restated := 0;
  skipped := 0;
  settlements_created := 0;
  original_entry_ids := '{}'::uuid[];
  restated_entry_ids := '{}'::uuid[];

  for v_row in
    with candidates as (
      select t.journal_entry_id, t.entry_date, t.created_at
      from public.historical_base_currency_restatement_targets t
      union all
      select t.journal_entry_id, t.entry_date, t.created_at
      from public.historical_base_currency_restatement_targets_fx t
      union all
      select t.journal_entry_id, t.entry_date, t.created_at
      from public.base_currency_restatement_retry_targets t
    )
    select c.journal_entry_id
    from candidates c
    where not exists (
      select 1
      from public.base_currency_restatement_entry_map mx
      where mx.original_journal_entry_id = c.journal_entry_id
        and mx.status = 'restated'
        and mx.restated_journal_entry_id is not null
    )
    order by c.entry_date asc, c.created_at asc, c.journal_entry_id asc
    limit greatest(coalesce(p_batch, 0), 0)
  loop
    v_processed := v_processed + 1;
    processed := v_processed;

    v_orig_ids := array_append(v_orig_ids, v_row.journal_entry_id::uuid);

    select * into v_entry
    from public.journal_entries je
    where je.id = v_row.journal_entry_id
    limit 1;

    if not found then
      insert into public.base_currency_restatement_entry_map(original_journal_entry_id, status, notes, batch_id)
      values (v_row.journal_entry_id, 'skipped', 'journal entry not found', v_batch)
      on conflict (original_journal_entry_id) do update
      set status = excluded.status,
          notes = excluded.notes,
          batch_id = excluded.batch_id;
      v_skipped := v_skipped + 1;
      skipped := v_skipped;
      continue;
    end if;

    v_rate_old_to_new := coalesce(
      public.get_fx_rate(v_old_base, v_entry.entry_date::date, 'accounting'),
      public.get_fx_rate(v_old_base, v_entry.entry_date::date, 'operational'),
      public.get_fx_rate(v_old_base, v_lock_at::date, 'accounting'),
      public.get_fx_rate(v_old_base, v_lock_at::date, 'operational')
    );
    if v_rate_old_to_new is null or v_rate_old_to_new <= 0 then
      insert into public.base_currency_restatement_entry_map(original_journal_entry_id, status, notes, batch_id)
      values (v_entry.id, 'skipped_final', 'missing/invalid old_base->new_base rate (all fallbacks)', v_batch)
      on conflict (original_journal_entry_id) do update
      set status = excluded.status,
          notes = excluded.notes,
          batch_id = excluded.batch_id;
      v_skipped := v_skipped + 1;
      skipped := v_skipped;
      continue;
    end if;

    insert into public.journal_entries(
      entry_date,
      memo,
      source_table,
      source_id,
      source_event,
      created_by,
      journal_id,
      document_id,
      branch_id,
      company_id,
      reference_entry_id
    )
    values (
      v_post_ts,
      concat('Historical base currency restatement v2 (SAR)', E'\n', 'Original JE: ', v_entry.id::text),
      'base_currency_restatement',
      v_entry.id::text,
      'historical_base_currency_restatement_v2',
      auth.uid(),
      v_entry.journal_id,
      v_entry.document_id,
      v_entry.branch_id,
      v_entry.company_id,
      v_entry.id
    )
    returning id into v_new_entry_id;

    v_new_ids := array_append(v_new_ids, v_new_entry_id);

    for v_row in
      select jl.*
      from public.journal_lines jl
      where jl.journal_entry_id = v_entry.id
      order by jl.created_at asc, jl.id asc
    loop
      insert into public.journal_lines(
        journal_entry_id,
        account_id,
        debit,
        credit,
        line_memo,
        cost_center_id,
        party_id,
        currency_code,
        fx_rate,
        foreign_amount,
        dept_id,
        project_id
      )
      values (
        v_new_entry_id,
        v_row.account_id,
        coalesce(v_row.credit, 0),
        coalesce(v_row.debit, 0),
        concat('Restatement reversal: ', coalesce(v_row.line_memo,'')),
        v_row.cost_center_id,
        v_row.party_id,
        v_row.currency_code,
        v_row.fx_rate,
        v_row.foreign_amount,
        v_row.dept_id,
        v_row.project_id
      );

      v_item_currency := upper(nullif(btrim(coalesce(v_row.currency_code, '')), ''));
      v_fx := null;

      if v_item_currency is not null and v_item_currency <> upper(v_new_base)
         and v_row.foreign_amount is not null and abs(v_row.foreign_amount) > 0.0000001 then
        v_fx := coalesce(
          v_row.fx_rate,
          public.get_fx_rate(v_item_currency, v_entry.entry_date::date, 'accounting'),
          public.get_fx_rate(v_item_currency, v_entry.entry_date::date, 'operational')
        );
        if v_fx is null or v_fx <= 0 then
          v_item_currency := null;
          v_fx := null;
        end if;
      else
        v_item_currency := null;
        v_fx := null;
      end if;

      if v_item_currency is null then
        v_amt_base := public._money_round(greatest(coalesce(v_row.debit, 0), coalesce(v_row.credit, 0)) * v_rate_old_to_new);
        insert into public.journal_lines(
          journal_entry_id,
          account_id,
          debit,
          credit,
          line_memo,
          cost_center_id,
          party_id,
          currency_code,
          fx_rate,
          foreign_amount,
          dept_id,
          project_id
        )
        values (
          v_new_entry_id,
          v_row.account_id,
          case when coalesce(v_row.debit, 0) > 0 then v_amt_base else 0 end,
          case when coalesce(v_row.credit, 0) > 0 then v_amt_base else 0 end,
          concat('Restated base (SAR) from old base ', upper(v_old_base)),
          v_row.cost_center_id,
          v_row.party_id,
          null,
          null,
          null,
          v_row.dept_id,
          v_row.project_id
        );
      else
        v_amt_base := public._money_round(coalesce(v_row.foreign_amount, 0) * v_fx);
        insert into public.journal_lines(
          journal_entry_id,
          account_id,
          debit,
          credit,
          line_memo,
          cost_center_id,
          party_id,
          currency_code,
          fx_rate,
          foreign_amount,
          dept_id,
          project_id
        )
        values (
          v_new_entry_id,
          v_row.account_id,
          case when coalesce(v_row.debit, 0) > 0 then v_amt_base else 0 end,
          case when coalesce(v_row.credit, 0) > 0 then v_amt_base else 0 end,
          concat('Restated FX (', v_item_currency, '→', upper(v_new_base), ')'),
          v_row.cost_center_id,
          v_row.party_id,
          v_item_currency,
          v_fx,
          v_row.foreign_amount,
          v_row.dept_id,
          v_row.project_id
        );
      end if;
    end loop;

    select coalesce(sum(coalesce(jl.debit,0)),0), coalesce(sum(coalesce(jl.credit,0)),0)
    into v_debit_sum, v_credit_sum
    from public.journal_lines jl
    where jl.journal_entry_id = v_new_entry_id;

    v_diff := coalesce(v_debit_sum,0) - coalesce(v_credit_sum,0);
    if abs(v_diff) > 0.02 then
      if v_fx_gain is null or v_fx_loss is null then
        raise exception 'missing fx gain/loss accounts';
      end if;
      if v_diff > 0 then
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_new_entry_id, v_fx_gain, 0, abs(v_diff), 'Restatement balancing (credit)');
      else
        insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
        values (v_new_entry_id, v_fx_loss, abs(v_diff), 0, 'Restatement balancing (debit)');
      end if;
    end if;

    perform public.check_journal_entry_balance(v_new_entry_id);

    insert into public.base_currency_restatement_entry_map(original_journal_entry_id, restated_journal_entry_id, status, notes, batch_id)
    values (v_entry.id, v_new_entry_id, 'restated', null, v_batch)
    on conflict (original_journal_entry_id) do update
    set restated_journal_entry_id = excluded.restated_journal_entry_id,
        status = excluded.status,
        notes = excluded.notes,
        batch_id = excluded.batch_id;

    v_restated := v_restated + 1;
    restated := v_restated;
  end loop;

  skipped := v_skipped;
  processed := v_processed;
  settlements_created := 0;
  original_entry_ids := v_orig_ids;
  restated_entry_ids := v_new_ids;

  return query
  select batch_id, processed, restated, skipped, settlements_created, original_entry_ids, restated_entry_ids;
end;
$$;


