--
-- Name: sign_ledger_entry("uuid", "uuid", "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sign_ledger_entry"("p_journal_entry_id" "uuid", "p_public_key_id" "uuid", "p_signature" "text", "p_algorithm" "text" DEFAULT 'ed25519'::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_chain text;
  v_id uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if p_journal_entry_id is null then
    raise exception 'journal_entry_id required';
  end if;
  if p_public_key_id is null then
    raise exception 'public_key_id required';
  end if;
  if nullif(btrim(coalesce(p_signature,'')), '') is null then
    raise exception 'signature required';
  end if;

  select lec.chain_hash into v_chain
  from public.ledger_entry_hash_chain lec
  where lec.journal_entry_id = p_journal_entry_id;
  if v_chain is null then
    raise exception 'hash chain missing for entry';
  end if;

  insert into public.ledger_entry_signatures(journal_entry_id, chain_hash, algorithm, signature, public_key_id, signed_by, metadata)
  values (p_journal_entry_id, v_chain, lower(coalesce(p_algorithm,'ed25519')), p_signature, p_public_key_id, auth.uid(), coalesce(p_metadata,'{}'::jsonb))
  on conflict (journal_entry_id, public_key_id) do update
  set chain_hash = excluded.chain_hash,
      algorithm = excluded.algorithm,
      signature = excluded.signature,
      signed_at = now(),
      signed_by = excluded.signed_by,
      metadata = excluded.metadata
  returning id into v_id;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'ledger.signature',
    'forensic',
    p_journal_entry_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('entryId', p_journal_entry_id::text, 'signatureId', v_id::text, 'publicKeyId', p_public_key_id::text),
    'LOW',
    'LEDGER_SIGNATURE'
  );

  return v_id;
end;
$$;


ALTER FUNCTION "public"."sign_ledger_entry"("p_journal_entry_id" "uuid", "p_public_key_id" "uuid", "p_signature" "text", "p_algorithm" "text", "p_metadata" "jsonb") OWNER TO "postgres";

--
-- Name: simulate_workflow_path("text", numeric, "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."simulate_workflow_path"("p_document_type" "text", "p_amount" numeric, "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_def public.workflow_definitions%rowtype;
  v_rule public.workflow_rules%rowtype;
  v_company uuid;
  v_branch uuid;
  v_currency text;
  v_steps jsonb;
begin
  if not public.has_admin_permission('accounting.view') then
    raise exception 'not allowed';
  end if;
  v_company := nullif(p_metadata->>'companyId','')::uuid;
  v_branch := nullif(p_metadata->>'branchId','')::uuid;
  v_currency := upper(nullif(p_metadata->>'currencyCode',''));

  select * into v_def
  from public.workflow_definitions wd
  where wd.is_active = true
    and lower(wd.module) = lower(coalesce(p_document_type,''))
  order by wd.created_at desc
  limit 1;

  if v_def.id is null then
    return jsonb_build_object('matched', false, 'reason', 'no_definition');
  end if;

  select * into v_rule
  from public.workflow_rules wr
  where wr.definition_id = v_def.id
    and wr.is_active = true
    and public._match_workflow_rule(wr.conditions, coalesce(p_amount,0), v_company, v_branch, v_currency)
  order by wr.priority asc, wr.created_at asc
  limit 1;

  if v_rule.id is null then
    return jsonb_build_object('matched', false, 'definitionId', v_def.id::text, 'reason', 'no_rule');
  end if;

  v_steps := coalesce(v_rule.steps, '[]'::jsonb);

  return jsonb_build_object(
    'matched', true,
    'definitionId', v_def.id::text,
    'definitionName', v_def.name,
    'ruleId', v_rule.id::text,
    'priority', v_rule.priority,
    'steps', v_steps
  );
end;
$$;


ALTER FUNCTION "public"."simulate_workflow_path"("p_document_type" "text", "p_amount" numeric, "p_metadata" "jsonb") OWNER TO "postgres";

--
-- Name: start_workflow("text", "text", "text", numeric, "text", "uuid", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."start_workflow"("p_module" "text", "p_target_table" "text", "p_target_id" "text", "p_amount_base" numeric, "p_currency_code" "text" DEFAULT NULL::"text", "p_company_id" "uuid" DEFAULT NULL::"uuid", "p_branch_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_def uuid;
  v_rule record;
  v_id uuid;
  v_step jsonb;
begin
  if not (public.has_admin_permission('accounting.manage') or public.has_admin_permission('accounting.approve')) then
    raise exception 'not allowed';
  end if;
  if p_module is null or btrim(p_module) = '' then
    raise exception 'module required';
  end if;
  if p_target_table is null or btrim(p_target_table) = '' then
    raise exception 'target_table required';
  end if;
  if p_target_id is null or btrim(p_target_id) = '' then
    raise exception 'target_id required';
  end if;

  select wd.id
  into v_def
  from public.workflow_definitions wd
  where wd.is_active = true
    and lower(wd.module) = lower(p_module)
  order by wd.created_at desc
  limit 1;

  if v_def is null then
    return null;
  end if;

  select wr.*
  into v_rule
  from public.workflow_rules wr
  where wr.definition_id = v_def
    and wr.is_active = true
    and public._match_workflow_rule(wr.conditions, coalesce(p_amount_base,0), p_company_id, p_branch_id, p_currency_code)
  order by wr.priority asc, wr.created_at asc
  limit 1;

  if not found then
    return null;
  end if;

  insert into public.workflow_instances(definition_id, rule_id, module, target_table, target_id, company_id, branch_id, amount_base, currency_code, status, current_step, created_by, metadata)
  values (v_def, v_rule.id, lower(p_module), lower(p_target_table), p_target_id, p_company_id, p_branch_id, coalesce(p_amount_base,0), upper(nullif(p_currency_code,'')), 'pending', 1, auth.uid(), coalesce(p_metadata,'{}'::jsonb))
  returning id into v_id;

  select value into v_step
  from jsonb_array_elements(coalesce(v_rule.steps,'[]'::jsonb))
  where (value->>'stepNo')::int = 1
  limit 1;

  if v_step is not null then
    perform public._workflow_insert_assignment(v_id, v_def, 1, v_step, 0, 'initial', null, null);
  end if;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'workflow.start',
    'workflow',
    v_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('instanceId', v_id::text, 'module', p_module, 'targetTable', p_target_table, 'targetId', p_target_id),
    'LOW',
    'WORKFLOW_START'
  );

  perform public._workflow_log_event(v_id, 'workflow.start', jsonb_build_object('module', p_module, 'targetTable', p_target_table, 'targetId', p_target_id));

  return v_id;
end;
$$;


ALTER FUNCTION "public"."start_workflow"("p_module" "text", "p_target_table" "text", "p_target_id" "text", "p_amount_base" numeric, "p_currency_code" "text", "p_company_id" "uuid", "p_branch_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";

--
-- Name: sync_ar_on_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_ar_on_invoice"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order record;
  v_is_cod boolean := false;
  v_entry_id uuid;
  v_ar_id uuid;
  v_ar_amount numeric := 0;
begin
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  select *
  into v_order
  from public.orders o
  where o.id = p_order_id;
  if not found then
    raise exception 'order not found';
  end if;
  v_is_cod := public._is_cod_delivery_order(coalesce(v_order.data,'{}'::jsonb), v_order.delivery_zone_id);
  if v_is_cod then
    return;
  end if;

  select je.id
  into v_entry_id
  from public.journal_entries je
  where je.source_table = 'orders'
    and je.source_id = p_order_id::text
    and je.source_event in ('invoiced','delivered')
  order by
    case when je.source_event = 'invoiced' then 0 else 1 end asc,
    je.entry_date desc
  limit 1;
  if not found then
    return;
  end if;

  select public.get_account_id_by_code('1200') into v_ar_id;
  if v_ar_id is null then
    raise exception 'AR account not found';
  end if;
  select coalesce(sum(jl.debit), 0) - coalesce(sum(jl.credit), 0)
  into v_ar_amount
  from public.journal_lines jl
  where jl.journal_entry_id = v_entry_id
    and jl.account_id = v_ar_id;
  if v_ar_amount is null or v_ar_amount <= 0 then
    return;
  end if;

  if exists (
    select 1 from public.ar_open_items a
    where a.invoice_id = p_order_id
      and a.status = 'open'
  ) then
    update public.ar_open_items
    set original_amount = v_ar_amount,
        open_balance = greatest(open_balance, v_ar_amount)
    where invoice_id = p_order_id
      and status = 'open';
  else
    insert into public.ar_open_items(invoice_id, order_id, journal_entry_id, original_amount, open_balance, status)
    values (p_order_id, p_order_id, v_entry_id, v_ar_amount, v_ar_amount, 'open');
  end if;
end;
$$;


ALTER FUNCTION "public"."sync_ar_on_invoice"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: sync_expense_cost_center(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_expense_cost_center"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
declare
  v_entry_id uuid;
begin
  -- Find the journal entry associated with this expense
  select id into v_entry_id
  from public.journal_entries
  where source_table = 'expenses' and source_id = new.id::text;

  if v_entry_id is not null then
    -- Update ALL lines (debit and credit) to match the expense cost center
    -- This ensures the cash side is also tagged, allowing for balanced reporting per cost center for expenses
    update public.journal_lines
    set cost_center_id = new.cost_center_id
    where journal_entry_id = v_entry_id;
  end if;
  
  return new;
end;
$$;


ALTER FUNCTION "public"."sync_expense_cost_center"() OWNER TO "postgres";

--
-- Name: sync_import_shipment_items_from_receipts("uuid", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_import_shipment_items_from_receipts"("p_shipment_id" "uuid", "p_replace" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_ship record;
  v_currency text;
  v_linked_count int := 0;
  v_upserted int := 0;
  v_deleted int := 0;
begin
  if not public.has_admin_permission('procurement.manage') then
    raise exception 'not allowed';
  end if;

  if p_shipment_id is null then
    raise exception 'p_shipment_id is required';
  end if;

  select *
  into v_ship
  from public.import_shipments s
  where s.id = p_shipment_id
  for update;

  if not found then
    raise exception 'shipment not found';
  end if;

  if v_ship.status = 'closed' then
    raise exception 'shipment is closed';
  end if;

  select count(*)
  into v_linked_count
  from public.purchase_receipts pr
  where pr.import_shipment_id = p_shipment_id;

  if v_linked_count = 0 then
    return jsonb_build_object('status','skipped','reason','no_linked_receipts','upserted',0,'deleted',0);
  end if;

  select
    case
      when count(distinct nullif(coalesce(po.currency, ''), '')) = 1 then max(nullif(coalesce(po.currency, ''), ''))
      else null
    end
  into v_currency
  from public.purchase_receipts pr
  join public.purchase_orders po on po.id = pr.purchase_order_id
  where pr.import_shipment_id = p_shipment_id;

  if v_currency is null or btrim(v_currency) = '' then
    v_currency := coalesce(public.get_base_currency(), 'USD');
  end if;

  with agg as (
    select
      pri.item_id::text as item_id,
      sum(coalesce(pri.quantity, 0))::numeric as quantity,
      case
        when sum(coalesce(pri.quantity, 0)) > 0 then
          (sum(coalesce(pri.quantity, 0) * greatest(coalesce(pri.unit_cost, 0) - coalesce(pri.transport_cost, 0) - coalesce(pri.supply_tax_cost, 0), 0)))
          / sum(coalesce(pri.quantity, 0))
        else 0
      end::numeric as unit_price_fob
    from public.purchase_receipts pr
    join public.purchase_receipt_items pri on pri.receipt_id = pr.id
    where pr.import_shipment_id = p_shipment_id
    group by pri.item_id
    having sum(coalesce(pri.quantity, 0)) > 0
  ),
  up as (
    insert into public.import_shipments_items(
      shipment_id,
      item_id,
      quantity,
      unit_price_fob,
      currency,
      expiry_date,
      notes,
      updated_at
    )
    select
      p_shipment_id,
      a.item_id,
      a.quantity,
      greatest(coalesce(a.unit_price_fob, 0), 0),
      v_currency,
      null,
      'synced_from_receipts',
      now()
    from agg a
    on conflict (shipment_id, item_id) do update
    set
      quantity = excluded.quantity,
      unit_price_fob = case when coalesce(import_shipments_items.unit_price_fob, 0) > 0 then import_shipments_items.unit_price_fob else excluded.unit_price_fob end,
      currency = coalesce(nullif(import_shipments_items.currency, ''), excluded.currency),
      updated_at = now()
    returning 1
  )
  select count(*) into v_upserted from up;

  if p_replace then
    with keep as (
      select pri.item_id::text as item_id
      from public.purchase_receipts pr
      join public.purchase_receipt_items pri on pri.receipt_id = pr.id
      where pr.import_shipment_id = p_shipment_id
      group by pri.item_id
      having sum(coalesce(pri.quantity, 0)) > 0
    ),
    del as (
      delete from public.import_shipments_items isi
      where isi.shipment_id = p_shipment_id
        and not exists (select 1 from keep k where k.item_id = isi.item_id::text)
      returning 1
    )
    select count(*) into v_deleted from del;
  end if;

  return jsonb_build_object(
    'status','ok',
    'linkedReceipts', v_linked_count,
    'upserted', v_upserted,
    'deleted', v_deleted,
    'currency', v_currency
  );
end;
$$;


ALTER FUNCTION "public"."sync_import_shipment_items_from_receipts"("p_shipment_id" "uuid", "p_replace" boolean) OWNER TO "postgres";

--
-- Name: sync_offline_pos_sale("text", "uuid", "jsonb", "jsonb", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_offline_pos_sale"("p_offline_id" "text", "p_order_id" "uuid", "p_order_data" "jsonb", "p_items" "jsonb", "p_warehouse_id" "uuid", "p_payments" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_existing_state text;
  v_reco_status text;
  v_reco_req uuid;
  v_err text;
  v_result jsonb;
  v_payment jsonb;
  v_i int := 0;
begin
  v_actor := auth.uid();
  if not public.is_staff() then
    raise exception 'not allowed';
  end if;

  if p_offline_id is null or btrim(p_offline_id) = '' then
    raise exception 'p_offline_id is required';
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;
  if p_warehouse_id is null then
    raise exception 'p_warehouse_id is required';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;
  if p_payments is null then
    p_payments := '[]'::jsonb;
  end if;
  if jsonb_typeof(p_payments) <> 'array' then
    raise exception 'p_payments must be a json array';
  end if;

  if jsonb_typeof(coalesce(p_order_data, '{}'::jsonb)->'promotionLines') = 'array'
     and jsonb_array_length(coalesce(p_order_data, '{}'::jsonb)->'promotionLines') > 0 then
    raise exception 'POS offline promotions are not allowed';
  end if;

  if exists (
    select 1
    from jsonb_array_elements(p_items) e(value)
    where (e.value ? 'promotionId')
       or (e.value ? 'promotion_id')
       or lower(coalesce(e.value->>'lineType','')) = 'promotion'
       or lower(coalesce(e.value->>'line_type','')) = 'promotion'
  ) then
    raise exception 'POS offline promotions are not allowed';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_offline_id));

  select s.state, coalesce(s.reconciliation_status, 'NONE'), s.reconciliation_approval_request_id
  into v_existing_state, v_reco_status, v_reco_req
  from public.pos_offline_sales s
  where s.offline_id = p_offline_id
  for update;

  if found and v_existing_state = 'DELIVERED' then
    return jsonb_build_object('status', 'DELIVERED', 'orderId', p_order_id::text, 'offlineId', p_offline_id);
  end if;

  if found and v_existing_state in ('CONFLICT','FAILED') and v_reco_status <> 'APPROVED' then
    return jsonb_build_object(
      'status', 'REQUIRES_RECONCILIATION',
      'orderId', p_order_id::text,
      'offlineId', p_offline_id,
      'approvalRequestId', case when v_reco_req is null then null else v_reco_req::text end
    );
  end if;

  insert into public.pos_offline_sales(offline_id, order_id, warehouse_id, state, payload, created_by, created_at, updated_at)
  values (p_offline_id, p_order_id, p_warehouse_id, 'SYNCED', coalesce(p_order_data, '{}'::jsonb), v_actor, now(), now())
  on conflict (offline_id)
  do update set
    order_id = excluded.order_id,
    warehouse_id = excluded.warehouse_id,
    state = case
      when public.pos_offline_sales.state = 'DELIVERED' then 'DELIVERED'
      else 'SYNCED'
    end,
    payload = excluded.payload,
    created_by = coalesce(public.pos_offline_sales.created_by, excluded.created_by),
    updated_at = now();

  select * from public.orders o where o.id = p_order_id for update;
  if not found then
    insert into public.orders(id, customer_auth_user_id, status, invoice_number, data, created_at, updated_at)
    values (
      p_order_id,
      v_actor,
      'pending',
      null,
      coalesce(p_order_data, '{}'::jsonb),
      now(),
      now()
    );
  else
    update public.orders
    set data = coalesce(p_order_data, data),
        updated_at = now()
    where id = p_order_id;
  end if;

  begin
    perform public.confirm_order_delivery(p_order_id, p_items, coalesce(p_order_data, '{}'::jsonb), p_warehouse_id);
  exception when others then
    v_err := sqlerrm;
    update public.pos_offline_sales
    set state = case
          when v_err ilike '%insufficient%' then 'CONFLICT'
          when v_err ilike '%expired%' then 'CONFLICT'
          when v_err ilike '%reservation%' then 'CONFLICT'
          else 'FAILED'
        end,
        last_error = v_err,
        reconciliation_status = case when v_existing_state in ('CONFLICT','FAILED') then 'NONE' else reconciliation_status end,
        reconciliation_approval_request_id = case when v_existing_state in ('CONFLICT','FAILED') then null else reconciliation_approval_request_id end,
        reconciled_by = case when v_existing_state in ('CONFLICT','FAILED') then null else reconciled_by end,
        reconciled_at = case when v_existing_state in ('CONFLICT','FAILED') then null else reconciled_at end,
        updated_at = now()
    where offline_id = p_offline_id;
    update public.orders
    set data = jsonb_set(coalesce(data, '{}'::jsonb), '{offlineState}', to_jsonb('CONFLICT'::text), true),
        updated_at = now()
    where id = p_order_id;
    return jsonb_build_object('status', 'CONFLICT', 'orderId', p_order_id::text, 'offlineId', p_offline_id, 'error', v_err);
  end;

  for v_payment in
    select value
    from jsonb_array_elements(p_payments)
  loop
    begin
      perform public.record_order_payment(
        p_order_id,
        coalesce(nullif(v_payment->>'amount','')::numeric, 0),
        coalesce(nullif(v_payment->>'method',''), ''),
        coalesce(nullif(v_payment->>'occurredAt','')::timestamptz, now()),
        'offline:' || p_offline_id || ':' || v_i::text
      );
    exception when others then
      null;
    end;
    v_i := v_i + 1;
  end loop;

  update public.pos_offline_sales
  set state = 'DELIVERED',
      last_error = null,
      updated_at = now()
  where offline_id = p_offline_id;

  update public.orders
  set data = jsonb_set(coalesce(data, '{}'::jsonb), '{offlineState}', to_jsonb('DELIVERED'::text), true),
      updated_at = now()
  where id = p_order_id;

  v_result := jsonb_build_object('status', 'DELIVERED', 'orderId', p_order_id::text, 'offlineId', p_offline_id);
  return v_result;
end;
$$;


ALTER FUNCTION "public"."sync_offline_pos_sale"("p_offline_id" "text", "p_order_id" "uuid", "p_order_data" "jsonb", "p_items" "jsonb", "p_warehouse_id" "uuid", "p_payments" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "sync_offline_pos_sale"("p_offline_id" "text", "p_order_id" "uuid", "p_order_data" "jsonb", "p_items" "jsonb", "p_warehouse_id" "uuid", "p_payments" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."sync_offline_pos_sale"("p_offline_id" "text", "p_order_id" "uuid", "p_order_data" "jsonb", "p_items" "jsonb", "p_warehouse_id" "uuid", "p_payments" "jsonb") IS 'PHASE7: Accepted drift. For POS offline sales, FEFO selection, expiry validation, stock deduction timestamp, and COGS posting are performed at SYNC time (server time), not at offline sale time.';


--
-- Name: sync_purchase_order_paid_amount_from_payments("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_purchase_order_paid_amount_from_payments"("p_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_total numeric;
  v_sum numeric;
begin
  if p_order_id is null then
    return;
  end if;

  select coalesce(po.total_amount, 0)
  into v_total
  from public.purchase_orders po
  where po.id = p_order_id
  for update;

  if not found then
    return;
  end if;

  select coalesce(sum(p.amount), 0)
  into v_sum
  from public.payments p
  where p.reference_table = 'purchase_orders'
    and p.direction = 'out'
    and p.reference_id = p_order_id::text;

  update public.purchase_orders po
  set paid_amount = least(coalesce(v_sum, 0), coalesce(v_total, 0)),
      updated_at = now()
  where po.id = p_order_id;
end;
$$;


ALTER FUNCTION "public"."sync_purchase_order_paid_amount_from_payments"("p_order_id" "uuid") OWNER TO "postgres";

