--
-- Name: trg_batches_pricing_defaults(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_batches_pricing_defaults"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_cost numeric;
  v_margin numeric;
begin
  v_cost := coalesce(new.cost_per_unit, 0);
  if v_cost <= 0 then
    v_cost := coalesce(new.unit_cost, 0);
  end if;

  if coalesce(new.unit_cost, 0) <= 0 and v_cost > 0 then
    new.unit_cost := v_cost;
  end if;
  new.cost_per_unit := v_cost;

  v_margin := coalesce(new.min_margin_pct, 0);
  if v_margin <= 0 then
    v_margin := public._resolve_default_min_margin_pct(new.item_id, new.warehouse_id);
  end if;
  new.min_margin_pct := greatest(0, v_margin);

  new.min_selling_price := public._money_round(new.cost_per_unit * (1 + (new.min_margin_pct / 100)));
  return new;
end;
$$;


ALTER FUNCTION "public"."trg_batches_pricing_defaults"() OWNER TO "postgres";

--
-- Name: trg_block_closed_import_shipment_children(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_block_closed_import_shipment_children"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_ship_id uuid;
  v_status text;
begin
  if coalesce(current_setting('app.internal_shipment_close', true), '') = '1' then
    return case when tg_op = 'DELETE' then old else new end;
  end if;

  v_ship_id := null;
  if tg_table_name = 'import_shipments_items' then
    v_ship_id := coalesce(new.shipment_id, old.shipment_id);
  elsif tg_table_name = 'import_expenses' then
    v_ship_id := coalesce(new.shipment_id, old.shipment_id);
  end if;

  if v_ship_id is null then
    return case when tg_op = 'DELETE' then old else new end;
  end if;

  select s.status into v_status
  from public.import_shipments s
  where s.id = v_ship_id;

  if coalesce(v_status, '') = 'closed' then
    raise exception 'Shipment is closed and its items/expenses cannot be modified';
  end if;

  return case when tg_op = 'DELETE' then old else new end;
end;
$$;


ALTER FUNCTION "public"."trg_block_closed_import_shipment_children"() OWNER TO "postgres";

--
-- Name: trg_block_journal_entries_in_closed_period(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_block_journal_entries_in_closed_period"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_date timestamptz;
begin
  v_date := coalesce(new.entry_date, old.entry_date);
  if v_date is not null and public.is_in_closed_period(v_date) then
    raise exception 'accounting period is closed';
  end if;
  return coalesce(new, old);
end;
$$;


