--
-- Name: trg_forbid_delete_posted_accounting_documents(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_forbid_delete_posted_accounting_documents"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
    begin
      if coalesce(old.status, '') = 'posted' then
        raise exception 'cannot delete posted accounting document; create reversal instead';
      end if;

      if exists (
        select 1
        from public.journal_entries je
        where je.document_id = old.id
        limit 1
      ) then
        raise exception 'cannot delete accounting document with journal entries; create reversal instead';
      end if;

      if exists (
        select 1
        from public.accounting_documents d
        where d.reversed_document_id = old.id
        limit 1
      ) then
        raise exception 'cannot delete accounting document referenced by reversals';
      end if;

      return old;
    end;
    $$;


ALTER FUNCTION "public"."trg_forbid_delete_posted_accounting_documents"() OWNER TO "postgres";

--
-- Name: trg_forbid_delete_posted_expenses(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_forbid_delete_posted_expenses"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  begin
    if exists (
      select 1
      from public.journal_entries je
      where je.source_table = 'expenses'
        and je.source_id = old.id::text
      limit 1
    ) then
      raise exception 'cannot delete posted expense; create a reversal instead';
    end if;

    if exists (
      select 1
      from public.payments p
      where p.reference_table = 'expenses'
        and p.direction = 'out'
        and p.reference_id = old.id::text
      limit 1
    ) then
      raise exception 'cannot delete expense with payments; create a reversal instead';
    end if;

    return old;
  end;
  $$;


