--
-- Name: trg_forbid_delete_posted_orders(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_forbid_delete_posted_orders"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  declare
    v_is_posted boolean := false;
  begin
    v_is_posted := exists (
      select 1
      from public.journal_entries je
      where je.source_table = 'orders'
        and je.source_id = old.id::text
        and je.source_event in ('invoiced','delivered')
      limit 1
    );
    if v_is_posted then
      raise exception 'cannot delete posted order; create a reversal instead';
    end if;
    return old;
  end;
