--
-- Name: trg_forbid_delete_posted_purchase_orders(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_forbid_delete_posted_purchase_orders"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  begin
    if coalesce(old.status, 'draft') <> 'draft' then
      raise exception 'cannot delete non-draft purchase order; create a reversal instead';
    end if;

    if exists (select 1 from public.purchase_receipts pr where pr.purchase_order_id = old.id limit 1) then
      raise exception 'cannot delete purchase order with receipts; create a reversal instead';
    end if;

    if exists (
      select 1
      from public.payments p
      where p.reference_table = 'purchase_orders'
        and p.direction = 'out'
        and p.reference_id = old.id::text
      limit 1
    ) then
      raise exception 'cannot delete purchase order with payments; create a reversal instead';
    end if;

    if exists (
      select 1
      from public.inventory_movements im
      where im.reference_table = 'purchase_orders'
        and im.reference_id = old.id::text
      limit 1
    ) then
      raise exception 'cannot delete purchase order with inventory movements; create a reversal instead';
    end if;

    return old;
  end;
  $$;


ALTER FUNCTION "public"."trg_forbid_delete_posted_purchase_orders"() OWNER TO "postgres";

--
-- Name: trg_forbid_disable_batch(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_forbid_disable_batch"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_remaining numeric;
  v_has_reservation boolean;
  v_has_movement boolean;
begin
  if tg_op <> 'UPDATE' then
    return new;
  end if;
  if old.id is distinct from new.id then
    return new;
  end if;
  if coalesce(new.status, 'active') = 'inactive' and coalesce(old.status, 'active') <> 'inactive' then
    select greatest(coalesce(b.quantity_received,0) - coalesce(b.quantity_consumed,0) - coalesce(b.quantity_transferred,0), 0)
    into v_remaining
    from public.batches b
    where b.id = new.id;

    select exists(select 1 from public.inventory_movements im where im.batch_id = new.id)
    into v_has_movement;

    -- If reservations table has batch_id column, check directly; otherwise fallback to stock_management JSON
    begin
      select exists(select 1 from public.order_item_reservations r where r.batch_id = new.id)
      into v_has_reservation;
    exception when undefined_column then
      select exists(
        select 1
        from public.stock_management sm
        where jsonb_typeof(sm.data->'reservedBatches') = 'object'
          and (sm.data->'reservedBatches') ? new.id::text
      )
      into v_has_reservation;
    end;

    if coalesce(v_remaining,0) > 0 or v_has_reservation or v_has_movement then
      raise exception 'BATCH_LOCKED_HAS_STOCK_OR_RESERVATIONS_OR_MOVEMENTS';
    end if;
    new.locked_at := now();
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."trg_forbid_disable_batch"() OWNER TO "postgres";

