--
-- Name: trg_freeze_ledger_tables(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_freeze_ledger_tables"() RETURNS "event_trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_cmd record;
  v_allow text;
begin
  v_allow := current_setting('app.allow_ledger_ddl', true);
  if v_allow = '1' then
    return;
  end if;
  for v_cmd in select * from pg_event_trigger_ddl_commands()
  loop
    if v_cmd.object_type in ('table','trigger','function')
      and coalesce(v_cmd.schema_name,'') = 'public'
      and (
        v_cmd.object_identity like '%public.accounting_documents%'
        or v_cmd.object_identity like '%public.journal_entries%'
        or v_cmd.object_identity like '%public.journal_lines%'
      )
    then
      raise exception 'ledger ddl frozen';
    end if;
  end loop;
end;
$$;


ALTER FUNCTION "public"."trg_freeze_ledger_tables"() OWNER TO "postgres";

--
-- Name: trg_freeze_posting_engine(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_freeze_posting_engine"() RETURNS "event_trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_cmd record;
  v_upgrade text;
begin
  v_upgrade := current_setting('app.posting_engine_upgrade', true);
  if v_upgrade = '1' then
    return;
  end if;

  for v_cmd in
    select *
    from pg_event_trigger_ddl_commands()
  loop
    if v_cmd.object_type = 'function'
      and coalesce(v_cmd.schema_name,'') = 'public'
      and (
        v_cmd.object_identity like 'function public.post_inventory_movement(%'
        or v_cmd.object_identity like 'function public.post_order_delivery(%'
        or v_cmd.object_identity like 'function public.post_payment(%'
      )
    then
      raise exception 'posting engine frozen: overriding post_* functions is forbidden';
    end if;
  end loop;
end;
$$;


ALTER FUNCTION "public"."trg_freeze_posting_engine"() OWNER TO "postgres";

--
-- Name: trg_fx_rates_direction_guard(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_fx_rates_direction_guard"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  declare
    v_base text;
    v_base_high boolean := false;
    v_cur_high boolean := false;
  begin
    v_base := public.get_base_currency();

    begin
      select coalesce(c.is_high_inflation, false)
      into v_base_high
      from public.currencies c
      where upper(c.code) = upper(v_base)
      limit 1;
    exception when undefined_table then
      v_base_high := false;
    end;

    begin
      select coalesce(c.is_high_inflation, false)
      into v_cur_high
      from public.currencies c
      where upper(c.code) = upper(new.currency_code)
      limit 1;
    exception when undefined_table then
      v_cur_high := false;
    end;

    if upper(coalesce(new.currency_code, '')) = upper(v_base) then
      return new;
    end if;

    if (not v_base_high) and v_cur_high then
      if coalesce(new.rate, 0) >= 1 then
        raise exception 'fx rate direction invalid: expected base per 1 foreign';
      end if;
    elsif v_base_high and (not v_cur_high) then
      if coalesce(new.rate, 0) <= 1 then
        raise exception 'fx rate direction invalid: expected base per 1 foreign';
      end if;
    end if;

    return new;
  end;
  $$;


ALTER FUNCTION "public"."trg_fx_rates_direction_guard"() OWNER TO "postgres";

--
-- Name: trg_fx_rates_normalize_high_inflation(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_fx_rates_normalize_high_inflation"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
  v_hi boolean := false;
  v_base_hi boolean := false;
begin
  v_base := public.get_base_currency();
  if new.currency_code is null then
    return new;
  end if;
  if upper(new.currency_code) = upper(v_base) then
    new.rate := 1;
    return new;
  end if;

  begin
    select coalesce(c.is_high_inflation, false)
    into v_hi
    from public.currencies c
    where upper(c.code) = upper(new.currency_code)
    limit 1;
  exception when others then
    v_hi := false;
  end;

  begin
    select coalesce(c.is_high_inflation, false)
    into v_base_hi
    from public.currencies c
    where upper(c.code) = upper(v_base)
    limit 1;
  exception when others then
    v_base_hi := false;
  end;

  if coalesce(new.rate, 0) > 0 and v_hi and not v_base_hi and new.rate > 10 then
    new.rate := 1 / new.rate;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."trg_fx_rates_normalize_high_inflation"() OWNER TO "postgres";

--
-- Name: trg_fx_rates_validate_and_normalize(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_fx_rates_validate_and_normalize"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
  v_base_high boolean := false;
  v_cur_high boolean := false;
  v_old_rate numeric;
begin
  v_base := public.get_base_currency();
  new.currency_code := upper(nullif(btrim(coalesce(new.currency_code, '')), ''));
  if new.currency_code is null then
    raise exception 'currency_code required';
  end if;
  if new.rate is null or new.rate <= 0 then
    raise exception 'rate must be > 0';
  end if;
  new.rate_type := lower(nullif(btrim(coalesce(new.rate_type, '')), ''));
  if new.rate_type is null then
    new.rate_type := 'operational';
  end if;
  if new.rate_type not in ('operational','accounting') then
    raise exception 'invalid rate_type';
  end if;

  select coalesce(c.is_high_inflation, false)
  into v_base_high
  from public.currencies c
  where upper(c.code) = upper(v_base)
  limit 1;

  select coalesce(c.is_high_inflation, false)
  into v_cur_high
  from public.currencies c
  where upper(c.code) = upper(new.currency_code)
  limit 1;

  if upper(new.currency_code) = upper(v_base) then
    if new.rate_type = 'operational' then
      new.rate := 1;
    elsif not v_base_high then
      new.rate := 1;
    end if;
    return new;
  end if;

  v_old_rate := new.rate;

  if (not v_base_high) and v_cur_high then
    if new.rate > 1 then
      new.rate := 1 / new.rate;
    end if;
  elsif v_base_high and (not v_cur_high) then
    if new.rate < 1 then
      new.rate := 1 / new.rate;
    end if;
  end if;

  if v_old_rate is distinct from new.rate then
    begin
      insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata)
      values (
        'fx_rate_normalized',
        'fx_rates',
        concat('Normalized FX rate for ', new.currency_code, ' ', new.rate_type, ' ', coalesce(new.rate_date::text, ''), ' from ', v_old_rate::text, ' to ', new.rate::text),
        auth.uid(),
        now(),
        jsonb_build_object('currency', new.currency_code, 'rate_type', new.rate_type, 'rate_date', new.rate_date, 'old', v_old_rate, 'new', new.rate)
      );
    exception when others then
      null;
    end;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."trg_fx_rates_validate_and_normalize"() OWNER TO "postgres";

--
-- Name: trg_guard_purchase_receipt_import_shipment_po(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_guard_purchase_receipt_import_shipment_po"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_ship_id uuid;
  v_po_id uuid;
  v_has_allowlist boolean;
  v_ship_status text;
begin
  if tg_op = 'DELETE' then
    return old;
  end if;

  v_ship_id := new.import_shipment_id;
  if v_ship_id is null then
    return new;
  end if;

  select s.status into v_ship_status
  from public.import_shipments s
  where s.id = v_ship_id;
  if coalesce(v_ship_status, '') = 'closed' then
    raise exception 'Shipment is closed and cannot be linked to receipts';
  end if;

  v_po_id := new.purchase_order_id;
  if v_po_id is null then
    return new;
  end if;

  if to_regclass('public.import_shipment_purchase_orders') is not null then
    select exists(
      select 1
      from public.import_shipment_purchase_orders l
      where l.shipment_id = v_ship_id
    )
    into v_has_allowlist;

    if v_has_allowlist then
      if not exists(
        select 1
        from public.import_shipment_purchase_orders l
        where l.shipment_id = v_ship_id
          and l.purchase_order_id = v_po_id
      ) then
        raise exception 'Purchase order % is not allowed for shipment %', v_po_id, v_ship_id;
      end if;
    end if;
  end if;

  if exists(
    select 1
    from public.purchase_receipts pr
    where pr.import_shipment_id = v_ship_id
      and pr.purchase_order_id = v_po_id
      and pr.id <> new.id
  ) then
    raise exception 'Purchase order % is already linked to shipment %', v_po_id, v_ship_id;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."trg_guard_purchase_receipt_import_shipment_po"() OWNER TO "postgres";

