--
-- Name: trg_lock_approval_requests(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_lock_approval_requests"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if tg_op = 'DELETE' then
    raise exception 'approval request is immutable';
  end if;

  if new.id <> old.id
     or new.target_table <> old.target_table
     or new.target_id <> old.target_id
     or new.request_type <> old.request_type
     or new.requested_by <> old.requested_by
     or new.payload_hash <> old.payload_hash
     or new.created_at <> old.created_at then
    raise exception 'approval request is immutable';
  end if;

  if old.status <> 'pending' then
    raise exception 'approval request already finalized';
  end if;

  if new.status = 'pending' then
    if new.approved_by is not null or new.approved_at is not null or new.rejected_by is not null or new.rejected_at is not null then
      raise exception 'approval request is immutable';
    end if;
  end if;

  if new.status = 'approved' then
    if new.approved_by is null or new.approved_at is null then
      raise exception 'approval request missing approved_by/approved_at';
    end if;
    if new.rejected_by is not null or new.rejected_at is not null then
      raise exception 'approval request is immutable';
    end if;
  end if;

  if new.status = 'rejected' then
    if new.rejected_by is null or new.rejected_at is null then
      raise exception 'approval request missing rejected_by/rejected_at';
    end if;
    if new.approved_by is not null or new.approved_at is not null then
      raise exception 'approval request is immutable';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."trg_lock_approval_requests"() OWNER TO "postgres";

--
-- Name: trg_lock_approval_steps(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_lock_approval_steps"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if tg_op = 'DELETE' then
    raise exception 'approval step is immutable';
  end if;

  if new.id <> old.id
     or new.request_id <> old.request_id
     or new.step_no <> old.step_no
     or new.approver_role <> old.approver_role then
    raise exception 'approval step is immutable';
  end if;

  if old.status <> 'pending' then
    raise exception 'approval step already finalized';
  end if;

  if new.status = 'pending' then
    if new.action_by is not null or new.action_at is not null then
      raise exception 'approval step is immutable';
    end if;
  end if;

  if new.status in ('approved', 'rejected') then
    if new.action_by is null or new.action_at is null then
      raise exception 'approval step missing action_by/action_at';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."trg_lock_approval_steps"() OWNER TO "postgres";

--
-- Name: trg_lock_base_currency_sar_app_settings(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_lock_base_currency_sar_app_settings"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_base text;
begin
  if new.id in ('app','singleton') then
    v_base := upper(nullif(btrim(coalesce(new.data->'settings'->>'baseCurrency','')), ''));
    if v_base is distinct from 'SAR' then
      raise exception 'base currency is locked to SAR';
    end if;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."trg_lock_base_currency_sar_app_settings"() OWNER TO "postgres";

--
-- Name: trg_lock_base_currency_sar_currencies(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_lock_base_currency_sar_currencies"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if new.code is null then
    raise exception 'currency code required';
  end if;

  if upper(new.code) = 'SAR' then
    new.is_base := true;
    new.is_high_inflation := false;
  else
    if coalesce(new.is_base, false) = true then
      raise exception 'base currency is locked to SAR';
    end if;
    if upper(new.code) = 'YER' then
      new.is_high_inflation := true;
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."trg_lock_base_currency_sar_currencies"() OWNER TO "postgres";

