CREATE OR REPLACE FUNCTION "public"."trg_orders_lock_warehouse_after_items"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_items jsonb;
begin
  v_items := coalesce(new.items, new.data->'items', '[]'::jsonb);
  if new.warehouse_id is distinct from old.warehouse_id then
    if jsonb_typeof(v_items) = 'array' and jsonb_array_length(v_items) > 0 then
      raise exception 'Cannot change warehouse after adding items';
    end if;
  end if;
  return new;
end;
$$;


