--
-- Name: trg_validate_app_settings_accounting_accounts(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_validate_app_settings_accounting_accounts"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  declare
    v_accounts jsonb;
    v_key text;
    v_val text;
    v_id uuid;
    v_active boolean;
  begin
    if public._is_migration_actor() then
      return new;
    end if;

    if new.id is distinct from 'singleton' and new.id is distinct from 'app' then
      return new;
    end if;

    v_accounts := coalesce(
      new.data->'settings'->'accounting_accounts',
      new.data->'accounting_accounts'
    );

    if v_accounts is null then
      return new;
    end if;

    foreach v_key in array array[
      'sales',
      'sales_returns',
      'inventory',
      'cogs',
      'ar',
      'ap',
      'vat_payable',
      'vat_recoverable',
      'cash',
      'bank',
      'deposits',
      'expenses',
      'shrinkage',
      'gain',
      'delivery_income',
      'sales_discounts',
      'over_short'
    ]
    loop
      v_val := nullif(btrim(coalesce(v_accounts->>v_key, '')), '');
      if v_val is null then
        raise exception 'missing accounting_accounts.%', v_key;
      end if;

      v_id := public.resolve_account_ref(v_val);
      if v_id is null then
        raise exception 'invalid accounting_accounts.%', v_key;
      end if;

      select coalesce(coa.is_active, false)
      into v_active
      from public.chart_of_accounts coa
      where coa.id = v_id
      limit 1;

      if coalesce(v_active, false) = false then
        raise exception 'inactive accounting_accounts.%', v_key;
      end if;
    end loop;

    return new;
  end;
  $$;


ALTER FUNCTION "public"."trg_validate_app_settings_accounting_accounts"() OWNER TO "postgres";

