--
-- Name: trial_balance("date", "date", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trial_balance"("p_start" "date", "p_end" "date", "p_cost_center_id" "uuid" DEFAULT NULL::"uuid", "p_journal_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("account_code" "text", "account_name" "text", "account_type" "text", "normal_balance" "text", "debit" numeric, "credit" numeric, "balance" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_lock_date date;
begin
  if not public.can_view_accounting_reports() then
    raise exception 'not allowed';
  end if;

  select s.locked_at::date
  into v_lock_date
  from public.base_currency_restatement_state s
  where s.id = 'sar_base_lock'
  limit 1;

  return query
  with eligible_entries as (
    select je.*
    from public.journal_entries je
    where (p_start is null or je.entry_date::date >= p_start)
      and (p_end is null or je.entry_date::date <= p_end)
      and (p_journal_id is null or je.journal_id = p_journal_id)
      and (
        v_lock_date is null
        or je.entry_date::date >= v_lock_date
        or coalesce(je.source_table,'') = 'base_currency_restatement'
      )
  ),
  filtered_lines as (
    select
      jl.account_id,
      coalesce(jl.debit,0) as debit,
      coalesce(jl.credit,0) as credit
    from eligible_entries e
    join public.journal_lines jl
      on jl.journal_entry_id = e.id
    where (p_cost_center_id is null or jl.cost_center_id = p_cost_center_id)
  )
  select
    coa.code as account_code,
    coa.name as account_name,
    coa.account_type,
    coa.normal_balance,
    coalesce(sum(fl.debit), 0) as debit,
    coalesce(sum(fl.credit), 0) as credit,
    coalesce(sum(fl.debit - fl.credit), 0) as balance
  from public.chart_of_accounts coa
  left join filtered_lines fl
    on fl.account_id = coa.id
  group by coa.code, coa.name, coa.account_type, coa.normal_balance
  order by coa.code;
end;
$$;


ALTER FUNCTION "public"."trial_balance"("p_start" "date", "p_end" "date", "p_cost_center_id" "uuid", "p_journal_id" "uuid") OWNER TO "postgres";

--
-- Name: trial_balance_by_range("date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trial_balance_by_range"("p_start" "date", "p_end" "date") RETURNS TABLE("account_code" "text", "account_name" "text", "account_type" "text", "normal_balance" "text", "opening_balance" numeric, "total_debits" numeric, "total_credits" numeric, "closing_balance" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with base as (
    select public.get_base_currency() as base
  ),
  opening_lines as (
    select
      jl.account_id,
      case
        when jl.currency_code is not null
          and upper(jl.currency_code) <> upper(b.base)
          and jl.fx_rate is not null
          and jl.foreign_amount is not null
          and jl.debit > 0
          then public._money_round(jl.foreign_amount * jl.fx_rate)
        else jl.debit
      end as debit,
      case
        when jl.currency_code is not null
          and upper(jl.currency_code) <> upper(b.base)
          and jl.fx_rate is not null
          and jl.foreign_amount is not null
          and jl.credit > 0
          then public._money_round(jl.foreign_amount * jl.fx_rate)
        else jl.credit
      end as credit,
      coa.normal_balance
    from public.journal_entries je
    join public.journal_lines jl
      on jl.journal_entry_id = je.id
    join public.chart_of_accounts coa
      on coa.id = jl.account_id
    cross join base b
    where p_start is not null
      and je.entry_date::date < p_start
  ),
  period_lines as (
    select
      jl.account_id,
      case
        when jl.currency_code is not null
          and upper(jl.currency_code) <> upper(b.base)
          and jl.fx_rate is not null
          and jl.foreign_amount is not null
          and jl.debit > 0
          then public._money_round(jl.foreign_amount * jl.fx_rate)
        else jl.debit
      end as debit,
      case
        when jl.currency_code is not null
          and upper(jl.currency_code) <> upper(b.base)
          and jl.fx_rate is not null
          and jl.foreign_amount is not null
          and jl.credit > 0
          then public._money_round(jl.foreign_amount * jl.fx_rate)
        else jl.credit
      end as credit,
      coa.normal_balance
    from public.journal_entries je
    join public.journal_lines jl
      on jl.journal_entry_id = je.id
    join public.chart_of_accounts coa
      on coa.id = jl.account_id
    cross join base b
    where (p_start is null or je.entry_date::date >= p_start)
      and (p_end is null or je.entry_date::date <= p_end)
  ),
  opening as (
    select
      coa.id as account_id,
      coalesce(sum(
        case
          when ol.normal_balance = 'debit' then (ol.debit - ol.credit)
          else (ol.credit - ol.debit)
        end
      ), 0) as opening_balance
    from public.chart_of_accounts coa
    left join opening_lines ol
      on ol.account_id = coa.id
    where coa.is_active = true
    group by coa.id
  ),
  period as (
    select
      coa.id as account_id,
      coalesce(sum(pl.debit), 0) as total_debits,
      coalesce(sum(pl.credit), 0) as total_credits,
      coalesce(sum(
        case
          when pl.normal_balance = 'debit' then (pl.debit - pl.credit)
          else (pl.credit - pl.debit)
        end
      ), 0) as period_delta
    from public.chart_of_accounts coa
    left join period_lines pl
      on pl.account_id = coa.id
    where coa.is_active = true
    group by coa.id
  )
  select
    coa.code as account_code,
    coa.name as account_name,
    coa.account_type,
    coa.normal_balance,
    o.opening_balance,
    p.total_debits,
    p.total_credits,
    (o.opening_balance + p.period_delta) as closing_balance
  from public.chart_of_accounts coa
  join opening o on o.account_id = coa.id
  join period p on p.account_id = coa.id
  where public.can_view_accounting_reports()
  order by coa.code;
$$;


ALTER FUNCTION "public"."trial_balance_by_range"("p_start" "date", "p_end" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "trial_balance_by_range"("p_start" "date", "p_end" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."trial_balance_by_range"("p_start" "date", "p_end" "date") IS 'Purpose: period trial balance with opening/period/closing and control totals computed externally. Source of truth: journal_entries/journal_lines signed by normal_balance.';


--
-- Name: trigger_encrypt_customer_data(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trigger_encrypt_customer_data"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'extensions', 'public'
    AS $$
BEGIN
  -- Encrypt Phone if changed
  IF NEW.phone_number IS NOT NULL AND (OLD.phone_number IS NULL OR NEW.phone_number <> OLD.phone_number) THEN
    NEW.phone_encrypted := public.encrypt_text(NEW.phone_number);
  END IF;

  -- Encrypt Address if changed (assuming address is in data->>'address')
  IF (NEW.data->>'address') IS NOT NULL AND (OLD.data IS NULL OR (NEW.data->>'address') <> (OLD.data->>'address')) THEN
    NEW.address_encrypted := public.encrypt_text(NEW.data->>'address');
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trigger_encrypt_customer_data"() OWNER TO "postgres";

--
-- Name: update_chart_account("uuid", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_chart_account"("p_account_id" "uuid", "p_code" "text" DEFAULT NULL::"text", "p_name" "text" DEFAULT NULL::"text", "p_account_type" "text" DEFAULT NULL::"text", "p_normal_balance" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_existing record;
  v_used boolean;
  v_next_code text;
  v_next_name text;
  v_next_type text;
  v_next_balance text;
begin
  if not public.is_owner() then
    raise exception 'not allowed';
  end if;
  if p_account_id is null then
    raise exception 'account_id is required';
  end if;

  select *
  into v_existing
  from public.chart_of_accounts coa
  where coa.id = p_account_id
  for update;
  if not found then
    raise exception 'account not found';
  end if;

  select exists(select 1 from public.journal_lines jl where jl.account_id = p_account_id)
  into v_used;

  v_next_code := btrim(coalesce(p_code, v_existing.code));
  v_next_name := btrim(coalesce(p_name, v_existing.name));
  v_next_type := coalesce(p_account_type, v_existing.account_type);
  v_next_balance := coalesce(p_normal_balance, v_existing.normal_balance);

  if v_next_code = '' then
    raise exception 'code is required';
  end if;
  if v_next_code !~ '^[0-9]{3,10}$' then
    raise exception 'invalid code';
  end if;
  if v_next_name = '' then
    raise exception 'name is required';
  end if;
  if coalesce(v_next_type,'') not in ('asset','liability','equity','income','expense') then
    raise exception 'invalid account_type';
  end if;
  if coalesce(v_next_balance,'') not in ('debit','credit') then
    raise exception 'invalid normal_balance';
  end if;

  if v_used then
    if v_next_code is distinct from v_existing.code
      or v_next_type is distinct from v_existing.account_type
      or v_next_balance is distinct from v_existing.normal_balance
    then
      raise exception 'account is used and cannot change code/type/balance';
    end if;
  end if;

  update public.chart_of_accounts
  set code = v_next_code,
      name = v_next_name,
      account_type = v_next_type,
      normal_balance = v_next_balance
  where id = p_account_id;
end;
$_$;


ALTER FUNCTION "public"."update_chart_account"("p_account_id" "uuid", "p_code" "text", "p_name" "text", "p_account_type" "text", "p_normal_balance" "text") OWNER TO "postgres";

