--
-- Name: upsert_item_packaging_uom("text", numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_item_packaging_uom"("p_item_id" "text", "p_pack_size" numeric DEFAULT NULL::numeric, "p_carton_size" numeric DEFAULT NULL::numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item text;
  v_base uuid;
  v_pack uuid;
  v_carton uuid;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('items.manage') or public.has_admin_permission('inventory.manage')) then
    raise exception 'not allowed';
  end if;
  v_item := nullif(btrim(coalesce(p_item_id, '')), '');
  if v_item is null then
    raise exception 'item_id required';
  end if;

  select base_uom_id into v_base
  from public.item_uom
  where item_id = v_item
  limit 1;

  if v_base is null then
    perform public.ensure_uom_code('piece', 'Piece');
    insert into public.item_uom(item_id, base_uom_id, purchase_uom_id, sales_uom_id)
    select mi.id, public.ensure_uom_code(lower(btrim(coalesce(mi.base_unit, mi.unit_type, 'piece'))), null), null, null
    from public.menu_items mi
    where mi.id = v_item
    on conflict (item_id) do nothing;

    select base_uom_id into v_base
    from public.item_uom
    where item_id = v_item
    limit 1;
  end if;

  if v_base is null then
    raise exception 'base uom missing for item';
  end if;

  insert into public.item_uom_units(item_id, uom_id, qty_in_base, is_active)
  values (v_item, v_base, 1, true)
  on conflict (item_id, uom_id)
  do update set qty_in_base = 1, is_active = true, updated_at = now();

  v_pack := public.ensure_uom_code('pack', 'Pack');
  v_carton := public.ensure_uom_code('carton', 'Carton');

  if coalesce(p_pack_size, 0) > 0 then
    insert into public.item_uom_units(item_id, uom_id, qty_in_base, is_active)
    values (v_item, v_pack, p_pack_size, true)
    on conflict (item_id, uom_id)
    do update set qty_in_base = excluded.qty_in_base, is_active = true, updated_at = now();
  else
    update public.item_uom_units
    set is_active = false, updated_at = now()
    where item_id = v_item and uom_id = v_pack;
  end if;

  if coalesce(p_carton_size, 0) > 0 then
    insert into public.item_uom_units(item_id, uom_id, qty_in_base, is_active)
    values (v_item, v_carton, p_carton_size, true)
    on conflict (item_id, uom_id)
    do update set qty_in_base = excluded.qty_in_base, is_active = true, updated_at = now();
  else
    update public.item_uom_units
    set is_active = false, updated_at = now()
    where item_id = v_item and uom_id = v_carton;
  end if;

  return jsonb_build_object(
    'itemId', v_item,
    'baseUomId', v_base::text,
    'packUomId', v_pack::text,
    'cartonUomId', v_carton::text,
    'packSize', nullif(coalesce(p_pack_size, 0), 0),
    'cartonSize', nullif(coalesce(p_carton_size, 0), 0)
  );
end;
$$;


ALTER FUNCTION "public"."upsert_item_packaging_uom"("p_item_id" "text", "p_pack_size" numeric, "p_carton_size" numeric) OWNER TO "postgres";

--
-- Name: upsert_item_uom_unit("text", "text", numeric, boolean, boolean, "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_item_uom_unit"("p_item_id" "text", "p_uom_code" "text", "p_qty_in_base" numeric, "p_is_default_purchase" boolean DEFAULT false, "p_is_default_sales" boolean DEFAULT false, "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item text;
  v_base uuid;
  v_uom uuid;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('items.manage') or public.has_admin_permission('inventory.manage')) then
    raise exception 'not allowed';
  end if;

  v_item := nullif(btrim(coalesce(p_item_id, '')), '');
  if v_item is null then
    raise exception 'item_id required';
  end if;
  if coalesce(p_qty_in_base, 0) <= 0 then
    raise exception 'qty_in_base must be > 0';
  end if;

  select base_uom_id into v_base
  from public.item_uom
  where item_id = v_item
  limit 1;

  if v_base is null then
    insert into public.item_uom(item_id, base_uom_id, purchase_uom_id, sales_uom_id)
    select mi.id, public.ensure_uom_code(lower(btrim(coalesce(mi.base_unit, mi.unit_type, 'piece'))), null), null, null
    from public.menu_items mi
    where mi.id = v_item
    on conflict (item_id) do nothing;

    select base_uom_id into v_base
    from public.item_uom
    where item_id = v_item
    limit 1;
  end if;

  if v_base is null then
    raise exception 'base uom missing for item';
  end if;

  insert into public.item_uom_units(item_id, uom_id, qty_in_base, is_active)
  values (v_item, v_base, 1, true)
  on conflict (item_id, uom_id)
  do update set qty_in_base = 1, is_active = true, updated_at = now();

  v_uom := public.ensure_uom_code(p_uom_code, null);

  insert into public.item_uom_units(
    item_id, uom_id, qty_in_base, is_active, is_default_purchase, is_default_sales, start_date, end_date
  )
  values (
    v_item, v_uom, p_qty_in_base, true, coalesce(p_is_default_purchase, false), coalesce(p_is_default_sales, false), p_start_date, p_end_date
  )
  on conflict (item_id, uom_id)
  do update set
    qty_in_base = excluded.qty_in_base,
    is_active = true,
    is_default_purchase = excluded.is_default_purchase,
    is_default_sales = excluded.is_default_sales,
    start_date = excluded.start_date,
    end_date = excluded.end_date,
    updated_at = now();

  if coalesce(p_is_default_purchase, false) then
    update public.item_uom
    set purchase_uom_id = v_uom
    where item_id = v_item;
  end if;

  if coalesce(p_is_default_sales, false) then
    update public.item_uom
    set sales_uom_id = v_uom
    where item_id = v_item;
  end if;

  return jsonb_build_object(
    'itemId', v_item,
    'baseUomId', v_base::text,
    'uomId', v_uom::text,
    'uomCode', (select code from public.uom where id=v_uom),
    'qtyInBase', p_qty_in_base,
    'isDefaultPurchase', coalesce(p_is_default_purchase, false),
    'isDefaultSales', coalesce(p_is_default_sales, false),
    'startDate', p_start_date,
    'endDate', p_end_date
  );
end;
$$;


ALTER FUNCTION "public"."upsert_item_uom_unit"("p_item_id" "text", "p_uom_code" "text", "p_qty_in_base" numeric, "p_is_default_purchase" boolean, "p_is_default_sales" boolean, "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";

--
-- Name: upsert_item_uom_unit_relative("text", "text", "text", numeric, boolean, boolean, "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_item_uom_unit_relative"("p_item_id" "text", "p_new_uom_code" "text", "p_from_uom_code" "text", "p_factor" numeric, "p_is_default_purchase" boolean DEFAULT false, "p_is_default_sales" boolean DEFAULT false, "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_from uuid;
  v_base uuid;
  v_qty_base numeric;
begin
  if coalesce(p_factor, 0) <= 0 then
    raise exception 'factor must be > 0';
  end if;
  v_from := public.ensure_uom_code(p_from_uom_code, null);
  select base_uom_id into v_base from public.item_uom where item_id = p_item_id limit 1;
  if v_base is null then
    raise exception 'base uom missing for item';
  end if;
  select qty_in_base into v_qty_base
  from public.item_uom_units
  where item_id = p_item_id and uom_id = v_from and is_active = true
  limit 1;
  if v_qty_base is null then
    raise exception 'missing from uom on item';
  end if;
  return public.upsert_item_uom_unit(
    p_item_id, p_new_uom_code, (v_qty_base * p_factor),
    p_is_default_purchase, p_is_default_sales,
    p_start_date, p_end_date
  );
end;
$$;


ALTER FUNCTION "public"."upsert_item_uom_unit_relative"("p_item_id" "text", "p_new_uom_code" "text", "p_from_uom_code" "text", "p_factor" numeric, "p_is_default_purchase" boolean, "p_is_default_sales" boolean, "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";

--
-- Name: upsert_item_uom_units("text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_item_uom_units"("p_item_id" "text", "p_units" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_item text;
  v_base uuid;
  v_base_code text;
  v_keep uuid[];
  v_elem jsonb;
  v_code text;
  v_name text;
  v_qty numeric;
  v_uom uuid;
begin
  if not (auth.role() = 'service_role' or public.has_admin_permission('items.manage') or public.has_admin_permission('inventory.manage')) then
    raise exception 'not allowed';
  end if;

  v_item := nullif(btrim(coalesce(p_item_id, '')), '');
  if v_item is null then
    raise exception 'item_id required';
  end if;

  select base_uom_id
  into v_base
  from public.item_uom
  where item_id = v_item
  limit 1;

  if v_base is null then
    insert into public.item_uom(item_id, base_uom_id, purchase_uom_id, sales_uom_id)
    select
      mi.id,
      public.ensure_uom_code(lower(btrim(coalesce(mi.base_unit, mi.unit_type, 'piece'))), null),
      null,
      null
    from public.menu_items mi
    where mi.id = v_item
    on conflict (item_id) do nothing;

    select base_uom_id
    into v_base
    from public.item_uom
    where item_id = v_item
    limit 1;
  end if;

  if v_base is null then
    raise exception 'base uom missing for item';
  end if;

  select code
  into v_base_code
  from public.uom
  where id = v_base
  limit 1;
  v_base_code := lower(btrim(coalesce(v_base_code, '')));

  v_keep := array[v_base];

  insert into public.item_uom_units(item_id, uom_id, qty_in_base, is_active)
  values (v_item, v_base, 1, true)
  on conflict (item_id, uom_id)
  do update set qty_in_base = excluded.qty_in_base, is_active = true, updated_at = now();

  if p_units is not null and jsonb_typeof(p_units) = 'array' then
    for v_elem in
      select * from jsonb_array_elements(p_units)
    loop
      v_code := lower(btrim(coalesce(v_elem->>'code', '')));
      v_name := btrim(coalesce(v_elem->>'name', ''));
      begin
        v_qty := nullif(btrim(coalesce(v_elem->>'qtyInBase', '')), '')::numeric;
      exception when others then
        v_qty := null;
      end;

      if v_code = '' or v_qty is null or v_qty <= 0 then
        continue;
      end if;

      if v_base_code <> '' and v_code = v_base_code then
        continue;
      end if;

      v_uom := public.ensure_uom_code(v_code, nullif(v_name, ''));
      if v_uom = v_base then
        continue;
      end if;

      if not (v_uom = any(v_keep)) then
        v_keep := array_append(v_keep, v_uom);
      end if;

      insert into public.item_uom_units(item_id, uom_id, qty_in_base, is_active)
      values (v_item, v_uom, v_qty, true)
      on conflict (item_id, uom_id)
      do update set qty_in_base = excluded.qty_in_base, is_active = true, updated_at = now();
    end loop;
  end if;

  update public.item_uom_units
  set is_active = false, updated_at = now()
  where item_id = v_item
    and not (uom_id = any(v_keep));

  return jsonb_build_object(
    'itemId', v_item,
    'baseUomId', v_base::text,
    'activeUomIds', to_jsonb(v_keep)
  );
end;
$$;


ALTER FUNCTION "public"."upsert_item_uom_units"("p_item_id" "text", "p_units" "jsonb") OWNER TO "postgres";

--
-- Name: upsert_party_open_item_from_party_ledger_entry("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_party_open_item_from_party_ledger_entry"("p_party_ledger_entry_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_ple record;
  v_je record;
  v_role text;
  v_type text;
  v_party_doc_id uuid;
begin
  if p_party_ledger_entry_id is null then
    return;
  end if;

  select *
  into v_ple
  from public.party_ledger_entries ple
  where ple.id = p_party_ledger_entry_id;

  if not found then
    return;
  end if;

  select je.source_table, je.source_id, je.source_event, je.entry_date
  into v_je
  from public.journal_entries je
  where je.id = v_ple.journal_entry_id;

  if coalesce(v_je.source_table,'') = 'settlements' then
    return;
  end if;

  if coalesce(v_je.source_event,'') = 'realized_fx' then
    return;
  end if;

  select psa.role
  into v_role
  from public.party_subledger_accounts psa
  where psa.account_id = v_ple.account_id
    and psa.is_active = true
  limit 1;

  if v_role is null then
    return;
  end if;

  v_type := public._party_open_item_type(v_je.source_table, v_je.source_event);

  v_party_doc_id := null;
  if coalesce(v_je.source_table,'') = 'party_documents' then
    begin
      v_party_doc_id := nullif(v_je.source_id,'')::uuid;
    exception when others then
      v_party_doc_id := null;
    end;
  end if;

  insert into public.party_open_items(
    party_id,
    journal_entry_id,
    journal_line_id,
    account_id,
    direction,
    occurred_at,
    due_date,
    item_role,
    item_type,
    source_table,
    source_id,
    source_event,
    party_document_id,
    currency_code,
    foreign_amount,
    base_amount,
    open_foreign_amount,
    open_base_amount,
    status
  )
  values (
    v_ple.party_id,
    v_ple.journal_entry_id,
    v_ple.journal_line_id,
    v_ple.account_id,
    v_ple.direction,
    v_ple.occurred_at,
    v_ple.occurred_at::date,
    v_role,
    v_type,
    v_je.source_table,
    v_je.source_id,
    v_je.source_event,
    v_party_doc_id,
    upper(coalesce(v_ple.currency_code, public.get_base_currency())),
    v_ple.foreign_amount,
    v_ple.base_amount,
    v_ple.foreign_amount,
    v_ple.base_amount,
    'open'
  )
  on conflict (journal_line_id) do nothing;
end;
$$;


ALTER FUNCTION "public"."upsert_party_open_item_from_party_ledger_entry"("p_party_ledger_entry_id" "uuid") OWNER TO "postgres";

--
-- Name: upsert_promotion("jsonb", "jsonb", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_promotion"("p_promotion" "jsonb", "p_items" "jsonb", "p_activate" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid;
  v_promo_id uuid;
  v_name text;
  v_start_at timestamptz;
  v_end_at timestamptz;
  v_is_active boolean;
  v_discount_mode text;
  v_fixed_total numeric;
  v_percent_off numeric;
  v_display_original_total numeric;
  v_max_uses int;
  v_exclusive_with_coupon boolean;
  v_item jsonb;
  v_item_id text;
  v_qty numeric;
  v_sort int;
  v_snapshot jsonb;
  v_promo_expense numeric;
  v_requires_approval boolean;
  v_req_id uuid;
begin
  v_actor := auth.uid();
  if v_actor is null then
    raise exception 'not authenticated';
  end if;
  if not public.is_admin() then
    raise exception 'not allowed';
  end if;

  if p_promotion is null then
    raise exception 'p_promotion is required';
  end if;
  if p_items is null or jsonb_typeof(p_items) <> 'array' then
    raise exception 'p_items must be a json array';
  end if;

  v_promo_id := public._uuid_or_null(p_promotion->>'id');
  v_name := nullif(btrim(coalesce(p_promotion->>'name','')), '');
  v_start_at := nullif(p_promotion->>'startAt','')::timestamptz;
  v_end_at := nullif(p_promotion->>'endAt','')::timestamptz;
  v_discount_mode := nullif(btrim(coalesce(p_promotion->>'discountMode','')), '');
  v_fixed_total := nullif((p_promotion->>'fixedTotal')::numeric, null);
  v_percent_off := nullif((p_promotion->>'percentOff')::numeric, null);
  v_display_original_total := nullif((p_promotion->>'displayOriginalTotal')::numeric, null);
  v_max_uses := nullif((p_promotion->>'maxUses')::int, null);
  v_exclusive_with_coupon := coalesce((p_promotion->>'exclusiveWithCoupon')::boolean, true);

  if v_name is null then
    raise exception 'name is required';
  end if;
  if v_start_at is null or v_end_at is null then
    raise exception 'startAt/endAt are required';
  end if;
  if v_start_at >= v_end_at then
    raise exception 'startAt must be before endAt';
  end if;
  if v_discount_mode not in ('fixed_total','percent_off') then
    raise exception 'invalid discountMode';
  end if;
  if v_discount_mode = 'fixed_total' then
    if v_fixed_total is null or v_fixed_total <= 0 then
      raise exception 'fixedTotal must be positive';
    end if;
    v_percent_off := null;
  else
    if v_percent_off is null or v_percent_off <= 0 or v_percent_off > 100 then
      raise exception 'percentOff must be between 0 and 100';
    end if;
    v_fixed_total := null;
  end if;

  if v_promo_id is null then
    insert into public.promotions(
      name, start_at, end_at, is_active,
      discount_mode, fixed_total, percent_off,
      display_original_total, max_uses, exclusive_with_coupon,
      created_by, data
    )
    values (
      v_name, v_start_at, v_end_at, false,
      v_discount_mode, v_fixed_total, v_percent_off,
      v_display_original_total, v_max_uses, v_exclusive_with_coupon,
      v_actor, coalesce(p_promotion->'data', '{}'::jsonb)
    )
    returning id into v_promo_id;
  else
    update public.promotions
    set
      name = v_name,
      start_at = v_start_at,
      end_at = v_end_at,
      discount_mode = v_discount_mode,
      fixed_total = v_fixed_total,
      percent_off = v_percent_off,
      display_original_total = v_display_original_total,
      max_uses = v_max_uses,
      exclusive_with_coupon = v_exclusive_with_coupon,
      data = coalesce(p_promotion->'data', data),
      updated_at = now()
    where id = v_promo_id;

    if not found then
      raise exception 'promotion_not_found';
    end if;
  end if;

  delete from public.promotion_items where promotion_id = v_promo_id;

  for v_item in select value from jsonb_array_elements(p_items)
  loop
    v_item_id := nullif(btrim(coalesce(v_item->>'itemId','')), '');
    v_qty := coalesce(nullif((v_item->>'quantity')::numeric, null), 0);
    v_sort := coalesce(nullif((v_item->>'sortOrder')::int, null), 0);
    if v_item_id is null then
      raise exception 'itemId is required';
    end if;
    if v_qty <= 0 then
      raise exception 'quantity must be positive';
    end if;

    insert into public.promotion_items(promotion_id, item_id, quantity, sort_order)
    values (v_promo_id, v_item_id, v_qty, v_sort);
  end loop;

  if coalesce(p_activate, false) then
    v_snapshot := public._compute_promotion_snapshot(v_promo_id, null, null, 1, null, false);
    v_promo_expense := coalesce(nullif((v_snapshot->>'promotionExpense')::numeric, null), 0);
    v_requires_approval := public.approval_required('discount', v_promo_expense);

    if v_requires_approval then
      v_req_id := public.create_approval_request(
        'promotions',
        v_promo_id::text,
        'discount',
        v_promo_expense,
        jsonb_build_object(
          'promotionId', v_promo_id::text,
          'name', v_name,
          'promotionExpense', v_promo_expense,
          'snapshot', v_snapshot
        )
      );

      update public.promotions
      set
        requires_approval = true,
        approval_status = 'pending',
        approval_request_id = v_req_id,
        is_active = false,
        updated_at = now()
      where id = v_promo_id;
    else
      update public.promotions
      set
        requires_approval = false,
        approval_status = 'approved',
        approval_request_id = null,
        is_active = true,
        updated_at = now()
      where id = v_promo_id;
    end if;
  end if;

  return jsonb_build_object(
    'promotionId', v_promo_id::text,
    'approvalRequestId', case when v_req_id is null then null else v_req_id::text end,
    'approvalStatus', (select p.approval_status from public.promotions p where p.id = v_promo_id),
    'isActive', (select p.is_active from public.promotions p where p.id = v_promo_id)
  );
end;
$$;


ALTER FUNCTION "public"."upsert_promotion"("p_promotion" "jsonb", "p_items" "jsonb", "p_activate" boolean) OWNER TO "postgres";

--
-- Name: uuid_from_text("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."uuid_from_text"("p_text" "text") RETURNS "uuid"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select (
    substr(md5(coalesce(p_text,'')), 1, 8) || '-' ||
    substr(md5(coalesce(p_text,'')), 9, 4) || '-' ||
    substr(md5(coalesce(p_text,'')), 13, 4) || '-' ||
    substr(md5(coalesce(p_text,'')), 17, 4) || '-' ||
    substr(md5(coalesce(p_text,'')), 21, 12)
  )::uuid;
$$;


ALTER FUNCTION "public"."uuid_from_text"("p_text" "text") OWNER TO "postgres";

--
-- Name: verify_ledger_hash_chain("date", "date", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."verify_ledger_hash_chain"("p_start" "date" DEFAULT NULL::"date", "p_end" "date" DEFAULT NULL::"date", "p_max" integer DEFAULT 50000) RETURNS TABLE("ok" boolean, "issue" "text", "journal_entry_id" "uuid", "expected_chain_hash" "text", "actual_chain_hash" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_prev text := null;
  v_row record;
  v_expected text;
  v_content text;
  v_seen int := 0;
begin
  if not public.has_admin_permission('accounting.view') then
    raise exception 'not allowed';
  end if;

  for v_row in
    select
      je.id as journal_entry_id,
      je.entry_date,
      je.created_at,
      lec.prev_chain_hash,
      lec.content_hash,
      lec.chain_hash
    from public.journal_entries je
    join public.ledger_entry_hash_chain lec on lec.journal_entry_id = je.id
    where (p_start is null or je.entry_date::date >= p_start)
      and (p_end is null or je.entry_date::date <= p_end)
    order by je.entry_date asc, je.created_at asc, je.id asc
    limit greatest(coalesce(p_max, 50000), 1)
  loop
    v_seen := v_seen + 1;
    v_content := public.compute_journal_entry_content_hash(v_row.journal_entry_id);
    if v_content <> v_row.content_hash then
      ok := false;
      issue := 'content_hash_mismatch';
      journal_entry_id := v_row.journal_entry_id;
      expected_chain_hash := null;
      actual_chain_hash := v_row.chain_hash;
      return next;
      continue;
    end if;

    if v_prev is distinct from v_row.prev_chain_hash then
      ok := false;
      issue := 'prev_chain_hash_mismatch';
      journal_entry_id := v_row.journal_entry_id;
      expected_chain_hash := v_prev;
      actual_chain_hash := v_row.prev_chain_hash;
      return next;
      v_prev := v_row.chain_hash;
      continue;
    end if;

    select encode(digest(convert_to(coalesce(v_prev,'') || '|' || v_content, 'utf8'), 'sha256'), 'hex') into v_expected;
    if v_expected <> v_row.chain_hash then
      ok := false;
      issue := 'chain_hash_mismatch';
      journal_entry_id := v_row.journal_entry_id;
      expected_chain_hash := v_expected;
      actual_chain_hash := v_row.chain_hash;
      return next;
      v_prev := v_row.chain_hash;
      continue;
    end if;

    v_prev := v_row.chain_hash;
  end loop;

  if v_seen = 0 then
    ok := true;
    issue := 'no_rows';
    journal_entry_id := null;
    expected_chain_hash := null;
    actual_chain_hash := null;
    return next;
    return;
  end if;

  ok := true;
  issue := 'ok';
  journal_entry_id := null;
  expected_chain_hash := null;
  actual_chain_hash := null;
  return next;
end;
$$;


ALTER FUNCTION "public"."verify_ledger_hash_chain"("p_start" "date", "p_end" "date", "p_max" integer) OWNER TO "postgres";

--
-- Name: void_delivered_order("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."void_delivered_order"("p_order_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order record;
  v_delivered_entry_id uuid;
  v_void_entry_id uuid;
  v_line record;
  v_void_lines_count int := 0;
  v_ar_id uuid;
  v_ar_amount numeric := 0;
  v_sale record;
  v_ret_batch_id uuid;
  v_source_batch record;
  v_movement_id uuid;
  v_wh uuid;
  v_data jsonb;
begin
  perform public._require_staff('void_delivered_order');
  if not (auth.role() = 'service_role' or public.has_admin_permission('accounting.void')) then
    raise exception 'not authorized';
  end if;
  if p_order_id is null then
    raise exception 'p_order_id is required';
  end if;

  select * into v_order from public.orders o where o.id = p_order_id for update;
  if not found then
    raise exception 'order not found';
  end if;
  if coalesce(v_order.status,'') <> 'delivered' then
    raise exception 'only delivered orders can be voided';
  end if;

  if coalesce(v_order.data->>'voidedAt','') <> '' then
    raise exception 'order already voided';
  end if;

  select je.id
  into v_delivered_entry_id
  from public.journal_entries je
  where je.source_table = 'orders'
    and je.source_id = p_order_id::text
    and je.source_event = 'delivered'
  limit 1;
  if not found then
    raise exception 'delivered journal entry not found';
  end if;

  select je.id
  into v_void_entry_id
  from public.journal_entries je
  where je.source_table = 'order_voids'
    and je.source_id = p_order_id::text
    and je.source_event = 'voided'
  limit 1;

  if v_void_entry_id is null then
    insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by, status)
    values (
      now(),
      concat('Void delivered order ', p_order_id::text),
      'order_voids',
      p_order_id::text,
      'voided',
      auth.uid(),
      'posted'
    )
    returning id into v_void_entry_id;
  end if;

  select count(1)
  into v_void_lines_count
  from public.journal_lines jl
  where jl.journal_entry_id = v_void_entry_id;

  if coalesce(v_void_lines_count, 0) = 0 then
    for v_line in
      select account_id, debit, credit, line_memo
      from public.journal_lines
      where journal_entry_id = v_delivered_entry_id
    loop
      insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo)
      values (
        v_void_entry_id,
        v_line.account_id,
        coalesce(v_line.credit,0),
        coalesce(v_line.debit,0),
        coalesce(v_line.line_memo,'')
      );
    end loop;
  end if;

  v_ar_id := public.get_account_id_by_code('1200');
  if v_ar_id is not null then
    select coalesce(sum(jl.debit), 0) - coalesce(sum(jl.credit), 0)
    into v_ar_amount
    from public.journal_lines jl
    where jl.journal_entry_id = v_delivered_entry_id
      and jl.account_id = v_ar_id;
    v_ar_amount := greatest(0, coalesce(v_ar_amount, 0));
  end if;

  if not exists (
    select 1
    from public.inventory_movements im
    where im.reference_table = 'orders'
      and im.reference_id = p_order_id::text
      and im.movement_type = 'return_in'
      and coalesce(im.data->>'event','') = 'voided'
  ) then
    for v_sale in
      select im.id, im.item_id, im.quantity, im.unit_cost, im.batch_id, im.warehouse_id, im.occurred_at
      from public.inventory_movements im
      where im.reference_table = 'orders'
        and im.reference_id = p_order_id::text
        and im.movement_type = 'sale_out'
      order by im.occurred_at asc, im.id asc
    loop
      select b.expiry_date, b.production_date, b.unit_cost
      into v_source_batch
      from public.batches b
      where b.id = v_sale.batch_id;

      v_wh := v_sale.warehouse_id;
      if v_wh is null then
        v_wh := coalesce(v_order.warehouse_id, public._resolve_default_admin_warehouse_id());
      end if;
      if v_wh is null then
        raise exception 'warehouse_id is required';
      end if;

      v_ret_batch_id := gen_random_uuid();
      insert into public.batches(
        id,
        item_id,
        receipt_item_id,
        receipt_id,
        warehouse_id,
        batch_code,
        production_date,
        expiry_date,
        quantity_received,
        quantity_consumed,
        unit_cost,
        qc_status,
        data
      )
      values (
        v_ret_batch_id,
        v_sale.item_id::text,
        null,
        null,
        v_wh,
        null,
        v_source_batch.production_date,
        v_source_batch.expiry_date,
        v_sale.quantity,
        0,
        coalesce(v_sale.unit_cost, v_source_batch.unit_cost, 0),
        'released',
        jsonb_build_object(
          'source', 'orders',
          'event', 'voided',
          'orderId', p_order_id::text,
          'sourceBatchId', v_sale.batch_id::text,
          'sourceMovementId', v_sale.id::text
        )
      );

      insert into public.inventory_movements(
        item_id, movement_type, quantity, unit_cost, total_cost,
        reference_table, reference_id, occurred_at, created_by, data, batch_id, warehouse_id
      )
      values (
        v_sale.item_id::text,
        'return_in',
        v_sale.quantity,
        coalesce(v_sale.unit_cost, v_source_batch.unit_cost, 0),
        v_sale.quantity * coalesce(v_sale.unit_cost, v_source_batch.unit_cost, 0),
        'orders',
        p_order_id::text,
        now(),
        auth.uid(),
        jsonb_build_object(
          'orderId', p_order_id::text,
          'warehouseId', v_wh::text,
          'event', 'voided',
          'sourceBatchId', v_sale.batch_id::text,
          'sourceMovementId', v_sale.id::text
        ),
        v_ret_batch_id,
        v_wh
      )
      returning id into v_movement_id;

      perform public.post_inventory_movement(v_movement_id);
      perform public.recompute_stock_for_item(v_sale.item_id::text, v_wh);
    end loop;
  end if;

  v_data := coalesce(v_order.data, '{}'::jsonb);
  v_data := jsonb_set(v_data, '{voidedAt}', to_jsonb(now()::text), true);
  if nullif(trim(coalesce(p_reason,'')),'') is not null then
    v_data := jsonb_set(v_data, '{voidReason}', to_jsonb(p_reason), true);
  end if;
  v_data := jsonb_set(v_data, '{voidedBy}', to_jsonb(auth.uid()::text), true);

  update public.orders
  set data = v_data,
      updated_at = now()
  where id = p_order_id;

  perform public._apply_ar_open_item_credit(p_order_id, v_ar_amount);
end;
$$;


ALTER FUNCTION "public"."void_delivered_order"("p_order_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: void_journal_entry("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."void_journal_entry"("p_entry_id" "uuid", "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_entry public.journal_entries%rowtype;
  v_new_entry_id uuid;
  v_line record;
  v_reason text;
begin
  if not public.has_admin_permission('accounting.void') then
    raise exception 'not allowed';
  end if;
  if p_entry_id is null then
    raise exception 'p_entry_id is required';
  end if;
  select * into v_entry from public.journal_entries where id = p_entry_id;
  if not found then
    raise exception 'journal entry not found';
  end if;
  if v_entry.source_table = 'manual' and v_entry.status = 'draft' then
    raise exception 'not allowed';
  end if;
  v_reason := nullif(trim(coalesce(p_reason,'')),'');
  if v_reason is null then
    raise exception 'reason required';
  end if;
  perform public.set_audit_reason(v_reason);

  perform set_config('app.accounting_bypass', '1', true);
  update public.journal_entries
  set status = 'voided',
      voided_by = auth.uid(),
      voided_at = now(),
      void_reason = v_reason
  where id = p_entry_id;

  insert into public.journal_entries(entry_date, memo, source_table, source_id, source_event, created_by)
  values (now(), concat('Void ', p_entry_id::text, ' ', coalesce(v_entry.memo,'')), 'journal_entries', p_entry_id::text, 'void', auth.uid())
  returning id into v_new_entry_id;

  for v_line in
    select account_id, debit, credit, line_memo, cost_center_id from public.journal_lines where journal_entry_id = p_entry_id
  loop
    insert into public.journal_lines(journal_entry_id, account_id, debit, credit, line_memo, cost_center_id)
    values (v_new_entry_id, v_line.account_id, v_line.credit, v_line.debit, coalesce(v_line.line_memo,'') || ' (reversal)', v_line.cost_center_id);
  end loop;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values ('journal_entries.void', 'accounting', p_entry_id::text, auth.uid(), now(),
          jsonb_build_object('voidOf', p_entry_id::text, 'newEntryId', v_new_entry_id::text),
          'HIGH', v_reason);
  return v_new_entry_id;
end;
$$;


ALTER FUNCTION "public"."void_journal_entry"("p_entry_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: void_party_document("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."void_party_document"("p_document_id" "uuid", "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc public.party_documents%rowtype;
  v_reason text;
  v_rev uuid;
begin
  if not public.has_admin_permission('accounting.void') then
    raise exception 'not allowed';
  end if;
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  v_reason := nullif(trim(coalesce(p_reason,'')),'');
  if v_reason is null then
    raise exception 'reason required';
  end if;

  select * into v_doc
  from public.party_documents
  where id = p_document_id
  for update;

  if not found then
    raise exception 'document not found';
  end if;

  if v_doc.status = 'voided' then
    return coalesce(v_doc.reversal_entry_id, v_doc.journal_entry_id, p_document_id);
  end if;

  if v_doc.status = 'posted' and v_doc.journal_entry_id is not null then
    v_rev := public.reverse_journal_entry(v_doc.journal_entry_id, v_reason);
  end if;

  update public.party_documents
  set status = 'voided',
      voided_by = auth.uid(),
      voided_at = now(),
      void_reason = v_reason,
      reversal_entry_id = coalesce(v_rev, reversal_entry_id)
  where id = p_document_id;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'party_documents.void',
    'documents',
    p_document_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('documentId', p_document_id::text, 'docNumber', v_doc.doc_number, 'docType', v_doc.doc_type, 'journalEntryId', coalesce(v_doc.journal_entry_id, '00000000-0000-0000-0000-000000000000'::uuid)::text, 'reversalEntryId', coalesce(v_rev, '00000000-0000-0000-0000-000000000000'::uuid)::text),
    'HIGH',
    v_reason
  );

  return coalesce(v_rev, v_doc.journal_entry_id, p_document_id);
end;
$$;


ALTER FUNCTION "public"."void_party_document"("p_document_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: void_settlement("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."void_settlement"("p_settlement_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_set public.settlement_headers%rowtype;
  v_rev_id uuid;
  v_line record;
  v_reason text;
  v_fx record;
  v_fx_rev uuid;
begin
  if not public.has_admin_permission('accounting.manage') then
    raise exception 'not allowed';
  end if;
  if not public.has_admin_permission('accounting.void') then
    raise exception 'not allowed';
  end if;

  if p_settlement_id is null then
    raise exception 'settlement_id required';
  end if;

  v_reason := nullif(trim(coalesce(p_reason,'')),'');
  if v_reason is null then
    v_reason := 'settlement reversal';
  end if;

  if public.is_in_closed_period(now()) then
    raise exception 'accounting period is closed';
  end if;

  select * into v_set
  from public.settlement_headers sh
  where sh.id = p_settlement_id
  for update;

  if not found then
    raise exception 'settlement not found';
  end if;

  if exists (
    select 1 from public.settlement_headers x where x.reverses_settlement_id = p_settlement_id
  ) then
    raise exception 'already reversed';
  end if;

  insert into public.settlement_headers(
    party_id,
    settlement_date,
    currency_code,
    status,
    settlement_type,
    reverses_settlement_id,
    created_by,
    notes
  )
  values (
    v_set.party_id,
    now(),
    v_set.currency_code,
    'posted',
    'reversal',
    v_set.id,
    auth.uid(),
    concat('Reversal: ', v_reason)
  )
  returning id into v_rev_id;

  for v_line in
    select *
    from public.settlement_lines sl
    where sl.settlement_id = p_settlement_id
  loop
    insert into public.settlement_lines(
      settlement_id,
      from_open_item_id,
      to_open_item_id,
      allocated_foreign_amount,
      allocated_base_amount,
      allocated_counter_base_amount,
      fx_rate,
      counter_fx_rate,
      realized_fx_amount
    )
    values (
      v_rev_id,
      v_line.from_open_item_id,
      v_line.to_open_item_id,
      v_line.allocated_foreign_amount,
      v_line.allocated_base_amount,
      v_line.allocated_counter_base_amount,
      v_line.fx_rate,
      v_line.counter_fx_rate,
      -coalesce(v_line.realized_fx_amount,0)
    );

    perform public._party_open_item_apply_delta(v_line.from_open_item_id, coalesce(v_line.allocated_base_amount,0), case when v_line.allocated_foreign_amount is null then null else coalesce(v_line.allocated_foreign_amount,0) end);
    perform public._party_open_item_apply_delta(v_line.to_open_item_id, coalesce(v_line.allocated_counter_base_amount,0), case when v_line.allocated_foreign_amount is null then null else coalesce(v_line.allocated_foreign_amount,0) end);
  end loop;

  for v_fx in
    select je.id
    from public.journal_entries je
    where je.source_table = 'settlements'
      and je.source_id = p_settlement_id::text
      and je.source_event = 'realized_fx'
  loop
    v_fx_rev := public.reverse_journal_entry(v_fx.id, concat('Reversal of settlement FX: ', v_reason));
  end loop;

  insert into public.system_audit_logs(action, module, details, performed_by, performed_at, metadata, risk_level, reason_code)
  values (
    'settlements.reverse',
    'accounting',
    p_settlement_id::text,
    auth.uid(),
    now(),
    jsonb_build_object('settlementId', p_settlement_id::text, 'reversalSettlementId', v_rev_id::text, 'reason', v_reason),
    'HIGH',
    'SETTLEMENT_REVERSE'
  );

  return v_rev_id;
end;
$$;


ALTER FUNCTION "public"."void_settlement"("p_settlement_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: accounting_documents; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."accounting_documents" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "document_type" "text" NOT NULL,
    "source_table" "text" NOT NULL,
    "source_id" "text" NOT NULL,
    "branch_id" "uuid" NOT NULL,
    "company_id" "uuid" NOT NULL,
    "status" "text" NOT NULL,
    "memo" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "reversed_document_id" "uuid",
    "document_number" "text",
