--
-- Name: base_currency_restatement_retry_targets; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."base_currency_restatement_retry_targets" AS
 SELECT "m"."original_journal_entry_id" AS "journal_entry_id",
    ("je"."entry_date")::"date" AS "entry_date",
    "je"."created_at",
    "je"."memo",
    "m"."status",
    "m"."notes"
   FROM ("public"."base_currency_restatement_entry_map" "m"
     JOIN "public"."journal_entries" "je" ON (("je"."id" = "m"."original_journal_entry_id")))
  WHERE (("m"."status" = 'skipped'::"text") AND ("m"."restated_journal_entry_id" IS NULL) AND ("m"."notes" = 'missing/invalid old_base->new_base accounting rate'::"text"));


