--
-- Name: enterprise_gl_lines; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."enterprise_gl_lines" WITH ("security_invoker"='true') AS
 SELECT ("je"."entry_date")::"date" AS "entry_date",
    "je"."id" AS "journal_entry_id",
    "jl"."id" AS "journal_line_id",
    "je"."memo" AS "entry_memo",
    "je"."source_table",
    "je"."source_id",
    "je"."source_event",
    "je"."company_id",
    "je"."branch_id",
    "je"."journal_id",
    "je"."document_id",
    "jl"."account_id",
    "coa"."code" AS "account_code",
    "coa"."name" AS "account_name",
    "coa"."account_type",
    "coa"."normal_balance",
    "coa"."ifrs_statement",
    "coa"."ifrs_category",
    "coa"."ifrs_line",
    "jl"."debit",
    "jl"."credit",
        CASE
            WHEN ("coa"."normal_balance" = 'credit'::"text") THEN ("jl"."credit" - "jl"."debit")
            ELSE ("jl"."debit" - "jl"."credit")
        END AS "signed_base_amount",
    "upper"(COALESCE("jl"."currency_code", "public"."get_base_currency"())) AS "currency_code",
    "jl"."fx_rate",
    "jl"."foreign_amount",
        CASE
            WHEN (("jl"."currency_code" IS NULL) OR ("upper"("jl"."currency_code") = "upper"("public"."get_base_currency"())) OR ("jl"."foreign_amount" IS NULL)) THEN NULL::numeric
            ELSE
            CASE
                WHEN ("jl"."debit" > (0)::numeric) THEN COALESCE("jl"."foreign_amount", (0)::numeric)
                ELSE (- COALESCE("jl"."foreign_amount", (0)::numeric))
            END
        END AS "signed_foreign_amount",
    "jl"."party_id",
    "jl"."cost_center_id",
    "jl"."dept_id",
    "jl"."project_id",
    "jl"."line_memo"
   FROM (("public"."journal_entries" "je"
     JOIN "public"."journal_lines" "jl" ON (("jl"."journal_entry_id" = "je"."id")))
     JOIN "public"."chart_of_accounts" "coa" ON (("coa"."id" = "jl"."account_id")))
  WHERE ((( SELECT ("s"."locked_at")::"date" AS "locked_at"
           FROM "public"."base_currency_restatement_state" "s"
          WHERE ("s"."id" = 'sar_base_lock'::"text")
         LIMIT 1) IS NULL) OR (("je"."entry_date")::"date" >= ( SELECT ("s"."locked_at")::"date" AS "locked_at"
           FROM "public"."base_currency_restatement_state" "s"
          WHERE ("s"."id" = 'sar_base_lock'::"text")
         LIMIT 1)) OR (COALESCE("je"."source_table", ''::"text") = 'base_currency_restatement'::"text"));


ALTER VIEW "public"."enterprise_gl_lines" OWNER TO "postgres";

