--
-- Name: historical_base_currency_restatement_targets; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."historical_base_currency_restatement_targets" AS
 WITH "state" AS (
         SELECT ("base_currency_restatement_state"."locked_at")::"date" AS "lock_date"
           FROM "public"."base_currency_restatement_state"
          WHERE ("base_currency_restatement_state"."id" = 'sar_base_lock'::"text")
         LIMIT 1
        ), "rng" AS (
         SELECT ( SELECT ("min"("je"."entry_date"))::"date" AS "min"
                   FROM "public"."journal_entries" "je") AS "min_date",
            COALESCE(( SELECT "state"."lock_date"
                   FROM "state"), CURRENT_DATE) AS "max_date"
        ), "eligible" AS (
         SELECT "je"."id" AS "journal_entry_id",
            ("je"."entry_date")::"date" AS "entry_date",
            "je"."created_at",
            "je"."memo",
            COALESCE("sum"(COALESCE("jl"."debit", (0)::numeric)), (0)::numeric) AS "debit_total",
            COALESCE("sum"(COALESCE("jl"."credit", (0)::numeric)), (0)::numeric) AS "credit_total"
           FROM (("public"."journal_entries" "je"
             JOIN "public"."journal_lines" "jl" ON (("jl"."journal_entry_id" = "je"."id")))
             JOIN "rng" ON (true))
          WHERE ((("je"."entry_date")::"date" >= "rng"."min_date") AND (("je"."entry_date")::"date" <= "rng"."max_date") AND (COALESCE("je"."source_table", ''::"text") <> ALL (ARRAY['fx_revaluation'::"text", 'settlements'::"text", 'base_currency_restatement'::"text"])) AND (COALESCE("je"."source_event", ''::"text") <> 'reversal'::"text") AND (NOT (EXISTS ( SELECT 1
                   FROM "public"."journal_lines" "jl2"
                  WHERE (("jl2"."journal_entry_id" = "je"."id") AND (("jl2"."currency_code" IS NOT NULL) OR ("jl2"."fx_rate" IS NOT NULL) OR ("jl2"."foreign_amount" IS NOT NULL)))))) AND (NOT (EXISTS ( SELECT 1
                   FROM "public"."journal_lines" "jl3"
                  WHERE (("jl3"."journal_entry_id" = "je"."id") AND ("jl3"."party_id" IS NOT NULL))))) AND (NOT (EXISTS ( SELECT 1
                   FROM "public"."base_currency_restatement_entry_map" "m"
                  WHERE ("m"."original_journal_entry_id" = "je"."id")))))
          GROUP BY "je"."id", "je"."entry_date", "je"."created_at", "je"."memo"
        )
 SELECT "journal_entry_id",
    "entry_date",
    "created_at",
    "memo",
    "debit_total",
    "credit_total"
   FROM "eligible" "e"
  WHERE ("abs"((COALESCE("debit_total", (0)::numeric) - COALESCE("credit_total", (0)::numeric))) <= 0.000001)
  ORDER BY "entry_date", "created_at", "journal_entry_id";


ALTER VIEW "public"."historical_base_currency_restatement_targets" OWNER TO "postgres";

--
-- Name: historical_base_currency_restatement_targets_fx; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."historical_base_currency_restatement_targets_fx" AS
 WITH "state" AS (
         SELECT ("base_currency_restatement_state"."locked_at")::"date" AS "lock_date"
           FROM "public"."base_currency_restatement_state"
          WHERE ("base_currency_restatement_state"."id" = 'sar_base_lock'::"text")
         LIMIT 1
        ), "rng" AS (
         SELECT ( SELECT ("min"("je"."entry_date"))::"date" AS "min"
                   FROM "public"."journal_entries" "je") AS "min_date",
            COALESCE(( SELECT "state"."lock_date"
                   FROM "state"), CURRENT_DATE) AS "max_date"
        ), "eligible" AS (
         SELECT "je"."id" AS "journal_entry_id",
            ("je"."entry_date")::"date" AS "entry_date",
            "je"."created_at",
            "je"."memo"
           FROM ("public"."journal_entries" "je"
             JOIN "rng" ON (true))
          WHERE ((("je"."entry_date")::"date" >= "rng"."min_date") AND (("je"."entry_date")::"date" <= "rng"."max_date") AND (COALESCE("je"."source_table", ''::"text") <> ALL (ARRAY['fx_revaluation'::"text", 'settlements'::"text", 'base_currency_restatement'::"text", 'base_currency_migration'::"text"])) AND (COALESCE("je"."source_event", ''::"text") <> 'reversal'::"text") AND (EXISTS ( SELECT 1
                   FROM "public"."journal_lines" "jl2"
                  WHERE (("jl2"."journal_entry_id" = "je"."id") AND (("jl2"."currency_code" IS NOT NULL) OR ("jl2"."fx_rate" IS NOT NULL) OR ("jl2"."foreign_amount" IS NOT NULL))))) AND (NOT (EXISTS ( SELECT 1
                   FROM "public"."base_currency_restatement_entry_map" "m"
                  WHERE (("m"."original_journal_entry_id" = "je"."id") AND ("m"."status" = 'restated'::"text") AND ("m"."restated_journal_entry_id" IS NOT NULL))))))
        )
 SELECT "journal_entry_id",
    "entry_date",
    "created_at",
    "memo"
   FROM "eligible" "e"
  ORDER BY "entry_date", "created_at", "journal_entry_id";


ALTER VIEW "public"."historical_base_currency_restatement_targets_fx" OWNER TO "postgres";

