    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "party_open_items_direction_check" CHECK (("direction" = ANY (ARRAY['debit'::"text", 'credit'::"text"]))),
    CONSTRAINT "party_open_items_status_check" CHECK (("status" = ANY (ARRAY['open'::"text", 'partially_settled'::"text", 'settled'::"text"])))
);


