--
-- Name: party_ap_aging_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."party_ap_aging_summary" WITH ("security_invoker"='true') AS
 WITH "open_items" AS (
         SELECT "poi"."party_id",
            GREATEST((0)::numeric, COALESCE("poi"."open_base_amount", (0)::numeric)) AS "outstanding",
            (CURRENT_DATE - COALESCE("poi"."due_date", ("poi"."occurred_at")::"date")) AS "age_days"
           FROM "public"."party_open_items" "poi"
          WHERE (("poi"."status" = ANY (ARRAY['open'::"text", 'partially_settled'::"text"])) AND ("poi"."item_role" = 'ap'::"text") AND ("poi"."direction" = 'credit'::"text") AND (COALESCE("poi"."open_base_amount", (0)::numeric) > 0.000001))
        )
 SELECT "party_id",
    COALESCE("sum"(
        CASE
            WHEN ("age_days" <= 0) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "current",
    COALESCE("sum"(
        CASE
            WHEN (("age_days" >= 1) AND ("age_days" <= 30)) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "days_1_30",
    COALESCE("sum"(
        CASE
            WHEN (("age_days" >= 31) AND ("age_days" <= 60)) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "days_31_60",
    COALESCE("sum"(
        CASE
            WHEN (("age_days" >= 61) AND ("age_days" <= 90)) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "days_61_90",
    COALESCE("sum"(
        CASE
            WHEN ("age_days" >= 91) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "days_91_plus",
    COALESCE("sum"("outstanding"), (0)::numeric) AS "total_outstanding"
   FROM "open_items" "oi"
  GROUP BY "party_id"
  ORDER BY COALESCE("sum"("outstanding"), (0)::numeric) DESC;


ALTER VIEW "public"."party_ap_aging_summary" OWNER TO "postgres";

--
-- Name: party_ar_aging_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."party_ar_aging_summary" WITH ("security_invoker"='true') AS
 WITH "open_items" AS (
