          WHERE (("poi"."status" = ANY (ARRAY['open'::"text", 'partially_settled'::"text"])) AND ("poi"."item_role" = 'ar'::"text") AND ("poi"."direction" = 'debit'::"text") AND (COALESCE("poi"."open_base_amount", (0)::numeric) > 0.000001))
        )
 SELECT "party_id",
    COALESCE("sum"(
        CASE
            WHEN ("age_days" <= 0) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "current",
    COALESCE("sum"(
        CASE
            WHEN (("age_days" >= 1) AND ("age_days" <= 30)) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "days_1_30",
    COALESCE("sum"(
        CASE
            WHEN (("age_days" >= 31) AND ("age_days" <= 60)) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "days_31_60",
    COALESCE("sum"(
        CASE
            WHEN (("age_days" >= 61) AND ("age_days" <= 90)) THEN "outstanding"
            ELSE (0)::numeric
        END), (0)::numeric) AS "days_61_90",
