--
-- Name: workflow_current_assignments; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."workflow_current_assignments" WITH ("security_invoker"='true') AS
 SELECT DISTINCT ON ("instance_id", "step_no") "id",
    "instance_id",
    "step_no",
    "assigned_permission",
    "assigned_to",
    "due_at",
    "escalation_level",
    "reason",
    "metadata",
    "created_at",
    "created_by"
   FROM "public"."workflow_step_assignments" "a"
  ORDER BY "instance_id", "step_no", "created_at" DESC, "id" DESC;


ALTER VIEW "public"."workflow_current_assignments" OWNER TO "postgres";

