   FROM "public"."admin_users" "me"
  WHERE (("me"."auth_user_id" = "auth"."uid"()) AND ("me"."is_active" = true) AND ("me"."role" = ANY (ARRAY['owner'::"text", 'manager'::"text"]))))) AND ("auth_user_id" <> "auth"."uid"()) AND ("role" <> 'owner'::"text"))) WITH CHECK (("role" <> 'owner'::"text"));


