-- Name: order_events order_events_delete_admin; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "order_events_delete_admin" ON "public"."order_events" FOR DELETE USING ("public"."is_admin"());


--
-- Name: order_events order_events_insert_admin; Type: POLICY; Schema: public; Owner: postgres
--

