  WHERE (("au"."auth_user_id" = "auth"."uid"()) AND ("au"."is_active" = true) AND ("au"."role" = 'delivery'::"text")))) AND (("data" ->> 'assignedDeliveryUserId'::"text") = ("auth"."uid"())::"text"))));


