--
-- Name: payments payments_select_least_privilege; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "payments_select_least_privilege" ON "public"."payments" FOR SELECT USING (((EXISTS ( SELECT 1
   FROM "public"."admin_users" "au"
  WHERE (("au"."auth_user_id" = "auth"."uid"()) AND ("au"."is_active" = true) AND ("au"."role" = ANY (ARRAY['owner'::"text", 'manager'::"text", 'accountant'::"text"]))))) OR (EXISTS ( SELECT 1
   FROM "public"."admin_users" "au"
  WHERE (("au"."auth_user_id" = "auth"."uid"()) AND ("au"."is_active" = true) AND ('accounting.manage'::"text" = ANY (COALESCE("au"."permissions", '{}'::"text"[])))))) OR ("created_by" = "auth"."uid"()) OR (("reference_table" = 'orders'::"text") AND ("reference_id" ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$'::"text") AND (EXISTS ( SELECT 1
   FROM "public"."orders" "o"
  WHERE (("o"."id" = ("payments"."reference_id")::"uuid") AND ("o"."customer_auth_user_id" = "auth"."uid"())))))));


